window.WebDevGymCurriculumData={"version":"2026-07-21","locale":"en","sections":[{"id":"sec-calendar","lessons":[{"id":"block-calendar-main","title":"Learning plan until 12/31/2026 🔗","html":"<div class=\"block\" id=\"block-calendar-main\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-calendar-main')\">Learning plan <span class=\"badge good\">until 12/31/2026</span><span class=\"anchor-icon\">🔗</span></div>\n\n      <div class=\"wdg-cal-toolbar\">\n        <button class=\"wdg-cal-btn\" onclick=\"wdgCalMoveDay(-1)\">← Day</button>\n        <button class=\"wdg-cal-btn primary\" onclick=\"wdgCalGoToday()\">Today</button>\n        <button class=\"wdg-cal-btn\" onclick=\"wdgCalMoveDay(1)\">Day →</button>\n        <button class=\"wdg-cal-btn\" onclick=\"wdgCalAddTask()\">Add</button>\n        <button class=\"wdg-cal-btn\" onclick=\"wdgCalExport()\">Export calendar</button>\n        <button class=\"wdg-cal-btn\" onclick=\"wdgCalImport()\">Import calendar</button>\n        <button class=\"wdg-cal-btn danger\" onclick=\"wdgCalResetPlan()\">Reset calendar</button>\n      </div>\n\n      <div class=\"wdg-cal-hero\">\n        <div class=\"wdg-cal-card\">\n          <p class=\"wdg-cal-kicker\" id=\"wdgCalDateLabel\">Today</p>\n          <h2 class=\"wdg-cal-title\" id=\"wdgCalTodayTitle\">Loading...</h2>\n          <p class=\"wdg-cal-desc\" id=\"wdgCalTodayDesc\">The calendar is preparing the next step.</p>\n          <div class=\"wdg-cal-stats\">\n            <div class=\"wdg-cal-stat\"><strong id=\"wdgCalDoneLessons\">0</strong><span>study days completed</span></div>\n            <div class=\"wdg-cal-stat\"><strong id=\"wdgCalDaysLeft\">0</strong><span>days until December 31</span></div>\n            <div class=\"wdg-cal-stat\"><strong id=\"wdgCalNextLessons\">0</strong><span>upcoming topics</span></div>\n          </div>\n        </div>\n        <div class=\"wdg-cal-card\">\n          <p class=\"wdg-cal-kicker\">Note</p>\n          <textarea class=\"wdg-cal-note\" id=\"wdgCalNote\" placeholder=\"What is important to remember about study, Kwork, or projects?\"></textarea>\n        </div>\n      </div>\n\n      <div class=\"wdg-cal-layout\">\n        <div class=\"wdg-cal-card\">\n          <div class=\"wdg-cal-month-head\">\n            <button class=\"wdg-cal-btn\" onclick=\"wdgCalMoveMonth(-1)\">←</button>\n            <h3 id=\"wdgCalMonthTitle\">Month</h3>\n            <button class=\"wdg-cal-btn\" onclick=\"wdgCalMoveMonth(1)\">→</button>\n          </div>\n          <div class=\"wdg-cal-grid\" style=\"margin-bottom:7px;\">\n            <div class=\"wdg-cal-weekday\">Mon</div>\n            <div class=\"wdg-cal-weekday\">Tue</div>\n            <div class=\"wdg-cal-weekday\">Wed</div>\n            <div class=\"wdg-cal-weekday\">Thu</div>\n            <div class=\"wdg-cal-weekday\">Fri</div>\n            <div class=\"wdg-cal-weekday\">Sat</div>\n            <div class=\"wdg-cal-weekday\">Sun</div>\n          </div>\n          <div class=\"wdg-cal-grid\" id=\"wdgCalGrid\"></div>\n        </div>\n\n        <div class=\"wdg-cal-card\">\n          <div class=\"wdg-cal-month-head\">\n            <h3>Day tasks</h3>\n            <div style=\"display:flex;gap:8px;flex-wrap:wrap;justify-content:flex-end;\">\n              <span class=\"wdg-cal-pill\" id=\"wdgCalDayType\">Plan</span>\n              <button class=\"wdg-cal-btn primary\" id=\"wdgCalCompleteDayBtn\" onclick=\"wdgCalToggleSelectedDay()\">Mark day done</button>\n            </div>\n          </div>\n          <div class=\"wdg-cal-task-list\" id=\"wdgCalTaskList\"></div>\n        </div>\n      </div>\n    </div>\n\n    "},{"id":"block-calendar-route","title":"Upcoming route next steps 🔗","html":"<div class=\"block\" id=\"block-calendar-route\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-calendar-route')\">Upcoming route <span class=\"badge good\">next steps</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"wdg-cal-route\" id=\"wdgCalRoute\"></div>\n    </div>\n  "}]},{"id":"sec-html","lessons":[{"id":"block-semantic","title":"Semantic tags important 🔗","html":"<div class=\"block\" id=\"block-semantic\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-semantic')\">Semantic tags <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">&lt;header&gt;  — site header (logo, navigation)\n&lt;nav&gt;     — menu / navigation\n&lt;main&gt;    — MAIN content (one per page!)\n&lt;section&gt; — thematic section\n&lt;article&gt; — independent block (article, post)\n&lt;aside&gt;   — sidebar\n&lt;footer&gt;  — footer (copyright, contacts)</div>\n      <div class=\"explain\">\n        Before, everything was done with <code>&lt;div class=\"header\"&gt;</code>. Now there is <code>&lt;header&gt;</code> — browser and search engines <em>understand</em> the structure.<br><br>\n        <strong>section vs article — beginners confuse:</strong><br>\n        <strong>&lt;article&gt;</strong> — independent block, that can be cut out and inserted into another site while keeping its meaning (blog post, news item, product card).<br>\n        <strong>&lt;section&gt;</strong> — just a thematic part of the page, not independent content (About section, Testimonials block on a landing page).\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb18\" onchange=\"updateProgress(this)\"><span>header, nav, main, section, article, aside, footer — instead of div</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb19\" onchange=\"updateProgress(this)\"><span>main — only one per page. It contains the main content</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb20\" onchange=\"updateProgress(this)\"><span>article — independent block, section — just a page section</span></label>\n      </div>\n    </div>\n    "},{"id":"block-page-structure","title":"Page structure basics 🔗","html":"<div class=\"block\" id=\"block-page-structure\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-page-structure')\">Page structure <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">HTML is the skeleton of any website. It is not responsible for beauty; it tells the browser: this is a heading, this is an image, this is a link.</div>\n      <div class=\"code\">&lt;!DOCTYPE html&gt;\n&lt;html lang=\"en\"&gt;\n  &lt;head&gt;\n    &lt;meta charset=\"UTF-8\"&gt;\n    &lt;title&gt;My site&lt;/title&gt;\n  &lt;/head&gt;\n  &lt;body&gt;\n    &lt;h1&gt;Hello, world!&lt;/h1&gt;\n  &lt;/body&gt;\n&lt;/html&gt;</div>\n      <div class=\"explain\">\n        <strong>&lt;!DOCTYPE html&gt;</strong> — tells the browser: this is modern HTML5. Always write it as the first line.<br>\n        <strong>&lt;html lang=\"en\"&gt;</strong> — the page root. <code>lang</code> tells the browser and search engines the language.<br>\n        <strong>&lt;head&gt;</strong> — the head of the site. It contains settings that are <em>not visible</em> on the page: encoding, tab title, CSS link.<br>\n        <strong>&lt;meta charset=\"UTF-8\"&gt;</strong> — so text displays correctly. Without it you may get broken characters.<br>\n        <strong>&lt;body&gt;</strong> — the body of the site. Everything you write here <em>will be visible to the user</em>.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb1\" onchange=\"updateProgress(this)\"><span>I understand why DOCTYPE is needed</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb2\" onchange=\"updateProgress(this)\"><span>I know the difference between &lt;head&gt; (settings) and &lt;body&gt; (visible content)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb3\" onchange=\"updateProgress(this)\"><span>I remember charset=\"UTF-8\" so text displays correctly</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb4\" onchange=\"updateProgress(this)\"><span>&lt;title&gt; — this is the browser tab text, not page content</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-headings","title":"Headings and text basics 🔗","html":"<div class=\"block\" id=\"block-headings\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-headings')\">Headings and text <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">&lt;h1&gt;Main heading&lt;/h1&gt;     ← only one per page!\n&lt;h2&gt;Section&lt;/h2&gt;\n&lt;h3&gt;Subsection&lt;/h3&gt;\n&lt;p&gt;This is a text paragraph.&lt;/p&gt;\n&lt;p&gt;Here is &lt;strong&gt;bold&lt;/strong&gt; and &lt;em&gt;italic&lt;/em&gt; text.&lt;/p&gt;</div>\n      <div class=\"explain\">\n        <strong>h1–h6</strong> — headings. h1 — the most important one (page title), h6 — the smallest. Keep the heading hierarchy in order: h1 → h2 → h3. <em>Do not skip levels!</em><br>\n        <strong>&lt;p&gt;</strong> — a paragraph. The browser automatically adds spacing between paragraphs.<br>\n        <strong>&lt;strong&gt;</strong> — bold, means <em>important</em> text.<br>\n        <strong>&lt;em&gt;</strong> — italic, means <em>emphasis</em> (emphasis).<br>\n        <strong>&lt;br&gt;</strong> — a line break. Do not use it for spacing. Use CSS for spacing.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb5\" onchange=\"updateProgress(this)\"><span>Only one h1 per page; the rest are h2, h3...</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb6\" onchange=\"updateProgress(this)\"><span>&lt;p&gt; for text, not &lt;div&gt;</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb7\" onchange=\"updateProgress(this)\"><span>&lt;strong&gt; = important, &lt;em&gt; = emphasis (emphasis)</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-links","title":"Links and images CORE #","html":"<div class=\"block wdg-quality-block\" id=\"block-links\"><div class=\"block-title\" onclick=\"scrollToBlock('block-links')\">Links and images <span class=\"badge must\">CORE</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">A link navigates to a page or section. A button performs an action. Do not nest <code>&lt;button&gt;</code> inside <code>&lt;a&gt;</code>: that creates invalid nested interactive content.</div><div class=\"code\">&lt;!-- External link --&gt;\n&lt;a href=\"https://example.com\" target=\"_blank\" rel=\"noopener noreferrer\"&gt;\n  Open documentation\n&lt;/a&gt;\n\n&lt;!-- A page and section on the current site --&gt;\n&lt;a href=\"settings.html\"&gt;Settings&lt;/a&gt;\n&lt;a href=\"#contacts\"&gt;Go to contacts&lt;/a&gt;\n\n&lt;!-- A link can look like a button without a nested button --&gt;\n&lt;a href=\"settings.html\" class=\"btn\"&gt;Settings&lt;/a&gt;\n\n&lt;img src=\"team.jpg\" alt=\"Project team at a desk\" width=\"640\"&gt;</div><div class=\"explain\"><code>href</code> stores the destination. <code>#contacts</code> targets an element with <code>id=\"contacts\"</code>. Add <code>rel=\"noopener noreferrer\"</code> for a new tab. <code>alt</code> describes the image meaning; a decorative image may use <code>alt=\"\"</code>. The <code>.btn</code> class changes appearance, not link semantics.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-links-1\" onchange=\"updateProgress(this)\"><span>Links navigate, buttons perform actions</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-links-2\" onchange=\"updateProgress(this)\"><span>I do not nest interactive elements</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-links-3\" onchange=\"updateProgress(this)\"><span>I write meaningful alt text</span></label></div></div>"},{"id":"block-lists","title":"Lists basics 🔗","html":"<div class=\"block\" id=\"block-lists\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-lists')\">Lists <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">&lt;!-- Bulleted list — when order does not matter --&gt;\n&lt;ul&gt;\n  &lt;li&gt;Milk&lt;/li&gt;\n  &lt;li&gt;Bread&lt;/li&gt;\n&lt;/ul&gt;\n\n&lt;!-- Numbered list — when order matters --&gt;\n&lt;ol&gt;\n  &lt;li&gt;Open the editor&lt;/li&gt;\n  &lt;li&gt;Write code&lt;/li&gt;\n  &lt;li&gt;Save the file&lt;/li&gt;\n&lt;/ol&gt;</div>\n      <div class=\"explain\">\n        <strong>&lt;ul&gt;</strong> — a bulleted list. The order of items <em>does not matter</em> (shopping list).<br>\n        <strong>&lt;ol&gt;</strong> — a numbered list 1, 2, 3... Order <em>matters</em> (instruction, recipe).<br>\n        <strong>&lt;li&gt;</strong> — list item. Always inside &lt;ul&gt; or &lt;ol&gt;.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb13\" onchange=\"updateProgress(this)\"><span>ul = order does not matter, ol = order matters</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb14\" onchange=\"updateProgress(this)\"><span>li — always inside ul or ol, not by itself</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-forms","title":"Forms: data that is actually submitted IMPORTANT #","html":"<div class=\"block wdg-quality-block\" id=\"block-forms\"><div class=\"block-title\" onclick=\"scrollToBlock('block-forms')\">Forms: data that is actually submitted <span class=\"badge good\">IMPORTANT</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">Every submitted form control needs a <code>name</code>. Without it, the value is visible in the browser but absent from <code>FormData</code>, Server Actions, and regular server handlers.</div><div class=\"code\">&lt;form action=\"/api/contact\" method=\"post\"&gt;\n  &lt;label for=\"contact-name\"&gt;Name&lt;/label&gt;\n  &lt;input id=\"contact-name\" name=\"name\" autocomplete=\"name\" required&gt;\n\n  &lt;label for=\"contact-email\"&gt;Email&lt;/label&gt;\n  &lt;input id=\"contact-email\" name=\"email\" type=\"email\" autocomplete=\"email\" required&gt;\n\n  &lt;label for=\"contact-message\"&gt;Message&lt;/label&gt;\n  &lt;textarea id=\"contact-message\" name=\"message\" rows=\"5\" required&gt;&lt;/textarea&gt;\n\n  &lt;label&gt;\n    &lt;input name=\"consent\" type=\"checkbox\" value=\"yes\" required&gt;\n    I consent to data processing\n  &lt;/label&gt;\n\n  &lt;button type=\"submit\"&gt;Submit&lt;/button&gt;\n&lt;/form&gt;\n\nconst data = new FormData(document.querySelector(\"form\"));\nconsole.log(data.get(\"email\"));</div><div class=\"explain\"><code>label for</code> connects to the field <code>id</code>. <code>name</code> becomes the submitted key. <code>type=\"email\"</code> enables basic browser validation and <code>required</code> blocks empty submission. The server must validate again. Disabled controls are not submitted.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-forms-1\" onchange=\"updateProgress(this)\"><span>Every submitted field has a name</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-forms-2\" onchange=\"updateProgress(this)\"><span>I connect labels to fields</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-forms-3\" onchange=\"updateProgress(this)\"><span>I validate on the server</span></label></div></div>"},{"id":"block-tables","title":"Tables: only for tabular data PRACTICE #","html":"<div class=\"block wdg-quality-block\" id=\"block-tables\"><div class=\"block-title\" onclick=\"scrollToBlock('block-tables')\">Tables: only for tabular data <span class=\"badge good\">PRACTICE</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">Tables are not obsolete: reports, pricing, statistics, and admin screens need them. What is obsolete is using a table to lay out an entire page.</div><div class=\"code\">&lt;table&gt;\n  &lt;caption&gt;Course results&lt;/caption&gt;\n  &lt;thead&gt;\n    &lt;tr&gt;&lt;th scope=\"col\"&gt;Student&lt;/th&gt;&lt;th scope=\"col\"&gt;Score&lt;/th&gt;&lt;/tr&gt;\n  &lt;/thead&gt;\n  &lt;tbody&gt;\n    &lt;tr&gt;&lt;th scope=\"row\"&gt;Anna&lt;/th&gt;&lt;td&gt;92&lt;/td&gt;&lt;/tr&gt;\n    &lt;tr&gt;&lt;th scope=\"row\"&gt;Max&lt;/th&gt;&lt;td&gt;87&lt;/td&gt;&lt;/tr&gt;\n  &lt;/tbody&gt;\n&lt;/table&gt;</div><div class=\"explain\"><code>caption</code> names the table. <code>thead</code> contains headings and <code>tbody</code> contains data. <code>th</code> marks a header cell, while <code>scope</code> connects it to a row or column. Use Grid or Flexbox for cards and page layout.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-tables-1\" onchange=\"updateProgress(this)\"><span>Tables are only for row-and-column data</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-tables-2\" onchange=\"updateProgress(this)\"><span>I add caption and th</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-tables-3\" onchange=\"updateProgress(this)\"><span>I never build layout with a table</span></label></div></div>"},{"id":"block-meta","title":"Meta tags — SEO and social networks important 🔗","html":"<div class=\"block\" id=\"block-meta\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-meta')\">Meta tags — SEO and social networks <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Meta tags are not visible on the page, but affect how the site looks in search results and social shares.</div>\n      <div class=\"code\">&lt;head&gt;\n  &lt;meta charset=\"UTF-8\"&gt;\n  &lt;meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\"&gt;\n\n  &lt;!-- SEO --&gt;\n  &lt;title&gt;My store — buy online&lt;/title&gt;\n  &lt;meta name=\"description\" content=\"Best store on the internet. Delivery in 1 day.\"&gt;\n  &lt;meta name=\"keywords\" content=\"store, shopping, delivery\"&gt;\n\n  &lt;!-- Open Graph — how it looks when shared (VK, Telegram) --&gt;\n  &lt;meta property=\"og:title\" content=\"My store\"&gt;\n  &lt;meta property=\"og:description\" content=\"Best store!\"&gt;\n  &lt;meta property=\"og:image\" content=\"https://myshop.ru/preview.jpg\"&gt;\n  &lt;meta property=\"og:url\" content=\"https://myshop.ru\"&gt;\n\n  &lt;!-- Indexing ban (for example, for login pages) --&gt;\n  &lt;meta name=\"robots\" content=\"noindex, nofollow\"&gt;\n&lt;/head&gt;</div>\n      <div class=\"explain\">\n        <strong>viewport</strong> — is required for mobile! Without it mobile browser shrinks the page.<br>\n        <strong>description</strong> — description, shown by Google under the link (160 characters).<br>\n        <strong>og:image</strong> — image when shared in messengers and social networks. Size: 1200×630 px.<br>\n        <strong>robots: noindex</strong> — page will not appear in search.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb25\" onchange=\"updateProgress(this)\"><span>viewport — is required for responsive site</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb26\" onchange=\"updateProgress(this)\"><span>description — up to 160 characters, visible in Google</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb27\" onchange=\"updateProgress(this)\"><span>og:image — image when shared (1200×630 px)</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-video-audio","title":"Video, audio, and iframe important 🔗","html":"<div class=\"block\" id=\"block-video-audio\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-video-audio')\">Video, audio, and iframe <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">HTML5 lets you embed media directly on the page — without Flash or third-party plugins.</div>\n      <div class=\"code-wrap\"><div class=\"code\">&lt;!-- Video --&gt;\n&lt;video src=\"movie.mp4\" controls width=\"640\"&gt;\n  Your browser does not support video.\n&lt;/video&gt;\n\n&lt;!-- Several formats (fallback) --&gt;\n&lt;video controls width=\"640\" poster=\"preview.jpg\"&gt;\n  &lt;source src=\"movie.webm\" type=\"video/webm\"&gt;\n  &lt;source src=\"movie.mp4\"  type=\"video/mp4\"&gt;\n&lt;/video&gt;\n\n&lt;!-- Audio --&gt;\n&lt;audio src=\"song.mp3\" controls&gt;&lt;/audio&gt;\n\n&lt;!-- YouTube / Google Maps / any site through iframe --&gt;\n&lt;iframe\n  src=\"https://www.youtube.com/embed/dQw4w9WgXcQ\"\n  width=\"560\" height=\"315\"\n  allowfullscreen&gt;\n&lt;/iframe&gt;</div><button class=\"copy-btn\" onclick=\"copyCode(this)\">Copy</button></div>\n      <div class=\"explain\">\n        <strong>controls</strong> — shows standard player buttons (play, pause, volume).<br>\n        <strong>poster</strong> — video preview image before play.<br>\n        <strong>&lt;source&gt;</strong> — several formats: browser takes the first one it supports.<br>\n        <strong>autoplay muted loop</strong> — autoplay without sound (background videos). Without <code>muted</code> browser blocks autoplay.<br>\n        <strong>&lt;iframe&gt;</strong> — embeds another site or video. allowfullscreen — allows fullscreen mode.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb28\" onchange=\"updateProgress(this)\"><span>controls — is required, otherwise the player will not be visible</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb29\" onchange=\"updateProgress(this)\"><span>autoplay requires muted, otherwise the browser blocks it</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb30\" onchange=\"updateProgress(this)\"><span>&lt;source&gt; — several formats (mp4 + webm) for cross-browser support</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb31\" onchange=\"updateProgress(this)\"><span>&lt;iframe&gt; — embedding YouTube, maps, or any external content</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-data-attrs","title":"Data attributes and accessibility (ARIA) important 🔗","html":"<div class=\"block\" id=\"block-data-attrs\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-data-attrs')\">Data attributes and accessibility (ARIA) <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">data-* let you store any data directly in HTML. ARIA helps people who use screen readers.</div>\n      <div class=\"code-wrap\"><div class=\"code\">&lt;!-- data-* — store custom data in HTML --&gt;\n&lt;button data-user-id=\"42\" data-role=\"admin\"\n        onclick=\"handleClick(this)\"&gt;\n  Open profile\n&lt;/button&gt;\n\n&lt;!-- Read in JS through dataset --&gt;\n&lt;script&gt;\nfunction handleClick(btn) {\n  console.log(btn.dataset.userID);  // \"42\"\n  console.log(btn.dataset.role);    // \"admin\"\n}\n&lt;/script&gt;\n\n&lt;!-- ARIA — hints for screen readers --&gt;\n&lt;button aria-label=\"Close menu\"&gt;✕&lt;/button&gt;\n&lt;input aria-required=\"true\" aria-describedby=\"hint\"&gt;\n&lt;p id=\"hint\"&gt;Minimum 8 characters&lt;/p&gt;\n\n&lt;!-- role — sets the element role --&gt;\n&lt;div role=\"alert\"&gt;Error! Check the form.&lt;/div&gt;\n&lt;nav aria-label=\"Main navigation\"&gt;...&lt;/nav&gt;</div><button class=\"copy-btn\" onclick=\"copyCode(this)\">Copy</button></div>\n      <div class=\"explain\">\n        <strong>data-attribute-name</strong> — the name is written with hyphens. In JS it is read through <code>dataset.attributeName</code> (camelCase).<br>\n        <strong>aria-label</strong> — explains the element to screen readers (when there is no visible text, for example button «✕»).<br>\n        <strong>aria-required</strong> — says the field is required (in addition to <code>required</code>).<br>\n        <strong>role=\"alert\"</strong> — the screen reader announces this text as soon as it appears.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb32\" onchange=\"updateProgress(this)\"><span>data-* — store data in HTML, read through dataset.name</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb33\" onchange=\"updateProgress(this)\"><span>aria-label — is required for icon buttons without text</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb34\" onchange=\"updateProgress(this)\"><span>role=\"alert\" — the screen reader will read the text immediately</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-images","title":"Images — img, srcset, picture basics 🔗","html":"<div class=\"block\" id=\"block-images\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-images')\">Images — img, srcset, picture <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">&lt;img&gt; — the most common media tag. It affects site speed, SEO, and accessibility for blind users.</div>\n      <div class=\"code\">&lt;!-- Basic image --&gt;\n&lt;img src=\"cat.jpg\" alt=\"A ginger cat sleeps on a sofa\" width=\"600\" height=\"400\"&gt;\n\n&lt;!-- alt=\"\" — decorative (pattern, icon). Otherwise describe it --&gt;\n\n&lt;!-- Lazy loading — do not load until visible --&gt;\n&lt;img src=\"photo.jpg\" alt=\"Sunset\" loading=\"lazy\"&gt;\n\n&lt;!-- Different sizes for different screens --&gt;\n&lt;img src=\"photo-800.jpg\"\n     srcset=\"photo-400.jpg  400w,\n             photo-800.jpg  800w,\n             photo-1600.jpg 1600w\"\n     sizes=\"(max-width: 600px) 100vw, 800px\"\n     alt=\"Mountains\"&gt;\n\n&lt;!-- &lt;picture&gt; — different formats (avif/webp/jpg) --&gt;\n&lt;picture&gt;\n  &lt;source srcset=\"photo.avif\" type=\"image/avif\"&gt;\n  &lt;source srcset=\"photo.webp\" type=\"image/webp\"&gt;\n  &lt;img    src=\"photo.jpg\"     alt=\"Sunset\"&gt;   &lt;!-- fallback --&gt;\n&lt;/picture&gt;</div>\n      <div class=\"explain\">\n        <strong>alt</strong> — text instead of the image if it fails to load. Screen readers and Google read it. Decorative — <code>alt=\"\"</code>, important — description.<br>\n        <strong>width / height</strong> — set them in HTML! This reserves space and removes layout jumps during loading (improves CLS in Lighthouse).<br>\n        <strong>loading=\"lazy\"</strong> — browser loads the image, only when it enters the viewport. Use it for all, <em>except the first image on the page</em>.<br>\n        <strong>srcset + sizes</strong> — browser chooses the required size for the screen. Saves traffic on phones.<br>\n        <strong>&lt;picture&gt;</strong> — you need for different formats (avif/webp/jpg) or completely different crops on desktop and phone.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb35\" onchange=\"updateProgress(this)\"><span>I always provide alt — text or alt=\"\" for decorative</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb36\" onchange=\"updateProgress(this)\"><span>width / height in HTML — to avoid content jumps</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb37\" onchange=\"updateProgress(this)\"><span>loading=\"lazy\" — for all images below the first screen</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb38\" onchange=\"updateProgress(this)\"><span>srcset — different sizes for phone and desktop</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb39\" onchange=\"updateProgress(this)\"><span>&lt;picture&gt; + webp/avif → smaller file size, jpg as fallback</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-html-core-web-vitals","title":"Core Web Vitals — speed through the user’s eyes important 🔗","html":"<div class=\"block\" id=\"block-html-core-web-vitals\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-html-core-web-vitals')\">Core Web Vitals — speed through the user’s eyes <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Core Web Vitals — Google metrics for how the user experiences the page: how fast main content appears, whether layout jumps, and how fast the site responds.</div>\n      <div class=\"code\">&lt;!-- LCP: main element of the first screen must load fast --&gt;\n&lt;img src=\"hero.webp\"\n     alt=\"Main project screen\"\n     width=\"1200\"\n     height=\"700\"\n     fetchpriority=\"high\"&gt;\n\n&lt;!-- CLS: always reserve space for media --&gt;\n&lt;img src=\"card.webp\" alt=\"Card\" width=\"360\" height=\"240\" loading=\"lazy\"&gt;\n\n&lt;!-- INP: do not attach heavy work directly to a click --&gt;\n&lt;button&gt;Open menu&lt;/button&gt;</div>\n      <div class=\"explain\">\n        <strong>LCP</strong> — how fast the main visible content appears: hero-image, large heading, first block.<br>\n        <strong>CLS</strong> — whether the page jumps during loading. Fixed with <code>width/height</code>, stable containers and clean font loading.<br>\n        <strong>INP</strong> — how fast the page responds to actions. Do not run heavy loops and big calculations directly in click handlers.<br>\n        <strong>Lighthouse</strong> in Chrome DevTools shows these metrics and suggests what to fix.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-html-cwv-1\" onchange=\"updateProgress(this)\"><span>LCP — main content of the first screen must load fast</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-html-cwv-2\" onchange=\"updateProgress(this)\"><span>CLS — set image sizes and avoid layout jumps</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-html-cwv-3\" onchange=\"updateProgress(this)\"><span>INP — do not block the interface with heavy JS in clicks</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-inputs","title":"Inputs — all form field types basics 🔗","html":"<div class=\"block\" id=\"block-inputs\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-inputs')\">Inputs — all form field types <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">The input element has more than 20 types. The right type enables a convenient phone keyboard, validation, and the you need picker.</div>\n      <div class=\"code\">&lt;!-- Text field --&gt;\n&lt;input type=\"text\"     name=\"name\"   placeholder=\"Name\"&gt;\n&lt;input type=\"email\"    name=\"email\"  required&gt;       &lt;!-- @ on phone --&gt;\n&lt;input type=\"tel\"      name=\"phone\"  pattern=\"[0-9]{11}\"&gt;\n&lt;input type=\"password\" name=\"pass\"   minlength=\"8\"&gt;\n&lt;input type=\"url\"      name=\"site\"&gt;\n&lt;input type=\"search\"   name=\"q\"&gt;\n\n&lt;!-- Numbers and ranges --&gt;\n&lt;input type=\"number\" min=\"1\" max=\"99\" step=\"1\" value=\"18\"&gt;\n&lt;input type=\"range\"  min=\"0\" max=\"100\" value=\"50\"&gt;   &lt;!-- range slider --&gt;\n\n&lt;!-- Dates and time --&gt;\n&lt;input type=\"date\"&gt;          &lt;!-- calendar --&gt;\n&lt;input type=\"time\"&gt;\n&lt;input type=\"datetime-local\"&gt;\n&lt;input type=\"month\"&gt;\n&lt;input type=\"week\"&gt;\n\n&lt;!-- Choice --&gt;\n&lt;input type=\"checkbox\" id=\"ok\"&gt; &lt;label for=\"ok\"&gt;I agree&lt;/label&gt;\n&lt;input type=\"radio\" name=\"size\" value=\"s\"&gt; S\n&lt;input type=\"radio\" name=\"size\" value=\"m\" checked&gt; M\n\n&lt;!-- File and color --&gt;\n&lt;input type=\"file\"  accept=\"image/*\" multiple&gt;\n&lt;input type=\"color\" value=\"#6366f1\"&gt;\n\n&lt;!-- &lt;textarea&gt; — long text, &lt;select&gt; — dropdown list --&gt;\n&lt;textarea rows=\"4\" maxlength=\"500\"&gt;&lt;/textarea&gt;\n&lt;select&gt;\n  &lt;option value=\"\"&gt;Choose...&lt;/option&gt;\n  &lt;option value=\"ru\"&gt;Russian&lt;/option&gt;\n  &lt;option value=\"en\"&gt;English&lt;/option&gt;\n&lt;/select&gt;</div>\n      <div class=\"explain\">\n        <strong>Why the right type matters?</strong> On phones <code>type=\"email\"</code> shows a keyboard with @, <code>type=\"tel\"</code> — numeric, <code>type=\"number\"</code> — only numbers. Without this it is inconvenient for the user.<br>\n        <strong>required, min, max, pattern, minlength</strong> — the browser will not submit a form with an error, without a single line of JS.<br>\n        <strong>&lt;label for=\"id\"&gt;</strong> — clicking the text focuses the field (and for a checkbox it toggles it). Makes the form easier and more accessible.<br>\n        <strong>name=\"...\"</strong> — is required! Without it, the field will not be sent to the server.<br>\n        <strong>placeholder ≠ label</strong> — placeholder disappears while typing. Always duplicate it with a label.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb40\" onchange=\"updateProgress(this)\"><span>type=\"email\" / \"tel\" / \"number\" — convenient keyboard on phones</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb41\" onchange=\"updateProgress(this)\"><span>required, min/max, pattern — validation without JS</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb42\" onchange=\"updateProgress(this)\"><span>&lt;label for=\"id\"&gt; — clicking the text focuses the field</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb43\" onchange=\"updateProgress(this)\"><span>name=\"...\" is required — otherwise the field will not be sent to the server</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb44\" onchange=\"updateProgress(this)\"><span>type=\"date\" / \"color\" / \"file\" — built-in browser pickers</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-iframe","title":"iframe — embed YouTube, maps, widgets important 🔗","html":"<div class=\"block\" id=\"block-iframe\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-iframe')\">iframe — embed YouTube, maps, widgets <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">&lt;iframe&gt; embeds a page inside a page. This is how videos, maps, Google Forms, and social widgets are embedded.</div>\n      <div class=\"code\">&lt;!-- YouTube --&gt;\n&lt;iframe width=\"560\" height=\"315\"\n        src=\"https://www.youtube.com/embed/dQw4w9WgXcQ\"\n        title=\"Video\"\n        frameborder=\"0\"\n        allow=\"autoplay; encrypted-media; picture-in-picture\"\n        allowfullscreen&gt;&lt;/iframe&gt;\n\n&lt;!-- Google Maps (ready embed-code) --&gt;\n&lt;iframe src=\"https://www.google.com/maps/embed?pb=...\"\n        width=\"600\" height=\"450\"\n        loading=\"lazy\"\n        referrerpolicy=\"no-referrer-when-downgrade\"&gt;&lt;/iframe&gt;\n\n&lt;!-- Responsive iframe (16:9) — wrap it --&gt;\n&lt;style&gt;\n  .embed { position: relative; aspect-ratio: 16 / 9; }\n  .embed iframe { position: absolute; inset: 0; width: 100%; height: 100%; border: 0; }\n&lt;/style&gt;\n\n&lt;div class=\"embed\"&gt;\n  &lt;iframe src=\"https://www.youtube.com/embed/...\" allowfullscreen&gt;&lt;/iframe&gt;\n&lt;/div&gt;\n\n&lt;!-- sandbox — constraints for external content (security) --&gt;\n&lt;iframe src=\"https://untrusted.com\"\n        sandbox=\"allow-scripts allow-same-origin\"&gt;&lt;/iframe&gt;</div>\n      <div class=\"explain\">\n        <strong>src=\"...embed...\"</strong> — YouTube/Maps have a separate embed URL. A normal link <code>youtube.com/watch?v=...</code> will not work — you need <code>youtube.com/embed/ID</code>.<br>\n        <strong>aspect-ratio + position:absolute</strong> — standard responsive-video technique. Without it iframe breaks layout on phones.<br>\n        <strong>loading=\"lazy\"</strong> — also works for iframe! Very useful for maps and videos — they are heavy.<br>\n        <strong>sandbox</strong> — restricts external content (cannot run JS, open popups, etc.). Use it when embedding a site you do not own.<br>\n        <strong>title</strong> — is required for screen readers. Explains what is inside the iframe.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb45\" onchange=\"updateProgress(this)\"><span>YouTube → copy Share → Embed and take the URL from src</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb46\" onchange=\"updateProgress(this)\"><span>aspect-ratio + position:absolute — responsive iframe</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb47\" onchange=\"updateProgress(this)\"><span>loading=\"lazy\" — map and video load only on scroll</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb48\" onchange=\"updateProgress(this)\"><span>title=\"...\" — needed for screen readers</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb49\" onchange=\"updateProgress(this)\"><span>sandbox — for untrusted content</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-details-dialog","title":"<details> and <dialog> — spoilers and modals without JS important 🔗","html":"<div class=\"block\" id=\"block-details-dialog\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-details-dialog')\">&lt;details&gt; and &lt;dialog&gt; — spoilers and modals without JS <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Modern HTML can create collapsible blocks and modal windows by itself. You do not need to write JS like years ago.</div>\n      <div class=\"code\">&lt;!-- Spoiler / FAQ --&gt;\n&lt;details&gt;\n  &lt;summary&gt;How to place an order?&lt;/summary&gt;\n  &lt;p&gt;Put the product in the cart and click Buy. We will call you back.&lt;/p&gt;\n&lt;/details&gt;\n\n&lt;details open&gt;     &lt;!-- opened by default --&gt;\n  &lt;summary&gt;Ingredients&lt;/summary&gt;\n  &lt;ul&gt;&lt;li&gt;flour&lt;/li&gt;&lt;li&gt;milk&lt;/li&gt;&lt;/ul&gt;\n&lt;/details&gt;\n\n&lt;!-- Modal window --&gt;\n&lt;dialog id=\"myModal\"&gt;\n  &lt;form method=\"dialog\"&gt;\n    &lt;h2&gt;Confirmation&lt;/h2&gt;\n    &lt;p&gt;Delete file?&lt;/p&gt;\n    &lt;button value=\"cancel\"&gt;Cancel&lt;/button&gt;\n    &lt;button value=\"ok\"&gt;Delete&lt;/button&gt;   &lt;!-- closes the dialog --&gt;\n  &lt;/form&gt;\n&lt;/dialog&gt;\n\n&lt;button onclick=\"myModal.showModal()\"&gt;Delete&lt;/button&gt;\n\n&lt;script&gt;\n  const dlg = document.getElementById('myModal');\n  dlg.addEventListener('close', () =&gt; {\n    if (dlg.returnValue === 'ok') {\n      console.log('Confirmed!');\n    }\n  });\n&lt;/script&gt;</div>\n      <div class=\"explain\">\n        <strong>&lt;details&gt; / &lt;summary&gt;</strong> — native spoiler. Perfect for FAQ, «more details», hidden description. Works without JS, keyboard accessible.<br>\n        <strong>&lt;dialog&gt;</strong> — native modal. <code>.showModal()</code> — open with backdrop (backdrop), <code>.show()</code> — without backdrop.<br>\n        <strong>method=\"dialog\"</strong> — special form type. Any button inside it automatically closes the dialog, and the button <code>value</code> goes into <code>dialog.returnValue</code>.<br>\n        <strong>Esc closes dialog</strong> — built in. No need to write anything.<br>\n        <strong>Styles</strong>: the backdrop is styled with <code>dialog::backdrop { background: rgba(0,0,0,.5); }</code>.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb50\" onchange=\"updateProgress(this)\"><span>&lt;details&gt; / &lt;summary&gt; — spoiler without JS, for FAQ</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb51\" onchange=\"updateProgress(this)\"><span>open — attribute for initially open state</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb52\" onchange=\"updateProgress(this)\"><span>&lt;dialog&gt; + showModal() — native modal with backdrop</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb53\" onchange=\"updateProgress(this)\"><span>Esc closes the dialog automatically</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb54\" onchange=\"updateProgress(this)\"><span>::backdrop — style the dialog backdrop</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-html-popover","title":"Popover API — popups and hints without JS modern 🔗","html":"<div class=\"block\" id=\"block-html-popover\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-html-popover')\">Popover API — popups and hints without JS <span class=\"badge good\">modern</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Popover API — native way to open a small panel, menu, or hint. The browser can close it by Esc and outside click.</div>\n      <div class=\"code\">&lt;button popovertarget=\"menu\"&gt;Open menu&lt;/button&gt;\n\n&lt;div id=\"menu\" popover&gt;\n  &lt;a href=\"/profile\"&gt;Profile&lt;/a&gt;\n  &lt;a href=\"/settings\"&gt;Settings&lt;/a&gt;\n&lt;/div&gt;\n\n&lt;style&gt;\n  [popover] {\n    border: 0;\n    border-radius: 10px;\n    padding: 12px;\n    box-shadow: 0 16px 40px rgba(0,0,0,.18);\n  }\n&lt;/style&gt;</div>\n      <div class=\"explain\">\n        <strong>popover</strong> — turns an element into a popup panel. It is hidden until opened.<br>\n        <strong>popovertarget</strong> — links a button with a popover element by id, without a click handler.<br>\n        <strong>When to use:</strong> dropdown menu, tooltip, filter, quick settings. For full action confirmation it is usually better to use <code>&lt;dialog&gt;</code>.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-html-popover-1\" onchange=\"updateProgress(this)\"><span>I understand popover and popovertarget</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-html-popover-2\" onchange=\"updateProgress(this)\"><span>I know the difference between popover and dialog</span></label>\n      </div>\n    </div>\n\n    "}]},{"id":"sec-css","lessons":[{"id":"block-css-connect","title":"How to connect CSS basics 🔗","html":"<div class=\"block\" id=\"block-css-connect\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-css-connect')\">How to connect CSS <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">CSS is the clothing of a website. HTML is the skeleton; CSS is the appearance: colors, sizes, layout.</div>\n      <div class=\"code\">&lt;!DOCTYPE html&gt;\n&lt;html&gt;\n&lt;head&gt;\n  &lt;!-- THIS LINE connects style.css --&gt;\n  &lt;link rel=\"stylesheet\" href=\"style.css\"&gt;\n&lt;/head&gt;\n&lt;body&gt;\n  &lt;h1&gt;Hello&lt;/h1&gt;\n&lt;/body&gt;\n&lt;/html&gt;\n\n/* And this is the style.css file */\nh1 {\n  color: red;\n  text-align: center;\n}</div>\n      <div class=\"explain\">\n        <strong>Without &lt;link&gt;</strong> the browser does not know about style.css. Styles will not apply.<br>\n        <strong>rel=\"stylesheet\"</strong> — tells the browser: this is a stylesheet.<br>\n        <strong>href=\"style.css\"</strong> — path to the file. If it is in a folder: <code>href=\"css/style.css\"</code>.<br>\n        <strong>Common mistake:</strong> you wrote CSS but did not connect &lt;link&gt;, so nothing changed!\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb55\" onchange=\"updateProgress(this)\"><span>&lt;link rel=\"stylesheet\" href=\"style.css\"&gt; — inside &lt;head&gt;</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb56\" onchange=\"updateProgress(this)\"><span>Without &lt;link&gt; styles will NOT apply</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb57\" onchange=\"updateProgress(this)\"><span>href — path to the file: \"style.css\", \"css/style.css\", \"../style.css\"</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-selectors","title":"Selectors — what styles apply to basics 🔗","html":"<div class=\"block\" id=\"block-selectors\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-selectors')\">Selectors — what styles apply to <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">p            { }   /* All &lt;p&gt; by tag */\n.card        { }   /* class=\"card\" — by class (most common!) */\n#header      { }   /* id=\"header\" — by id (one per page) */\na:hover      { }   /* link on mouse hover */\ndiv &gt; p      { }   /* &lt;p&gt; — direct child &lt;div&gt; */</div>\n      <div class=\"explain\">\n        <strong>Class (.)</strong> — can be used on many elements.<br>\n        <strong>ID (#)</strong> — only <em>one</em> element on the page.<br>\n        <strong>Specificity</strong>: <code>#id</code> &gt; <code>.class</code> &gt; <code>tag</code>.<br>\n        <strong>:hover</strong> — style on hover. :focus — on field focus. :active — while pressed.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb58\" onchange=\"updateProgress(this)\"><span>Class (.) — for many elements. ID (#) — for one</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb59\" onchange=\"updateProgress(this)\"><span>:hover — hover, :focus — focus</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-css-responsive-2026","title":"Responsive layout: Flexbox + Grid 2026 CORE #","html":"<div class=\"block wdg-2026-block\" id=\"block-css-responsive-2026\"><div class=\"block-title\" onclick=\"scrollToBlock('block-css-responsive-2026')\">Responsive layout: Flexbox + Grid <span class=\"badge must\">2026 CORE</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">Flexbox aligns content on one axis; Grid builds a full layout. Modern CSS can often adapt without an extra breakpoint.</div><div class=\"code\">.page {\n  display: grid;\n  grid-template-columns: 16rem minmax(0, 1fr);\n  gap: 24px;\n}\n\n.cards {\n  display: grid;\n  grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));\n  gap: 16px;\n}\n\n.toolbar {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: 12px;\n  flex-wrap: wrap;\n}\n\n@media (max-width: 48rem) {\n  .page { grid-template-columns: 1fr; }\n}</div><div class=\"explain\"><strong>Flexbox</strong> fits menus, button rows, and alignment. <strong>Grid</strong> controls rows and columns together. <code>minmax(0, 1fr)</code> prevents overflow, while <code>auto-fit</code> wraps cards automatically.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-css-responsive-2026-1\" onchange=\"updateProgress(this)\"><span>I choose Flexbox for a row and Grid for a grid</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-css-responsive-2026-2\" onchange=\"updateProgress(this)\"><span>I use repeat(), minmax(), and auto-fit</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-css-responsive-2026-3\" onchange=\"updateProgress(this)\"><span>I test 360 px, 768 px, and a wide screen</span></label></div></div>"},{"id":"block-flexbox","title":"Flexbox — layout in a row basics 🔗","html":"<div class=\"block\" id=\"block-flexbox\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-flexbox')\">Flexbox — layout in a row <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">.container {\n  display: flex;\n  justify-content: center;   /* Horizontally */\n  align-items: center;       /* Vertically */\n  gap: 16px;                 /* Spacing between elements */\n  flex-wrap: wrap;           /* Wrap to a new line */\n}\n.item { flex: 1; }</div>\n      <div class=\"explain\">\n        <strong>display: flex</strong> — all direct children of the container stand in a row.<br>\n        <strong>justify-content</strong> — horizontally. <strong>align-items</strong> — vertically.<br>\n        <strong>gap</strong> — spacing between elements.<br>\n        <strong>flex-wrap: wrap</strong> — if they do not fit, they wrap to the next line.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb81\" onchange=\"updateProgress(this)\"><span>justify-content — horizontally, align-items — vertically</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb82\" onchange=\"updateProgress(this)\"><span>gap — spacing between elements</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb83\" onchange=\"updateProgress(this)\"><span>flex-wrap: wrap — wrap to a new line</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-grid","title":"Grid — grid / table important 🔗","html":"<div class=\"block\" id=\"block-grid\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-grid')\">Grid — grid / table <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">.grid {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr); /* 3 columns */\n  gap: 20px;\n}\n@media (max-width: 768px) {\n  .grid { grid-template-columns: 1fr; } /* On phones — 1 column */\n}\n.span-2 { grid-column: span 2; } /* Spans 2 columns */</div>\n      <div class=\"explain\">\n        <strong>repeat(3, 1fr)</strong> — «repeat 3 times by 1 fraction». You get 3 equal columns.<br>\n        <strong>grid-column: span 2</strong> — this cell will span 2 columns.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb84\" onchange=\"updateProgress(this)\"><span>repeat(3, 1fr) — 3 equal columns</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb85\" onchange=\"updateProgress(this)\"><span>Grid for page grids, Flexbox for elements inside</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-css-tailwind-mobile-2026","title":"Tailwind CSS with Mobile First 2026 CORE #","html":"<div class=\"block wdg-2026-block\" id=\"block-css-tailwind-mobile-2026\"><div class=\"block-title\" onclick=\"scrollToBlock('block-css-tailwind-mobile-2026')\">Tailwind CSS with Mobile First <span class=\"badge must\">2026 CORE</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">Write the phone layout first. The md: and lg: prefixes add changes for wider screens.</div><div class=\"code\">&lt;section class=\"grid grid-cols-1 gap-4 p-4 md:grid-cols-2 md:p-6 lg:grid-cols-3\"&gt;\n  &lt;article class=\"rounded-lg border border-slate-700 bg-slate-900 p-4\"&gt;\n    &lt;h2 class=\"text-lg font-semibold text-white\"&gt;Project&lt;/h2&gt;\n    &lt;p class=\"mt-2 text-sm text-slate-300\"&gt;Responsive by default.&lt;/p&gt;\n    &lt;button class=\"mt-4 w-full bg-violet-600 px-4 py-2 text-white md:w-auto\"&gt;\n      Open\n    &lt;/button&gt;\n  &lt;/article&gt;\n&lt;/section&gt;</div><div class=\"explain\">Unprefixed utilities form the mobile base. <code>md:grid-cols-2</code> starts at md. Tailwind does not replace CSS knowledge; it names CSS rules. Extract repeated UI into a component instead of copying a long class list.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-css-tailwind-mobile-2026-1\" onchange=\"updateProgress(this)\"><span>I start with the mobile version</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-css-tailwind-mobile-2026-2\" onchange=\"updateProgress(this)\"><span>I understand the CSS behind utilities</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-css-tailwind-mobile-2026-3\" onchange=\"updateProgress(this)\"><span>I extract repeated UI into components</span></label></div></div>"},{"id":"block-tailwind-product-card-2026","title":"Product card with Tailwind CSS PRACTICE #","html":"<div class=\"block wdg-quality-block\" id=\"block-tailwind-product-card-2026\"><div class=\"block-title\" onclick=\"scrollToBlock('block-tailwind-product-card-2026')\">Product card with Tailwind CSS <span class=\"badge good\">PRACTICE</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">A product card is a useful utility-composition example. HTML still provides semantics while Tailwind handles presentation and responsive states.</div><div class=\"code\">&lt;article class=\"overflow-hidden rounded-lg border border-slate-700 bg-slate-900\"&gt;\n  &lt;img class=\"aspect-[4/3] w-full object-cover\"\n       src=\"keyboard.jpg\" alt=\"Key Pro mechanical keyboard\"&gt;\n  &lt;div class=\"p-4\"&gt;\n    &lt;h2 class=\"text-lg font-semibold text-white\"&gt;Key Pro&lt;/h2&gt;\n    &lt;p class=\"mt-1 text-sm text-slate-300\"&gt;Quiet switches, RGB&lt;/p&gt;\n    &lt;div class=\"mt-4 flex items-center justify-between gap-3\"&gt;\n      &lt;strong class=\"text-xl text-white\"&gt;7 990 ?&lt;/strong&gt;\n      &lt;button class=\"rounded-md bg-violet-600 px-4 py-2 text-white hover:bg-violet-500\"&gt;\n        Add to cart\n      &lt;/button&gt;\n    &lt;/div&gt;\n  &lt;/div&gt;\n&lt;/article&gt;</div><div class=\"explain\"><code>aspect-[4/3]</code> reserves stable image space so the card does not jump during loading. <code>object-cover</code> fills the area without distortion. Render repeated cards from data in a component instead of copying markup.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-tailwind-product-card-2026-1\" onchange=\"updateProgress(this)\"><span>I keep a semantic article</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-tailwind-product-card-2026-2\" onchange=\"updateProgress(this)\"><span>I reserve the aspect ratio</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-tailwind-product-card-2026-3\" onchange=\"updateProgress(this)\"><span>I extract repeated UI</span></label></div></div>"},{"id":"block-tailwind-basics","title":"Tailwind CSS — utility-first stack 2026 🔗","html":"<div class=\"block\" id=\"block-tailwind-basics\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-tailwind-basics')\">Tailwind CSS — utility-first stack <span class=\"badge must\">2026</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">In new React projects, Tailwind is often chosen instead of hand-written SCSS: styles are assembled from small utility classes directly in JSX, and the design system lives in the config.</div>\n      <div class=\"code\"><span class=\"cm\">// Example component in Tailwind</span>\n&lt;<span class=\"tag\">button</span>\n  <span class=\"attr\">className</span>=<span class=\"str\">\"rounded-lg bg-indigo-600 px-4 py-2 text-sm font-semibold text-white hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-indigo-500\"</span>\n&gt;\n  Save\n&lt;/<span class=\"tag\">button</span>&gt;\n\n<span class=\"cm\">// tailwind.config.ts — team design tokens</span>\n<span class=\"kw\">export default</span> {\n  theme: {\n    extend: {\n      colors: { brand: <span class=\"str\">'#6366f1'</span> },\n      borderRadius: { card: <span class=\"str\">'8px'</span> }\n    }\n  }\n}</div>\n      <div class=\"explain\">\n        <strong>Utility-first</strong> — a class describes one CSS property: <code>px-4</code>, <code>flex</code>, <code>text-sm</code>.<br>\n        <strong>Plus for teams:</strong> fewer random CSS files and name conflicts, easier to keep consistent spacing, colors, and states.<br>\n        <strong>Important:</strong> Tailwind does not replace CSS knowledge. You need to understand cascade, flex/grid, responsiveness, and accessibility, otherwise classes turn into chaos.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb152a\" onchange=\"updateProgress(this)\"><span>I understand the utility-first approach in Tailwind CSS</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb152b\" onchange=\"updateProgress(this)\"><span>I know where colors, spacing, and radii are configured in Tailwind</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-div","title":"<div> — universal container basics 🔗","html":"<div class=\"block\" id=\"block-div\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-div')\">&lt;div&gt; — universal container <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">&lt;div&gt; — is a box without semantic meaning. It does not tell the browser what is inside. Just a container where you put elements.</div>\n      <div class=\"code\">&lt;!-- Group elements together --&gt;\n&lt;div class=\"card\"&gt;\n  &lt;img src=\"photo.jpg\" alt=\"Photo\"&gt;\n  &lt;h3&gt;Card title&lt;/h3&gt;\n  &lt;p&gt;Card description&lt;/p&gt;\n  &lt;button&gt;More details&lt;/button&gt;\n&lt;/div&gt;\n\n/* CSS: style the whole card */\n.card {\n  background: white;\n  border-radius: 12px;\n  padding: 20px;\n  margin: 10px;\n}</div>\n      <div class=\"explain\">\n        <strong>&lt;div&gt;</strong> — just a container. It does not mean «card», «heading», «link». It means «something is grouped here».<br>\n        <strong>Why:</strong> to apply styles to everything at once. For example: make a border around image + text + button.<br>\n        <strong>class=\"card\"</strong> — give it a name. In CSS: <code>.card { background: white; padding: 20px; }</code>.<br><br>\n        <strong>When to use &lt;div&gt;:</strong> when need group elements for styling.<br>\n        <strong>When NOT to use:</strong> instead of &lt;p&gt; for text, instead of &lt;button&gt; for buttons. If there is a semantic tag, use it.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb60\" onchange=\"updateProgress(this)\"><span>&lt;div&gt; — container-«box», groups elements</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb61\" onchange=\"updateProgress(this)\"><span>class=\"name\" — give it a name, style in CSS through .name</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb62\" onchange=\"updateProgress(this)\"><span>Use &lt;div&gt; for grouping, not instead of semantic tags</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-span","title":"<span> — inline container important 🔗","html":"<div class=\"block\" id=\"block-span\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-span')\">&lt;span&gt; — inline container <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">&lt;span&gt; — as &lt;div&gt;, but does NOT create a new line. For part of text inside &lt;p&gt;.</div>\n      <div class=\"code\">&lt;p&gt;Price: &lt;span class=\"price\"&gt;999 rub&lt;/span&gt;&lt;/p&gt;\n&lt;p&gt;This &lt;span class=\"highlight\"&gt;very&lt;/span&gt; important!&lt;/p&gt;\n\n/* CSS */\n.price { color: red; font-weight: bold; }\n.highlight {\n  background-color: yellow;\n  padding: 2px 4px;\n  border-radius: 4px;\n}</div>\n      <div class=\"explain\">\n        <strong>&lt;span&gt;</strong> — inline container. Does not move to a new line. Works inside text.<br>\n        <strong>Difference from &lt;div&gt;:</strong> &lt;div&gt; = block, new row. &lt;span&gt; = inside rows, does not break the text.<br>\n        Use &lt;span&gt; when need color part of the text, highlight part of a word, etc.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb63\" onchange=\"updateProgress(this)\"><span>&lt;span&gt; — container inside rows, does not create a new line</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb64\" onchange=\"updateProgress(this)\"><span>&lt;div&gt; = block (new row), &lt;span&gt; = inline (inside text)</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-nested-selectors","title":"Nested selectors — styles inside pages basics 🔗","html":"<div class=\"block\" id=\"block-nested-selectors\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-nested-selectors')\">Nested selectors — styles inside pages <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">One CSS file, but each page has its own text colors, buttons, and links. How? Put a space between the page class and the element.</div>\n      <div class=\"code\">/* h1 — different on each page */\n.page-home h1 {\n  color: black;\n}\n.page-recipe h1 {\n  color: white;\n}\n.page-settings h1 {\n  color: yellow;\n}\n\n/* p, button, a — also different */\n.page-home p { color: gray; }\n.page-home button { background-color: red; }\n\n.page-recipe p { color: lightgreen; }\n.page-recipe button { background-color: green; }\n\n.page-settings button { background-color: blue; }</div>\n      <div class=\"explain\">\n        <strong>Space = «inside»:</strong> <code>.page-home h1</code> is read as «find all h1 <em>inside</em> element with class page-home».<br>\n        This lets you style <strong>any</strong> element on a specific page, without touching the others.<br>\n        <strong>.page-home button</strong> — only buttons on home page. <strong>.page-recipe p</strong> — only paragraphs on page recipe.<br>\n        This works for everything: <code>.page-home img</code>, <code>.page-settings a</code>, <code>.page-recipe ul</code> — for any tag inside class.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb65\" onchange=\"updateProgress(this)\"><span>.page-home h1 — space means inside. Only h1 on the home page</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb66\" onchange=\"updateProgress(this)\"><span>You can style any tag: p, a, button, img, ul, li — everything</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb67\" onchange=\"updateProgress(this)\"><span>One CSS file → different styles on different pages</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-center-button","title":"Centering a button without hacks CORE #","html":"<div class=\"block wdg-quality-block\" id=\"block-center-button\"><div class=\"block-title\" onclick=\"scrollToBlock('block-center-button')\">Centering a button without hacks <span class=\"badge must\">CORE</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">Center an element through its container or automatic inline margins. Large fixed <code>margin-left</code> values break responsive layouts.</div><div class=\"code\">/* Option 1: the container controls alignment */\n.actions {\n  display: flex;\n  justify-content: center;\n}\n\n/* Option 2: a single block-level button */\n.save-button {\n  display: block;\n  margin-inline: auto;\n}\n\n&lt;div class=\"actions\"&gt;\n  &lt;button type=\"button\"&gt;Save&lt;/button&gt;\n&lt;/div&gt;</div><div class=\"explain\"><code>justify-content</code> works along the flex container main axis. <code>margin-inline: auto</code> splits free space equally. Do not wrap a button in a link for centering or appearance.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-center-button-1\" onchange=\"updateProgress(this)\"><span>I center through layout</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-center-button-2\" onchange=\"updateProgress(this)\"><span>I understand the container role</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-center-button-3\" onchange=\"updateProgress(this)\"><span>I do not mix links and buttons</span></label></div></div>"},{"id":"block-boxmodel","title":"Box Model (Box Model) basics 🔗","html":"<div class=\"block\" id=\"block-boxmodel\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-boxmodel')\">Box Model (Box Model) <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">  ┌─────── margin (external spacing) ──────┐\n  │  ┌────── border (border) ─────────┐   │\n  │  │  ┌─── padding (inner spacing) ─┐  │\n  │  │  │        width / height       │  │\n  │  │  └─────────────────────────────┘  │\n  │  └────────────────────────────────────┘\n  └──────────────────────────────────────────┘\n\ndiv {\n  width: 200px;\n  padding: 20px;   /* expands the block from inside */\n  border: 2px solid black;\n  margin: 30px;    /* spacing from neighboring elements */\n  box-sizing: border-box; /* padding does NOT increase width */\n}</div>\n      <div class=\"explain\">\n        <strong>margin</strong> — outside. Spacing from neighboring elements.<br>\n        <strong>border</strong> — border around the element.<br>\n        <strong>padding</strong> — inside. Spacing between content and the border.<br>\n        <strong>box-sizing: border-box</strong> — always use it. Then width includes padding and border.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb79\" onchange=\"updateProgress(this)\"><span>margin — outside, padding — inside, border — border</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb80\" onchange=\"updateProgress(this)\"><span>box-sizing: border-box — the first line of any CSS</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-scroll-anim","title":"Scroll animation (Intersection Observer) animations 🔗","html":"<div class=\"block\" id=\"block-scroll-anim\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-scroll-anim')\">Scroll animation (Intersection Observer) <span class=\"badge anim\">animations</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Elements appear smoothly when the user scrolls to them, like on modern sites.</div>\n      <div class=\"code\">/* CSS — hidden by default */\n.fade-in {\n  opacity: 0;\n  transform: translateY(30px);\n  transition: all 0.6s ease;\n}\n/* Class is added by JS */\n.fade-in.visible {\n  opacity: 1;\n  transform: translateY(0);\n}\n\n// JS — watch elements appear\nconst observer = new IntersectionObserver((entries) =&gt; {\n  entries.forEach(entry =&gt; {\n    if (entry.isIntersecting) {\n      entry.target.classList.add('visible');\n    }\n  });\n}, { threshold: 0.1 });\n\ndocument.querySelectorAll('.fade-in').forEach(el =&gt; {\n  observer.observe(el);\n});</div>\n      <div class=\"explain\">\n        <strong>IntersectionObserver</strong> — browser API. It watches whether an element entered the visible screen area.<br>\n        <strong>threshold: 0.1</strong> — «trigger when 10% of the element is visible».<br>\n        <strong>entry.isIntersecting</strong> — true, if element is currently visible on screen.<br>\n        This better, than listening to the event <code>scroll</code> — does not slow the page!\n      </div>\n      <div class=\"live-example\">\n        <div class=\"live-example-header\">▶ LIVE EXAMPLE — click the button to simulate scrolling</div>\n        <div class=\"live-example-body\" style=\"flex-direction: column; align-items: stretch; padding: 12px;\">\n          <div class=\"demo-scroll-box\" id=\"scrollDemo\">\n            <div class=\"scroll-item\">🚀 Block 1 — appears first</div>\n            <div class=\"scroll-item\">🎨 Block 2 — slides in smoothly</div>\n            <div class=\"scroll-item\">⚡ Block 3 — one after another</div>\n          </div>\n          <button onclick=\"triggerScrollAnim()\" style=\"margin-top:8px; padding:8px 16px; border-radius:8px; background:#6366f1; color:white; border:none; cursor:pointer; font-family:inherit; font-size:13px;\">▶ Start animation</button>\n        </div>\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb89\" onchange=\"updateProgress(this)\"><span>IntersectionObserver — watch appearance on screen</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb90\" onchange=\"updateProgress(this)\"><span>opacity + transform — main pair for a smooth appearance</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-vars","title":"CSS-variables advanced 🔗","html":"<div class=\"block\" id=\"block-vars\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-vars')\">CSS-variables <span class=\"badge pro\">advanced</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">/* Define variables once */\n:root {\n  --color-main: #6366f1;\n  --radius: 8px;\n  --font: 'Segoe UI', sans-serif;\n}\n.btn {\n  background: var(--color-main);\n  border-radius: var(--radius);\n  transition: all 0.2s ease;\n}\n/* Dark theme — change one variable! */\n[data-theme=\"dark\"] {\n  --color-main: #818cf8;\n}</div>\n      <div class=\"explain\">\n        <strong>--name</strong> — this creates a CSS variable. <strong>var(--name)</strong> — this is how it is used.<br>\n        <strong>:root</strong> — variables are available on the whole page.<br>\n        Theme switching: change 5 variables and the whole site recolors.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb93\" onchange=\"updateProgress(this)\"><span>CSS-variables: define once, use everywhere</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb94\" onchange=\"updateProgress(this)\"><span>transition = smoothness. Without it changes are instant</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-toggle-guide","title":"Toggle (Toggle Switch) — as make animations 🔗","html":"<div class=\"block\" id=\"block-toggle-guide\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-toggle-guide')\">Toggle (Toggle Switch) — as make <span class=\"badge anim\">animations</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Toggle is a styled checkbox. It is made with &lt;input type=\"checkbox\"&gt; plus CSS pseudo-elements.</div>\n      <div class=\"code\">/* HTML */\n&lt;label class=\"toggle-wrap\"&gt;\n  &lt;input type=\"checkbox\" id=\"myToggle\"&gt;\n  &lt;span class=\"slider\"&gt;&lt;/span&gt;\n&lt;/label&gt;\n\n/* CSS */\n.toggle-wrap {\n  position: relative;\n  width: 52px;\n  height: 28px;\n  cursor: pointer;\n}\n.toggle-wrap input { opacity: 0; width:0; height:0; } /* Hide */\n\n.slider {\n  position: absolute;\n  inset: 0;\n  background: #d1d5db;\n  border-radius: 99px;\n  transition: background 0.3s ease;\n}\n.slider::before {          /* Knob */\n  content: '';\n  position: absolute;\n  width: 20px;\n  height: 20px;\n  background: white;\n  border-radius: 50%;\n  bottom: 4px;\n  left: 4px;\n  transition: transform 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);\n  box-shadow: 0 1px 4px rgba(0,0,0,.2);\n}\n/* When enabled */\ninput:checked + .slider { background: #6366f1; }\ninput:checked + .slider::before { transform: translateX(24px); }\n\n// Read state in JS:\nconst toggle = document.getElementById('myToggle');\ntoggle.addEventListener('change', () =&gt; {\n  if (toggle.checked) {\n    console.log('On!');\n    document.body.classList.add('dark-theme');\n  } else {\n    console.log('Off!');\n    document.body.classList.remove('dark-theme');\n  }\n});</div>\n      <div class=\"live-example\">\n        <div class=\"live-example-header\">▶ LIVE EXAMPLE — click toggles</div>\n        <div class=\"live-example-body\" style=\"gap: 24px;\">\n          <div class=\"demo-toggle-wrap\">\n            <div class=\"toggle-label\">Dark topic</div>\n            <button class=\"toggle\" id=\"t1\" onclick=\"toggleSwitch('t1', 'toggleStatus1')\"></button>\n            <div class=\"toggle-status\" id=\"toggleStatus1\">Off</div>\n          </div>\n          <div class=\"demo-toggle-wrap\">\n            <div class=\"toggle-label\">Notifications</div>\n            <button class=\"toggle on\" id=\"t2\" onclick=\"toggleSwitch('t2', 'toggleStatus2')\"></button>\n            <div class=\"toggle-status\" id=\"toggleStatus2\">On</div>\n          </div>\n          <div class=\"demo-toggle-wrap\">\n            <div class=\"toggle-label\">Wi-Fi</div>\n            <button class=\"toggle\" id=\"t3\" onclick=\"toggleSwitch('t3', 'toggleStatus3')\"></button>\n            <div class=\"toggle-status\" id=\"toggleStatus3\">Off</div>\n          </div>\n        </div>\n      </div>\n      <div class=\"explain\">\n        <strong>input:checked + .slider</strong> — CSS selector: when the checkbox is checked, style the next .slider element.<br>\n        <strong>::before</strong> — pseudo-element that creates the toggle knob without extra HTML.<br>\n        <strong>transform: translateX(24px)</strong> — moves the knob to the right when enabled.<br>\n        In JS you read <code>toggle.checked</code> — this is <code>true</code> or <code>false</code>.\n      </div>\n      <div class=\"items\">\n      <!-- MINI TEST FOR TOGGLE -->\n      <div class=\"quiz-block\" id=\"quiz-toggle\">\n        <div class=\"quiz-title\">🧪 Mini test — Toggle</div>\n        <div class=\"quiz-question\">1. What is a CSS toggle based on?</div>\n        <div class=\"quiz-options\">\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-tog-1\" value=\"a\"> <span>On a &lt;div&gt; with a JavaScript handler</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-tog-1\" value=\"b\"> <span>On a hidden &lt;input type=\"checkbox\"&gt; with a styled span</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-tog-1\" value=\"c\"> <span>On a &lt;button&gt; with a toggle class</span></label>\n        </div>\n        <div class=\"quiz-question\">2. Which CSS selector tracks checkbox state?</div>\n        <div class=\"quiz-options\">\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-tog-2\" value=\"a\"> <span>input.active + .slider</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-tog-2\" value=\"b\"> <span>input:checked + .slider</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-tog-2\" value=\"c\"> <span>input[on] ~ .slider</span></label>\n        </div>\n        <div class=\"practice-block\">\n          <div class=\"practice-title\">⌨️ Practice</div>\n          <div class=\"practice-task\">Write a CSS rule that changes .slider background to green when the related checkbox is checked.</div>\n          <textarea class=\"practice-input\" id=\"practice-toggle\" placeholder=\"input:checked + .slider { ... }\"></textarea>\n        </div>\n        <button class=\"quiz-check-btn\" onclick=\"checkQuiz('toggle')\">✓ Check</button>\n        <div class=\"quiz-result\" id=\"result-toggle\"></div>\n      </div>\n        <div class=\"items\" id=\"items-toggle\">\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb609\" onchange=\"updateProgress(this)\" disabled><span>🔒 Toggle = hidden checkbox + styled span</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb95\" onchange=\"updateProgress(this)\"><span>input:checked + .slider — style when enabled</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb96\" onchange=\"updateProgress(this)\"><span>toggle.checked in JS — true/false state</span></label>\n      </div>\n    </div>\n\n    <div class=\"block\" id=\"block-gradient-text\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-gradient-text')\">Gradient text and effects <span class=\"badge anim\">animations</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">/* Gradient text */\n.gradient-text {\n  background: linear-gradient(135deg, #6366f1, #ec4899, #f59e0b);\n  -webkit-background-clip: text;\n  -webkit-text-fill-color: transparent;\n  background-clip: text;\n  background-size: 200% 200%;\n  animation: gradientShift 3s ease infinite;\n}\n@keyframes gradientShift {\n  0%, 100% { background-position: 0% 50%; }\n  50%       { background-position: 100% 50%; }\n}\n\n/* Glassmorphism (glass) */\n.glass {\n  background: rgba(255, 255, 255, 0.1);\n  backdrop-filter: blur(10px);\n  border: 1px solid rgba(255, 255, 255, 0.2);\n  border-radius: 16px;\n}</div>\n      <div class=\"live-example\">\n        <div class=\"live-example-header\">▶ LIVE EXAMPLE</div>\n        <div class=\"live-example-body\">\n          <div class=\"demo-gradient-text\">Hello!</div>\n        </div>\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb97\" onchange=\"updateProgress(this)\"><span>background-clip: text — applies background to text</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb98\" onchange=\"updateProgress(this)\"><span>backdrop-filter: blur() — glass effect</span></label>\n      </div>\n    </div>\n\n    <div class=\"block\" id=\"block-position\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-position')\">Position — positioning elements <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">position — one of the most commonly used properties. Without it you cannot make a modal, dropdown menu, or button over an image.</div>\n      <div class=\"code\">/* static — default (in document flow) */\n.box { position: static; }\n\n/* relative — moves relative to its own place */\n.box { position: relative; top: 10px; left: 20px; }\n\n/* absolute — is removed from flow and positioned\n   relative to the nearest ancestor with position not static */\n.parent { position: relative; }\n.child  { position: absolute; top: 0; right: 0; }\n\n/* fixed — sticks to the browser window (header, back-to-top button) */\n.header { position: fixed; top: 0; left: 0; width: 100%; z-index: 100; }\n\n/* sticky — sticks on scroll */\n.sidebar { position: sticky; top: 20px; }</div>\n      <div class=\"explain\">\n        <strong>static</strong> — all elements by default. top/left/right/bottom do not work.<br>\n        <strong>relative</strong> — moves, but its place in the flow is preserved. Often used as an anchor for absolute children.<br>\n        <strong>absolute</strong> — looks for the nearest ancestor with <code>position: relative/absolute/fixed</code>. If not found, it is positioned relative to &lt;html&gt;.<br>\n        <strong>fixed</strong> — does not react to scroll. Ideal for headers and floating buttons.<br>\n        <strong>z-index</strong> — who is drawn on top. higher number = higher layer.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb99\" onchange=\"updateProgress(this)\"><span>relative — anchor for absolute children</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb100\" onchange=\"updateProgress(this)\"><span>absolute is positioned by the nearest relative ancestor</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb101\" onchange=\"updateProgress(this)\"><span>fixed is attached to the screen and does not scroll</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb102\" onchange=\"updateProgress(this)\"><span>z-index controls layer order</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb103\" onchange=\"updateProgress(this)\"><span>sticky — sticks when it reaches the edge</span></label>\n      </div>\n    </div>\n\n    <div class=\"block\" id=\"block-pseudo\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-pseudo')\">Pseudo-classes and pseudo-elements <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Pseudo-classes react to element state (:hover, :focus). Pseudo-elements add content without extra HTML (::before, ::after).</div>\n      <div class=\"code\">/* === PSEUDO-CLASSES === */\na:hover  { color: #6366f1; }          /* on mouse hover */\na:active { opacity: .7; }             /* on click */\ninput:focus { border-color: #6366f1; } /* on focus */\n\nli:first-child { font-weight: bold; }  /* first element */\nli:last-child  { color: gray; }        /* last */\nli:nth-child(2) { background: #f0f; }  /* second */\nli:nth-child(odd) { background: #f9f9f9; } /* odd */\n\n/* === PSEUDO-ELEMENTS === */\n/* Add content BEFORE and AFTER an element */\n.badge::before {\n  content: \"★ \";   /* required property */\n  color: gold;\n}\n\n.card::after {\n  content: \"\";      /* empty content — for decoration */\n  display: block;\n  width: 100%;\n  height: 3px;\n  background: linear-gradient(to right, #6366f1, #ec4899);\n}\n\n/* Text selection */\n::selection { background: #6366f1; color: white; }</div>\n      <div class=\"explain\">\n        <strong>:hover</strong> — style on hover. Works on any element, not only links.<br>\n        <strong>:focus</strong> — style on focus (Tab or click). Important for accessibility.<br>\n        <strong>:nth-child(n)</strong> — selects the nth element among siblings. <code>odd</code> = odd, <code>even</code> = even.<br>\n        <strong>::before / ::after</strong> — «virtual» elements. Needs <code>content</code> (at least empty <code>\"\"</code>).<br>\n        <strong>Difference</strong>: one colon <code>:</code> — pseudo-class, two <code>::</code> — pseudo-element.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb104\" onchange=\"updateProgress(this)\"><span>:hover / :focus / :active — three interaction states</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb105\" onchange=\"updateProgress(this)\"><span>:nth-child(odd/even) — zebra styles for tables and lists</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb106\" onchange=\"updateProgress(this)\"><span>::before / ::after — decoration without HTML, you need content: \"\"</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb107\" onchange=\"updateProgress(this)\"><span>: — pseudo-class, :: — pseudo-element</span></label>\n      </div>\n    </div>\n\n    <div class=\"block\" id=\"block-media\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-media')\">Media queries — responsiveness <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Media queries let you apply different styles for different screen sizes. Mobile-first means writing for mobile first, then expanding.</div>\n      <div class=\"code\">/* === Mobile-first approach === */\n/* Base styles — for mobile (&lt; 768px) */\n.container { padding: 0 16px; }\n.nav { display: none; }               /* menu hidden on mobile */\n.visually-hidden {\n  position: absolute;\n  width: 1px; height: 1px;\n  overflow: hidden;\n  clip: rect(0 0 0 0);\n}\n\n/* Tablet — from 768px */\n@media (min-width: 768px) {\n  .container { max-width: 960px; margin: 0 auto; }\n  .nav { display: flex; }             /* menu appears */\n}\n\n/* Desktop — from 1024px */\n@media (min-width: 1024px) {\n  .container { max-width: 1200px; }\n  .grid { grid-template-columns: repeat(3, 1fr); }\n}\n\n/* === Typical breakpoints === */\n/* 480px  — large phones         */\n/* 768px  — tablets                 */\n/* 1024px — laptops                 */\n/* 1280px — desktops                 */\n\n/* === Screen orientation === */\n@media (orientation: landscape) {\n  .hero { min-height: 60vh; }\n}\n\n/* === System dark theme === */\n@media (prefers-color-scheme: dark) {\n  body { background: #0f1117; color: #e2e8f0; }\n}</div>\n      <div class=\"explain\">\n        <strong>min-width</strong> — «from X pixels and wider» (mobile-first). Most often this is the right approach.<br>\n        <strong>max-width</strong> — «up to X pixels» (desktop-first). Old approach, but sometimes useful.<br>\n        <strong>Breakpoint</strong> — width where design changes (768px, 1024px...).<br>\n        <strong>display: none</strong> fully removes the element from the accessibility tree. If text must stay for screen readers, use the <code>.visually-hidden</code> pattern, not just display hiding.<br>\n        <strong>prefers-color-scheme</strong> — detects whether dark theme is enabled in the OS.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb108\" onchange=\"updateProgress(this)\"><span>Mobile-first: first styles for mobile, then @media (min-width)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb109\" onchange=\"updateProgress(this)\"><span>768px — tablet, 1024px — desktop</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb110\" onchange=\"updateProgress(this)\"><span>Check site in DevTools (F12 → phone icon)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb111\" onchange=\"updateProgress(this)\"><span>prefers-color-scheme — auto dark theme</span></label>\n      </div>\n    </div>\n\n\n    <div class=\"block\" id=\"block-container-queries\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-container-queries')\">Container Queries — responsiveness by container <span class=\"badge good\">learn after</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Media queries react to the size of the whole browser window. But what if the same card appears in a narrow sidebar and in a wide page center? Container Queries solve exactly that.</div>\n      <div class=\"code\">/* Declare an element as a query container */\n.card-wrapper {\n  container-type: inline-size;\n  container-name: card;\n}\n\n/* Card styles change from the CONTAINER width, not the screen */\n.card { display: block; }\n\n@container card (min-width: 400px) {\n  .card { display: flex; gap: 16px; }   /* wide container — flex */\n}\n\n@container card (max-width: 399px) {\n  .card { display: block; }              /* narrow container — block */\n}\n\n/* The same card adapts automatically\n   in a sidebar (narrow) and in the main content area (wide) */</div>\n      <div class=\"explain\">\n        <strong>Regular @media</strong> — looks at the width of the whole browser window.<br>\n        <strong>@container</strong> — looks at the parent container width, independent of the screen size.<br>\n        <strong>container-type: inline-size</strong> — required declaration that makes the parent a container; otherwise @container will not work.<br>\n        <strong>Where to use:</strong> reusable components (cards, widgets) that can appear in places with different widths — sidebar, grid, modal.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb112\" onchange=\"updateProgress(this)\"><span>container-type: inline-size — container declaration</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb113\" onchange=\"updateProgress(this)\"><span>@container (min-width: ...) — query by container width, not screen width</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb114\" onchange=\"updateProgress(this)\"><span>I understand the difference between @media and @container</span></label>\n      </div>\n    </div>\n\n    <div class=\"block\" id=\"block-typography\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-typography')\">Typography — fonts and text <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">The right font makes a site look professional. Google Fonts is free, has 1000+ fonts, and connects with one line.</div>\n      <div class=\"code-wrap\"><div class=\"code\">&lt;!-- Connect Google Fonts in &lt;head&gt; --&gt;\n&lt;link href=\"https://fonts.googleapis.com/css2?family=Inter:wght@400;600;700&amp;display=swap\" rel=\"stylesheet\"&gt;\n\n/* Apply it in CSS */\nbody {\n  font-family: 'Inter', sans-serif; /* main font */\n  font-size: 16px;                  /* base size */\n  line-height: 1.6;                 /* line spacing */\n  color: #1a1a2e;\n}\n\nh1 { font-size: 2.5rem;  font-weight: 700; }\nh2 { font-size: 1.75rem; font-weight: 600; }\np  { font-size: 1rem;    font-weight: 400; }\n\n/* Cut text with an ellipsis */\n.truncate {\n  white-space: nowrap;\n  overflow: hidden;\n  text-overflow: ellipsis;  /* \"long te...\" */\n}\n\n/* Useful utilities */\n.uppercase { text-transform: uppercase; letter-spacing: 0.08em; }\n.center    { text-align: center; }\n.muted     { color: #9ca3af; font-size: 0.875rem; }</div><button class=\"copy-btn\" onclick=\"copyCode(this)\">Copy</button></div>\n      <div class=\"explain\">\n        <strong>font-family: 'Inter', sans-serif</strong> — if Inter does not load, the browser will use the system sans-serif.<br>\n        <strong>rem</strong> — relative unit. 1rem = 16px. Better than px, because it scales with browser settings.<br>\n        <strong>line-height: 1.6</strong> — without units! It is a multiplier. 1.6 = 1.6 × font-size. Ideal for text: 1.5–1.7.<br>\n        <strong>text-overflow: ellipsis</strong> — cuts text with an ellipsis. You need three properties at the same time: white-space + overflow + text-overflow.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb115\" onchange=\"updateProgress(this)\"><span>I connect Google Fonts through &lt;link&gt; in &lt;head&gt;</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb116\" onchange=\"updateProgress(this)\"><span>rem instead of px — scales with browser settings</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb117\" onchange=\"updateProgress(this)\"><span>line-height without units (1.5–1.7) — ideal for readability</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb118\" onchange=\"updateProgress(this)\"><span>text-overflow: ellipsis — you need white-space:nowrap + overflow:hidden</span></label>\n      </div>\n    </div>\n\n    <div class=\"block\" id=\"block-transition\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-transition')\">Transition — smooth changes <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Transition makes CSS property changes smooth. It is the simplest way to add life to an interface.</div>\n      <div class=\"code-wrap\"><div class=\"code\">/* Syntax: transition: property duration timing-function delay */\n.btn {\n  background: #6366f1;\n  color: white;\n  padding: 12px 24px;\n  border-radius: 8px;\n  transition: background 0.25s ease;  /* smooth background change */\n}\n.btn:hover { background: #4f46e5; }\n\n/* Several properties */\n.card {\n  box-shadow: 0 1px 4px rgba(0,0,0,.08);\n  transform: translateY(0);\n  transition: box-shadow 0.2s ease,\n              transform   0.2s ease;\n}\n.card:hover {\n  box-shadow: 0 8px 24px rgba(0,0,0,.15);\n  transform: translateY(-4px);  /* floats up */\n}\n\n/* Timing functions */\n/* ease      — slow → fast → slow (default) */\n/* linear    — even                                   */\n/* ease-in   — slow → fast                            */\n/* ease-out  — fast → slow (good for appearing)     */\n/* cubic-bezier(0.34,1.56,0.64,1) — spring effect        */</div><button class=\"copy-btn\" onclick=\"copyCode(this)\">Copy</button></div>\n      <div class=\"explain\">\n        <strong>transition: background 0.25s ease</strong> — three parts: what changes, how long, and which timing function.<br>\n        <strong>ease-out</strong> — best option for elements appearing (appears fast, stops smoothly).<br>\n        <strong>transition: all</strong> — convenient, but be careful: it animates everything in a row, including width/height — this is expensive for the browser.<br>\n        Prefer animating <code>transform</code> and <code>opacity</code> — they work on the GPU and do not trigger page reflow.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb119\" onchange=\"updateProgress(this)\"><span>transition: property 0.25s ease — put it on the original element, not on :hover</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb120\" onchange=\"updateProgress(this)\"><span>ease-out — for appearing. ease-in — for disappearing</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb121\" onchange=\"updateProgress(this)\"><span>transform + opacity are faster than width/height/margin</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb122\" onchange=\"updateProgress(this)\"><span>You can list several properties separated by commas</span></label>\n      </div>\n    </div>\n\n    <div class=\"block\" id=\"block-transform\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-transform')\">Transform — move, rotate, scale <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Transform moves, rotates, and scales an element without changing document flow. It works through the GPU and does not cause reflow.</div>\n      <div class=\"code-wrap\"><div class=\"code\">/* Main functions transform */\n\n/* Move */\ntransform: translateX(50px);        /* to the right on 50px          */\ntransform: translateY(-20px);       /* up on 20px           */\ntransform: translate(50px, -20px);  /* both at once               */\ntransform: translateX(50%);         /* 50% from its own width     */\n\n/* Scale */\ntransform: scale(1.2);   /* increase by 20% */\ntransform: scale(0.8);   /* decrease by 20% */\n\n/* Rotation */\ntransform: rotate(45deg);   /* clockwise       */\ntransform: rotate(-90deg);  /* counterclockwise   */\n\n/* Combination — left to right! */\ntransform: translate(-50%, -50%) scale(1.1);\n\n/* Real example — centering an absolute block */\n.popup {\n  position: absolute;\n  top: 50%;  left: 50%;\n  transform: translate(-50%, -50%);  /* perfect centering */\n}\n\n/* Icon rotates on opening */\n.arrow { transition: transform 0.3s ease; }\n.open .arrow { transform: rotate(180deg); }\n\n/* Card floats up on hover */\n.card {\n  transition: transform 0.2s ease-out;\n}\n.card:hover { transform: translateY(-6px) scale(1.02); }</div><button class=\"copy-btn\" onclick=\"copyCode(this)\">Copy</button></div>\n      <div class=\"explain\">\n        <strong>translate(-50%, -50%)</strong> — classic centering trick: moves by half of its <em>own</em> size.<br>\n        <strong>Order matters!</strong> <code>translate() scale()</code> ≠ <code>scale() translate()</code> — transformations are applied from right to left.<br>\n        <strong>transform-origin</strong> — the point around which rotation/scale happens. By default <code>center center</code>.<br>\n        Always combine <code>transform</code> with <code>transition</code> — otherwise the change will be instant, without animation.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb123\" onchange=\"updateProgress(this)\"><span>translate(-50%,-50%) + position:absolute — perfect centering</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb124\" onchange=\"updateProgress(this)\"><span>scale(1.05) on hover — popular card zoom effect</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb125\" onchange=\"updateProgress(this)\"><span>rotate(180deg) — arrow rotation when a menu opens</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb126\" onchange=\"updateProgress(this)\"><span>transform + transition together = smooth animation</span></label>\n      </div>\n    </div>\n\n    <div class=\"block\" id=\"block-shadows\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-shadows')\">Shadows — box-shadow, text-shadow, drop-shadow <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Shadows make an interface feel dimensional. The main thing is not to overdo it. A good shadow is soft and barely noticeable.</div>\n      <div class=\"code\">/* box-shadow: x-offset y-offset blur spread color */\n.card {\n  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);   /* soft, like Material */\n}\n\n/* Floating effect on hover */\n.card:hover {\n  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.15);\n  transform: translateY(-3px);\n}\n\n/* Several shadows separated by commas */\n.fancy {\n  box-shadow:\n    0 1px 2px rgba(0, 0, 0, 0.1),\n    0 4px 12px rgba(0, 0, 0, 0.08);\n}\n\n/* Inner shadow (inset) */\n.input {\n  box-shadow: inset 0 2px 4px rgba(0, 0, 0, 0.08);\n}\n\n/* Glowing outline around buttons */\n.btn:focus {\n  box-shadow: 0 0 0 3px rgba(99, 102, 241, 0.4);\n}\n\n/* text-shadow — shadow text */\nh1 {\n  text-shadow: 2px 2px 4px rgba(0, 0, 0, 0.3);\n}\n\n/* Neon glow */\n.neon {\n  color: #fff;\n  text-shadow:\n    0 0 5px  #6366f1,\n    0 0 10px #6366f1,\n    0 0 20px #6366f1;\n}\n\n/* drop-shadow — shadow by shape (for images and SVG) */\n.icon {\n  filter: drop-shadow(0 4px 6px rgba(0, 0, 0, 0.2));\n}</div>\n      <div class=\"explain\">\n        <strong>box-shadow parameters</strong>: x — horizontal offset, y — vertical offset, blur, spread, color. The larger the blur, the softer the shadow.<br>\n        <strong>rgba(0,0,0,0.08)</strong> — almost always better than solid gray. Transparency fits well on any background.<br>\n        <strong>inset</strong> — shadow <em>inside</em> the element. Pressed-in effect (input fields, progress bars).<br>\n        <strong>filter: drop-shadow()</strong> ≠ box-shadow. drop-shadow follows the real shape of the element — useful for PNG/SVG with transparency.<br>\n        <strong>0 0 0 3px color</strong> — focus ring for buttons and inputs instead of the unattractive default browser outline.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb127\" onchange=\"updateProgress(this)\"><span>0 2px 8px rgba(0,0,0,.08) — standard soft card shadow</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb128\" onchange=\"updateProgress(this)\"><span>:hover — bigger shadow + translateY(-3px) → floating effect</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb129\" onchange=\"updateProgress(this)\"><span>inset — inner shadow (fields, switches)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb130\" onchange=\"updateProgress(this)\"><span>filter: drop-shadow() — for icons and SVG, follows the shape</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb131\" onchange=\"updateProgress(this)\"><span>Focus ring: box-shadow + outline: 3px solid transparent for accessibility</span></label>\n      </div>\n    </div>\n\n    <div class=\"block\" id=\"block-zindex\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-zindex')\">z-index and stacking context — what is above what <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">z-index controls the stacking order of elements. The confusing part is why z-index: 9999 sometimes does not work. The reason is stacking context.</div>\n      <div class=\"code\">/* z-index works ONLY on positioned elements */\n.modal {\n  position: fixed;       /* required! */\n  z-index: 1000;\n  inset: 0;\n}\n\n/* Without position: ... → z-index is ignored */\n.broken {\n  z-index: 999;          /* does NOT work! */\n}\n\n/* Standard layer hierarchy */\n.dropdown   { z-index: 100; }\n.sticky-nav { z-index: 200; }\n.modal      { z-index: 1000; }\n.toast      { z-index: 2000; }   /* always top */\n\n/* Stacking context — a separate stacking world */\n.parent {\n  position: relative;\n  z-index: 1;            /* creates context */\n  /* OR: opacity &lt; 1, transform, filter, isolation: isolate */\n}\n\n.parent .child {\n  z-index: 9999;         /* still will not escape the parent! */\n}\n\n/* Solution — raise the parent or move the child into body */\n.parent { isolation: isolate; }   /* explicit stacking context */</div>\n      <div class=\"explain\">\n        <strong>z-index works only on position</strong> ≠ static. Without <code>position: relative/absolute/fixed/sticky</code> — it is ignored.<br>\n        <strong>Stacking context</strong> — a separate stacking world. Inside it, z-index is calculated separately. Any child <code>z-index</code> cannot escape the parent context.<br>\n        <strong>What creates context</strong>: position + z-index (any), <code>opacity &lt; 1</code>, <code>transform</code>, <code>filter</code>, <code>will-change</code>, <code>isolation: isolate</code>.<br>\n        <strong>“z-index: 9999 does not work!”</strong> — almost always caused by a parent with opacity/transform. Find it in DevTools → Layers, or add to the modal <code>position: fixed</code> and place it in &lt;body&gt;.<br>\n        <strong>Do not spam huge numbers.</strong> 1, 10, 100, 1000 — systematic. 9999 is a sign that something is wrong.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb132\" onchange=\"updateProgress(this)\"><span>z-index works only on position: relative/absolute/fixed/sticky</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb133\" onchange=\"updateProgress(this)\"><span>I understand what stacking context is</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb134\" onchange=\"updateProgress(this)\"><span>I use a system: 100/200/1000/2000, not 9999</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb135\" onchange=\"updateProgress(this)\"><span>opacity / transform on a parent = z-index trap</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb136\" onchange=\"updateProgress(this)\"><span>isolation: isolate — explicitly create its own stacking context</span></label>\n      </div>\n    </div>\n\n    <div class=\"block\" id=\"block-filter\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-filter')\">filter and backdrop-filter — blur, glassmorphism <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">filter applies a visual effect to an element (like in Photoshop). backdrop-filter blurs what is <em>behind</em> the element — this creates glass panels.</div>\n      <div class=\"code\">/* filter — effects on the element itself */\n.img-blur     { filter: blur(4px); }\n.img-bw       { filter: grayscale(100%); }\n.img-bright   { filter: brightness(1.2); }\n.img-contrast { filter: contrast(1.4); }\n.img-hue      { filter: hue-rotate(90deg); }   /* changes hue */\n.img-invert   { filter: invert(1); }            /* negative */\n.img-saturate { filter: saturate(2); }\n\n/* Several effects separated by spaces */\n.cool {\n  filter: brightness(1.1) contrast(1.2) saturate(1.3);\n}\n\n/* hover — colorize a black-and-white photo */\n.gallery img {\n  filter: grayscale(100%);\n  transition: filter 0.4s;\n}\n.gallery img:hover { filter: grayscale(0); }\n\n/* backdrop-filter — blurs the BACKGROUND under the element (glassmorphism) */\n.glass {\n  background: rgba(255, 255, 255, 0.15);\n  backdrop-filter: blur(12px) saturate(1.5);\n  -webkit-backdrop-filter: blur(12px) saturate(1.5);  /* Safari */\n  border: 1px solid rgba(255, 255, 255, 0.2);\n  border-radius: 16px;\n}\n\n/* Dimming for a modal */\n.modal-bg {\n  background: rgba(0, 0, 0, 0.4);\n  backdrop-filter: blur(8px);\n}</div>\n      <div class=\"explain\">\n        <strong>filter</strong> applies to the whole element (including content). <strong>backdrop-filter</strong> applies to what is <em>behind</em> it through a translucent background.<br>\n        <strong>Glassmorphism</strong> — a trendy frosted-glass effect. Recipe: translucent background + <code>backdrop-filter: blur()</code> + thin light border.<br>\n        <strong>-webkit-backdrop-filter</strong> — is required for Safari (including iPhone). Without the prefix, it does not work.<br>\n        <strong>Performance.</strong> blur and backdrop-filter are heavy. Do not put them on large elements and do not animate blur radius — it will lag on mobile.<br>\n        <strong>Gray gallery image + colored on hover</strong> — a trick designers like. Done with one <code>filter: grayscale()</code>.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb137\" onchange=\"updateProgress(this)\"><span>filter: blur, grayscale, brightness, contrast — main effects</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb138\" onchange=\"updateProgress(this)\"><span>You can combine through a space: filter: brightness(1.1) saturate(1.3)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb139\" onchange=\"updateProgress(this)\"><span>backdrop-filter: blur — glassmorphism (glass recipe)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb140\" onchange=\"updateProgress(this)\"><span>-webkit-backdrop-filter is required for Safari</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb141\" onchange=\"updateProgress(this)\"><span>Large blur values slow down mobile — use sparingly</span></label>\n      </div>\n    </div>\n\n    <div class=\"block\" id=\"block-object-fit\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-object-fit')\">object-fit and aspect-ratio — images without stretching <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">The most common layout pain is images of different sizes in identical frames. object-fit and aspect-ratio solve this in two lines.</div>\n      <div class=\"code\">/* Product card — all images same size */\n.card-img {\n  width: 100%;\n  height: 240px;\n  object-fit: cover;       /* fills and crops extra */\n  object-position: center; /* what to show (center by default) */\n}\n\n/* Values object-fit */\nimg.fit-cover    { object-fit: cover;    }  /* fill and crop */\nimg.fit-contain  { object-fit: contain;  }  /* fit entirely */\nimg.fit-fill     { object-fit: fill;     }  /* stretch (distorting!) */\nimg.fit-none     { object-fit: none;     }  /* as is */\nimg.fit-scale    { object-fit: scale-down; }  /* contain, but do not enlarge */\n\n/* aspect-ratio — set ratio without hacks with padding */\n.video-frame {\n  width: 100%;\n  aspect-ratio: 16 / 9;    /* height = width × 9/16 */\n  background: #000;\n}\n\n.avatar {\n  width: 80px;\n  aspect-ratio: 1;          /* square no matter what */\n  border-radius: 50%;\n  object-fit: cover;\n}\n\n/* Responsive grid of equal-height cards */\n.grid {\n  display: grid;\n  grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));\n  gap: 16px;\n}\n.grid img {\n  width: 100%;\n  aspect-ratio: 4 / 3;\n  object-fit: cover;\n  border-radius: 8px;\n}</div>\n      <div class=\"explain\">\n        <strong>object-fit: cover</strong> — the main lifesaver. The image fills the container and extra parts are cropped. No black bars or distortion.<br>\n        <strong>object-fit: contain</strong> — the opposite: fits the whole image. Useful for logos of different shapes — nothing is cropped.<br>\n        <strong>object-position: top / 50% 30%</strong> — which part is visible with <code>cover</code>. By default — center. For portraits, you often need <code>top</code>.<br>\n        <strong>aspect-ratio: 16/9</strong> — sets the proportion. Before, people did it through <code>padding-top: 56.25%</code> — forget that hack.<br>\n        <strong>Works for video and iframe too.</strong> For video and YouTube iframes, this is the ideal responsive method.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb142\" onchange=\"updateProgress(this)\"><span>object-fit: cover — fill and crop (product cards)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb143\" onchange=\"updateProgress(this)\"><span>object-fit: contain — fit entirely (logos)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb144\" onchange=\"updateProgress(this)\"><span>object-position — which part to show with cover</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb145\" onchange=\"updateProgress(this)\"><span>aspect-ratio: 16/9 / 1/1 / 4/3 — proportions in one line</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb146\" onchange=\"updateProgress(this)\"><span>aspect-ratio + object-fit:cover — ready recipe for galleries</span></label>\n      </div>\n    </div>\n\n    <button class=\"try-btn\" onclick=\"sendPrompt('Give me a beginner CSS animation task with a code example')\">Get a CSS task ↗</button>\n  </div>\n\n    "},{"id":"block-scss-basics","title":"SCSS — variables and nesting basics 🔗","html":"<div class=\"block\" id=\"block-scss-basics\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-scss-basics')\">SCSS — variables and nesting <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">SCSS is CSS with superpowers. It compiles into normal CSS. Used in many commercial projects.</div>\n      <div class=\"code\"><span class=\"cm\">// Variables</span>\n<span class=\"kw\">$primary:</span> <span class=\"str\">#6366f1</span>;\n<span class=\"kw\">$font-size-base:</span> <span class=\"num\">16px</span>;\n<span class=\"kw\">$radius:</span> <span class=\"num\">8px</span>;\n\n<span class=\"cm\">// Nesting — no need to repeat selectors</span>\n<span class=\"kw\">.card</span> {\n  padding: <span class=\"num\">20px</span>;\n  border-radius: <span class=\"kw\">$radius</span>;\n\n  <span class=\"kw\">&amp;__title</span> { font-size: <span class=\"num\">18px</span>; }    <span class=\"cm\">// .card__title</span>\n  <span class=\"kw\">&amp;__body</span>  { color: <span class=\"str\">#666</span>; }       <span class=\"cm\">// .card__body</span>\n\n  <span class=\"kw\">&amp;:hover</span>  { box-shadow: <span class=\"num\">0 4px 20px</span> rgba(<span class=\"num\">0,0,0,.1</span>); }\n  <span class=\"kw\">&amp;--dark</span>  { background: <span class=\"str\">#1a1a2e</span>; }  <span class=\"cm\">// .card--dark (BEM)</span>\n}\n\n<span class=\"cm\">// Mixins — reusable style blocks</span>\n<span class=\"kw\">@mixin</span> <span class=\"fn\">flex-center</span> {\n  display: flex;\n  align-items: center;\n  justify-content: center;\n}\n\n<span class=\"kw\">.hero</span> {\n  <span class=\"kw\">@include</span> <span class=\"fn\">flex-center</span>;\n  min-height: <span class=\"num\">100vh</span>;\n}</div>\n      <div class=\"explain\">\n        <strong>$variable</strong> — colors, sizes, fonts. Change it in one place — it changes everywhere.<br>\n        <strong>&amp;</strong> — reference to the parent selector. &amp; + __element = BEM without repetition.<br>\n        <strong>@mixin + @include</strong> — like functions in CSS. Extract repeated styles once.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb147\" onchange=\"updateProgress(this)\"><span>$variables — colors, sizes, spacing</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb148\" onchange=\"updateProgress(this)\"><span>Nesting and &amp; — reference to the parent</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb149\" onchange=\"updateProgress(this)\"><span>@mixin and @include — style reuse</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-scss-advanced","title":"SCSS — functions, loops and @extend important 🔗","html":"<div class=\"block\" id=\"block-scss-advanced\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-scss-advanced')\">SCSS — functions, loops and @extend <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// Functions</span>\n<span class=\"kw\">@function</span> <span class=\"fn\">rem</span>(px) {\n  <span class=\"kw\">@return</span> #{px / 16}rem;\n}\n<span class=\"kw\">.title</span> { font-size: <span class=\"fn\">rem</span>(<span class=\"num\">24</span>); } <span class=\"cm\">// → 1.5rem</span>\n\n<span class=\"cm\">// @each loop</span>\n<span class=\"kw\">$colors:</span> (primary: <span class=\"str\">#6366f1</span>, success: <span class=\"str\">#22c55e</span>, danger: <span class=\"str\">#ef4444</span>);\n\n<span class=\"kw\">@each</span> $name, $color <span class=\"kw\">in</span> <span class=\"kw\">$colors</span> {\n  <span class=\"kw\">.btn-#{$name}</span> {\n    background: <span class=\"kw\">$color</span>;\n    color: white;\n  }\n}\n<span class=\"cm\">// Generates: .btn-primary, .btn-success, .btn-danger</span>\n\n<span class=\"cm\">// @extend — style inheritance</span>\n<span class=\"kw\">%btn-base</span> {\n  padding: <span class=\"num\">8px 16px</span>;\n  border-radius: <span class=\"num\">6px</span>;\n  border: none;\n  cursor: pointer;\n}\n<span class=\"kw\">.btn-primary</span> { <span class=\"kw\">@extend</span> %btn-base; background: <span class=\"str\">#6366f1</span>; }\n<span class=\"kw\">.btn-danger</span>  { <span class=\"kw\">@extend</span> %btn-base; background: <span class=\"str\">#ef4444</span>; }</div>\n      <div class=\"explain\">\n        <strong>@function</strong> — returns a value. Convenient for converting px → rem.<br>\n        <strong>@each</strong> — loop over a list or map. Generates many classes from one piece of code.<br>\n        <strong>%placeholder + @extend</strong> — does not create an extra HTML class, only combines CSS rules.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb150\" onchange=\"updateProgress(this)\"><span>@function — your own function that returns a value</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb151\" onchange=\"updateProgress(this)\"><span>@each — class generation from a list</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb152\" onchange=\"updateProgress(this)\"><span>@extend and %placeholder — style inheritance</span></label>\n      </div>\n    </div>\n\n\n    "},{"id":"block-css-modern-layer-nesting","title":"Modern CSS: @layer and nesting learn after CSS 🔗","html":"<div class=\"block\" id=\"block-css-modern-layer-nesting\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-css-modern-layer-nesting')\">Modern CSS: @layer and nesting <span class=\"badge good\">learn after CSS</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">/* Cascade layers — control priority order without !important */</span>\n<span class=\"kw\">@layer</span> reset, base, components, utilities;\n\n<span class=\"kw\">@layer</span> components {\n  <span class=\"tag\">.card</span> {\n    padding: <span class=\"num\">16px</span>;\n\n    <span class=\"cm\">/* Native CSS nesting */</span>\n    &amp;:hover { box-shadow: <span class=\"num\">0 8px 24px</span> rgba(<span class=\"num\">0,0,0,.12</span>); }\n    &amp; .title { font-size: <span class=\"num\">18px</span>; }\n  }\n}</div>\n      <div class=\"explain\">\n        <strong>@layer</strong> helps agree in advance what is more important: reset, base, components, or utilities. This reduces the need for <code>!important</code>.<br>\n        <strong>CSS Nesting</strong> is already supported by modern browsers: simple nesting can be written without SCSS if the project stack allows it.<br>\n        <strong>SCSS is still useful</strong> for functions, mixins, and complex loops, but nesting is no longer its unique superpower.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb152c\" onchange=\"updateProgress(this)\"><span>@layer — I control the cascade without wars over !important</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb152d\" onchange=\"updateProgress(this)\"><span>CSS Nesting — I understand native nesting without SCSS</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-css-2026-native-apis","title":"CSS 2026: @scope, scroll-driven and View Transitions modern 🔗","html":"<div class=\"block\" id=\"block-css-2026-native-apis\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-css-2026-native-apis')\">CSS 2026: @scope, scroll-driven and View Transitions <span class=\"badge must\">modern</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Modern CSS increasingly replaces small JS libraries: local styles, scroll-based animations, and transitions between screens can be done natively.</div>\n      <div class=\"code\"><span class=\"cm\">/* @scope — styles live only inside .profile-card */</span>\n<span class=\"kw\">@scope</span> (.profile-card) {\n  <span class=\"tag\">.title</span> { color: <span class=\"str\">#6366f1</span>; }\n  <span class=\"tag\">button</span> { border-radius: <span class=\"num\">8px</span>; }\n}\n\n<span class=\"cm\">/* Scroll-driven animation — progress depends on scroll */</span>\n<span class=\"tag\">.progress-row</span> {\n  transform-origin: left;\n  animation: grow linear;\n  animation-timerow: scroll();\n}\n\n<span class=\"kw\">@keyframes</span> grow {\n  from { transform: scaleX(<span class=\"num\">0</span>); }\n  to   { transform: scaleX(<span class=\"num\">1</span>); }\n}\n\n<span class=\"cm\">/* View Transitions — smooth screen/page changes */</span>\n<span class=\"kw\">::view-transition-old</span>(root),\n<span class=\"kw\">::view-transition-new</span>(root) {\n  animation-duration: <span class=\"num\">220ms</span>;\n}</div>\n      <div class=\"explain\">\n        <strong>@scope</strong> restricts the scope of selectors. This is similar to component-local styles, but without CSS Modules.<br>\n        <strong>Scroll-driven animations</strong> bind animations to page scroll. For progress bars and soft effects, you often do not need Intersection Observer.<br>\n        <strong>View Transitions API</strong> helps make smooth transitions between interface states. Great for SPAs and small interactive pages.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-css-modern-1\" onchange=\"updateProgress(this)\"><span>@scope — local CSS selector scope</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-css-modern-2\" onchange=\"updateProgress(this)\"><span>Scroll-driven animations — scroll-based animations without JS</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-css-modern-3\" onchange=\"updateProgress(this)\"><span>View Transitions — smooth transitions between UI states</span></label>\n      </div>\n    </div>\n"}]},{"id":"sec-js","lessons":[{"id":"block-vars-js","title":"Variables — where we store data basics 🔗","html":"<div class=\"block\" id=\"block-vars-js\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-vars-js')\">Variables — where we store data <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">A variable is a named box that stores a value.</div>\n      <div class=\"code\">// const — value CANNOT be changed (constant)\nconst PI = 3.14;\nconst name = \"Alex\";\n\n// let — value CAN be changed\nlet age = 25;\nage = 26;  // ok, age is now 26\n\n// Data types:\nlet text = \"Hello\";    // string (row)\nlet number = 42;        // number\nlet isOnrow = true;    // boolean (yes/no)\nlet nothing = null;     // empty intentionally\nlet notSet;             // undefined (not set)</div>\n      <div class=\"explain\">\n        <strong>const</strong> — use in 90% of cases. Cannot be reassigned.<br>\n        <strong>let</strong> — when the value will definitely change (counter, flag).<br>\n        <strong>var</strong> — <em>forget it</em>. In modern code, use only const and let.<br>\n        <strong>null vs undefined</strong>: null = we intentionally put emptiness. undefined = nobody has put a value yet.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb153\" onchange=\"updateProgress(this)\"><span>const by default, let only if you need changes</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb154\" onchange=\"updateProgress(this)\"><span>var is outdated! Only const and let</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-functions","title":"Functions — regular, arrow, parameters basics 🔗","html":"<div class=\"block\" id=\"block-functions\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-functions')\">Functions — regular, arrow, parameters <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">A function is a “recipe”. Write it once and use it as many times as you want. In JS there are two main forms: regular functions and arrow functions.</div>\n      <div class=\"code\">// Regular function (function declaration)\nfunction greet(name) {\n  return \"Hello, \" + name + \"!\";\n}\n\ngreet(\"World\");   // \"Hello, World!\"\n\n// Arrow function — shorter, without its own this\nconst greet2 = (name) =&gt; \"Hello, \" + name + \"!\";\n\n// If there is one parameter — parentheses can be removed\nconst square = n =&gt; n * n;\n\n// If the body is one expression, return and {} are not needed\nconst sum = (a, b) =&gt; a + b;\n\n// Several lines — curly braces and return are needed\nconst greet3 = (name) =&gt; {\n  const upper = name.toUpperCase();\n  return \"Hello, \" + upper + \"!\";\n};\n\n// Default parameters\nfunction order(item, quantity = 1, price = 100) {\n  return `${item} × ${quantity} = ${quantity * price}₽`;\n}\norder(\"coffee\");              // \"coffee × 1 = 100\"\norder(\"tea\", 3);            // \"tea × 3 = 300\"\norder(\"juice\", 2, 80);        // \"juice × 2 = 160\"\n\n// Rest parameter — collects “everything else” into an array\nfunction sumAll(...numbers) {\n  return numbers.reduce((s, n) =&gt; s + n, 0);\n}\nsumAll(1, 2, 3, 4, 5);   // 15\n\n// Callback — a function passed as an argument\n[1, 2, 3].map(n =&gt; n * 2);   // [2, 4, 6]\nsetTimeout(() =&gt; console.log(\"after one second\"), 1000);</div>\n      <div class=\"explain\">\n        \n<strong>How to read a function:</strong> a function is a named piece of logic. Parameters inside parentheses are data the function receives from outside.<br>\n        <strong>return</strong> is the function result. If there is no return, the function returns <code>undefined</code>. <code>console.log</code> only prints; it does not return a value.<br>\n        <strong>function greet(name)</strong> reads as “create an action greet that needs name”. Calling <code>greet(\"World\")</code> puts the string into the parameter.<br>\n        <strong>An arrow function</strong> is often shorter: <code>n =&gt; n * n</code> means “take n and return n * n”. If the body is one expression, return is implicit.<br>\n        <strong>If an arrow function has braces</strong>, <code>return</code> is needed again: <code>() =&gt; { return value; }</code>.<br>\n        <strong>Default parameters</strong> help when an argument is missing: <code>quantity = 1</code>.<br>\n        <strong>Callback</strong> is a function passed into another function. This is how <code>map</code>, <code>filter</code>, <code>addEventListener</code>, and <code>setTimeout</code> work.\n\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb184\" onchange=\"updateProgress(this)\"><span>const f = () =&gt; ... — arrow by default</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb185\" onchange=\"updateProgress(this)\"><span>n =&gt; n * 2 — short syntax with one expression</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb186\" onchange=\"updateProgress(this)\"><span>function name() — needed for methods and hoisting</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb187\" onchange=\"updateProgress(this)\"><span>Default parameters: function f(x = 10)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb188\" onchange=\"updateProgress(this)\"><span>...rest collects arguments into an array</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-arrays","title":"Arrays — list elements basics 🔗","html":"<div class=\"block\" id=\"block-arrays\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-arrays')\">Arrays — list elements <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">const fruits = [\"apple\", \"banana\", \"pear\"];\n\nfruits[0];           // \"apple\" — numbering starts at 0!\nfruits.length;       // 3\n\nfruits.push(\"mango\");      // Add to the end\nfruits.pop();              // Delete last\nfruits.unshift(\"orange\"); // Add to the beginning\nfruits.shift();            // Delete the first item\n\nconst numbers = [1, 2, 3, 4, 5];\nconst doubled = numbers.map(n =&gt; n * 2);  // [2,4,6,8,10]\nconst big = numbers.filter(n =&gt; n &gt; 3);   // [4, 5]\nconst sum = numbers.reduce((t, n) =&gt; t + n, 0); // 15</div>\n      <div class=\"explain\">\n        \n<strong>How to read an array:</strong> an array is an ordered list of values. Indexes start at 0, so <code>fruits[0]</code> is the first item.<br>\n        <strong>.length</strong> shows the number of items. The last index is always <code>length - 1</code>.<br>\n        <strong>push / pop</strong> work with the end of the array. <code>push</code> adds, <code>pop</code> removes the last item and returns it.<br>\n        <strong>unshift / shift</strong> work with the beginning. Avoid overusing them on large lists because items must shift positions.<br>\n        <strong>map</strong> is for creating a new array of the same length with transformed items: multiply numbers, turn objects into HTML, format names.<br>\n        <strong>filter</strong> is for keeping only some items: completed tasks, products above 1000, cards matching search text.<br>\n        <strong>reduce</strong> is for turning an array into one value: sum, max, grouped object, statistics.<br>\n        <strong>How to read reduce:</strong> <code>t</code> is the accumulator, <code>n</code> is the current item, and <code>0</code> is the starting value. Each step returns the next accumulator.\n\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb159\" onchange=\"updateProgress(this)\"><span>Numbering starts at 0: fruits[0] — first element</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb160\" onchange=\"updateProgress(this)\"><span>map transforms, filter filters, reduce reduces</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-destructuring","title":"Destructuring and spread — modern syntax important 🔗","html":"<div class=\"block\" id=\"block-destructuring\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-destructuring')\">Destructuring and spread — modern syntax <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Destructuring is a short way to “pull out” fields from an object or array. Spread means “spread/unpack” an array or object.</div>\n      <div class=\"code\">// === Object destructuring ===\nconst user = { name: \"Alex\", age: 25, city: \"Moscow\" };\n\n// Old way\nconst name1 = user.name;\nconst age1  = user.age;\n\n// New way\nconst { name, age } = user;\nconsole.log(name, age);     // \"Alex\" 25\n\n// Renaming + default value\nconst { name: userName, role = \"guest\" } = user;\nconsole.log(userName, role);   // \"Alex\" \"guest\"\n\n// === Array destructuring ===\nconst colors = [\"red\", \"green\", \"blue\"];\nconst [first, second] = colors;     // \"red\"  \"green\"\nconst [, , third] = colors;         // only third: \"blue\"\n\n// Swapping variables\nlet a = 1, b = 2;\n[a, b] = [b, a];   // now a=2, b=1\n\n// === In function parameters ===\nfunction showUser({ name, age }) {\n  console.log(`${name}, ${age} years old`);\n}\nshowUser(user);   // \"Alex, 25 years old\"\n\n// === Spread (...) — «spread/unpack» ===\nconst arr1 = [1, 2, 3];\nconst arr2 = [...arr1, 4, 5];          // [1,2,3,4,5]\nconst copy = [...arr1];                // full copy\n\nconst obj1 = { a: 1, b: 2 };\nconst obj2 = { ...obj1, c: 3 };        // {a:1, b:2, c:3}\nconst updated = { ...user, age: 26 };  // copy + updated field\n\n// Pass array as arguments\nconst nums = [5, 8, 1, 9, 2];\nMath.max(...nums);                     // 9</div>\n      <div class=\"explain\">\n        <strong>{ name } = user</strong> — take the <code>name</code> field from an object and immediately create a variable with the same name.<br>\n        <strong>: renaming</strong> — <code>{ name: userName }</code> creates a <code>userName</code> variable.<br>\n        <strong>= value</strong> — if the field is missing, the default is used. Both are often combined: <code>{ role = \"guest\" }</code>.<br>\n        <strong>...spread</strong> “spreads” an array or object. Ideal for copying and updating (not mutating!).<br>\n        <strong>Update an object without changing the original</strong>: <code>{ ...user, age: 26 }</code>. Foundation for React and Redux.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb194\" onchange=\"updateProgress(this)\"><span>const { name, age } = user — get fields in one line</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb195\" onchange=\"updateProgress(this)\"><span>const [first, second] = arr — the same for arrays</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb196\" onchange=\"updateProgress(this)\"><span>function f({ name, age }) — destructuring in parameters</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb197\" onchange=\"updateProgress(this)\"><span>[...arr1, 4, 5] — copy + add, without mutations</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb198\" onchange=\"updateProgress(this)\"><span>{...user, age: 26} — update a field without touching the original</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-js-modern-2026","title":"Modern JavaScript data transformations 2026 CORE #","html":"<div class=\"block wdg-2026-block\" id=\"block-js-modern-2026\"><div class=\"block-title\" onclick=\"scrollToBlock('block-js-modern-2026')\">Modern JavaScript data transformations <span class=\"badge must\">2026 CORE</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">Arrow functions, destructuring, Rest/Spread, and array methods are everyday tools, not syntax tricks.</div><div class=\"code\">const users = [\n  { id: 1, name: \"Mira\", active: true, score: 12 },\n  { id: 2, name: \"Leo\", active: false, score: 7 },\n  { id: 3, name: \"Nika\", active: true, score: 18 }\n];\n\nconst activeNames = users\n  .filter(({ active }) =&gt; active)\n  .map(({ name }) =&gt; name);\n\nconst total = users.reduce((sum, { score }) =&gt; sum + score, 0);\nconst updateUser = (user, changes) =&gt; ({ ...user, ...changes });\nconst [first, ...rest] = users;</div><div class=\"explain\"><code>filter</code> selects, <code>map</code> transforms, and <code>reduce</code> combines an array. Destructuring reads named fields. Spread creates a new object without mutation; Rest collects remaining values. There is no reason to use <code>var</code> here.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-js-modern-2026-1\" onchange=\"updateProgress(this)\"><span>I use arrow functions, destructuring, and Rest/Spread</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-js-modern-2026-2\" onchange=\"updateProgress(this)\"><span>I know map, filter, and reduce</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-js-modern-2026-3\" onchange=\"updateProgress(this)\"><span>I avoid var and unnecessary mutation</span></label></div></div>"},{"id":"block-async","title":"Promise and async/await — async made human-readable important 🔗","html":"<div class=\"block\" id=\"block-async\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-async')\">Promise and async/await — async made human-readable <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">When code “waits” (server request, timer), it works asynchronously. Promise is a promise to give a result “later”. async/await is syntax that makes it look like normal code.</div>\n      <div class=\"code\">// Promise — a “promise” of a future result\nconst promise = new Promise((resolve, reject) =&gt; {\n  setTimeout(() =&gt; {\n    const ok = Math.random() &gt; 0.3;\n    if (ok) resolve(\"Data arrived!\");\n    else    reject(\"Server crashed\");\n  }, 1000);\n});\n\n// .then().catch() — old style\npromise\n  .then(data =&gt; console.log(data))      // success\n  .catch(err =&gt; console.error(err))     // error\n  .finally(() =&gt; console.log(\"Done\")); // always\n\n// async/await — modern style (reads like normal code)\nasync function loadUser(id) {\n  try {\n    const res  = await fetch(`/api/users/${id}`);\n    if (!res.ok) throw new Error(\"HTTP \" + res.status);\n\n    const user = await res.json();      // wait for parsing\n    console.log(user.name);\n    return user;\n  } catch (err) {\n    console.error(\"Did not load:\", err.message);\n    return null;\n  }\n}\n\n// Run\nloadUser(42).then(u =&gt; console.log(u));\n\n// await works only inside async functions!\n// To wait for several in parallel — Promise.all\nasync function loadAll() {\n  const [users, posts] = await Promise.all([\n    fetch(\"/api/users\").then(r =&gt; r.json()),\n    fetch(\"/api/posts\").then(r =&gt; r.json())\n  ]);   // requests run in parallel — faster\n  return { users, posts };\n}</div>\n      <div class=\"explain\">\n        <strong>Promise</strong> — object that will <em>eventually</em> return a result (resolve) or error (reject). Most often you do not create them yourself — they are returned by <code>fetch</code>, <code>fs</code>, libraries.<br>\n        <strong>async</strong> before a function → it automatically returns a Promise.<br>\n        <strong>await</strong> “pauses” the function until the promise resolves. Under the hood, it is the same <code>.then()</code>, but it reads like synchronous code.<br>\n        <strong>try / catch</strong> with async/await — works! Any error from await is caught in catch.<br>\n        <strong>Promise.all([...])</strong> — runs promises in parallel. Much faster than <code>await</code> one by one.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb189\" onchange=\"updateProgress(this)\"><span>Promise — a “promise” of a future result</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb190\" onchange=\"updateProgress(this)\"><span>.then(ok).catch(err) — old but working method</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb191\" onchange=\"updateProgress(this)\"><span>async/await — modern, reads like normal code</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb192\" onchange=\"updateProgress(this)\"><span>await — only inside async functions!</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb193\" onchange=\"updateProgress(this)\"><span>Promise.all — parallel requests, wait for all at once</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-fetch","title":"Fetch: HTTP errors, JSON, and cancellation IMPORTANT #","html":"<div class=\"block wdg-quality-block\" id=\"block-fetch\"><div class=\"block-title\" onclick=\"scrollToBlock('block-fetch')\">Fetch: HTTP errors, JSON, and cancellation <span class=\"badge good\">IMPORTANT</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\"><code>fetch()</code> rejects on a network failure, but 404 and 500 still produce a normal <code>Response</code>. Always check <code>response.ok</code>.</div><div class=\"code\">async function loadProjects(signal) {\n  const response = await fetch(\"/api/projects\", { signal });\n  if (!response.ok) {\n    throw new Error(\"HTTP \" + response.status);\n  }\n  return response.json();\n}\n\nconst controller = new AbortController();\ntry {\n  const projects = await loadProjects(controller.signal);\n  console.log(projects);\n} catch (error) {\n  if (error.name !== \"AbortError\") console.error(error);\n}\n\n// controller.abort(); // cancel the stale request</div><div class=\"explain\">Check status before parsing the body with <code>json()</code>. <code>try/catch</code> handles network failures, your own <code>throw</code>, and parsing errors. <code>AbortController</code> cancels work when the user leaves or starts a newer search.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-fetch-1\" onchange=\"updateProgress(this)\"><span>I check response.ok</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-fetch-2\" onchange=\"updateProgress(this)\"><span>I show errors to the user</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-fetch-3\" onchange=\"updateProgress(this)\"><span>I cancel stale requests</span></label></div></div>"},{"id":"block-trycatch","title":"try / catch — error handling important 🔗","html":"<div class=\"block\" id=\"block-trycatch\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-trycatch')\">try / catch — error handling <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Errors happen: the server did not respond, the user entered invalid data. try/catch lets you handle them without crashing the whole script.</div>\n      <div class=\"code\">// Basic try / catch\ntry {\n  const data = JSON.parse(\"not a JSON string\");  // error!\n  console.log(data);\n} catch (err) {\n  console.log(\"Error:\", err.message);  // catch it\n} finally {\n  console.log(\"Always runs\");   // both on success and on error\n}\n\n// With fetch (async/await + try/catch)\nasync function loadUser(id) {\n  try {\n    const res = await fetch(`/api/users/${id}`);\n\n    if (!res.ok) {\n      throw new Error(`Server returned ${res.status}`);  // throw an error ourselves\n    }\n\n    const user = await res.json();\n    return user;\n\n  } catch (err) {\n    console.error(\"Failed to load user:\", err.message);\n    return null;  // return null instead of crashing\n  }\n}\n\n// Custom error\nfunction divide(a, b) {\n  if (b === 0) throw new Error(\"Cannot divide by zero!\");\n  return a / b;\n}\n\ntry {\n  console.log(divide(10, 0));\n} catch (e) {\n  console.warn(e.message);  // \"Cannot divide by zero!\"\n}</div>\n      <div class=\"explain\">\n        <strong>try</strong> — code that may fail with an error.<br>\n        <strong>catch (err)</strong> — we get here on an error. <code>err.message</code> — error text.<br>\n        <strong>finally</strong> — always runs (close connection, hide loader).<br>\n        <strong>throw new Error(\"...\")</strong> — you create an error yourself (for example, for invalid data).\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb179\" onchange=\"updateProgress(this)\"><span>try { } catch (err) { } — required pair</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb180\" onchange=\"updateProgress(this)\"><span>err.message — read error text</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb181\" onchange=\"updateProgress(this)\"><span>finally — close resources, hide spinner</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb182\" onchange=\"updateProgress(this)\"><span>throw new Error() — throw an error yourself for invalid data</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb183\" onchange=\"updateProgress(this)\"><span>I wrap fetch / JSON.parse in try/catch</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-js-network-2026","title":"Real request: fetch + async/await 2026 CORE #","html":"<div class=\"block wdg-2026-block\" id=\"block-js-network-2026\"><div class=\"block-title\" onclick=\"scrollToBlock('block-js-network-2026')\">Real request: fetch + async/await <span class=\"badge must\">2026 CORE</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">A request has loading, success, empty, and error states. Handle all of them, not only the happy-path console.log.</div><div class=\"code\">async function loadProjects() {\n  renderStatus(\"loading\");\n\n  try {\n    const response = await fetch(\"/api/projects\");\n    if (!response.ok) throw new Error(\"HTTP \" + response.status);\n\n    const projects = await response.json();\n    renderProjects(projects);\n    renderStatus(projects.length ? \"success\" : \"empty\");\n  } catch (error) {\n    console.error(error);\n    renderStatus(\"error\");\n  }\n}</div><div class=\"explain\"><code>await</code> waits for a Promise inside the async function without freezing the page. HTTP 404/500 does not automatically throw, so check <code>response.ok</code>. <code>try/catch</code> handles failure, while render functions keep network and DOM logic separate.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-js-network-2026-1\" onchange=\"updateProgress(this)\"><span>I check response.ok</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-js-network-2026-2\" onchange=\"updateProgress(this)\"><span>I handle errors with try/catch</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-js-network-2026-3\" onchange=\"updateProgress(this)\"><span>I separate data loading from DOM rendering</span></label></div></div>"},{"id":"block-strings","title":"Strings — working with text basics 🔗","html":"<div class=\"block\" id=\"block-strings\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-strings')\">Strings — working with text <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">const name = \"World\";\nconst age = 25;\n\n// Templates — insert variables into text\nconst msg = `Hello, ${name}! You are ${age} years old.`;\n\nmsg.length;               // String length\nmsg.toUpperCase();        // \"HELLO, WORLD!\"\nmsg.toLowerCase();        // \"hello, world!\"\nmsg.includes(\"World\");      // true\nmsg.replace(\"World\", \"friend\"); // \"Hello, friend!\"\nmsg.trim();               // Remove spaces at the edges\nmsg.split(\", \");          // [\"Hello\", \"World!\"]</div>\n      <div class=\"explain\">\n        \n<strong>How to read this code:</strong> a string is text. If text is stored in a variable, methods can inspect it, search inside it, change case, replace a part, or split it into pieces.<br>\n        <strong>Template strings</strong> use backticks <code>`</code>. Inside them, <code>${name}</code> means: take the value of <code>name</code> and insert it into the text.<br>\n        <strong>Important:</strong> string methods usually <em>do not change the original string</em>. They return a new result. <code>msg.toUpperCase()</code> returns uppercase text, but <code>msg</code> stays the same.<br>\n        <strong>.length</strong> is not a function, so it has no parentheses. It simply stores the number of characters.<br>\n        <strong>.includes(\"World\")</strong> asks: “does this text contain this part?” The answer is <code>true</code> or <code>false</code>.<br>\n        <strong>.trim()</strong> is very useful before form validation: a user may type only spaces, and <code>trim()</code> turns that into an empty string.<br>\n        <strong>.split(\", \")</strong> cuts text by a separator and returns an array. If the separator is not found, you get an array with one string.<br>\n        <strong>When to use it:</strong> forms, page search, user messages, formatting names, checking email/login before sending.\n\n      </div>\n      <!-- MINI TEST FOR STRINGS -->\n      <div class=\"quiz-block\" id=\"quiz-strings\">\n        <div class=\"quiz-title\">🧪 Mini-test — Strings</div>\n        <div class=\"quiz-question\">1. Which method removes spaces at the start and end of a string?</div>\n        <div class=\"quiz-options\">\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-str-1\" value=\"a\"> <span>.clean()</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-str-1\" value=\"b\"> <span>.trim()</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-str-1\" value=\"c\"> <span>.strip()</span></label>\n        </div>\n        <div class=\"quiz-question\">2. How do you insert a variable into a string using a template?</div>\n        <div class=\"quiz-options\">\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-str-2\" value=\"a\"> <span>\"Hello, \" + name</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-str-2\" value=\"b\"> <span>`Hello, ${name}`</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-str-2\" value=\"c\"> <span>f\"Hello, {name}\"</span></label>\n        </div>\n        <div class=\"practice-block\">\n          <div class=\"practice-title\">⌨️ Practice</div>\n          <div class=\"practice-task\">Write a <code>trimAndUpper</code> function that takes a string, removes spaces at the edges, and returns it in uppercase.</div>\n          <textarea class=\"practice-input\" id=\"practice-strings\" placeholder=\"function trimAndUpper(str) { ... }\"></textarea>\n        </div>\n        <button class=\"quiz-check-btn\" onclick=\"checkQuiz('strings')\">✓ Check</button>\n        <div class=\"quiz-result\" id=\"result-strings\"></div>\n      </div>\n      <div class=\"items\" id=\"items-strings\">\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb610\" onchange=\"updateProgress(this)\" disabled><span>🔒 Templates: `${variable}` inside backticks</span></label>\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb611\" onchange=\"updateProgress(this)\" disabled><span>🔒 .trim() — remove spaces, .includes() — check for a substring</span></label>\n      </div>\n      <div class=\"locked-items-notice\">🔒 Complete the test and practice to unlock the checkboxes</div>\n    </div>\n\n    "},{"id":"block-conditions","title":"Conditions — if... then... basics 🔗","html":"<div class=\"block\" id=\"block-conditions\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-conditions')\">Conditions — if... then... <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">const age = 20;\n\nif (age &gt;= 18) {\n  console.log(\"Adult\");\n} else if (age &gt;= 14) {\n  console.log(\"Teenager\");\n} else {\n  console.log(\"Child\");\n}\n\n// Ternary operator — short if/else syntax\nconst status = age &gt;= 18 ? \"adult\" : \"child\";\n\n// ===  strict equality (5 === \"5\" → false!)\n// !==  strict inequality\n// &amp;&amp;   AND (both conditions are true)\n// ||   OR (at least one is true)</div>\n      <div class=\"explain\">\n        \n<strong>How to read if:</strong> the browser goes from top to bottom and runs the first block whose condition becomes <code>true</code>. The remaining branches are skipped.<br>\n        <strong>if</strong> is the first check. <strong>else if</strong> is a backup check if the first one failed. <strong>else</strong> is the fallback when nothing above matched.<br>\n        <strong>Where to use ===:</strong> when you compare “is this value equal to that value?”. For example <code>role === \"admin\"</code>, <code>score === 0</code>, <code>theme === \"dark\"</code>.<br>\n        <strong>Where to use &gt;=:</strong> when checking a boundary: age, price, amount, screen width, number of clicks. <code>age &gt;= 18</code> means “18 or more”.<br>\n        <strong>&amp;&amp;</strong> means both conditions must be true: <code>age &gt;= 18 &amp;&amp; hasTicket</code>.<br>\n        <strong>||</strong> means one condition is enough: <code>role === \"admin\" || role === \"moderator\"</code>.<br>\n        <strong>The ternary operator</strong> is good for choosing one short value. If you need several actions, normal <code>if/else</code> is easier to read.<br>\n        <strong>Common mistake:</strong> <code>=</code> assigns, <code>===</code> compares. In conditions you almost always want <code>===</code>.\n\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb155\" onchange=\"updateProgress(this)\"><span>Always use === (strict), not == (loose)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb156\" onchange=\"updateProgress(this)\"><span>Ternary: condition ? yes : no</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-loops","title":"Loops — repeat an action basics 🔗","html":"<div class=\"block\" id=\"block-loops\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-loops')\">Loops — repeat an action <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">// for — when we know how many times\nfor (let i = 0; i &lt; 5; i++) {\n  console.log(i);  // 0, 1, 2, 3, 4\n}\n\n// while — when we do NOT know how many times\nlet count = 3;\nwhile (count &gt; 0) {\n  console.log(count);\n  count--;\n}\n\n// for...of — iterating over an array\nconst fruits = [\"apple\", \"banana\", \"pear\"];\nfor (const fruit of fruits) {\n  console.log(fruit);\n}</div>\n      <div class=\"explain\">\n        \n<strong>How to read a for loop:</strong> <code>let i = 0</code> is where it starts, <code>i &lt; 5</code> is while it continues, <code>i++</code> is what happens after each round.<br>\n        <strong>Why it prints 0..4:</strong> the loop starts at 0, and <code>i &lt; 5</code> stops it before 5. When <code>i</code> becomes 5, the condition is false.<br>\n        <strong>while</strong> is useful when you do not know the exact number of repeats in advance. For example, wait until valid input appears.<br>\n        <strong>while danger:</strong> if nothing inside changes the value, the condition may stay true forever, causing an infinite loop.<br>\n        <strong>for...of</strong> is best when you need the actual array item: fruit, card, task, user. It is simpler than reading by index.<br>\n        <strong>When to use it:</strong> render cards, go through buttons, calculate a sum, find an element, create HTML for each object.\n\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb157\" onchange=\"updateProgress(this)\"><span>for — when you know how many times, while — while a condition is true</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb158\" onchange=\"updateProgress(this)\"><span>for...of — iterating over array elements</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-dom","title":"DOM — controlling the page basics 🔗","html":"<div class=\"block\" id=\"block-dom\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-dom')\">DOM — controlling the page <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">// FIND an element\nconst btn = document.querySelector(\".btn\");       // First\nconst all = document.querySelectorAll(\"li\");      // All\n\n// CHANGE\nbtn.textContent = \"Clicked!\";       // Change text\nbtn.style.color = \"red\";           // Change style\nbtn.classList.add(\"active\");       // Add class\nbtn.classList.remove(\"active\");    // Remove class\nbtn.classList.toggle(\"open\");      // Toggle\n\n// CREATE and ADD\nconst div = document.createElement(\"div\");\ndiv.textContent = \"New block\";\ndocument.body.appendChild(div);\n\n// DELETE\nbtn.remove();</div>\n      <div class=\"explain\">\n        \n<strong>How to read DOM code:</strong> first you find an element on the page, then you change its text, style, classes, or attach events.<br>\n        <strong>querySelector</strong> returns the first matching element. It uses a CSS selector: <code>\".btn\"</code> for a class, <code>\"#title\"</code> for an id, <code>\"button\"</code> for a tag.<br>\n        <strong>querySelectorAll</strong> returns a list of elements. You usually loop over it with <code>forEach</code>, because it is not one element but a collection.<br>\n        <strong>textContent</strong> changes text inside an element. For normal text it is safer than <code>innerHTML</code>.<br>\n        <strong>classList</strong> is better than changing <code>style</code> all the time. JS keeps the logic, CSS keeps the look.<br>\n        <strong>createElement + append</strong> are used when an element must appear after user action: new task, message, card, form error.\n\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb161\" onchange=\"updateProgress(this)\"><span>querySelector — one, querySelectorAll — all</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb162\" onchange=\"updateProgress(this)\"><span>classList.add / remove / toggle / contains</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-events","title":"Events — reacting to actions basics 🔗","html":"<div class=\"block\" id=\"block-events\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-events')\">Events — reacting to actions <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">const btn = document.querySelector(\".btn\");\n\nbtn.addEventListener(\"click\", (e) =&gt; {\n  console.log(\"Clicked!\");\n  e.preventDefault(); // Cancel default behavior\n});\n\nconst input = document.querySelector(\"input\");\ninput.addEventListener(\"input\", (e) =&gt; {\n  console.log(\"Typed:\", e.target.value);\n});\n\n// Common events:\n// click, dblclick — click / double click\n// input, change — input / field change\n// submit — form submission\n// keydown, keyup — keyboard\n// mouseover, mouseout — mouse\n// scroll — scrolling</div>\n      <div class=\"explain\">\n        \n<strong>How to read an event:</strong> <code>addEventListener(\"click\", ...)</code> means “when click happens, run this function”. The code inside does not run immediately; it waits for user action.<br>\n        <strong>The first argument</strong> is the event name as a string: <code>\"click\"</code>, <code>\"input\"</code>, <code>\"submit\"</code>, <code>\"keydown\"</code>.<br>\n        <strong>The second argument</strong> is the function that will run later. <code>handleClick</code> passes the function, <code>handleClick()</code> calls it immediately.<br>\n        <strong>e</strong> or <strong>event</strong> is the event object. The browser puts details there: where the click happened, which key was pressed, what is inside an input.<br>\n        <strong>e.target</strong> is the exact element that triggered the event. <code>e.target.value</code> is the text inside an input.<br>\n        <strong>e.preventDefault()</strong> is used in forms so the browser does not reload the page after submit.<br>\n        <strong>How to choose an event:</strong> button — <code>click</code>, live text field — <code>input</code>, form send — <code>submit</code>, keyboard — <code>keydown</code>.\n\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb163\" onchange=\"updateProgress(this)\"><span>addEventListener — listen to an event</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb164\" onchange=\"updateProgress(this)\"><span>e.target.value — input field value</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb165\" onchange=\"updateProgress(this)\"><span>e.preventDefault() — prevent reload</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-localstorage","title":"localStorage: strings, null, and safe parsing IMPORTANT #","html":"<div class=\"block wdg-quality-block\" id=\"block-localstorage\"><div class=\"block-title\" onclick=\"scrollToBlock('block-localstorage')\">localStorage: strings, null, and safe parsing <span class=\"badge good\">IMPORTANT</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\"><code>localStorage.getItem()</code> returns a string or <code>null</code>. Handle the missing value before converting its type. Never store passwords, tokens, or other secrets here.</div><div class=\"code\">localStorage.setItem(\"theme\", \"dark\");\nconst theme = localStorage.getItem(\"theme\") ?? \"light\";\n\nconst rawScore = localStorage.getItem(\"score\");\nconst parsedScore = rawScore === null ? 0 : Number(rawScore);\nconst score = Number.isFinite(parsedScore) ? parsedScore : 0;\n\nconst user = { id: 7, name: \"Mira\" };\nlocalStorage.setItem(\"user\", JSON.stringify(user));\n\nconst rawUser = localStorage.getItem(\"user\");\nconst savedUser = rawUser === null ? null : JSON.parse(rawUser);\nlocalStorage.removeItem(\"theme\");</div><div class=\"explain\"><code>??</code> uses a fallback only for <code>null</code> and <code>undefined</code>, preserving valid <code>0</code> and empty strings. <code>Number(localStorage.getItem(\"score\")) ?? 0</code> is useless because the value cannot be <code>null</code> after <code>Number()</code>. Store objects with <code>JSON.stringify</code> and account for invalid stored data.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-localstorage-1\" onchange=\"updateProgress(this)\"><span>I remember string | null</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-localstorage-2\" onchange=\"updateProgress(this)\"><span>I check NaN after Number()</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-localstorage-3\" onchange=\"updateProgress(this)\"><span>I never store secrets</span></label></div></div>"},{"id":"block-localstorage-counter","title":"A counter with persisted state PRACTICE #","html":"<div class=\"block wdg-quality-block\" id=\"block-localstorage-counter\"><div class=\"block-title\" onclick=\"scrollToBlock('block-localstorage-counter')\">A counter with persisted state <span class=\"badge good\">PRACTICE</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">The app restores state first and then renders it. After every real change, the new value is written back.</div><div class=\"code\">const count = document.querySelector(\".count\");\nconst plus = document.querySelector(\".plus\");\nconst reset = document.querySelector(\".reset\");\n\nconst rawScore = localStorage.getItem(\"score\");\nlet score = rawScore === null ? 0 : Number(rawScore);\nif (!Number.isFinite(score)) score = 0;\n\nfunction render() { count.textContent = score; }\nfunction save() { localStorage.setItem(\"score\", String(score)); }\n\nplus.addEventListener(\"click\", () =&gt; {\n  score += 1;\n  save();\n  render();\n});\n\nreset.addEventListener(\"click\", () =&gt; {\n  score = 0;\n  save();\n  render();\n});\n\nrender();</div><div class=\"explain\"><code>score</code> is state, <code>render()</code> synchronizes the DOM, and <code>save()</code> only handles storage. The first <code>render()</code> is required or the restored value stays invisible until a click. Do not redeclare <code>score</code> after reading storage.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-localstorage-counter-1\" onchange=\"updateProgress(this)\"><span>I restore before render()</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-localstorage-counter-2\" onchange=\"updateProgress(this)\"><span>I separate state, save, and render</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-localstorage-counter-3\" onchange=\"updateProgress(this)\"><span>I do not declare score twice</span></label></div></div>"},{"id":"block-objects","title":"Objects — structured data basics 🔗","html":"<div class=\"block\" id=\"block-objects\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-objects')\">Objects — structured data <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">An object is a set of “key: value” pairs. Ideal for describing entities: user, product, task.</div>\n      <div class=\"code\">// Create an object\nconst user = {\n  name: \"Alex\",\n  age: 25,\n  isAdmin: false,\n  greet() {\n    return `Hello, I am ${this.name}!`;\n  }\n};\n\n// Read properties\nconsole.log(user.name);       // \"Alex\"\nconsole.log(user[\"age\"]);     // 25  (second method)\n\n// Change / add properties\nuser.age = 26;\nuser.city = \"Moscow\";         // added a new field\n\n// Method call\nconsole.log(user.greet());    // \"Hello, I am Alex!\"\n\n// Destructuring (pull fields into variables)\nconst { name, age } = user;\nconsole.log(name, age);       // \"Alex\" 26\n\n// Iterate over all keys\nfor (const key in user) {\n  console.log(key, user[key]);\n}\n\n// Array of objects\nconst products = [\n  { id: 1, name: \"Laptop\", price: 50000 },\n  { id: 2, name: \"Mouse\",    price: 1200 },\n];\nproducts.forEach(p =&gt; console.log(p.name, p.price));\n\n// Object copy (spread)\nconst copy = { ...user, role: \"editor\" };</div>\n      <div class=\"explain\">\n        <strong>Dot notation</strong>: <code>user.name</code> — the most common way.<br>\n        <strong>Bracket notation</strong>: <code>user[\"name\"]</code> — needed when the key is in a variable.<br>\n        <strong>this</strong> — inside a method, refers to the object itself.<br>\n        <strong>Destructuring</strong>: <code>const {name, age} = user</code> — short way to get several fields.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb175\" onchange=\"updateProgress(this)\"><span>Object = { key: value }, read through a dot</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb176\" onchange=\"updateProgress(this)\"><span>Destructuring: const { name, age } = user</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb177\" onchange=\"updateProgress(this)\"><span>Spread: { ...obj } — copies object</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb178\" onchange=\"updateProgress(this)\"><span>Array of objects — typical data structure from a server</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-timers","title":"setTimeout, setInterval, debounce important 🔗","html":"<div class=\"block\" id=\"block-timers\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-timers')\">setTimeout, setInterval, debounce <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Timers run code “after some time” or “every some time”. They power everything: toasts, tooltips, search while typing, animations, server polling.</div>\n      <div class=\"code\">// setTimeout — run ONCE after N ms\nsetTimeout(() =&gt; {\n  console.log(\"A second passed\");\n}, 1000);\n\n// Save id so it can be cancelled\nconst id = setTimeout(() =&gt; alert(\"Will not appear!\"), 5000);\nclearTimeout(id);   // cancel\n\n// setInterval — repeat EVERY N ms\nconst tick = setInterval(() =&gt; {\n  console.log(new Date().toLocaleTimeString());\n}, 1000);\n\n// Stop after 10 seconds\nsetTimeout(() =&gt; clearInterval(tick), 10000);\n\n// === Real example: auto-hiding toast ===\nfunction showToast(text) {\n  const t = document.querySelector(\".toast\");\n  t.textContent = text;\n  t.classList.add(\"show\");\n  setTimeout(() =&gt; t.classList.remove(\"show\"), 3000);\n}\n\n// === Debounce — «run not immediately, but after it calms down» ===\n// Useful for search input: wait until the user stops typing\nfunction debounce(fn, ms = 300) {\n  let timer;\n  return (...args) =&gt; {\n    clearTimeout(timer);\n    timer = setTimeout(() =&gt; fn(...args), ms);\n  };\n}\n\nconst searchInput = document.querySelector(\"#search\");\nconst search = debounce((value) =&gt; {\n  console.log(\"searching:\", value);\n  // fetch(`/api/search?q=${value}`)\n}, 400);\n\nsearchInput.addEventListener(\"input\", e =&gt; search(e.target.value));</div>\n      <div class=\"explain\">\n        <strong>setTimeout(fn, ms)</strong> — once after N milliseconds. <strong>setInterval</strong> — every N ms.<br>\n        <strong>clearTimeout / clearInterval</strong> — cancel by saved id. Always call it when removing a component / leaving a page — otherwise memory leaks.<br>\n        <strong>0 ms</strong> — <code>setTimeout(fn, 0)</code> — NOT immediately. Delays until “after the current code”. Often used to wait for DOM rendering.<br>\n        <strong>Debounce</strong> — “wait for silence” pattern. The user types → the request is sent only after a 400ms pause. Protects the server from thousands of requests.<br>\n        <strong>Throttle</strong> — “no more than once per N ms”. Used for scroll and resize.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb199\" onchange=\"updateProgress(this)\"><span>setTimeout(fn, ms) — once after N ms</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb200\" onchange=\"updateProgress(this)\"><span>setInterval(fn, ms) — every N ms. clearInterval — stop</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb201\" onchange=\"updateProgress(this)\"><span>I save the id and call clear on unmount</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb202\" onchange=\"updateProgress(this)\"><span>Debounce — for input search (request after a pause)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb203\" onchange=\"updateProgress(this)\"><span>Throttle — for scroll and resize (once per N ms)</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-classes","title":"Classes — class, extends, this advanced 🔗","html":"<div class=\"block\" id=\"block-classes\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-classes')\">Classes — class, extends, this <span class=\"badge pro\">advanced</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Classes are “templates” for creating similar objects. Under the hood, they are regular functions and prototypes, but the syntax is more familiar.</div>\n      <div class=\"code\">class User {\n  // Constructor — called on new User(...)\n  constructor(name, age) {\n    this.name = name;\n    this.age  = age;\n  }\n\n  // Method\n  greet() {\n    return `Hello, I am ${this.name}!`;\n  }\n\n  // Getter — called WITHOUT parentheses\n  get isAdult() {\n    return this.age &gt;= 18;\n  }\n\n  // Setter\n  set newName(value) {\n    this.name = value.trim();\n  }\n\n  // Static method — on the class, not on the object\n  static fromString(str) {\n    const [name, age] = str.split(\",\");\n    return new User(name, Number(age));\n  }\n}\n\nconst u = new User(\"Alex\", 25);\nconsole.log(u.greet());      // \"Hello, I am Alex!\"\nconsole.log(u.isAdult);      // true (without parentheses!)\n\nconst u2 = User.fromString(\"John,30\");   // static\n\n// === Inheritance ===\nclass Admin extends User {\n  constructor(name, age, role) {\n    super(name, age);   // parent constructor call\n    this.role = role;\n  }\n\n  greet() {\n    return super.greet() + ` I am ${this.role}.`;   // override\n  }\n}\n\nconst a = new Admin(\"Mary\", 30, \"admin\");\nconsole.log(a.greet());   // \"Hello, I am Mary! I am admin.\"\n\n// Private fields (with #)\nclass Account {\n  #balance = 0;            // private! inaccessible from outside\n\n  deposit(sum) { this.#balance += sum; }\n  get balance() { return this.#balance; }\n}</div>\n      <div class=\"explain\">\n        <strong>constructor</strong> — special method, called once on <code>new ClassName()</code>. Initial fields are set here.<br>\n        <strong>this</strong> inside methods — the current object. <em>Arrow functions inside a class do not have their own this</em>, regular methods do.<br>\n        <strong>get / set</strong> — properties that are actually functions. Outside — <code>obj.isAdult</code> without parentheses.<br>\n        <strong>static</strong> — method called on the class, not on the object. Often these are “factories”: <code>User.fromString(...)</code>.<br>\n        <strong>extends + super</strong> — inheritance. <code>super(...)</code> in a constructor is required <em>before</em> using this.<br>\n        <strong>#field</strong> — private fields (new syntax). They cannot be accessed from outside.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb204\" onchange=\"updateProgress(this)\"><span>class + constructor + methods — basic form</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb205\" onchange=\"updateProgress(this)\"><span>this — reference to the current object</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb206\" onchange=\"updateProgress(this)\"><span>get / set — property-functions (without parentheses outside)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb207\" onchange=\"updateProgress(this)\"><span>static — method on the class itself (factories)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb208\" onchange=\"updateProgress(this)\"><span>extends + super(...) — inheritance</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-js-eventloop","title":"Event Loop — how async works interview classic 🔗","html":"<div class=\"block\" id=\"block-js-eventloop\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-js-eventloop')\">Event Loop — how async works <span class=\"badge must\">interview classic</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">The most common interview question: “Why does this code output in this exact order?” Without Event Loop, async JS is impossible to understand.</div>\n      <div class=\"code\"><span class=\"cm\">// JavaScript executes code in this order:</span>\n<span class=\"cm\">// 1. All SYNCHRONOUS code</span>\n<span class=\"cm\">// 2. All MICROTASKS (Promise.then, async/await)</span>\n<span class=\"cm\">// 3. One MACROTASK (setTimeout, setInterval)</span>\n<span class=\"cm\">// 4. Repeat steps 2-3</span>\n\nconsole.<span class=\"fn\">log</span>(<span class=\"str\">'1: synchronous'</span>);\n\n<span class=\"fn\">setTimeout</span>(() =&gt; console.<span class=\"fn\">log</span>(<span class=\"str\">'4: macrotask'</span>), <span class=\"num\">0</span>);\n\nPromise.<span class=\"fn\">resolve</span>().<span class=\"fn\">then</span>(() =&gt; console.<span class=\"fn\">log</span>(<span class=\"str\">'3: microtask'</span>));\n\nconsole.<span class=\"fn\">log</span>(<span class=\"str\">'2: synchronous'</span>);\n\n<span class=\"cm\">// Output: 1, 2, 3, 4</span>\n<span class=\"cm\">// Even though setTimeout(fn, 0) is a 0ms timer, it runs AFTER Promise!</span></div>\n      <div class=\"explain\">\n        <strong>Call Stack</strong> — executes synchronous code top down, one by one.<br>\n        <strong>Microtasks</strong> (Promise, async/await) — have higher priority than macrotasks. The microtask queue is fully emptied before each macrotask.<br>\n        <strong>Macrotasks</strong> (setTimeout, setInterval, events) — run one per Event Loop tick.<br>\n        <strong>Main takeaway:</strong> <code>setTimeout(fn, 0)</code> does not mean “immediately” — it means “after all current synchronous code and all microtasks finish”.\n      </div>\n      <div class=\"eventloop-lab\">\n        <div class=\"tool-row\">\n          <button class=\"try-btn\" style=\"margin:0;\" onclick=\"runEventLoopDemo()\">Run code</button>\n          <span style=\"font-size:12px;color:#6b7280;\">Watch where sync code, Promise, and setTimeout go.</span>\n        </div>\n        <div class=\"eventloop-board\">\n          <div class=\"event-col\"><h4>Call Stack</h4><div id=\"elStack\"></div></div>\n          <div class=\"event-col\"><h4>Microtasks</h4><div id=\"elMicro\"></div></div>\n          <div class=\"event-col\"><h4>Macrotasks</h4><div id=\"elMacro\"></div></div>\n        </div>\n        <div class=\"tool-result\" id=\"elLog\">Click “Run code”.</div>\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb209\" onchange=\"updateProgress(this)\"><span>Execution order: synchronous code → microtasks → macrotasks</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb210\" onchange=\"updateProgress(this)\"><span>Promise.then — microtask, runs before setTimeout</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb211\" onchange=\"updateProgress(this)\"><span>I can explain why setTimeout(fn, 0) does not run instantly</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-js-closures","title":"Closures interview classic 🔗","html":"<div class=\"block\" id=\"block-js-closures\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-js-closures')\">Closures <span class=\"badge must\">interview classic</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Interviewers’ favorite question #1. A closure is a function that “remembers” variables from the environment where it was created, even after that environment has finished.</div>\n      <div class=\"code\"><span class=\"cm\">// Simple example — counter</span>\n<span class=\"kw\">function</span> <span class=\"fn\">createCounter</span>() {\n  <span class=\"kw\">let</span> count = <span class=\"num\">0</span>; <span class=\"cm\">// this variable is captured by the closure</span>\n\n  <span class=\"kw\">return function</span>() {\n    count++; <span class=\"cm\">// inner function remembers count from the outer scope</span>\n    <span class=\"kw\">return</span> count;\n  };\n}\n\n<span class=\"kw\">const</span> counter = <span class=\"fn\">createCounter</span>();\ncounter(); <span class=\"cm\">// 1</span>\ncounter(); <span class=\"cm\">// 2</span>\ncounter(); <span class=\"cm\">// 3 — count is not reset between calls!</span>\n\n<span class=\"cm\">// Each createCounter call creates ITS OWN closure</span>\n<span class=\"kw\">const</span> counter2 = <span class=\"fn\">createCounter</span>();\ncounter2(); <span class=\"cm\">// 1 — counter2 has its own count</span>\n\n<span class=\"cm\">// Practical example — private variables</span>\n<span class=\"kw\">function</span> <span class=\"fn\">createBankAccount</span>(initialBalance) {\n  <span class=\"kw\">let</span> balance = initialBalance; <span class=\"cm\">// \"private\" variable</span>\n  <span class=\"kw\">return</span> {\n    deposit: amount =&gt; balance += amount,\n    getBalance: () =&gt; balance\n  };\n} <span class=\"cm\">// outside there is no direct access to balance — only through methods</span></div>\n      <div class=\"explain\">\n        <strong>A closure is created whenever</strong> a function is declared inside another function and uses its variables.<br>\n        <strong>Why need:</strong> creating private variables, counters, result caching (memoization), event handlers that remember context.<br>\n        <strong>Common interview trap:</strong> closures in loops with <code>var</code> — all functions see the final variable value, not the value from creation time. With <code>let</code>, this problem is gone.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb212\" onchange=\"updateProgress(this)\"><span>I understand that a function “remembers” variables from the outer environment</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb213\" onchange=\"updateProgress(this)\"><span>I wrote my own counter through a closure</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb214\" onchange=\"updateProgress(this)\"><span>I know the var-in-loops closure trap and why let solves it</span></label>\n      </div>\n    </div>\n\n\n    "},{"id":"block-js-architecture","title":"JS code architecture before React important 🔗","html":"<div class=\"block\" id=\"block-js-architecture\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-js-architecture')\">JS code architecture before React <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Before components, it is important to learn how to split normal JavaScript into modules: data separately, business logic separately, rendering separately.</div>\n      <div class=\"code\"><span class=\"cm\">// api/users.js — data layer</span>\n<span class=\"kw\">export async function</span> <span class=\"fn\">loadUsers</span>() {\n  <span class=\"kw\">const</span> res = <span class=\"kw\">await</span> <span class=\"fn\">fetch</span>(<span class=\"str\">'/api/users'</span>);\n  <span class=\"kw\">return</span> res.<span class=\"fn\">json</span>();\n}\n\n<span class=\"cm\">// domain/users.js — business logic</span>\n<span class=\"kw\">export function</span> <span class=\"fn\">getActiveUsers</span>(users) {\n  <span class=\"kw\">return</span> users.<span class=\"fn\">filter</span>(user =&gt; user.active);\n}\n\n<span class=\"cm\">// ui/renderUsers.js — rendering</span>\n<span class=\"kw\">export function</span> <span class=\"fn\">renderUsers</span>(users, root) {\n  root.innerHTML = users.<span class=\"fn\">map</span>(u =&gt; <span class=\"str\">`&lt;li&gt;${u.name}&lt;/li&gt;`</span>).<span class=\"fn\">join</span>(<span class=\"str\">''</span>);\n}</div>\n      <div class=\"explain\">\n        <strong>import/export</strong> — basic core value: a file exposes only what other parts of the app need.<br>\n        <strong>Layers</strong> help avoid mixing fetch, calculations, and DOM rendering in one function. Such code is easier to test and move into React.<br>\n        <strong>Main habit:</strong> if a function simultaneously calls an API, calculates data, and changes HTML, it is time to split it.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb214a\" onchange=\"updateProgress(this)\"><span>I split JS into modules through import/export</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb214b\" onchange=\"updateProgress(this)\"><span>I separate data, business logic, and rendering</span></label>\n      </div>\n    </div>\n"}]},{"id":"sec-ts","lessons":[{"id":"block-ts-strict-2026","title":"Strict typing for real data 2026 CORE #","html":"<div class=\"block wdg-2026-block\" id=\"block-ts-strict-2026\"><div class=\"block-title\" onclick=\"scrollToBlock('block-ts-strict-2026')\">Strict typing for real data <span class=\"badge must\">2026 CORE</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">Type arguments, API results, props, and state. Unverified external data starts as unknown, never any.</div><div class=\"code\">type Role = \"student\" | \"mentor\";\n\ninterface User {\n  id: number;\n  name: string;\n  role: Role;\n  skills: string[];\n}\n\nfunction getLabel(user: User): string {\n  return user.name + \" - \" + user.role;\n}\n\nfunction isUser(value: unknown): value is User {\n  if (typeof value !== \"object\" || value === null) return false;\n  return \"id\" in value &amp;&amp; \"name\" in value &amp;&amp; \"role\" in value;\n}</div><div class=\"explain\"><code>interface</code> fits object contracts; <code>type</code> fits unions and composed types. <code>unknown</code> requires a check before access. <code>any</code> disables TypeScript exactly where data is untrusted.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-ts-strict-2026-1\" onchange=\"updateProgress(this)\"><span>I type parameters and return values</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-ts-strict-2026-2\" onchange=\"updateProgress(this)\"><span>I use unknown instead of any</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-ts-strict-2026-3\" onchange=\"updateProgress(this)\"><span>I describe object arrays</span></label></div></div>"},{"id":"block-ts-basics","title":"TypeScript Basics — variable types basics 🔗","html":"<div class=\"block\" id=\"block-ts-basics\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-ts-basics')\">TypeScript Basics — variable types <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">TypeScript adds a type system to JavaScript. After a colon, we write the type: <code>let name: string = \"John\"</code>.</div>\n      <div class=\"code\"><span class=\"cm\">// Basic types</span>\n<span class=\"kw\">let</span> name: <span class=\"str\">string</span> = <span class=\"str\">\"John\"</span>;\n<span class=\"kw\">let</span> age: <span class=\"num\">number</span> = 25;\n<span class=\"kw\">let</span> isActive: <span class=\"str\">boolean</span> = <span class=\"kw\">true</span>;\n<span class=\"kw\">let</span> tags: <span class=\"str\">string</span>[] = [<span class=\"str\">\"HTML\"</span>, <span class=\"str\">\"CSS\"</span>];\n\n<span class=\"cm\">// Union type — several allowed types</span>\n<span class=\"kw\">let</span> id: <span class=\"str\">string</span> | <span class=\"str\">number</span> = 42;\nid = <span class=\"str\">\"abc\"</span>; <span class=\"cm\">// also ok!</span>\n\n<span class=\"cm\">// Function with parameter and return types</span>\n<span class=\"kw\">function</span> <span class=\"fn\">greet</span>(name: <span class=\"str\">string</span>): <span class=\"str\">string</span> {\n  <span class=\"kw\">return</span> <span class=\"str\">`Hello, ${name}!`</span>;\n}\n\n<span class=\"cm\">// any — disables type checking (avoid it!)</span>\n<span class=\"kw\">let</span> data: <span class=\"str\">any</span> = <span class=\"str\">\"anything\"</span>;</div>\n      <div class=\"explain\">\n        <strong>Why types?</strong> TS reports errors while writing code, before launching in the browser.<br>\n        <strong>string[]</strong> — array of strings. You can also write <code>Array&lt;string&gt;</code>.<br>\n        <strong>Union (|)</strong> — a variable can be one of several types.<br>\n        <strong>Avoid any!</strong> It disables all the benefits of TypeScript.\n      </div>\n      <!-- MINI TEST -->\n      <div class=\"quiz-block\" id=\"quiz-ts-basics\">\n        <div class=\"quiz-title\">🧪 Mini-test — knowledge check</div>\n        <div class=\"quiz-question\">1. How do you correctly specify the type of an array of strings in TypeScript?</div>\n        <div class=\"quiz-options\">\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-ts-basics-1\" value=\"a\"> <span>Array[string]</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-ts-basics-1\" value=\"b\"> <span>string[]</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-ts-basics-1\" value=\"c\"> <span>strings</span></label>\n        </div>\n        <div class=\"quiz-question\">2. What is a Union type?</div>\n        <div class=\"quiz-options\">\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-ts-basics-2\" value=\"a\"> <span>A type that disables checking</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-ts-basics-2\" value=\"b\"> <span>A variable that can be one of several types</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-ts-basics-2\" value=\"c\"> <span>A special type for functions</span></label>\n        </div>\n        <!-- PRACTICE -->\n        <div class=\"practice-block\">\n          <div class=\"practice-title\">⌨️ Practice</div>\n          <div class=\"practice-task\">Write an <code>add(a, b)</code> function with <code>number</code> parameter types and a <code>number</code> return type.</div>\n          <textarea class=\"practice-input\" id=\"practice-ts-basics\" placeholder=\"function add(a: number, b: number): number { ... }\"></textarea>\n        </div>\n        <button class=\"quiz-check-btn\" onclick=\"checkQuiz('ts-basics')\">✓ Check</button>\n        <div class=\"quiz-result\" id=\"result-ts-basics\"></div>\n      </div>\n      <div class=\"items\" id=\"items-ts-basics\">\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb612\" onchange=\"updateProgress(this)\" disabled><span>🔒 Basic types: string, number, boolean, string[]</span></label>\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb613\" onchange=\"updateProgress(this)\" disabled><span>🔒 Union type: string | number — several allowed types</span></label>\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb614\" onchange=\"updateProgress(this)\" disabled><span>🔒 Typed functions: (name: string): string</span></label>\n      </div>\n      <div class=\"locked-items-notice\">🔒 Complete the test and practice to unlock the checkboxes</div>\n    </div>\n\n    "},{"id":"block-ts-interfaces","title":"Interfaces and type alias important 🔗","html":"<div class=\"block\" id=\"block-ts-interfaces\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-ts-interfaces')\">Interfaces and type alias <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// Interface — describes object shape</span>\n<span class=\"kw\">interface</span> <span class=\"fn\">User</span> {\n  name: <span class=\"str\">string</span>;\n  age: <span class=\"num\">number</span>;\n  email?: <span class=\"str\">string</span>; <span class=\"cm\">// ? — optional field</span>\n}\n\n<span class=\"kw\">const</span> user: <span class=\"fn\">User</span> = { name: <span class=\"str\">\"John\"</span>, age: 25 };\n\n<span class=\"cm\">// Type alias — similar to interface, but more flexible</span>\n<span class=\"kw\">type</span> Status = <span class=\"str\">\"active\"</span> | <span class=\"str\">\"inactive\"</span> | <span class=\"str\">\"banned\"</span>;\n<span class=\"kw\">let</span> currentStatus: Status = <span class=\"str\">\"active\"</span>;\n\n<span class=\"cm\">// Interface extension</span>\n<span class=\"kw\">interface</span> <span class=\"fn\">Admin</span> <span class=\"kw\">extends</span> <span class=\"fn\">User</span> {\n  role: <span class=\"str\">string</span>;\n  permissions: <span class=\"str\">string</span>[];\n}</div>\n      <div class=\"explain\">\n        <strong>interface</strong> — contract for an object. Fields with <code>?</code> are optional.<br>\n        <strong>type</strong> — more flexible. Better for unions, primitives, and function types.<br>\n        <strong>extends</strong> — inherits fields from the parent interface.\n      </div>\n      <div class=\"quiz-block\" id=\"quiz-ts-interfaces\">\n        <div class=\"quiz-title\">🧪 Mini-test</div>\n        <div class=\"quiz-question\">1. What does <code>?</code> after a field name in an interface mean?</div>\n        <div class=\"quiz-options\">\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-ts-if-1\" value=\"a\"> <span>Required field</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-ts-if-1\" value=\"b\"> <span>Optional field</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-ts-if-1\" value=\"c\"> <span>Type is boolean</span></label>\n        </div>\n        <div class=\"quiz-question\">2. Which syntax is used to extend an interface?</div>\n        <div class=\"quiz-options\">\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-ts-if-2\" value=\"a\"> <span>interface Admin implements User</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-ts-if-2\" value=\"b\"> <span>interface Admin extends User</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-ts-if-2\" value=\"c\"> <span>interface Admin &lt;- User</span></label>\n        </div>\n        <div class=\"practice-block\">\n          <div class=\"practice-title\">⌨️ Practice</div>\n          <div class=\"practice-task\">Write a <code>Product</code> interface with fields: <code>id</code> (number), <code>name</code> (string), <code>price</code> (number), and optional <code>discount</code> (number).</div>\n          <textarea class=\"practice-input\" id=\"practice-ts-interfaces\" placeholder=\"interface Product { ... }\"></textarea>\n        </div>\n        <button class=\"quiz-check-btn\" onclick=\"checkQuiz('ts-interfaces')\">✓ Check</button>\n        <div class=\"quiz-result\" id=\"result-ts-interfaces\"></div>\n      </div>\n      <div class=\"items\" id=\"items-ts-interfaces\">\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb615\" onchange=\"updateProgress(this)\" disabled><span>🔒 interface — describes object shape</span></label>\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb616\" onchange=\"updateProgress(this)\" disabled><span>🔒 ? — optional field</span></label>\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb617\" onchange=\"updateProgress(this)\" disabled><span>🔒 extends — interface inheritance</span></label>\n      </div>\n      <div class=\"locked-items-notice\">🔒 Complete the test and practice to unlock the checkboxes</div>\n    </div>\n\n    "},{"id":"block-ts-generics","title":"Generics (Generics) important 🔗","html":"<div class=\"block\" id=\"block-ts-generics\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-ts-generics')\">Generics (Generics) <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Generics are “variables for types”. You write a function once, and it works with any type without losing typing.</div>\n      <div class=\"code\"><span class=\"cm\">// Without a generic — you need to write it for each type</span>\n<span class=\"kw\">function</span> <span class=\"fn\">firstNumber</span>(arr: <span class=\"str\">number</span>[]): <span class=\"str\">number</span> { <span class=\"kw\">return</span> arr[<span class=\"num\">0</span>]; }\n<span class=\"kw\">function</span> <span class=\"fn\">firstString</span>(arr: <span class=\"str\">string</span>[]): <span class=\"str\">string</span> { <span class=\"kw\">return</span> arr[<span class=\"num\">0</span>]; }\n\n<span class=\"cm\">// With a generic — one function for everything</span>\n<span class=\"kw\">function</span> <span class=\"fn\">first</span>&lt;T&gt;(arr: T[]): T {\n  <span class=\"kw\">return</span> arr[<span class=\"num\">0</span>];\n}\n<span class=\"fn\">first</span>([<span class=\"num\">1</span>, <span class=\"num\">2</span>, <span class=\"num\">3</span>]);       <span class=\"cm\">// T = number</span>\n<span class=\"fn\">first</span>([<span class=\"str\">\"a\"</span>, <span class=\"str\">\"b\"</span>]);     <span class=\"cm\">// T = string</span>\n\n<span class=\"cm\">// Generics in interfaces</span>\n<span class=\"kw\">interface</span> <span class=\"fn\">ApiResponse</span>&lt;T&gt; {\n  data: T;\n  status: <span class=\"str\">number</span>;\n  message: <span class=\"str\">string</span>;\n}\n<span class=\"kw\">const</span> res: <span class=\"fn\">ApiResponse</span>&lt;<span class=\"fn\">User</span>&gt; = { data: user, status: <span class=\"num\">200</span>, message: <span class=\"str\">\"OK\"</span> };</div>\n      <div class=\"explain\">\n        <strong>&lt;T&gt;</strong> — “type variable”. Name it T, U, K, V — any name.<br>\n        <strong>T[]</strong> — array of elements of type T. When called, T is inferred automatically.<br>\n        <strong>ApiResponse&lt;User&gt;</strong> — concretization: data will be of type User.\n      </div>\n      <div class=\"quiz-block\" id=\"quiz-ts-generics\">\n        <div class=\"quiz-title\">🧪 Mini-test</div>\n        <div class=\"quiz-question\">1. What are generics used for?</div>\n        <div class=\"quiz-options\">\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-tsg-1\" value=\"a\"> <span>To disable type checking</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-tsg-1\" value=\"b\"> <span>To write universal code that works with any type</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-tsg-1\" value=\"c\"> <span>Only for working with arrays</span></label>\n        </div>\n        <div class=\"quiz-question\">2. What is &lt;T&gt; in function first&lt;T&gt;(arr: T[])?</div>\n        <div class=\"quiz-options\">\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-tsg-2\" value=\"a\"> <span>HTML-tag</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-tsg-2\" value=\"b\"> <span>Type variable — TS will substitute the concrete type on call</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-tsg-2\" value=\"c\"> <span>Conditional type</span></label>\n        </div>\n        <div class=\"practice-block\">\n          <div class=\"practice-title\">⌨️ Practice</div>\n          <div class=\"practice-task\">Write a generic <code>identity&lt;T&gt;</code> function that takes an argument of type T and returns the same value.</div>\n          <textarea class=\"practice-input\" id=\"practice-ts-generics\" placeholder=\"function identity&lt;T&gt;(arg: T): T { ... }\"></textarea>\n        </div>\n        <button class=\"quiz-check-btn\" onclick=\"checkQuiz('ts-generics')\">✓ Check</button>\n        <div class=\"quiz-result\" id=\"result-ts-generics\"></div>\n      </div>\n      <div class=\"items\" id=\"items-ts-generics\">\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb618\" onchange=\"updateProgress(this)\" disabled><span>🔒 &lt;T&gt; — type variable, inferred automatically</span></label>\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb619\" onchange=\"updateProgress(this)\" disabled><span>🔒 Generics in functions: function fn&lt;T&gt;(arg: T): T</span></label>\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb620\" onchange=\"updateProgress(this)\" disabled><span>🔒 Generics in interfaces: interface Resp&lt;T&gt; { data: T }</span></label>\n      </div>\n      <div class=\"locked-items-notice\">🔒 Complete the test and practice to unlock the checkboxes</div>\n    </div>\n\n    "},{"id":"block-ts-generics-react-2026","title":"Generics and React types 2026 CORE #","html":"<div class=\"block wdg-2026-block\" id=\"block-ts-generics-react-2026\"><div class=\"block-title\" onclick=\"scrollToBlock('block-ts-generics-react-2026')\">Generics and React types <span class=\"badge must\">2026 CORE</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">A generic preserves the relationship between input and output types. Use it when an operation is reusable but its result must stay precise.</div><div class=\"code\">type ApiResult&lt;T&gt; = { data: T; error: string | null };\n\nfunction firstItem&lt;T&gt;(items: T[]): T | undefined {\n  return items[0];\n}\n\ntype ProjectCardProps = {\n  title: string;\n  completed: boolean;\n  onToggle: (completed: boolean) =&gt; void;\n};\n\nfunction ProjectCard({ title, completed, onToggle }: ProjectCardProps) {\n  return &lt;button onClick={() =&gt; onToggle(!completed)}&gt;{title}&lt;/button&gt;;\n}</div><div class=\"explain\"><code>T</code> is filled by the caller, so <code>ApiResult&lt;User[]&gt;</code> keeps data as User[]. Props precisely describe the component. Start with the Vite/Next.js preset and <code>strict: true</code>; do not memorize dozens of flags without a need.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-ts-generics-react-2026-1\" onchange=\"updateProgress(this)\"><span>I understand generic input/output relationships</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-ts-generics-react-2026-2\" onchange=\"updateProgress(this)\"><span>I type React props without any</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-ts-generics-react-2026-3\" onchange=\"updateProgress(this)\"><span>I use a strict preset</span></label></div></div>"},{"id":"block-ts-react","title":"TypeScript + React — component typing often in practice 🔗","html":"<div class=\"block\" id=\"block-ts-react\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-ts-react')\">TypeScript + React — component typing <span class=\"badge must\">often in practice</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Commercial React code is almost always in TypeScript. Main beginner question: how to type props with functions and children?</div>\n      <div class=\"code\"><span class=\"cm\">// Typing props through an interface</span>\n<span class=\"kw\">interface</span> ButtonProps {\n  label: <span class=\"str\">string</span>;\n  onClick: (e: React.MouseEvent&lt;HTMLButtonElement&gt;) =&gt; <span class=\"kw\">void</span>; <span class=\"cm\">// handler gets a button event</span>\n  children?: React.ReactNode;     <span class=\"cm\">// anything: text, JSX, array</span>\n  style?: React.CSSProperties;    <span class=\"cm\">// inline styles as an object</span>\n}\n\n<span class=\"kw\">const</span> Button: React.FC&lt;ButtonProps&gt; = ({ label, onClick, children, style }) =&gt; {\n  <span class=\"kw\">return</span> (\n    &lt;<span class=\"tag\">button</span> <span class=\"attr\">onClick</span>={onClick} <span class=\"attr\">style</span>={style}&gt;\n      {label} {children}\n    &lt;/<span class=\"tag\">button</span>&gt;\n  );\n};\n\n<span class=\"cm\">// Event typing</span>\n<span class=\"kw\">function</span> <span class=\"fn\">handleClick</span>(e: React.MouseEvent&lt;HTMLButtonElement&gt;) {\n  console.<span class=\"fn\">log</span>(e.currentTarget);\n}\n\n<span class=\"kw\">function</span> <span class=\"fn\">handleSubmit</span>(e: React.FormEvent&lt;HTMLFormElement&gt;) {\n  e.<span class=\"fn\">preventDefault</span>();\n}\n\n<span class=\"cm\">// useRef for DOM-elements</span>\n<span class=\"kw\">const</span> inputRef = <span class=\"fn\">useRef</span>&lt;HTMLInputElement&gt;(<span class=\"kw\">null</span>);\n<span class=\"cm\">// now inputRef.current is typed as HTMLInputElement | null</span>\n<span class=\"cm\">// TS does not complain about .current.focus() after a null check</span></div>\n      <div class=\"explain\">\n        <strong>React.FC&lt;Props&gt;</strong> — type for functional components (although many now type props directly without FC).<br>\n        <strong>React.ReactNode</strong> — widest type for children: string, number, JSX, array, null.<br>\n        <strong>React.MouseEvent&lt;HTMLButtonElement&gt;</strong> — typed event, knows exactly that currentTarget is a button.<br>\n        <strong>useRef&lt;HTMLInputElement&gt;(null)</strong> — standard pattern for refs to DOM elements.<br>\n        <strong>React 19:</strong> ref can be passed to a component as a normal prop; <code>forwardRef</code> still appears in old code, but for new components it is often no longer needed.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb232\" onchange=\"updateProgress(this)\"><span>Typing props with functions and children (React.ReactNode)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb233\" onchange=\"updateProgress(this)\"><span>React.MouseEvent, React.FormEvent — event typing</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb234\" onchange=\"updateProgress(this)\"><span>useRef&lt;HTMLInputElement&gt;(null) — typing refs to DOM</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-ts-utility","title":"Utility Types important 🔗","html":"<div class=\"block\" id=\"block-ts-utility\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-ts-utility')\">Utility Types <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Utility Types are built-in TS helpers for type transformations. Used in every real project.</div>\n      <div class=\"code\"><span class=\"kw\">interface</span> <span class=\"fn\">User</span> { id: <span class=\"str\">number</span>; name: <span class=\"str\">string</span>; email: <span class=\"str\">string</span>; age: <span class=\"str\">number</span>; }\n\n<span class=\"cm\">// Partial — all fields optional</span>\n<span class=\"kw\">type</span> UserDraft = Partial&lt;<span class=\"fn\">User</span>&gt;;\n<span class=\"cm\">// { id?: number; name?: string; email?: string; age?: number }</span>\n\n<span class=\"cm\">// Required — all field required</span>\n<span class=\"kw\">type</span> StrictUser = Required&lt;<span class=\"fn\">User</span>&gt;;\n\n<span class=\"cm\">// Pick — take only needed fields</span>\n<span class=\"kw\">type</span> UserPreview = Pick&lt;<span class=\"fn\">User</span>, <span class=\"str\">\"id\"</span> | <span class=\"str\">\"name\"</span>&gt;;\n\n<span class=\"cm\">// Omit — exclude fields</span>\n<span class=\"kw\">type</span> UserWithoutID = Omit&lt;<span class=\"fn\">User</span>, <span class=\"str\">\"id\"</span>&gt;;\n\n<span class=\"cm\">// Readonly — forbid changes</span>\n<span class=\"kw\">type</span> FrozenUser = Readonly&lt;<span class=\"fn\">User</span>&gt;;</div>\n      <div class=\"explain\">\n        <strong>Partial&lt;T&gt;</strong> — all fields with ?. Convenient for edit forms.<br>\n        <strong>Pick&lt;T, K&gt;</strong> — selects only the listed fields.<br>\n        <strong>Omit&lt;T, K&gt;</strong> — removes the listed fields.<br>\n        <strong>Readonly&lt;T&gt;</strong> — object cannot be changed after creation.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb215\" onchange=\"updateProgress(this)\"><span>Partial&lt;T&gt; — all fields optional</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb216\" onchange=\"updateProgress(this)\"><span>Pick&lt;T, K&gt; and Omit&lt;T, K&gt; — select/exclude fields</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb217\" onchange=\"updateProgress(this)\"><span>Readonly&lt;T&gt; — forbid object changes</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-ts-enums","title":"Enum and literal types know 🔗","html":"<div class=\"block\" id=\"block-ts-enums\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-ts-enums')\">Enum and literal types <span class=\"badge\">know</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// Enum — named constants</span>\n<span class=\"kw\">enum</span> <span class=\"fn\">Direction</span> { Up = <span class=\"str\">\"UP\"</span>, Down = <span class=\"str\">\"DOWN\"</span>, Left = <span class=\"str\">\"LEFT\"</span>, Right = <span class=\"str\">\"RIGHT\"</span> }\n<span class=\"kw\">const</span> move = <span class=\"fn\">Direction</span>.Up; <span class=\"cm\">// \"UP\"</span>\n\n<span class=\"cm\">// Literal types (preferred over enum in modern TS)</span>\n<span class=\"kw\">type</span> Theme = <span class=\"str\">\"light\"</span> | <span class=\"str\">\"dark\"</span> | <span class=\"str\">\"auto\"</span>;\n<span class=\"kw\">function</span> <span class=\"fn\">setTheme</span>(theme: Theme) { <span class=\"cm\">/* ... */</span> }\n<span class=\"fn\">setTheme</span>(<span class=\"str\">\"light\"</span>);  <span class=\"cm\">// ✓</span>\n<span class=\"fn\">setTheme</span>(<span class=\"str\">\"blue\"</span>);  <span class=\"cm\">// ✗ TS error!</span>\n\n<span class=\"cm\">// const assertion — object as literal</span>\n<span class=\"kw\">const</span> config = { env: <span class=\"str\">\"prod\"</span>, port: <span class=\"num\">3000</span> } <span class=\"kw\">as const</span>;</div>\n      <div class=\"explain\">\n        <strong>enum</strong> — groups related constants. But in modern TS, union literals are used more often.<br>\n        <strong>Literal type</strong> — a concrete value as a type. TS checks that exactly this value was passed.<br>\n        <strong>as const</strong> — makes all values readonly literals.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb218\" onchange=\"updateProgress(this)\"><span>enum — named constants as a group</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb219\" onchange=\"updateProgress(this)\"><span>Literal types: \"light\" | \"dark\" | \"auto\"</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb220\" onchange=\"updateProgress(this)\"><span>as const — turns values into readonly literals</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-ts-narrowing","title":"Type Narrowing and Type Guards important 🔗","html":"<div class=\"block\" id=\"block-ts-narrowing\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-ts-narrowing')\">Type Narrowing and Type Guards <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// typeof narrowing</span>\n<span class=\"kw\">function</span> <span class=\"fn\">printID</span>(id: <span class=\"str\">string</span> | <span class=\"str\">number</span>) {\n  <span class=\"kw\">if</span> (<span class=\"kw\">typeof</span> id === <span class=\"str\">\"string\"</span>) {\n    console.log(id.<span class=\"fn\">toUpperCase</span>()); <span class=\"cm\">// TS knows: id is a string</span>\n  } <span class=\"kw\">else</span> {\n    console.log(id.<span class=\"fn\">toFixed</span>(2));   <span class=\"cm\">// TS knows: id is a number</span>\n  }\n}\n\n<span class=\"cm\">// instanceof narrowing</span>\n<span class=\"kw\">function</span> <span class=\"fn\">logError</span>(err: unknown) {\n  <span class=\"kw\">if</span> (err <span class=\"kw\">instanceof</span> Error) {\n    console.log(err.message); <span class=\"cm\">// now we know this is Error</span>\n  }\n}\n\n<span class=\"cm\">// Custom type guard</span>\n<span class=\"kw\">function</span> <span class=\"fn\">isUser</span>(obj: <span class=\"str\">any</span>): obj <span class=\"kw\">is</span> <span class=\"fn\">User</span> {\n  <span class=\"kw\">return</span> obj &amp;&amp; <span class=\"kw\">typeof</span> obj.name === <span class=\"str\">\"string\"</span>;\n}</div>\n      <div class=\"explain\">\n        <strong>Narrowing</strong> — TS “narrows” the type after a check. Inside if(typeof x === \"string\"), x is definitely a string.<br>\n        <strong>instanceof</strong> — narrowing for classes and objects.<br>\n        <strong>is</strong> — custom type guard, you tell TS yourself what type it is.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb221\" onchange=\"updateProgress(this)\"><span>typeof narrowing — narrowing through a typeof check</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb222\" onchange=\"updateProgress(this)\"><span>instanceof narrowing — for classes and objects</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb223\" onchange=\"updateProgress(this)\"><span>Custom type guard: function isX(v): v is Type</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-ts-async","title":"Async/await with types and working with API important 🔗","html":"<div class=\"block\" id=\"block-ts-async\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-ts-async')\">Async/await with types and working with API <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// Promise with return type</span>\n<span class=\"kw\">async function</span> <span class=\"fn\">fetchUser</span>(id: <span class=\"str\">number</span>): Promise&lt;<span class=\"fn\">User</span>&gt; {\n  <span class=\"kw\">const</span> res = <span class=\"kw\">await</span> <span class=\"fn\">fetch</span>(<span class=\"str\">`/api/users/${id}`</span>);\n  <span class=\"kw\">if</span> (!res.ok) <span class=\"kw\">throw new</span> Error(<span class=\"str\">\"Not found\"</span>);\n  <span class=\"kw\">const</span> data: <span class=\"fn\">User</span> = <span class=\"kw\">await</span> res.<span class=\"fn\">json</span>();\n  <span class=\"kw\">return</span> data;\n}\n\n<span class=\"cm\">// Error handling with unknown</span>\n<span class=\"kw\">try</span> {\n  <span class=\"kw\">const</span> user = <span class=\"kw\">await</span> <span class=\"fn\">fetchUser</span>(<span class=\"num\">1</span>);\n  console.log(user.name);\n} <span class=\"kw\">catch</span> (err: unknown) {\n  <span class=\"kw\">if</span> (err <span class=\"kw\">instanceof</span> Error) console.error(err.message);\n}\n\n<span class=\"cm\">// Typed fetch helper</span>\n<span class=\"kw\">async function</span> <span class=\"fn\">api</span>&lt;T&gt;(url: <span class=\"str\">string</span>): Promise&lt;T&gt; {\n  <span class=\"kw\">return</span> (<span class=\"kw\">await</span> <span class=\"fn\">fetch</span>(url)).<span class=\"fn\">json</span>();\n}</div>\n      <div class=\"explain\">\n        <strong>Promise&lt;User&gt;</strong> — tells TS that the async function returns User.<br>\n        <strong>catch (err: unknown)</strong> — correct type for caught errors. Never any!<br>\n        <strong>api&lt;T&gt;</strong> — generic fetch: <code>api&lt;User&gt;('/api/me')</code> returns a typed User.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb224\" onchange=\"updateProgress(this)\"><span>Promise&lt;T&gt; — return type of async functions</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb225\" onchange=\"updateProgress(this)\"><span>catch (err: unknown) — not any for errors</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb226\" onchange=\"updateProgress(this)\"><span>Typed fetch helper with a generic</span></label>\n      </div>\n    </div>\n  \n    "},{"id":"block-ts-discriminated","title":"Discriminated Unions and advanced types important 🔗","html":"<div class=\"block\" id=\"block-ts-discriminated\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-ts-discriminated')\">Discriminated Unions and advanced types <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// Discriminated Union — union with a shared discriminator field</span>\n<span class=\"kw\">type</span> Action =\n  | { type: <span class=\"str\">'INCREMENT'</span>; amount: <span class=\"str\">number</span> }\n  | { type: <span class=\"str\">'SET_NAME'</span>; name: <span class=\"str\">string</span> }\n  | { type: <span class=\"str\">'RESET'</span> };\n\n<span class=\"kw\">function</span> <span class=\"fn\">reducer</span>(action: Action) {\n  <span class=\"kw\">switch</span> (action.type) {\n    <span class=\"kw\">case</span> <span class=\"str\">'INCREMENT'</span>: <span class=\"kw\">return</span> action.amount; <span class=\"cm\">// TS knows: amount exists</span>\n    <span class=\"kw\">case</span> <span class=\"str\">'SET_NAME'</span>:  <span class=\"kw\">return</span> action.name;   <span class=\"cm\">// TS knows: name exists</span>\n    <span class=\"kw\">case</span> <span class=\"str\">'RESET'</span>:     <span class=\"kw\">return</span> <span class=\"num\">0</span>;\n  }\n}\n\n<span class=\"cm\">// keyof and typeof — working with object types</span>\n<span class=\"kw\">const</span> config = { host: <span class=\"str\">'localhost'</span>, port: <span class=\"num\">3000</span> };\n<span class=\"kw\">type</span> ConfigKey = <span class=\"kw\">keyof typeof</span> config; <span class=\"cm\">// 'host' | 'port'</span>\n\n<span class=\"cm\">// ReturnType — function return type</span>\n<span class=\"kw\">function</span> <span class=\"fn\">getUser</span>() { <span class=\"kw\">return</span> { id: <span class=\"num\">1</span>, name: <span class=\"str\">'Ivan'</span> }; }\n<span class=\"kw\">type</span> User = <span class=\"kw\">ReturnType</span>&lt;<span class=\"kw\">typeof</span> <span class=\"fn\">getUser</span>&gt;; <span class=\"cm\">// { id: number, name: string }</span></div>\n      <div class=\"explain\">\n        <strong>Discriminated Union</strong> — TS automatically narrows the type inside switch/if by the discriminator field.<br>\n        <strong>keyof typeof obj</strong> — often used for safe access to object keys.<br>\n        <strong>ReturnType</strong> — do not duplicate the type manually; infer it from the function.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb229\" onchange=\"updateProgress(this)\"><span>Discriminated Union — union with a discriminator field</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb230\" onchange=\"updateProgress(this)\"><span>keyof, typeof — working with existing object types</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb231\" onchange=\"updateProgress(this)\"><span>ReturnType, Parameters — utility types for functions</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-ts-void-never","title":"void, never, unknown — differences interview classic 🔗","html":"<div class=\"block\" id=\"block-ts-void-never\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-ts-void-never')\">void, never, unknown — differences <span class=\"badge good\">interview classic</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// void — function returns nothing</span>\n<span class=\"kw\">function</span> <span class=\"fn\">logMessage</span>(msg: <span class=\"str\">string</span>): <span class=\"kw\">void</span> {\n  console.<span class=\"fn\">log</span>(msg);\n  <span class=\"cm\">// no return — or return; without value</span>\n}\n\n<span class=\"cm\">// never — function never finishes normally</span>\n<span class=\"kw\">function</span> <span class=\"fn\">throwError</span>(msg: <span class=\"str\">string</span>): <span class=\"kw\">never</span> {\n  <span class=\"kw\">throw new</span> <span class=\"fn\">Error</span>(msg); <span class=\"cm\">// always throws an error</span>\n}\n\n<span class=\"cm\">// never — for exhaustive switch checks</span>\n<span class=\"kw\">type</span> Shape = { kind: <span class=\"str\">'circle'</span> } | { kind: <span class=\"str\">'square'</span> };\n\n<span class=\"kw\">function</span> <span class=\"fn\">area</span>(s: Shape) {\n  <span class=\"kw\">switch</span> (s.kind) {\n    <span class=\"kw\">case</span> <span class=\"str\">'circle'</span>: <span class=\"kw\">return</span> <span class=\"num\">1</span>;\n    <span class=\"kw\">case</span> <span class=\"str\">'square'</span>: <span class=\"kw\">return</span> <span class=\"num\">2</span>;\n    <span class=\"kw\">default</span>:\n      <span class=\"kw\">const</span> _exhaustive: <span class=\"kw\">never</span> = s; <span class=\"cm\">// TS error if a case is forgotten!</span>\n      <span class=\"kw\">return</span> _exhaustive;\n  }\n}\n\n<span class=\"cm\">// unknown vs any — both mean \"any type\", but unknown is safer</span>\n<span class=\"kw\">let</span> a: <span class=\"kw\">any</span> = <span class=\"num\">5</span>;\na.<span class=\"fn\">toUpperCase</span>(); <span class=\"cm\">// ❌ compiles, crashes at runtime</span>\n\n<span class=\"kw\">let</span> u: unknown = <span class=\"num\">5</span>;\nu.<span class=\"fn\">toUpperCase</span>(); <span class=\"cm\">// ✅ TS requires a type check first</span>\n<span class=\"kw\">if</span> (<span class=\"kw\">typeof</span> u === <span class=\"str\">'string'</span>) u.<span class=\"fn\">toUpperCase</span>(); <span class=\"cm\">// ✅ now can</span></div>\n      <div class=\"explain\">\n        <strong>void</strong> — function returns no value (or the returned value is ignored).<br>\n        <strong>never</strong> — function never finishes normally (throws an error, infinite loop) or code branch is unreachable.<br>\n        <strong>unknown vs any</strong> — <code>any</code> fully disables type checks, <code>unknown</code> forces you to check the type before use. Use unknown instead of any.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb235\" onchange=\"updateProgress(this)\"><span>void — function returns nothing</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb236\" onchange=\"updateProgress(this)\"><span>never — unreachable code or a function that always throws an error</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb237\" onchange=\"updateProgress(this)\"><span>unknown is safer than any — requires a type check before use</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-ts-conditional-mapped","title":"Conditional Types and Mapped Types level middle 🔗","html":"<div class=\"block\" id=\"block-ts-conditional-mapped\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-ts-conditional-mapped')\">Conditional Types and Mapped Types <span class=\"badge good\">level middle</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Without these topics, it is hard to read the source code of large libraries (React, Redux, Zod), but for your own code you do not need them that often — study them when you feel confident in the basics.</div>\n      <div class=\"code\"><span class=\"cm\">// Conditional Types — \"type ternary\"</span>\n<span class=\"kw\">type</span> IsString&lt;T&gt; = T <span class=\"kw\">extends</span> <span class=\"str\">string</span> ? <span class=\"str\">true</span> : <span class=\"str\">false</span>;\n\n<span class=\"kw\">type</span> A = IsString&lt;<span class=\"str\">string</span>&gt;; <span class=\"cm\">// true</span>\n<span class=\"kw\">type</span> B = IsString&lt;<span class=\"str\">number</span>&gt;; <span class=\"cm\">// false</span>\n\n<span class=\"cm\">// Real example — extract array element type</span>\n<span class=\"kw\">type</span> ElementType&lt;T&gt; = T <span class=\"kw\">extends</span> (infer U)[] ? U : T;\n<span class=\"kw\">type</span> Item = ElementType&lt;<span class=\"str\">string</span>[]&gt;; <span class=\"cm\">// string</span>\n\n<span class=\"cm\">// Mapped Types — creating a new type based on an existing one</span>\n<span class=\"kw\">interface</span> User { name: <span class=\"str\">string</span>; age: <span class=\"str\">number</span>; }\n\n<span class=\"kw\">type</span> ReadonlyUser = {\n  [K <span class=\"kw\">in keyof</span> User]: readonly User[K];\n}; <span class=\"cm\">// all fields become readonly</span>\n\n<span class=\"kw\">type</span> OptionalUser = {\n  [K <span class=\"kw\">in keyof</span> User]?: User[K];\n}; <span class=\"cm\">// all fields become optional — this is how Partial&lt;T&gt; works!</span></div>\n      <div class=\"explain\">\n        <strong>T extends U ? X : Y</strong> — conditional type, works like a ternary operator, but at the type level.<br>\n        <strong>infer</strong> — “extracts” a type from a structure, often used inside conditional types.<br>\n        <strong>Mapped Types</strong> — iterate over all keys of an existing type and transform them. This is how built-in <code>Partial&lt;T&gt;</code>, <code>Readonly&lt;T&gt;</code>, <code>Pick&lt;T&gt;</code>.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb238\" onchange=\"updateProgress(this)\"><span>T extends U ? X : Y — conditional type syntax</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb239\" onchange=\"updateProgress(this)\"><span>Mapped Types — [K in keyof T] for type transformations</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb240\" onchange=\"updateProgress(this)\"><span>I understand that Partial/Readonly/Pick are just Mapped Types</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-ts-satisfies","title":"Type Assertions: as and satisfies modern TS 🔗","html":"<div class=\"block\" id=\"block-ts-satisfies\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-ts-satisfies')\">Type Assertions: as and satisfies <span class=\"badge good\">modern TS</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// as — classic type assertion (you tell TS \"trust me\")</span>\n<span class=\"kw\">const</span> input = document.<span class=\"fn\">getElementById</span>(<span class=\"str\">'email'</span>) <span class=\"kw\">as</span> HTMLInputElement;\ninput.value; <span class=\"cm\">// now available — but TS simply \"trusted\" us</span>\n\n<span class=\"cm\">// Problem with as — you can accidentally specify the wrong type</span>\n<span class=\"kw\">const</span> wrong = <span class=\"str\">'hello'</span> <span class=\"kw\">as unknown as</span> <span class=\"str\">number</span>; <span class=\"cm\">// TS will stay silent, but this is a bug</span>\n\n<span class=\"cm\">// satisfies (TS 4.9+) — checks compatibility WITHOUT changing the type</span>\n<span class=\"kw\">type</span> Colors = Record&lt;<span class=\"str\">string</span>, [<span class=\"str\">number</span>, <span class=\"str\">number</span>, <span class=\"str\">number</span>]&gt;;\n\n<span class=\"kw\">const</span> palette = {\n  red:   [<span class=\"num\">255</span>, <span class=\"num\">0</span>, <span class=\"num\">0</span>],\n  green: [<span class=\"num\">0</span>, <span class=\"num\">255</span>, <span class=\"num\">0</span>]\n} <span class=\"kw\">satisfies</span> Colors;\n\n<span class=\"cm\">// ✅ TS checks that the structure matches Colors,</span>\n<span class=\"cm\">// but palette.red remains the exact type [number,number,number],</span>\n<span class=\"cm\">// not the broad Colors type — autocomplete works more precisely!</span>\n\npalette.red[<span class=\"num\">0</span>]; <span class=\"cm\">// TS knows this is exactly red, not any key</span></div>\n      <div class=\"explain\">\n        <strong>as MyType</strong> — forcefully tells the compiler “this is exactly this type”, without real checking. Use carefully; it is easy to create a bug.<br>\n        <strong>satisfies</strong> — checks that the value MATCHES the type, but keeps the exact (narrower) inferred variable type. Best of both worlds: safety + precise autocomplete.<br>\n        <strong>When to use what:</strong> satisfies is preferred in modern TS (4.9+), as — when working with old code or DOM API.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb241\" onchange=\"updateProgress(this)\"><span>as MyType — classic type assertion</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb242\" onchange=\"updateProgress(this)\"><span>satisfies — type check while preserving the exact inferred type</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb243\" onchange=\"updateProgress(this)\"><span>I understand why satisfies is better than as for constant objects</span></label>\n      </div>\n    </div>\n"}]},{"id":"sec-react","lessons":[{"id":"block-react-components","title":"Components and JSX basics 🔗","html":"<div class=\"block\" id=\"block-react-components\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-components')\">Components and JSX <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">A component is a function that returns JSX (HTML-like syntax). Each component is a separate reusable piece of the interface.</div>\n      <div class=\"code\"><span class=\"cm\">// Functional component</span>\n<span class=\"kw\">function</span> <span class=\"fn\">Button</span>({ text, onClick }) {\n  <span class=\"kw\">return</span> (\n    &lt;<span class=\"tag\">button</span> <span class=\"attr\">onClick</span>={onClick} <span class=\"attr\">className</span>=<span class=\"str\">\"btn\"</span>&gt;\n      {text}\n    &lt;/<span class=\"tag\">button</span>&gt;\n  );\n}\n\n<span class=\"cm\">// Component usage</span>\n<span class=\"kw\">function</span> <span class=\"fn\">App</span>() {\n  <span class=\"kw\">return</span> (\n    &lt;<span class=\"tag\">div</span>&gt;\n      &lt;<span class=\"fn\">Button</span> <span class=\"attr\">text</span>=<span class=\"str\">\"Click me\"</span> <span class=\"attr\">onClick</span>={() =&gt; <span class=\"fn\">alert</span>(<span class=\"str\">\"Click!\"</span>)} /&gt;\n      &lt;<span class=\"fn\">Button</span> <span class=\"attr\">text</span>=<span class=\"str\">\"Another button\"</span> <span class=\"attr\">onClick</span>={() =&gt; <span class=\"fn\">console</span>.<span class=\"fn\">log</span>(<span class=\"str\">\"ok\"</span>)} /&gt;\n    &lt;/<span class=\"tag\">div</span>&gt;\n  );\n}</div>\n      <div class=\"explain\">\n        <strong>JSX</strong> — HTML inside JS. The browser does not understand it; Babel/Vite compiles it into JS.<br>\n        <strong>Props</strong> — component parameters. Like HTML attributes, but through {}.<br>\n        <strong>className instead of class</strong> — because class is a reserved JS word.<br>\n        <strong>{}</strong> — JS expression inside JSX. You can use variables, functions, and ternary expressions.\n      </div>\n      <div class=\"quiz-block\" id=\"quiz-react-components\">\n        <div class=\"quiz-title\">🧪 Mini-test</div>\n        <div class=\"quiz-question\">1. How should you write the class attribute on an HTML element in JSX?</div>\n        <div class=\"quiz-options\">\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-rc-1\" value=\"a\"> <span>class=\"btn\"</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-rc-1\" value=\"b\"> <span>className=\"btn\"</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-rc-1\" value=\"c\"> <span>cssClass=\"btn\"</span></label>\n        </div>\n        <div class=\"quiz-question\">2. What are props in React?</div>\n        <div class=\"quiz-options\">\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-rc-2\" value=\"a\"> <span>Internal component state</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-rc-2\" value=\"b\"> <span>Parameters passed into a component</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-rc-2\" value=\"c\"> <span>Styles component</span></label>\n        </div>\n        <div class=\"practice-block\">\n          <div class=\"practice-title\">⌨️ Practice</div>\n          <div class=\"practice-task\">Write a <code>Card</code> component that accepts <code>title</code> and <code>description</code> as props and returns JSX with &lt;h2&gt; and &lt;p&gt;.</div>\n          <textarea class=\"practice-input\" id=\"practice-react-components\" placeholder=\"function Card({ title, description }) { return (...) }\"></textarea>\n        </div>\n        <button class=\"quiz-check-btn\" onclick=\"checkQuiz('react-components')\">✓ Check</button>\n        <div class=\"quiz-result\" id=\"result-react-components\"></div>\n      </div>\n      <div class=\"items\" id=\"items-react-components\">\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb621\" onchange=\"updateProgress(this)\" disabled><span>🔒 Component — function that returns JSX</span></label>\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb622\" onchange=\"updateProgress(this)\" disabled><span>🔒 Props — component parameters</span></label>\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb623\" onchange=\"updateProgress(this)\" disabled><span>🔒 className instead of class in JSX</span></label>\n      </div>\n      <div class=\"locked-items-notice\">🔒 Complete the test and practice to unlock the checkboxes</div>\n    </div>\n\n    "},{"id":"block-react-hooks","title":"Hooks: useState and useEffect basics 🔗","html":"<div class=\"block\" id=\"block-react-hooks\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-hooks')\">Hooks: useState and useEffect <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Hooks are special React functions that start with use. useState is for storing data, useEffect is for side effects.</div>\n      <div class=\"code\"><span class=\"kw\">import</span> { useState, useEffect } <span class=\"kw\">from</span> <span class=\"str\">'react'</span>;\n\n<span class=\"kw\">function</span> <span class=\"fn\">Counter</span>() {\n  <span class=\"cm\">// count — current value, setCount — update function</span>\n  <span class=\"kw\">const</span> [count, setCount] = <span class=\"fn\">useState</span>(<span class=\"num\">0</span>);\n\n  <span class=\"cm\">// useEffect: run when count changes</span>\n  <span class=\"fn\">useEffect</span>(() =&gt; {\n    document.title = <span class=\"str\">`Counter: ${count}`</span>;\n  }, [count]); <span class=\"cm\">// [count] — dependency</span>\n\n  <span class=\"kw\">return</span> (\n    &lt;<span class=\"tag\">div</span>&gt;\n      &lt;<span class=\"tag\">p</span>&gt;Counter: {count}&lt;/<span class=\"tag\">p</span>&gt;\n      &lt;<span class=\"tag\">button</span> <span class=\"attr\">onClick</span>={() =&gt; <span class=\"fn\">setCount</span>(count + <span class=\"num\">1</span>)}&gt;+1&lt;/<span class=\"tag\">button</span>&gt;\n      &lt;<span class=\"tag\">button</span> <span class=\"attr\">onClick</span>={() =&gt; <span class=\"fn\">setCount</span>(<span class=\"num\">0</span>)}&gt;Reset&lt;/<span class=\"tag\">button</span>&gt;\n    &lt;/<span class=\"tag\">div</span>&gt;\n  );\n}</div>\n      <div class=\"explain\">\n        <strong>useState(0)</strong> — initial value 0. Returns [value, updateFunction].<br>\n        <strong>setCount</strong> — calling it re-renders the component with the new value.<br>\n        <strong>useEffect(fn, [deps])</strong> — fn is called after render when deps change.<br>\n        <strong>[] (empty array)</strong> — useEffect runs once on mount.\n      </div>\n      <div class=\"quiz-block\" id=\"quiz-react-hooks\">\n        <div class=\"quiz-title\">🧪 Mini-test</div>\n        <div class=\"quiz-question\">1. What does useState(0) return?</div>\n        <div class=\"quiz-options\">\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-rh-1\" value=\"a\"> <span>Only the current value</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-rh-1\" value=\"b\"> <span>Array: [current value, update function]</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-rh-1\" value=\"c\"> <span>Object with a value field</span></label>\n        </div>\n        <div class=\"quiz-question\">2. What happens if you pass [] to useEffect?</div>\n        <div class=\"quiz-options\">\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-rh-2\" value=\"a\"> <span>useEffect will not run at all</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-rh-2\" value=\"b\"> <span>useEffect runs once when the component mounts</span></label>\n          <label class=\"quiz-option\"><input type=\"radio\" name=\"q-rh-2\" value=\"c\"> <span>useEffect will run on every render</span></label>\n        </div>\n        <div class=\"practice-block\">\n          <div class=\"practice-title\">⌨️ Practice</div>\n          <div class=\"practice-task\">Write a component with <code>name</code> state (string), an input field, and a paragraph that outputs <code>Hello, {name}!</code>.</div>\n          <textarea class=\"practice-input\" id=\"practice-react-hooks\" placeholder=\"function Greeter() { const [name, setName] = useState(''); ... }\"></textarea>\n        </div>\n        <button class=\"quiz-check-btn\" onclick=\"checkQuiz('react-hooks')\">✓ Check</button>\n        <div class=\"quiz-result\" id=\"result-react-hooks\"></div>\n      </div>\n      <div class=\"items\" id=\"items-react-hooks\">\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb624\" onchange=\"updateProgress(this)\" disabled><span>🔒 useState — stores state, setX triggers render</span></label>\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb625\" onchange=\"updateProgress(this)\" disabled><span>🔒 useEffect(fn, [deps]) — side effects after render</span></label>\n        <label class=\"item locked\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb626\" onchange=\"updateProgress(this)\" disabled><span>🔒 [] in useEffect — one run on mount</span></label>\n      </div>\n      <div class=\"locked-items-notice\">🔒 Complete the test and practice to unlock the checkboxes</div>\n    </div>\n\n    "},{"id":"block-react-useref","title":"useRef — direct access to DOM basics 🔗","html":"<div class=\"block\" id=\"block-react-useref\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-useref')\">useRef — direct access to DOM <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">useRef is a fundamental hook. Needed when you need direct access to a DOM element (focus, sizes) or to save a value that should NOT trigger a re-render.</div>\n      <div class=\"code\"><span class=\"kw\">import</span> { useRef, useEffect } <span class=\"kw\">from</span> <span class=\"str\">'react'</span>;\n\n<span class=\"kw\">function</span> <span class=\"fn\">SearchInput</span>() {\n  <span class=\"kw\">const</span> inputRef = <span class=\"fn\">useRef</span>(<span class=\"kw\">null</span>);\n\n  <span class=\"fn\">useEffect</span>(() =&gt; {\n    inputRef.current.<span class=\"fn\">focus</span>(); <span class=\"cm\">// auto-focus on mount</span>\n  }, []);\n\n  <span class=\"kw\">return</span> &lt;<span class=\"tag\">input</span> <span class=\"attr\">ref</span>={inputRef} <span class=\"attr\">type</span>=<span class=\"str\">\"text\"</span> /&gt;;\n}\n\n<span class=\"cm\">// useRef for values that should not trigger re-render</span>\n<span class=\"kw\">function</span> <span class=\"fn\">Timer</span>() {\n  <span class=\"kw\">const</span> intervalID = <span class=\"fn\">useRef</span>(<span class=\"kw\">null</span>); <span class=\"cm\">// store timer ID</span>\n  <span class=\"kw\">const</span> [seconds, setSeconds] = <span class=\"fn\">useState</span>(<span class=\"num\">0</span>);\n\n  <span class=\"kw\">const</span> start = () =&gt; {\n    intervalID.current = <span class=\"fn\">setInterval</span>(() =&gt; <span class=\"fn\">setSeconds</span>(s =&gt; s + <span class=\"num\">1</span>), <span class=\"num\">1000</span>);\n  };\n  <span class=\"kw\">const</span> stop = () =&gt; <span class=\"fn\">clearInterval</span>(intervalID.current);\n\n  <span class=\"kw\">return</span> &lt;&gt;{seconds}s &lt;<span class=\"tag\">button</span> <span class=\"attr\">onClick</span>={start}&gt;Start&lt;/<span class=\"tag\">button</span>&gt; &lt;<span class=\"tag\">button</span> <span class=\"attr\">onClick</span>={stop}&gt;Stop&lt;/<span class=\"tag\">button</span>&gt;&lt;/&gt;;\n}</div>\n      <div class=\"explain\">\n        <strong>useRef(null)</strong> creates object <code>{ current: null }</code>. Pass it to <code>ref=</code> on a JSX element — React will put the DOM node there.<br>\n        <strong>Main difference from useState:</strong> changing <code>ref.current</code> does NOT trigger a component re-render. Use it for “behind the scenes” values (timer ID, previous value, render counter).<br>\n        <strong>Common use cases:</strong> input focus, measuring block sizes, storing setInterval/setTimeout IDs, access to video/canvas elements.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb263\" onchange=\"updateProgress(this)\"><span>useRef for access to a DOM element (focus, measurements)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb264\" onchange=\"updateProgress(this)\"><span>useRef for values that should not trigger re-render</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb265\" onchange=\"updateProgress(this)\"><span>I understand the difference between useRef and useState</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-react-rhf-zod-2026","title":"React Hook Form + Zod 2026 CORE #","html":"<div class=\"block wdg-2026-block\" id=\"block-react-rhf-zod-2026\"><div class=\"block-title\" onclick=\"scrollToBlock('block-react-rhf-zod-2026')\">React Hook Form + Zod <span class=\"badge must\">2026 CORE</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">React Hook Form manages form state with minimal rerenders; Zod validates data and becomes the TypeScript type source.</div><div class=\"code\">const schema = z.object({\n  email: z.string().email(\"Invalid email\"),\n  age: z.coerce.number().int().min(14)\n});\n\ntype FormData = z.infer&lt;typeof schema&gt;;\n\nfunction ProfileForm() {\n  const { register, handleSubmit, formState: { errors } } =\n    useForm&lt;FormData&gt;({ resolver: zodResolver(schema) });\n\n  return &lt;form onSubmit={handleSubmit(console.log)}&gt;\n    &lt;input {...register(\"email\")} /&gt;\n    &lt;span&gt;{errors.email?.message}&lt;/span&gt;\n    &lt;button&gt;Save&lt;/button&gt;\n  &lt;/form&gt;;\n}</div><div class=\"explain\"><code>register</code> connects an input, <code>handleSubmit</code> validates before your callback, and <code>errors</code> contains messages. <code>z.infer</code> keeps schema and type synchronized. Validate again on the server.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-react-rhf-zod-2026-1\" onchange=\"updateProgress(this)\"><span>I register fields with RHF</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-react-rhf-zod-2026-2\" onchange=\"updateProgress(this)\"><span>I infer the type with z.infer</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-react-rhf-zod-2026-3\" onchange=\"updateProgress(this)\"><span>I show errors next to fields</span></label></div></div>"},{"id":"block-react-zustand-2026","title":"Shared state with Zustand 2026 CORE #","html":"<div class=\"block wdg-2026-block\" id=\"block-react-zustand-2026\"><div class=\"block-title\" onclick=\"scrollToBlock('block-react-zustand-2026')\">Shared state with Zustand <span class=\"badge must\">2026 CORE</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">Keep local state in useState. Zustand is useful when distant components share client UI state.</div><div class=\"code\">type ThemeStore = {\n  theme: \"light\" | \"dark\";\n  toggleTheme: () =&gt; void;\n};\n\nconst useThemeStore = create&lt;ThemeStore&gt;((set) =&gt; ({\n  theme: \"dark\",\n  toggleTheme: () =&gt; set((state) =&gt; ({\n    theme: state.theme === \"dark\" ? \"light\" : \"dark\"\n  }))\n}));\n\nconst theme = useThemeStore((state) =&gt; state.theme);</div><div class=\"explain\">The store contains data and actions. A selector subscribes to the required slice and reduces rerenders. Keep server data on the server or in a request cache instead of copying it into global state.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-react-zustand-2026-1\" onchange=\"updateProgress(this)\"><span>I distinguish local and shared state</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-react-zustand-2026-2\" onchange=\"updateProgress(this)\"><span>I use a Zustand selector</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-react-zustand-2026-3\" onchange=\"updateProgress(this)\"><span>I do not copy server data into the store</span></label></div></div>"},{"id":"block-react-ui-2026","title":"shadcn/ui + Radix UI 2026 CORE #","html":"<div class=\"block wdg-2026-block\" id=\"block-react-ui-2026\"><div class=\"block-title\" onclick=\"scrollToBlock('block-react-ui-2026')\">shadcn/ui + Radix UI <span class=\"badge must\">2026 CORE</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">Radix provides accessible behavior; shadcn/ui provides editable component code built with Radix and Tailwind.</div><div class=\"code\">import { Button } from \"@/components/ui/button\";\nimport { Dialog, DialogContent, DialogTitle, DialogTrigger }\n  from \"@/components/ui/dialog\";\n\nexport function DeleteDialog() {\n  return &lt;Dialog&gt;\n    &lt;DialogTrigger asChild&gt;\n      &lt;Button variant=\"destructive\"&gt;Delete&lt;/Button&gt;\n    &lt;/DialogTrigger&gt;\n    &lt;DialogContent&gt;\n      &lt;DialogTitle&gt;Delete project?&lt;/DialogTitle&gt;\n      &lt;Button variant=\"destructive\"&gt;Confirm&lt;/Button&gt;\n    &lt;/DialogContent&gt;\n  &lt;/Dialog&gt;;\n}</div><div class=\"explain\">The dialog handles focus, Escape, roles, and keyboard input. Its code lives in your project and can be styled. Do not remove labels, aria attributes, or focus styles to match a picture.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-react-ui-2026-1\" onchange=\"updateProgress(this)\"><span>I distinguish Radix from shadcn/ui</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-react-ui-2026-2\" onchange=\"updateProgress(this)\"><span>I preserve keyboard and focus behavior</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-react-ui-2026-3\" onchange=\"updateProgress(this)\"><span>I edit components in my project</span></label></div></div>"},{"id":"block-react-lists","title":"Lists and conditional render basics 🔗","html":"<div class=\"block\" id=\"block-react-lists\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-lists')\">Lists and conditional render <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">For lists, use .map() with a required key. Conditional rendering is done through &amp;&amp; or the ternary operator.</div>\n      <div class=\"code\"><span class=\"kw\">const</span> todos = [\n  { id: <span class=\"num\">1</span>, text: <span class=\"str\">\"Learn React\"</span>, done: <span class=\"kw\">false</span> },\n  { id: <span class=\"num\">2</span>, text: <span class=\"str\">\"Build a project\"</span>, done: <span class=\"kw\">true</span> },\n];\n\n<span class=\"kw\">function</span> <span class=\"fn\">TodoList</span>() {\n  <span class=\"kw\">return</span> (\n    &lt;<span class=\"tag\">ul</span>&gt;\n      {todos.<span class=\"fn\">map</span>(todo =&gt; (\n        &lt;<span class=\"tag\">li</span> <span class=\"attr\">key</span>={todo.id}&gt;  <span class=\"cm\">{/* key is required! */}</span>\n          {todo.text}\n          {todo.done &amp;&amp; &lt;<span class=\"tag\">span</span>&gt; ✓&lt;/<span class=\"tag\">span</span>&gt;}  <span class=\"cm\">{/* &amp;&amp; render */}</span>\n        &lt;/<span class=\"tag\">li</span>&gt;\n      ))}\n    &lt;/<span class=\"tag\">ul</span>&gt;\n  );\n}\n\n<span class=\"cm\">// Ternary operator</span>\n<span class=\"kw\">function</span> <span class=\"fn\">Status</span>({ isLoading }) {\n  <span class=\"kw\">return</span> isLoading ? &lt;<span class=\"tag\">p</span>&gt;Loading...&lt;/<span class=\"tag\">p</span>&gt; : &lt;<span class=\"tag\">p</span>&gt;Done&lt;/<span class=\"tag\">p</span>&gt;;\n}</div>\n      <div class=\"explain\">\n        <strong>key</strong> — unique identifier for React when updating a list. Never use the array index as a key.<br>\n        <strong>&amp;&amp;</strong> — renders the right part only if the left side is true.<br>\n        <strong>? :</strong> — ternary: one thing or another.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb244\" onchange=\"updateProgress(this)\"><span>.map() for rendering lists with a required key</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb245\" onchange=\"updateProgress(this)\"><span>Conditional render: {condition &amp;&amp; &lt;Component /&gt;}</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb246\" onchange=\"updateProgress(this)\"><span>Ternary render: condition ? &lt;A /&gt; : &lt;B /&gt;</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-react-forms","title":"React forms: controlled inputs and scaling IMPORTANT #","html":"<div class=\"block wdg-quality-block\" id=\"block-react-forms\"><div class=\"block-title\" onclick=\"scrollToBlock('block-react-forms')\">React forms: controlled inputs and scaling <span class=\"badge good\">IMPORTANT</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">A controlled input reads <code>value</code> from state. Every keystroke updates state and schedules a render of that component, which is normal until the component becomes too expensive.</div><div class=\"code\">function SearchForm() {\n  const [query, setQuery] = useState(\"\");\n\n  function handleSubmit(event) {\n    event.preventDefault();\n    if (!query.trim()) return;\n    console.log(query.trim());\n  }\n\n  return (\n    &lt;form onSubmit={handleSubmit}&gt;\n      &lt;input name=\"query\" value={query}\n        onChange={(event) =&gt; setQuery(event.target.value)} /&gt;\n      &lt;button type=\"submit\"&gt;Search&lt;/button&gt;\n    &lt;/form&gt;\n  );\n}</div><div class=\"explain\">Keep state near the field so a large screen does not rerender unnecessarily. For large forms, React Hook Form reduces manual state and uses focused subscriptions. Zod validates data shape but does not make typing faster by itself. Zustand is for shared application state, not an automatic replacement for form state.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-react-forms-1\" onchange=\"updateProgress(this)\"><span>I understand value  ->  onChange  ->  state  ->  render</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-react-forms-2\" onchange=\"updateProgress(this)\"><span>I keep state close to the field</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-react-forms-3\" onchange=\"updateProgress(this)\"><span>I distinguish state, validation, and shared state</span></label></div></div>"},{"id":"block-react-context","title":"React Context: scope and rerenders IMPORTANT #","html":"<div class=\"block wdg-quality-block\" id=\"block-react-context\"><div class=\"block-title\" onclick=\"scrollToBlock('block-react-context')\">React Context: scope and rerenders <span class=\"badge good\">IMPORTANT</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">When the provider <code>value</code> gets a new identity, React updates components that consume that Context. This does not mean every component inside the Provider must rerender.</div><div class=\"code\">const ThemeContext = createContext(null);\n\nfunction ThemeProvider({ children }) {\n  const [theme, setTheme] = useState(\"dark\");\n  const value = useMemo(() =&gt; ({ theme, setTheme }), [theme]);\n\n  return (\n    &lt;ThemeContext.Provider value={value}&gt;\n      {children}\n    &lt;/ThemeContext.Provider&gt;\n  );\n}\n\nfunction ThemeButton() {\n  const { theme, setTheme } = useContext(ThemeContext);\n  return &lt;button onClick={() =&gt; setTheme(theme === \"dark\" ? \"light\" : \"dark\")}&gt;Theme&lt;/button&gt;;\n}</div><div class=\"explain\">Context is useful for theme, locale, and the current user. Do not put the entire app into one Context; split unrelated data. <code>useMemo</code> avoids creating a new value object without a reason, but consumers still update when <code>theme</code> changes. Selector-based stores such as Zustand help with frequently changing shared state.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-react-context-1\" onchange=\"updateProgress(this)\"><span>I split unrelated contexts</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-react-context-2\" onchange=\"updateProgress(this)\"><span>I understand value identity</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-react-context-3\" onchange=\"updateProgress(this)\"><span>I use selector stores for a reason</span></label></div></div>"},{"id":"block-react-memo","title":"useMemo, useCallback and React.memo know 🔗","html":"<div class=\"block\" id=\"block-react-memo\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-memo')\">useMemo, useCallback and React.memo <span class=\"badge\">know</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// useMemo — cache a calculation</span>\n<span class=\"kw\">const</span> total = <span class=\"fn\">useMemo</span>(() =&gt; {\n  <span class=\"kw\">return</span> items.<span class=\"fn\">reduce</span>((sum, i) =&gt; sum + i.price, <span class=\"num\">0</span>);\n}, [items]); <span class=\"cm\">// recalculate only when items change</span>\n\n<span class=\"cm\">// useCallback — cache a function</span>\n<span class=\"kw\">const</span> handleClick = <span class=\"fn\">useCallback</span>(() =&gt; {\n  <span class=\"fn\">doSomething</span>(id);\n}, [id]);\n\n<span class=\"cm\">// React.memo — do not re-render if props did not change</span>\n<span class=\"kw\">const</span> ExpensiveCard = React.<span class=\"fn\">memo</span>(<span class=\"kw\">function</span> <span class=\"fn\">Card</span>({ title }) {\n  <span class=\"kw\">return</span> &lt;<span class=\"tag\">div</span>&gt;{title}&lt;/<span class=\"tag\">div</span>&gt;;\n});</div>\n      <div class=\"explain\">\n        <strong>useMemo</strong> — caches the function result. Recalculates only when dependencies change.<br>\n        <strong>useCallback</strong> — caches a function reference. Needed when passing callbacks to React.memo components.<br>\n        <strong>React.memo</strong> — HOC-wrapper. Skips render if props did not change.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb253\" onchange=\"updateProgress(this)\"><span>useMemo — cache calculations with dependencies</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb254\" onchange=\"updateProgress(this)\"><span>useCallback — stable function reference</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb255\" onchange=\"updateProgress(this)\"><span>React.memo — skip re-render when props do not change</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-react-router","title":"React Router — navigation important 🔗","html":"<div class=\"block\" id=\"block-react-router\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-router')\">React Router — navigation <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// npm install react-router-dom</span>\n<span class=\"kw\">import</span> { BrowserRouter, Routes, Route, Link, useNavigate, useParams } <span class=\"kw\">from</span> <span class=\"str\">'react-router-dom'</span>;\n\n<span class=\"kw\">function</span> <span class=\"fn\">App</span>() {\n  <span class=\"kw\">return</span> (\n    &lt;<span class=\"fn\">BrowserRouter</span>&gt;\n      &lt;<span class=\"tag\">nav</span>&gt;\n        &lt;<span class=\"fn\">Link</span> <span class=\"attr\">to</span>=<span class=\"str\">\"/\"</span>&gt;Home&lt;/<span class=\"fn\">Link</span>&gt;\n        &lt;<span class=\"fn\">Link</span> <span class=\"attr\">to</span>=<span class=\"str\">\"/about\"</span>&gt;About us&lt;/<span class=\"fn\">Link</span>&gt;\n      &lt;/<span class=\"tag\">nav</span>&gt;\n      &lt;<span class=\"fn\">Routes</span>&gt;\n        &lt;<span class=\"fn\">Route</span> <span class=\"attr\">path</span>=<span class=\"str\">\"/\"</span> <span class=\"attr\">element</span>={&lt;<span class=\"fn\">Home</span> /&gt;} /&gt;\n        &lt;<span class=\"fn\">Route</span> <span class=\"attr\">path</span>=<span class=\"str\">\"/users/:id\"</span> <span class=\"attr\">element</span>={&lt;<span class=\"fn\">UserPage</span> /&gt;} /&gt;\n      &lt;/<span class=\"fn\">Routes</span>&gt;\n    &lt;/<span class=\"fn\">BrowserRouter</span>&gt;\n  );\n}\n\n<span class=\"kw\">function</span> <span class=\"fn\">UserPage</span>() {\n  <span class=\"kw\">const</span> { id } = <span class=\"fn\">useParams</span>(); <span class=\"cm\">// get :id from URL</span>\n  <span class=\"kw\">const</span> navigate = <span class=\"fn\">useNavigate</span>();\n  <span class=\"kw\">return</span> &lt;<span class=\"tag\">button</span> <span class=\"attr\">onClick</span>={() =&gt; <span class=\"fn\">navigate</span>(<span class=\"str\">\"/\"</span>)}&gt;Back&lt;/<span class=\"tag\">button</span>&gt;;\n}</div>\n      <div class=\"explain\">\n        <strong>BrowserRouter</strong> — wraps the whole app and gives access to routing.<br>\n        <strong>Routes + Route</strong> — declarative route description.<br>\n        <strong>Link</strong> — navigation without page reload.<br>\n        <strong>useParams</strong> — reads dynamic URL parts (:id).<br>\n        <strong>useNavigate</strong> — programmatic navigation between pages.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb256\" onchange=\"updateProgress(this)\"><span>BrowserRouter + Routes + Route — routing structure</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb257\" onchange=\"updateProgress(this)\"><span>Link — navigation without reload</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb258\" onchange=\"updateProgress(this)\"><span>useParams — dynamic URL parameters</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb259\" onchange=\"updateProgress(this)\"><span>useNavigate — programmatic navigation</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-react-custom-hooks","title":"Custom hooks important 🔗","html":"<div class=\"block\" id=\"block-react-custom-hooks\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-custom-hooks')\">Custom hooks <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// Hook for fetch requests with old request cancellation</span>\n<span class=\"kw\">function</span> <span class=\"fn\">useFetch</span>&lt;T&gt;(url: <span class=\"str\">string</span>) {\n  <span class=\"kw\">const</span> [data, setData] = <span class=\"fn\">useState</span>&lt;T | <span class=\"kw\">null</span>&gt;(<span class=\"kw\">null</span>);\n  <span class=\"kw\">const</span> [loading, setLoading] = <span class=\"fn\">useState</span>(<span class=\"kw\">true</span>);\n  <span class=\"kw\">const</span> [error, setError] = <span class=\"fn\">useState</span>&lt;<span class=\"str\">string</span> | <span class=\"kw\">null</span>&gt;(<span class=\"kw\">null</span>);\n\n  <span class=\"fn\">useEffect</span>(() =&gt; {\n    <span class=\"kw\">const</span> controller = <span class=\"kw\">new</span> <span class=\"fn\">AbortController</span>();\n    <span class=\"fn\">setLoading</span>(<span class=\"kw\">true</span>);\n    <span class=\"fn\">setError</span>(<span class=\"kw\">null</span>);\n\n    <span class=\"fn\">fetch</span>(url, { signal: controller.signal })\n      .<span class=\"fn\">then</span>(r =&gt; {\n        <span class=\"kw\">if</span> (!r.ok) <span class=\"kw\">throw new</span> <span class=\"fn\">Error</span>(<span class=\"str\">`HTTP ${r.status}`</span>);\n        <span class=\"kw\">return</span> r.<span class=\"fn\">json</span>();\n      })\n      .<span class=\"fn\">then</span>(d =&gt; <span class=\"fn\">setData</span>(d))\n      .<span class=\"fn\">catch</span>(e =&gt; {\n        <span class=\"kw\">if</span> (e.name !== <span class=\"str\">'AbortError'</span>) <span class=\"fn\">setError</span>(e.message);\n      })\n      .<span class=\"fn\">finally</span>(() =&gt; {\n        <span class=\"kw\">if</span> (!controller.signal.aborted) <span class=\"fn\">setLoading</span>(<span class=\"kw\">false</span>);\n      });\n\n    <span class=\"kw\">return</span> () =&gt; controller.<span class=\"fn\">abort</span>();\n  }, [url]);\n\n  <span class=\"kw\">return</span> { data, loading, error };\n}</div>\n      <div class=\"explain\">\n        <strong>Custom hook</strong> — function that starts with use and encapsulates logic.<br>\n        <strong>AbortController</strong> cancels the old request in cleanup. Without this, a slow old URL response can overwrite fresh data — this is a race condition.<br>\n        <strong>useFetch</strong> — classic example: data + loading state + error + request cancellation.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb260\" onchange=\"updateProgress(this)\"><span>Custom hook — use* function, encapsulates logic</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb261\" onchange=\"updateProgress(this)\"><span>useFetch — pattern: data/loading/error</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb262\" onchange=\"updateProgress(this)\"><span>AbortController in cleanup protects from race condition</span></label>\n      </div>\n    </div>\n  \n    "},{"id":"block-react-cleanup","title":"useEffect: cleanup function common beginner mistake 🔗","html":"<div class=\"block\" id=\"block-react-cleanup\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-cleanup')\">useEffect: cleanup function <span class=\"badge must\">common beginner mistake</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Beginners often forget to clean up resources in useEffect — this leads to memory leaks and bugs like “hanging” handlers after leaving a component.</div>\n      <div class=\"code\"><span class=\"cm\">// ❌ Without cleanup — memory leak and bugs</span>\n<span class=\"fn\">useEffect</span>(() =&gt; {\n  <span class=\"kw\">const</span> id = <span class=\"fn\">setInterval</span>(() =&gt; console.<span class=\"fn\">log</span>(<span class=\"str\">'tick'</span>), <span class=\"num\">1000</span>);\n  <span class=\"cm\">// the timer will keep running even after leaving the component!</span>\n}, []);\n\n<span class=\"cm\">// ✅ With cleanup function — return inside useEffect</span>\n<span class=\"fn\">useEffect</span>(() =&gt; {\n  <span class=\"kw\">const</span> id = <span class=\"fn\">setInterval</span>(() =&gt; console.<span class=\"fn\">log</span>(<span class=\"str\">'tick'</span>), <span class=\"num\">1000</span>);\n\n  <span class=\"kw\">return</span> () =&gt; <span class=\"fn\">clearInterval</span>(id); <span class=\"cm\">// called on unmount</span>\n}, []);\n\n<span class=\"cm\">// ✅ Unsubscribe from events</span>\n<span class=\"fn\">useEffect</span>(() =&gt; {\n  <span class=\"kw\">const</span> handleResize = () =&gt; console.<span class=\"fn\">log</span>(window.innerWidth);\n  window.<span class=\"fn\">addEventListener</span>(<span class=\"str\">'resize'</span>, handleResize);\n\n  <span class=\"kw\">return</span> () =&gt; window.<span class=\"fn\">removeEventListener</span>(<span class=\"str\">'resize'</span>, handleResize);\n}, []);</div>\n      <div class=\"explain\">\n        <strong>return inside useEffect</strong> — function that runs before the next effect run OR on component unmount.<br>\n        <strong>What must be cleaned:</strong> setInterval/setTimeout, addEventListener, subscriptions (WebSocket, observers), requests that can be canceled.<br>\n        <strong>Rule:</strong> if you “start” something in useEffect (timer, subscription), you almost always need to “stop” it in cleanup.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb266\" onchange=\"updateProgress(this)\"><span>return () =&gt; {} inside useEffect — cleanup function</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb267\" onchange=\"updateProgress(this)\"><span>clearInterval/removeEventListener in cleanup</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb268\" onchange=\"updateProgress(this)\"><span>I understand when forgotten cleanup causes a memory leak</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-react-effect-loop","title":"useEffect: infinite loop common error 🔗","html":"<div class=\"block\" id=\"block-react-effect-loop\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-effect-loop')\">useEffect: infinite loop <span class=\"badge must\">common error</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">If an effect changes state and runs after every render, the component can enter an infinite update loop.</div>\n      <div class=\"code\"><span class=\"cm\">// ❌ No dependency array — effect runs after every render</span>\n<span class=\"fn\">useEffect</span>(() =&gt; {\n  <span class=\"fn\">setCount</span>(count + <span class=\"num\">1</span>);\n});\n\n<span class=\"cm\">// ❌ Dependency on count + changing count inside the effect</span>\n<span class=\"fn\">useEffect</span>(() =&gt; {\n  <span class=\"fn\">setCount</span>(count + <span class=\"num\">1</span>);\n}, [count]);\n\n<span class=\"cm\">// ✅ If you need to run once on mount</span>\n<span class=\"fn\">useEffect</span>(() =&gt; {\n  <span class=\"fn\">setCount</span>(c =&gt; c + <span class=\"num\">1</span>);\n}, []);</div>\n      <div class=\"explain\">\n        <strong>useEffect without the second argument</strong> runs after every render.<br>\n        <strong>setState inside an effect</strong> causes a new render. If the effect runs again and calls setState again, the tab starts freezing.<br>\n        <strong>Rule:</strong> dependencies should describe the external data of the effect, not be a random list of variables.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb268a\" onchange=\"updateProgress(this)\"><span>I understand why setState in useEffect can loop a component</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-react-data-fetching","title":"TanStack Query — correct work with server industry standard 🔗","html":"<div class=\"block\" id=\"block-react-data-fetching\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-data-fetching')\">TanStack Query — correct work with server <span class=\"badge good\">industry standard</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Writing raw fetch inside useEffect is an outdated approach. It leads to race conditions, no caching, and tons of boilerplate code for loading/error states.</div>\n      <div class=\"code\"><span class=\"cm\">// ❌ Old way — fetch in useEffect</span>\n<span class=\"kw\">function</span> <span class=\"fn\">UserProfile</span>({ id }) {\n  <span class=\"kw\">const</span> [user, setUser] = <span class=\"fn\">useState</span>(<span class=\"kw\">null</span>);\n  <span class=\"kw\">const</span> [loading, setLoading] = <span class=\"fn\">useState</span>(<span class=\"kw\">true</span>);\n\n  <span class=\"fn\">useEffect</span>(() =&gt; {\n    <span class=\"fn\">fetch</span>(<span class=\"str\">`/api/users/${id}`</span>)\n      .<span class=\"fn\">then</span>(r =&gt; r.<span class=\"fn\">json</span>())\n      .<span class=\"fn\">then</span>(data =&gt; { <span class=\"fn\">setUser</span>(data); <span class=\"fn\">setLoading</span>(<span class=\"kw\">false</span>); });\n    <span class=\"cm\">// no request cancellation, no cache, no error handling...</span>\n  }, [id]);\n}\n\n<span class=\"cm\">// ✅ TanStack Query — cache, retries, cancellation out of the box</span>\n<span class=\"kw\">import</span> { useQuery } <span class=\"kw\">from</span> <span class=\"str\">'@tanstack/react-query'</span>;\n\n<span class=\"kw\">function</span> <span class=\"fn\">UserProfile</span>({ id }) {\n  <span class=\"kw\">const</span> { data: user, isLoading, error } = <span class=\"fn\">useQuery</span>({\n    queryKey: [<span class=\"str\">'user'</span>, id],\n    queryFn: () =&gt; <span class=\"fn\">fetch</span>(<span class=\"str\">`/api/users/${id}`</span>).<span class=\"fn\">then</span>(r =&gt; r.<span class=\"fn\">json</span>())\n  });\n\n  <span class=\"kw\">if</span> (isLoading) <span class=\"kw\">return</span> &lt;<span class=\"tag\">p</span>&gt;Loading...&lt;/<span class=\"tag\">p</span>&gt;;\n  <span class=\"kw\">if</span> (error) <span class=\"kw\">return</span> &lt;<span class=\"tag\">p</span>&gt;Error&lt;/<span class=\"tag\">p</span>&gt;;\n  <span class=\"kw\">return</span> &lt;<span class=\"tag\">p</span>&gt;{user.name}&lt;/<span class=\"tag\">p</span>&gt;;\n}</div>\n      <div class=\"explain\">\n        <strong>TanStack Query (React Query)</strong> — automatic caching, retries on error, cancellation of unnecessary requests on unmount.<br>\n        <strong>queryKey</strong> — unique request identifier; cache is built from it. If id changes → automatically new request.<br>\n        <strong>RTK Query</strong> — analog from Redux Toolkit if the project already uses Redux.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb272\" onchange=\"updateProgress(this)\"><span>I understand problems of raw fetch in useEffect (race conditions, cache)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb273\" onchange=\"updateProgress(this)\"><span>useQuery — queryKey, queryFn, isLoading, error</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb274\" onchange=\"updateProgress(this)\"><span>I know that TanStack Query is the standard for working with server state</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-react-advanced-hooks","title":"useReducer and useLayoutEffect for broader knowledge 🔗","html":"<div class=\"block\" id=\"block-react-advanced-hooks\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-advanced-hooks')\">useReducer and useLayoutEffect <span class=\"badge\">for broader knowledge</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// useReducer — useState alternative for complex update logic</span>\n<span class=\"kw\">function</span> <span class=\"fn\">reducer</span>(state, action) {\n  <span class=\"kw\">switch</span> (action.type) {\n    <span class=\"kw\">case</span> <span class=\"str\">'increment'</span>: <span class=\"kw\">return</span> { count: state.count + <span class=\"num\">1</span> };\n    <span class=\"kw\">case</span> <span class=\"str\">'decrement'</span>: <span class=\"kw\">return</span> { count: state.count - <span class=\"num\">1</span> };\n    <span class=\"kw\">case</span> <span class=\"str\">'reset'</span>: <span class=\"kw\">return</span> { count: <span class=\"num\">0</span> };\n    <span class=\"kw\">default</span>: <span class=\"kw\">return</span> state;\n  }\n}\n\n<span class=\"kw\">function</span> <span class=\"fn\">Counter</span>() {\n  <span class=\"kw\">const</span> [state, dispatch] = <span class=\"fn\">useReducer</span>(reducer, { count: <span class=\"num\">0</span> });\n  <span class=\"kw\">return</span> (\n    &lt;&gt;\n      {state.count}\n      &lt;<span class=\"tag\">button</span> <span class=\"attr\">onClick</span>={() =&gt; <span class=\"fn\">dispatch</span>({ type: <span class=\"str\">'increment'</span> })}&gt;+&lt;/<span class=\"tag\">button</span>&gt;\n    &lt;/&gt;\n  );\n}\n\n<span class=\"cm\">// useLayoutEffect — like useEffect, but runs BEFORE painting on screen</span>\n<span class=\"fn\">useLayoutEffect</span>(() =&gt; {\n  <span class=\"cm\">// measure an element and immediately apply style — without \"flicker\"</span>\n  <span class=\"kw\">const</span> height = ref.current.offsetHeight;\n  ref.current.style.marginTop = height + <span class=\"str\">'px'</span>;\n}, []);</div>\n      <div class=\"explain\">\n        <strong>useReducer</strong> — convenient when state update logic is complex (many action types) or depends on previous state.<br>\n        <strong>useLayoutEffect</strong> — runs synchronously BEFORE the browser paints changes. Use only for DOM measurements that must be visible instantly (otherwise there will be “flicker”).\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb275\" onchange=\"updateProgress(this)\"><span>useReducer — useState alternative for complex logic</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb276\" onchange=\"updateProgress(this)\"><span>useLayoutEffect — runs before painting, for DOM measurements</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-react-fsd","title":"FSD Architecture — standard for large projects market standard 🔗","html":"<div class=\"block\" id=\"block-react-fsd\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-fsd')\">FSD Architecture — standard for large projects <span class=\"badge good\">market standard</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">In small projects, files are grouped by type: components/, hooks/, pages/. In large projects, this turns into a mess. The modern market standard is FSD (Feature-Sliced Design).</div>\n      <div class=\"code\"><span class=\"cm\">// Architecture is divided into 3 main concepts:</span>\n<span class=\"cm\">// Layer → Slice → Segment</span>\n\n<span class=\"cm\">// FSD folder structure:</span>\nsrc/\n  ├── app/         <span class=\"cm\">// App initialization (providers, global styles, routing)</span>\n  ├── pages/       <span class=\"cm\">// App pages (page components, assemble widgets)</span>\n  ├── widgets/     <span class=\"cm\">// Large independent blocks (Header, Sidebar, Product grid)</span>\n  ├── features/    <span class=\"cm\">// Interactive user actions (Like, Add to cart, Search)</span>\n  ├── entities/    <span class=\"cm\">// Business entities (User, Product, Article — their cards and logic)</span>\n  ├── shared/      <span class=\"cm\">// Reusable foundation (UI kit: Button, Input, API clients, helpers)</span>\n\n<span class=\"cm\">// Main FSD rule:</span>\n<span class=\"cm\">// Higher layers can import only what is</span>\n<span class=\"cm\">// in LOWER layers. Never the other way around!</span>\n<span class=\"cm\">// For example, a component from shared/ cannot import something from features/</span></div>\n      <div class=\"explain\">\n        <strong>FSD protects from spaghetti code</strong> and tangled imports — each layer knows its place.<br>\n        <strong>Hierarchy:</strong> app → pages → widgets → features → entities → shared. Each next layer is built only from the previous ones.<br>\n        <strong>Main rule:</strong> lower layers never know about upper layers. shared/ knows nothing about features/, and features/ knows nothing about widgets/.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb277\" onchange=\"updateProgress(this)\"><span>FSD protects from spaghetti code and tangled imports</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb278\" onchange=\"updateProgress(this)\"><span>I understand the hierarchy: app → pages → widgets → features → entities → shared</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb279\" onchange=\"updateProgress(this)\"><span>I know the rule: lower layers never know about upper layers</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-react-zustand-selectors","title":"Zustand: selectors — meaningless without them critical 🔗","html":"<div class=\"block\" id=\"block-react-zustand-selectors\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-zustand-selectors')\">Zustand: selectors — meaningless without them <span class=\"badge must\">critical</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Without selectors, Zustand re-renders a component on ANY store change — this erases its main advantage over useContext.</div>\n      <div class=\"code\"><span class=\"cm\">// ❌ Without selector — component re-renders on ANY store change</span>\n<span class=\"kw\">const</span> { meals, user, theme } = <span class=\"fn\">useStore</span>(); <span class=\"cm\">// subscribed to EVERYTHING</span>\n<span class=\"cm\">// Theme changed? The component re-renders even if it only uses meals!</span>\n\n<span class=\"cm\">// ✅ With selector — subscribe only to the needed field</span>\n<span class=\"kw\">const</span> meals = <span class=\"fn\">useStore</span>(state =&gt; state.meals);\n<span class=\"cm\">// Now the component re-renders ONLY when meals changes</span>\n\n<span class=\"cm\">// Several fields — several separate selectors</span>\n<span class=\"kw\">const</span> user = <span class=\"fn\">useStore</span>(state =&gt; state.user);\n<span class=\"kw\">const</span> addMeal = <span class=\"fn\">useStore</span>(state =&gt; state.addMeal);\n\n<span class=\"cm\">// If several fields are needed at once — useShallow for Zustand 5+</span>\n<span class=\"kw\">import</span> { useShallow } <span class=\"kw\">from</span> <span class=\"str\">'zustand/react/shallow'</span>;\n\n<span class=\"kw\">const</span> { meals, user } = <span class=\"fn\">useStore</span>(\n  <span class=\"fn\">useShallow</span>(state =&gt; ({ meals: state.meals, user: state.user }))\n);</div>\n      <div class=\"explain\">\n        <strong>useStore()</strong> without an argument — subscription to the whole store. Any change in any field triggers re-render.<br>\n        <strong>useStore(state =&gt; state.field)</strong> — subscription only to a specific field. This is the selector.<br>\n        <strong>useShallow</strong> — modern method for Zustand 5+: wraps the selector and shallowly compares object fields, not the whole reference.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb280\" onchange=\"updateProgress(this)\"><span>useStore(state =&gt; state.field) — selector subscribed to one field</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb281\" onchange=\"updateProgress(this)\"><span>I understand that without a selector, Zustand loses its main advantage</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb282\" onchange=\"updateProgress(this)\"><span>shallow — for selectors returning several fields</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-react-zustand-persist","title":"Zustand middleware: persist and devtools commercial code 🔗","html":"<div class=\"block\" id=\"block-react-zustand-persist\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-zustand-persist')\">Zustand middleware: persist and devtools <span class=\"badge must\">commercial code</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">In real projects, the store often must survive page reload: theme, cart, settings, interface token-state. Zustand has middleware for this.</div>\n      <div class=\"code\"><span class=\"kw\">import</span> { create } <span class=\"kw\">from</span> <span class=\"str\">'zustand'</span>;\n<span class=\"kw\">import</span> { persist, devtools } <span class=\"kw\">from</span> <span class=\"str\">'zustand/middleware'</span>;\n\n<span class=\"kw\">const</span> useSettingsStore = <span class=\"fn\">create</span>()(\n  <span class=\"fn\">devtools</span>(\n    <span class=\"fn\">persist</span>(\n      (set) =&gt; ({\n        theme: <span class=\"str\">'dark'</span>,\n        setTheme: (theme) =&gt; <span class=\"fn\">set</span>({ theme })\n      }),\n      { name: <span class=\"str\">'settings-storage'</span> } <span class=\"cm\">// key in localStorage</span>\n    )\n  )\n);\n\n<span class=\"cm\">// After reload, the theme is restored automatically</span>\n<span class=\"kw\">const</span> theme = <span class=\"fn\">useSettingsStore</span>(s =&gt; s.theme);</div>\n      <div class=\"explain\">\n        <strong>persist</strong> saves part of the store in localStorage/sessionStorage and restores it on app start.<br>\n        <strong>devtools</strong> connects the store to Redux DevTools — convenient for watching state changes step by step.<br>\n        <strong>partialize</strong> can be used if you need to save not the whole store, but only safe fields.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-react-zustand-persist-1\" onchange=\"updateProgress(this)\"><span>persist — automatic store saving in localStorage</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-react-zustand-persist-2\" onchange=\"updateProgress(this)\"><span>devtools — debugging Zustand through Redux DevTools</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-react-19-compiler-actions","title":"React 19: Compiler, useActionState, useFormStatus modern 🔗","html":"<div class=\"block\" id=\"block-react-19-compiler-actions\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-19-compiler-actions')\">React 19: Compiler, useActionState, useFormStatus <span class=\"badge good\">modern</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">React is moving toward less manual optimization and more convenient form handling. Old hooks did not disappear, but new projects are written differently.</div>\n      <div class=\"code\"><span class=\"cm\">// React Compiler reduces the need for manual useMemo/useCallback</span>\n<span class=\"cm\">// Idea: the compiler itself understands what can be memoized safely.</span>\n\n<span class=\"cm\">// useActionState — form state around an action</span>\n<span class=\"kw\">function</span> <span class=\"fn\">Signup</span>() {\n  <span class=\"kw\">const</span> [state, formAction, pending] = <span class=\"fn\">useActionState</span>(signupAction, {\n    error: <span class=\"kw\">null</span>\n  });\n\n  <span class=\"kw\">return</span> (\n    &lt;<span class=\"tag\">form</span> <span class=\"attr\">action</span>={formAction}&gt;\n      &lt;<span class=\"tag\">input</span> <span class=\"attr\">name</span>=<span class=\"str\">\"email\"</span> /&gt;\n      {state.error &amp;&amp; &lt;<span class=\"tag\">p</span>&gt;{state.error}&lt;/<span class=\"tag\">p</span>&gt;}\n      &lt;<span class=\"tag\">button</span> <span class=\"attr\">disabled</span>={pending}&gt;Create&lt;/<span class=\"tag\">button</span>&gt;\n    &lt;/<span class=\"tag\">form</span>&gt;\n  );\n}\n\n<span class=\"cm\">// useFormStatus is read by child form buttons</span>\n<span class=\"kw\">function</span> <span class=\"fn\">SubmitButton</span>() {\n  <span class=\"kw\">const</span> { pending } = <span class=\"fn\">useFormStatus</span>();\n  <span class=\"kw\">return</span> &lt;<span class=\"tag\">button</span> <span class=\"attr\">disabled</span>={pending}&gt;{pending ? <span class=\"str\">'Waiting...'</span> : <span class=\"str\">'Submit'</span>}&lt;/<span class=\"tag\">button</span>&gt;;\n}</div>\n      <div class=\"explain\">\n        <strong>React Compiler</strong> automates part of memoization. But in legacy code, <code>useMemo</code>, <code>useCallback</code>, and <code>React.memo</code> still appear constantly.<br>\n        <strong>useActionState</strong> connects a form action with result state: error, success, pending.<br>\n        <strong>useFormStatus</strong> convenient for submit buttons inside forms: it can know that the form is currently submitting.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-react19-1\" onchange=\"updateProgress(this)\"><span>React Compiler — idea of automatic memoization</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-react19-2\" onchange=\"updateProgress(this)\"><span>useActionState — form result state</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-react19-3\" onchange=\"updateProgress(this)\"><span>useFormStatus — pending-state inside forms</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-react-testing","title":"Testing: Vitest + React Testing Library level middle 🔗","html":"<div class=\"block\" id=\"block-react-testing\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-testing')\">Testing: Vitest + React Testing Library <span class=\"badge good\">level middle</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Vitest is a modern and fast Jest replacement, especially for Vite projects (uses the same engine and config). React Testing Library is the standard for testing React components.</div>\n      <div class=\"code\"><span class=\"cm\">// Installation</span>\n<span class=\"kw\">npm install</span> -D vitest @testing-library/react @testing-library/jest-dom jsdom\n\n<span class=\"cm\">// Button.test.jsx</span>\n<span class=\"kw\">import</span> { render, screen, fireEvent } <span class=\"kw\">from</span> <span class=\"str\">'@testing-library/react'</span>;\n<span class=\"kw\">import</span> { describe, it, expect, vi } <span class=\"kw\">from</span> <span class=\"str\">'vitest'</span>;\n<span class=\"kw\">import</span> Button <span class=\"kw\">from</span> <span class=\"str\">'./Button'</span>;\n\n<span class=\"fn\">describe</span>(<span class=\"str\">'Button'</span>, () =&gt; {\n  <span class=\"fn\">it</span>(<span class=\"str\">'renders passed text'</span>, () =&gt; {\n    <span class=\"fn\">render</span>(&lt;<span class=\"tag\">Button</span> <span class=\"attr\">label</span>=<span class=\"str\">\"Buy\"</span> /&gt;);\n    <span class=\"fn\">expect</span>(screen.<span class=\"fn\">getByText</span>(<span class=\"str\">'Buy'</span>)).<span class=\"fn\">toBeInTheDocument</span>();\n  });\n\n  <span class=\"fn\">it</span>(<span class=\"str\">'calls onClick on click'</span>, () =&gt; {\n    <span class=\"kw\">const</span> handleClick = vi.<span class=\"fn\">fn</span>(); <span class=\"cm\">// mock function</span>\n    <span class=\"fn\">render</span>(&lt;<span class=\"tag\">Button</span> <span class=\"attr\">label</span>=<span class=\"str\">\"Buy\"</span> <span class=\"attr\">onClick</span>={handleClick} /&gt;);\n\n    fireEvent.<span class=\"fn\">click</span>(screen.<span class=\"fn\">getByText</span>(<span class=\"str\">'Buy'</span>));\n    <span class=\"fn\">expect</span>(handleClick).<span class=\"fn\">toHaveBeenCalledTimes</span>(<span class=\"num\">1</span>);\n  });\n});</div>\n      <div class=\"explain\">\n        <strong>render()</strong> — mounts the component into a virtual DOM for the test.<br>\n        <strong>screen.getByText/getByRole</strong> — finds elements the way a user sees them (by text, role), not by CSS classes.<br>\n        <strong>vi.fn()</strong> — creates a stub function (mock) that can be checked: whether it was called, how many times, with which arguments.<br>\n        <strong>RTL philosophy:</strong> “test like a user” — do not test internal component state, test what is visible and what happens on screen.<br>\n        <strong>Playwright / Cypress</strong> — E2E tests: run a real browser, click through the interface, and check a full user scenario, for example login → cart → payment.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb283\" onchange=\"updateProgress(this)\"><span>Vitest — fast Jest replacement for Vite projects</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb284\" onchange=\"updateProgress(this)\"><span>render, screen.getByText/getByRole — basic RTL methods</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb285\" onchange=\"updateProgress(this)\"><span>vi.fn() and fireEvent — mock functions and event simulation</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb285a\" onchange=\"updateProgress(this)\"><span>Playwright or Cypress — E2E tests for real user scenarios</span></label>\n      </div>\n    </div>\n"},{"id":"block-react-enterprise-architecture","title":"React in large products: microfrontends enterprise 🔗","html":"<div class=\"block\" id=\"block-react-enterprise-architecture\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-react-enterprise-architecture')\">React in large products: microfrontends <span class=\"badge opt\">enterprise</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">In large companies, a React app is often split into independent parts: teams release their own modules separately, and the shell assembles them together.</div>\n      <div class=\"explain\">\n        <strong>Module Federation</strong> — method for connecting parts of an app from different builds at runtime. Often appears together with Webpack or Rspack.<br>\n        <strong>Rspack and Turbopack</strong> — Rust-based bundlers: Rspack often replaces Webpack in enterprise React/Vue, Turbopack develops inside Next.js.<br>\n        <strong>Monorepository</strong> — one repository for several packages or apps; often uses Turborepo, pnpm workspaces, Nx.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb285b\" onchange=\"updateProgress(this)\"><span>Module Federation — understand the idea of microfrontends</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb285c\" onchange=\"updateProgress(this)\"><span>Rspack/Turbopack — know what Rust-based bundlers are</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb285d\" onchange=\"updateProgress(this)\"><span>Monorepos and Turborepo — basic concept of code splitting</span></label>\n      </div>\n    </div>\n"}]},{"id":"sec-linux","lessons":[{"id":"block-linux-basics","title":"Basic terminal commands basics 🔗","html":"<div class=\"block\" id=\"block-linux-basics\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-linux-basics')\">Basic terminal commands <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">The terminal is a text interface to the system. It is faster than the mouse for most developer tasks.</div>\n      <div class=\"code\"><span class=\"cm\"># Navigation</span>\n<span class=\"kw\">pwd</span>              <span class=\"cm\"># where am I now?</span>\n<span class=\"kw\">ls</span> -la           <span class=\"cm\"># list files (including hidden)</span>\n<span class=\"kw\">cd</span> projects      <span class=\"cm\"># go to folder</span>\n<span class=\"kw\">cd</span> ..            <span class=\"cm\"># one level up</span>\n<span class=\"kw\">cd</span> ~             <span class=\"cm\"># home folder</span>\n\n<span class=\"cm\"># Files and folders</span>\n<span class=\"kw\">mkdir</span> my-app     <span class=\"cm\"># create folder</span>\n<span class=\"kw\">touch</span> index.html  <span class=\"cm\"># create file</span>\n<span class=\"kw\">cp</span> file.txt copy.txt   <span class=\"cm\"># copy</span>\n<span class=\"kw\">mv</span> old.txt new.txt     <span class=\"cm\"># rename/move</span>\n<span class=\"kw\">rm</span> file.txt      <span class=\"cm\"># delete file</span>\n<span class=\"kw\">rm</span> -rf folder/   <span class=\"cm\"># delete folder (careful!)</span>\n\n<span class=\"cm\"># Viewing files</span>\n<span class=\"kw\">cat</span> file.txt     <span class=\"cm\"># print content</span>\n<span class=\"kw\">less</span> file.txt    <span class=\"cm\"># paged view (q — quit)</span>\n<span class=\"kw\">head</span> -20 file.txt <span class=\"cm\"># first 20 lines</span>\n<span class=\"kw\">tail</span> -f log.txt  <span class=\"cm\"># follow file in real time</span></div>\n      <div class=\"explain\">\n        <strong>pwd</strong> — Print Working Directory. Always know where you are.<br>\n        <strong>ls -la</strong> — shows hidden files (starting with .) and permissions.<br>\n        <strong>rm -rf</strong> — dangerous command! Deletes everything without confirmation and without trash.<br>\n        <strong>tail -f</strong> — indispensable for viewing logs in real time.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb286\" onchange=\"updateProgress(this)\"><span>pwd, ls, cd — file system navigation</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb287\" onchange=\"updateProgress(this)\"><span>mkdir, touch, cp, mv, rm — file management</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb288\" onchange=\"updateProgress(this)\"><span>cat, less, head, tail — content viewing</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-linux-permissions","title":"Permissions and users important 🔗","html":"<div class=\"block\" id=\"block-linux-permissions\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-linux-permissions')\">Permissions and users <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\"># chmod — change permissions</span>\n<span class=\"kw\">chmod</span> 755 script.sh  <span class=\"cm\"># rwxr-xr-x</span>\n<span class=\"kw\">chmod</span> +x script.sh   <span class=\"cm\"># add execute permission</span>\n<span class=\"kw\">chmod</span> 644 file.txt   <span class=\"cm\"># rw-r--r-- (typical for files)</span>\n\n<span class=\"cm\"># Permission decoding: rwxrwxrwx</span>\n<span class=\"cm\"># r=4 w=2 x=1 | owner | group | others</span>\n<span class=\"cm\"># 755 = 7(rwx) 5(r-x) 5(r-x)</span>\n\n<span class=\"cm\"># sudo — run as root</span>\n<span class=\"kw\">sudo</span> apt install nginx\n<span class=\"kw\">sudo</span> systemctl start nginx\n\n<span class=\"cm\"># Change owner</span>\n<span class=\"kw\">chown</span> user:group file.txt\n\n<span class=\"cm\"># Current user</span>\n<span class=\"kw\">whoami</span>\n<span class=\"kw\">id</span></div>\n      <div class=\"explain\">\n        <strong>chmod 755</strong> — owner can do everything (7=rwx), others can only read and execute (5=r-x).<br>\n        <strong>chmod +x</strong> — quickly adds script execution permission.<br>\n        <strong>sudo</strong> — Superuser DO. Needed for system operations. Do not overuse it.<br>\n        <strong>644</strong> — standard permissions for files. 755 — for folders and scripts.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb289\" onchange=\"updateProgress(this)\"><span>chmod — changing permissions (numeric and letter format)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb290\" onchange=\"updateProgress(this)\"><span>sudo — running as root, apt install</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb291\" onchange=\"updateProgress(this)\"><span>Decoding rwx: r=4, w=2, x=1</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-linux-processes","title":"Processes and system monitoring important 🔗","html":"<div class=\"block\" id=\"block-linux-processes\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-linux-processes')\">Processes and system monitoring <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\"># Process viewing</span>\n<span class=\"kw\">ps</span> aux            <span class=\"cm\"># all processes</span>\n<span class=\"kw\">ps</span> aux | <span class=\"kw\">grep</span> node <span class=\"cm\"># find Node processes</span>\n<span class=\"kw\">top</span>               <span class=\"cm\"># real-time monitoring</span>\n<span class=\"kw\">htop</span>              <span class=\"cm\"># convenient top version (needs install)</span>\n\n<span class=\"cm\"># Process management</span>\n<span class=\"kw\">kill</span> 1234          <span class=\"cm\"># stop process by PID</span>\n<span class=\"kw\">kill</span> -9 1234       <span class=\"cm\"># force kill</span>\n<span class=\"kw\">pkill</span> node         <span class=\"cm\"># kill by name</span>\nCtrl+C             <span class=\"cm\"># interrupt current process</span>\nCtrl+Z             <span class=\"cm\"># pause (bg/fg for management)</span>\n\n<span class=\"cm\"># Background launch</span>\n<span class=\"kw\">npm</span> start &amp;       <span class=\"cm\"># run in background</span>\n<span class=\"kw\">nohup</span> node app.js &amp; <span class=\"cm\"># run and detach from terminal</span>\n\n<span class=\"cm\"># Ports</span>\n<span class=\"kw\">lsof</span> -i :3000     <span class=\"cm\"># what listens on port 3000?</span>\n<span class=\"kw\">netstat</span> -tulpn    <span class=\"cm\"># all open ports</span></div>\n      <div class=\"explain\">\n        <strong>ps aux | grep node</strong> — pipe (|) passes output of one command into another. Key bash pattern.<br>\n        <strong>kill -9</strong> — SIGKILL, cannot be intercepted. Use only if normal kill does not help.<br>\n        <strong>lsof -i :3000</strong> — lifesaver when “port is already busy” while starting a dev server.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb292\" onchange=\"updateProgress(this)\"><span>ps aux, top — process viewing and monitoring</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb293\" onchange=\"updateProgress(this)\"><span>kill, pkill — stopping processes</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb294\" onchange=\"updateProgress(this)\"><span>lsof -i — check busy ports</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb295\" onchange=\"updateProgress(this)\"><span>Pipe (|) — passing output between commands</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-linux-ssh","title":"SSH — connecting to servers important 🔗","html":"<div class=\"block\" id=\"block-linux-ssh\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-linux-ssh')\">SSH — connecting to servers <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\"># SSH connection</span>\n<span class=\"kw\">ssh</span> user@server.com\n<span class=\"kw\">ssh</span> -p 2222 user@server.com  <span class=\"cm\"># custom port</span>\n<span class=\"kw\">ssh</span> -i ~/.ssh/id_rsa user@server.com  <span class=\"cm\"># with a key</span>\n\n<span class=\"cm\"># Generate SSH keys</span>\n<span class=\"kw\">ssh-keygen</span> -t ed25519 -C \"email@example.com\"\n<span class=\"cm\"># Private: ~/.ssh/id_ed25519 (NEVER SHARE!)</span>\n<span class=\"cm\"># Public: ~/.ssh/id_ed25519.pub (to server)</span>\n\n<span class=\"cm\"># Copy key to server</span>\n<span class=\"kw\">ssh-copy-id</span> user@server.com\n\n<span class=\"cm\"># Copy files</span>\n<span class=\"kw\">scp</span> file.txt user@server:/home/user/\n<span class=\"kw\">scp</span> -r folder/ user@server:/home/user/\n\n<span class=\"cm\"># ~/.ssh/config — save settings</span>\nHost myserver\n  HostName 192.168.1.1\n  User ubuntu\n  IDentityFile ~/.ssh/id_ed25519</div>\n      <div class=\"explain\">\n        <strong>ed25519</strong> — modern key algorithm. Better than rsa.<br>\n        <strong>Private key</strong> — never share it! Public key (.pub) can be shared everywhere.<br>\n        <strong>~/.ssh/config</strong> — after setup, you can connect simply: <code>ssh myserver</code>.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb296\" onchange=\"updateProgress(this)\"><span>ssh user@host — connection to a remote server</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb297\" onchange=\"updateProgress(this)\"><span>ssh-keygen — generate an ed25519 key pair</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb298\" onchange=\"updateProgress(this)\"><span>scp — copy files by SSH</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb299\" onchange=\"updateProgress(this)\"><span>~/.ssh/config — save connection settings</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-linux-bash","title":"Bash scripts and automation know 🔗","html":"<div class=\"block\" id=\"block-linux-bash\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-linux-bash')\">Bash scripts and automation <span class=\"badge\">know</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">#!/bin/bash</span>\n<span class=\"cm\"># Variables</span>\n<span class=\"kw\">NAME</span>=<span class=\"str\">\"World\"</span>\n<span class=\"kw\">echo</span> <span class=\"str\">\"Hello, $NAME!\"</span>\n\n<span class=\"cm\"># Conditions</span>\n<span class=\"kw\">if</span> [ -f \"package.json\" ]; <span class=\"kw\">then</span>\n  <span class=\"kw\">echo</span> \"Node project found\"\n<span class=\"kw\">else</span>\n  <span class=\"kw\">echo</span> \"package.json not found\"\n<span class=\"kw\">fi</span>\n\n<span class=\"cm\"># Loop</span>\n<span class=\"kw\">for</span> file <span class=\"kw\">in</span> *.html; <span class=\"kw\">do</span>\n  <span class=\"kw\">echo</span> \"File: $file\"\n<span class=\"kw\">done</span>\n\n<span class=\"cm\"># Useful aliases in ~/.bashrc or ~/.zshrc</span>\n<span class=\"kw\">alias</span> gs=<span class=\"str\">\"git status\"</span>\n<span class=\"kw\">alias</span> gp=<span class=\"str\">\"git push\"</span>\n<span class=\"kw\">alias</span> ll=<span class=\"str\">\"ls -la\"</span>\n<span class=\"kw\">alias</span> dev=<span class=\"str\">\"npm run dev\"</span></div>\n      <div class=\"explain\">\n        <strong>#!/bin/bash</strong> — shebang. First line tells the system how to run the script.<br>\n        <strong>[ -f file ]</strong> — checks if a file exists. [ -d ] — folder.<br>\n        <strong>alias</strong> — shortcuts for frequent commands. Save in ~/.bashrc or ~/.zshrc and apply: <code>source ~/.bashrc</code>.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb300\" onchange=\"updateProgress(this)\"><span>#!/bin/bash — shebang and script launch</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb301\" onchange=\"updateProgress(this)\"><span>if/for in bash — conditions and loops</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb302\" onchange=\"updateProgress(this)\"><span>alias — command shortcuts in ~/.bashrc</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-linux-packagemanagers","title":"Package managers and npm tools basics 🔗","html":"<div class=\"block\" id=\"block-linux-packagemanagers\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-linux-packagemanagers')\">Package managers and npm tools <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\"># apt (Debian/Ubuntu)</span>\n<span class=\"kw\">sudo apt update</span>        <span class=\"cm\"># update package list</span>\n<span class=\"kw\">sudo apt install</span> curl git\n<span class=\"kw\">sudo apt remove</span> nginx\n\n<span class=\"cm\"># brew (macOS)</span>\n<span class=\"kw\">brew install</span> node\n<span class=\"kw\">brew update &amp;&amp; brew upgrade</span>\n\n<span class=\"cm\"># npm global packages</span>\n<span class=\"kw\">npm install -g</span> typescript\n<span class=\"kw\">npm install -g</span> vite\n<span class=\"kw\">corepack enable</span>       <span class=\"cm\"># enables pnpm/yarn through Node</span>\n<span class=\"kw\">pnpm create vite</span> my-app\n<span class=\"kw\">bun create vite</span> my-app\n<span class=\"kw\">npm list -g --depth=0</span>  <span class=\"cm\"># list installed</span>\n\n<span class=\"cm\"># nvm — Node version manager</span>\n<span class=\"kw\">nvm install</span> 20\n<span class=\"kw\">nvm use</span> 20\n<span class=\"kw\">nvm ls</span>               <span class=\"cm\"># list versions</span></div>\n      <div class=\"explain\">\n        <strong>apt update</strong> — always run before install, otherwise you may install an outdated version.<br>\n        <strong>nvm</strong> — Node Version Manager. Allows having several Node versions at the same time.<br>\n        <strong>pnpm</strong> — fast package manager, saves disk space through a shared store.<br>\n        <strong>Bun</strong> — modern runtime and package manager for local development, often faster than Node/npm on typical tasks.<br>\n        Different projects may require different Node versions — nvm solves this problem.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb303\" onchange=\"updateProgress(this)\"><span>apt/brew — system package managers</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb304\" onchange=\"updateProgress(this)\"><span>npm install -g — global npm packages</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb304a\" onchange=\"updateProgress(this)\"><span>pnpm and Bun — modern npm alternatives for frontend projects</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb305\" onchange=\"updateProgress(this)\"><span>nvm — Node.js version management</span></label>\n      </div>\n    </div>\n  "}]},{"id":"sec-vite","lessons":[{"id":"block-vite-basics","title":"Vite — fast dev server and build basics 🔗","html":"<div class=\"block\" id=\"block-vite-basics\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-vite-basics')\">Vite — fast dev server and build <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Vite is a next-generation build tool. The dev server starts instantly, and HMR updates modules without page reload.</div>\n      <div class=\"code\"><span class=\"cm\"># Create new project</span>\n<span class=\"kw\">npm create vite@latest</span> my-app\n<span class=\"cm\"># Choose: React / Vue / Vanilla + TypeScript</span>\n\n<span class=\"kw\">cd</span> my-app\n<span class=\"kw\">npm install</span>\n<span class=\"kw\">npm run dev</span>     <span class=\"cm\"># dev-server on http://localhost:5173</span>\n<span class=\"kw\">npm run build</span>   <span class=\"cm\"># build into dist/ folder</span>\n<span class=\"kw\">npm run preview</span> <span class=\"cm\"># preview production build</span>\n\n<span class=\"cm\">// vite.config.ts</span>\n<span class=\"kw\">import</span> { defineConfig } <span class=\"kw\">from</span> <span class=\"str\">'vite'</span>\n<span class=\"kw\">import</span> react <span class=\"kw\">from</span> <span class=\"str\">'@vitejs/plugin-react'</span>\n\n<span class=\"kw\">export default</span> <span class=\"fn\">defineConfig</span>({\n  plugins: [<span class=\"fn\">react</span>()],\n  server: { port: <span class=\"num\">3000</span> },\n  build: { outDir: <span class=\"str\">'dist'</span> }\n})</div>\n      <div class=\"explain\">\n        <strong>HMR</strong> — Hot Module Replacement. Changed a file — the browser updates only that module, without reloading the page.<br>\n        <strong>npm run build</strong> — minifies, splits into chunks, optimizes. Ready for deploy.<br>\n        <strong>dist/</strong> — this is the folder you upload to hosting or GitHub Pages.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb306\" onchange=\"updateProgress(this)\"><span>npm create vite@latest — create project with a template</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb307\" onchange=\"updateProgress(this)\"><span>dev/build/preview — three key Vite commands</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb308\" onchange=\"updateProgress(this)\"><span>vite.config.ts — plugin and server setup</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-vite-eslint","title":"ESLint + Prettier — code quality important 🔗","html":"<div class=\"block\" id=\"block-vite-eslint\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-vite-eslint')\">ESLint + Prettier — code quality <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\"># Installation</span>\n<span class=\"kw\">npm install -D eslint prettier stylelint stylelint-config-standard</span>\n<span class=\"kw\">npm install -D eslint-config-prettier</span>\n<span class=\"kw\">npm install -D @typescript-eslint/eslint-plugin</span>\n\n<span class=\"cm\">// .eslintrc.json</span>\n{\n  <span class=\"str\">\"extends\"</span>: [<span class=\"str\">\"eslint:recommended\"</span>, <span class=\"str\">\"prettier\"</span>],\n  <span class=\"str\">\"rules\"</span>: {\n    <span class=\"str\">\"no-unused-vars\"</span>: <span class=\"str\">\"warn\"</span>,\n    <span class=\"str\">\"no-console\"</span>: <span class=\"str\">\"off\"</span>\n  }\n}\n\n<span class=\"cm\">// .prettierrc</span>\n{\n  <span class=\"str\">\"semi\"</span>: <span class=\"kw\">true</span>,\n  <span class=\"str\">\"singleQuote\"</span>: <span class=\"kw\">true</span>,\n  <span class=\"str\">\"tabWidth\"</span>: <span class=\"num\">2</span>,\n  <span class=\"str\">\"printWidth\"</span>: <span class=\"num\">100</span>\n}\n\n<span class=\"cm\"># package.json scripts</span>\n<span class=\"str\">\"lint\"</span>: <span class=\"str\">\"eslint src --ext .ts,.tsx\"</span>,\n<span class=\"str\">\"format\"</span>: <span class=\"str\">\"prettier --write src/\"</span>,\n<span class=\"str\">\"lint:css\"</span>: <span class=\"str\">\"stylelint \\\"src/**/*.css\\\"\"</span></div>\n      <div class=\"explain\">\n        <strong>ESLint</strong> — finds errors and anti-patterns in code. Can be configured for the team.<br>\n        <strong>Prettier</strong> — auto-formatting. Ends team debates about tabs and commas.<br>\n        <strong>Stylelint</strong> — linter for CSS/SCSS: catches duplicates, unknown properties, wrong order, and accidental style errors.<br>\n        <strong>-D</strong> — devDependency. These packages are needed only in development, not in production.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb309\" onchange=\"updateProgress(this)\"><span>ESLint — linter, finds errors and anti-patterns</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb310\" onchange=\"updateProgress(this)\"><span>Prettier — auto-formatting, .prettierrc config</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb310a\" onchange=\"updateProgress(this)\"><span>Stylelint — linter for CSS/SCSS, complements ESLint</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb311\" onchange=\"updateProgress(this)\"><span>npm scripts — lint and format in package.json</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-vite-env","title":"Environment variables (.env) important 🔗","html":"<div class=\"block\" id=\"block-vite-env\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-vite-env')\">Environment variables (.env) <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\"># .env file (in project root)</span>\nVITE_API_URL=https://api.example.com\nVITE_APP_NAME=MyApp\n<span class=\"cm\"># Everything that starts with VITE_ is available in the browser</span>\n\n<span class=\"cm\"># .env.local — for local secrets (add to .gitignore!)</span>\nVITE_API_KEY=super_secret_key\n\n<span class=\"cm\">// Usage in code</span>\n<span class=\"kw\">const</span> apiUrl = import.meta.env.VITE_API_URL;\n<span class=\"kw\">const</span> isDev = import.meta.env.DEV;   <span class=\"cm\">// true in dev mode</span>\n<span class=\"kw\">const</span> isProd = import.meta.env.PROD; <span class=\"cm\">// true in production</span>\n\n<span class=\"cm\"># .gitignore — must exclude!</span>\n.env.local\n.env.*.local\nnode_modules/\ndist/</div>\n      <div class=\"explain\">\n        <strong>VITE_</strong> — prefix is required! Without it, the variable will not get into browser code.<br>\n        <strong>.env.local</strong> — never commit to git! API keys and tokens are stored here.<br>\n        <strong>import.meta.env</strong> — Vite-specific. In old Webpack projects you often see <code>process.env.*</code>, but in new Vite projects focus on <code>VITE_</code>.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb312\" onchange=\"updateProgress(this)\"><span>VITE_ prefix — only such variables get into the browser</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb313\" onchange=\"updateProgress(this)\"><span>import.meta.env — access to env variables in Vite</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb314\" onchange=\"updateProgress(this)\"><span>.env.local in .gitignore — secret protection</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-vite-ssr-islands","title":"SSR, Islands and new bundlers overview 🔗","html":"<div class=\"block\" id=\"block-vite-ssr-islands\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-vite-ssr-islands')\">SSR, Islands and new bundlers <span class=\"badge rec\">overview</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">You do not need to study this first. But it is useful to understand words from vacancies: SSR, SSG, Islands, Rspack, Turbopack.</div>\n      <div class=\"code\"><span class=\"cm\">// CSR — normal React/Vite in the browser</span>\nBrowser downloaded JS → React built the page\n\n<span class=\"cm\">// SSR — server immediately returns ready HTML</span>\nRequest → server renders page → browser sees content faster\n\n<span class=\"cm\">// SSG — pages are built ahead of time</span>\nnpm run build → ready HTML files → very fast hosting\n\n<span class=\"cm\">// Islands Architecture — JS only where needed</span>\nHeader = HTML\nArticle = HTML\nCartButton = interactive JS island\n\n<span class=\"cm\">// Modern tools</span>\nVite      — fast dev-server\nAstro     — islands + content sites\nRspack    — fast webpack-compatible bundler\nTurbopack — bundler in the Next.js ecosystem</div>\n      <div class=\"explain\">\n        <strong>CSR</strong> easiest for the start: Vite + React. Downside — first screen may wait for JS.<br>\n        <strong>SSR</strong> helps SEO and first content speed, but requires a server part.<br>\n        <strong>Islands</strong> — Astro idea: most of the page is static, only needed parts become interactive.<br>\n        <strong>Do not jump too early:</strong> first confident JS/React, then SSR and architecture.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-vite-ssr-1\" onchange=\"updateProgress(this)\"><span>I understand the difference between CSR, SSR and SSG</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-vite-ssr-2\" onchange=\"updateProgress(this)\"><span>I understand the Islands idea: JS only for interactive parts</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-vite-ssr-3\" onchange=\"updateProgress(this)\"><span>I have heard of Astro, Rspack, Turbopack and understand why they are needed</span></label>\n      </div>\n    </div>\n  "}]},{"id":"sec-career","lessons":[{"id":"block-career-stack","title":"What the market actually requires basics 🔗","html":"<div class=\"block\" id=\"block-career-stack\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-career-stack')\">What the market actually requires <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Analysis of 500+ junior frontend vacancies on hh.ru — this is what employers write most often.</div>\n      <div class=\"code\"><span class=\"cm\">// Required in 90%+ junior vacancies</span>\nHTML5 + CSS3 (Flexbox, Grid)\nJavaScript (ES6+)\nReact or Vue\nGit + GitHub\nResponsive layout\n\n<span class=\"cm\">// Required in 60-80% of vacancies</span>\nTypeScript\nnpm / Webpack / Vite\nREST API + fetch / axios\nBasic Node.js knowledge\n\n<span class=\"cm\">// Plus for resume (not required)</span>\nNext.js / Nuxt\nRedux / Zustand\nDocker (basics)\nUnit tests (Jest)</div>\n      <div class=\"explain\">\n        <strong>Main advice:</strong> do not learn everything at once. Cover HTML+CSS+JS+React+Git — this is enough for the first offer.<br>\n        <strong>TypeScript</strong> — add immediately after you feel confident in JS. This adds +20-30% to salary.<br>\n        <strong>Next.js</strong> — logical next step after React. Highly demanded in 2024-2025.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb315\" onchange=\"updateProgress(this)\"><span>I know my target stack for the first job</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb316\" onchange=\"updateProgress(this)\"><span>I understand the difference between junior/middle requirements</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-career-salary","title":"Frontend developer salaries important 🔗","html":"<div class=\"block\" id=\"block-career-salary\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-career-salary')\">Frontend developer salaries <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// Russia (Moscow/remote), 2024-2025</span>\nJunior (0-1 year):     50 000 — 120 000 ₽\nMiddle (1-3 years):   120 000 — 250 000 ₽\nSenior (3+ years old):     250 000 — 500 000+ ₽\n\n<span class=\"cm\">// International market (remote, USD)</span>\nJunior:    $1 000 — $2 500/month\nMiddle:    $2 500 — $5 000/month\nSenior:    $5 000 — $12 000+/month\n\n<span class=\"cm\">// What raises salary fastest</span>\n+ TypeScript          → +15-25%\n+ React + Next.js     → +20-30%\n+ English B2+      → +50-100% (international market)\n+ Open Source contribution   → strong hiring signal\n+ Pet projects with code → shows real level</div>\n      <div class=\"explain\">\n        <strong>Important:</strong> numbers are examples and strongly depend on company, city, and market conditions.<br>\n        <strong>English</strong> — fastest way to multiply income. Even B1 opens international vacancies.<br>\n        <strong>Watch current data</strong> on hh.ru (section \"Salary\"), levels.fyi, glassdoor.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb317\" onchange=\"updateProgress(this)\"><span>I know the market range for my level</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb318\" onchange=\"updateProgress(this)\"><span>I know what specifically raises my value</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-career-portfolio","title":"Portfolio — what actually works basics 🔗","html":"<div class=\"block\" id=\"block-career-portfolio\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-career-portfolio')\">Portfolio — what actually works <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// 3 projects are better than 10 weak ones</span>\n\n<span class=\"cm\">// Project 1 — layout (shows the basics)</span>\nAccurate layout from Figma design\nResponsiveness at 3 breakpoints\nAnimations, hover effects\n→ Show: GitHub + live deploy\n\n<span class=\"cm\">// Project 2 — JS/React app</span>\nTodo / weather / news / movies\nWorking with APIs (fetch + async/await)\nState, routing, components\n→ Show: GitHub + Vercel/Netlify\n\n<span class=\"cm\">// Project 3 — something of your own</span>\nA real problem you solve\nIt does not matter how simple — the idea matters\n→ Show: GitHub + link + README</div>\n      <div class=\"explain\">\n        <strong>Main mistake</strong> — portfolio without live links. Deploy to Vercel or GitHub Pages — required.<br>\n        <strong>README</strong> — write what it is, what technologies, how to run it. This shows development culture.<br>\n        <strong>Code quality is more important than quantity</strong> — employers open GitHub and look at code.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb319\" onchange=\"updateProgress(this)\"><span>There are at least 2 projects on GitHub with live links</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb320\" onchange=\"updateProgress(this)\"><span>Each project has a normal README</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb321\" onchange=\"updateProgress(this)\"><span>Projects are deployed and open by link</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-career-resume","title":"Frontend developer resume important 🔗","html":"<div class=\"block\" id=\"block-career-resume\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-career-resume')\">Frontend developer resume <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// Resume structure (1 page)</span>\n\n1. Name + contacts\n   Email, GitHub, Telegram, city (or \"remote\")\n\n2. Stack (no fluff)\n   JavaScript, TypeScript, React, HTML/CSS,\n   Git, REST API, Vite\n\n3. Experience / Projects (if no job yet)\n   Project name\n   What you did + which technologies\n   Link to GitHub and deploy\n\n4. Education\n   Briefly, without extra stuff\n\n<span class=\"cm\">// Common resume mistakes</span>\n✗ \"Responsible, communicative...\"  ← nobody reads this\n✗ Business suit photo               ← not required\n✗ \"I know HTML/CSS\" without details        ← too vague\n✗ Resume on 3 pages                 ← maximum 1\n\n<span class=\"cm\">// What works</span>\n✓ Concrete technologies and projects\n✓ Link to GitHub directly in the header\n✓ \"React, TypeScript — 1 year of commercial experience\"</div>\n      <div class=\"explain\">\n        <strong>Resume services:</strong> hh.ru, LinkedIn, Notion (public page).<br>\n        <strong>Main rule</strong> — be concrete. Not \"know JavaScript\", but \"React + TypeScript, built 3 projects\".<br>\n        <strong>GitHub is more important than resume</strong> for juniors — if there is code there, many HRs barely look at anything else.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb322\" onchange=\"updateProgress(this)\"><span>Resume done, fits on 1 page</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb323\" onchange=\"updateProgress(this)\"><span>Resume has a GitHub link with projects</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb324\" onchange=\"updateProgress(this)\"><span>No fluff — only stack, projects, contacts</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-career-interview","title":"Interview — how it goes and what they ask important 🔗","html":"<div class=\"block\" id=\"block-career-interview\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-career-interview')\">Interview — how it goes and what they ask <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// Typical junior frontend questions</span>\n\n<span class=\"cm\">// HTML/CSS</span>\n- Difference between display:none and visibility:hidden?\n- How does CSS specificity work?\n- What is BEM?\n- Flexbox vs Grid — when to use which?\n\n<span class=\"cm\">// JavaScript</span>\n- Difference let/const/var?\n- What is a closure?\n- Event loop — as works?\n- Promise vs async/await?\n- Difference == and ===?\n\n<span class=\"cm\">// React</span>\n- Component lifecycle\n- Why key in lists?\n- useState vs useReducer?\n- What is props drilling?\n\n<span class=\"cm\">// Practice (live coding)</span>\n- Reverse a string\n- Remove duplicates from an array\n- Write a simple component\n- Make fetch and show data</div>\n      <div class=\"explain\">\n        <strong>Live coding</strong> — do not panic if you do not know the answer. Think out loud — this is more important than the correct answer.<br>\n        <strong>Questions for the company</strong> — always prepare 2-3 questions: stack, code review, what a typical day looks like.<br>\n        <strong>After rejection</strong> — ask for feedback. This best way to understand what to improve.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb325\" onchange=\"updateProgress(this)\"><span>I can answer basic JS questions without Google</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb326\" onchange=\"updateProgress(this)\"><span>Practiced live coding (leetcode easy / codewars)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb327\" onchange=\"updateProgress(this)\"><span>Prepared questions for the company</span></label>\n      </div>\n    </div>\n  "}]},{"id":"sec-nexus","lessons":[{"id":"block-nexus-main","title":"Nexus Notes knowledge base 🔗","html":"<div class=\"block\" id=\"block-nexus-main\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-nexus-main')\">Nexus Notes <span class=\"badge good\">knowledge base</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Use it for frontend notes: DOM, localStorage, Kwork ideas, project snippets. To link notes, write <code>[[DOM]]</code> or <code>[[My project]]</code>.</div>\n      <div class=\"nexus-shell\">\n        <aside class=\"nexus-panel\">\n          <div class=\"nexus-actions\"><button class=\"nexus-btn primary\" onclick=\"nexusCreateNote()\">+ Note</button><button class=\"nexus-btn\" onclick=\"nexusExportNotes()\">Export</button><button class=\"nexus-btn\" onclick=\"nexusImportNotes()\">Import</button></div>\n          <input class=\"nexus-search\" id=\"nexusSearch\" placeholder=\"Search notes...\" oninput=\"nexusRenderList()\">\n          <div class=\"nexus-list\" id=\"nexusList\"></div>\n        </aside>\n        <main class=\"nexus-panel\">\n          <div class=\"nexus-actions\"><button class=\"nexus-btn primary\" onclick=\"nexusSaveActive()\">Save</button><button class=\"nexus-btn\" onclick=\"nexusCreateLinkedNotes()\">Create missing links</button><button class=\"nexus-btn danger\" onclick=\"nexusDeleteActive()\">Delete</button></div>\n          <input class=\"nexus-title-input\" id=\"nexusTitle\" placeholder=\"Note title\" oninput=\"nexusUpdateDraft()\">\n          <div class=\"nexus-editor-grid\" style=\"margin-top:12px;\"><textarea class=\"nexus-textarea\" id=\"nexusBody\" placeholder=\"Write a note. Example: Today I learned [[localStorage]] and [[DOM]].\" oninput=\"nexusUpdateDraft()\"></textarea><div class=\"nexus-preview\" id=\"nexusPreview\"></div></div>\n          <div class=\"nexus-graph\" id=\"nexusGraph\"></div>\n        </main>\n      </div>\n    </div>\n  "}]},{"id":"sec-ai","lessons":[{"id":"block-ai-default","title":"By default: Llama 3.3 70B built in","html":"<div class=\"block\" id=\"block-ai-default\">\n      <div class=\"block-title\">By default: Llama 3.3 70B <span class=\"badge must\">built in</span></div>\n      <div class=\"tip\">Without any settings, the AI assistant already works on the free Llama 3.3 70B model (through Groq). Just open the chat with the 💬 button in the bottom-right corner or select text on the page.</div>\n    </div>\n\n    "},{"id":"block-ai-custom","title":"⚙ Custom model and API key optional 🔗","html":"<div class=\"block\" id=\"block-ai-custom\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-ai-custom')\">⚙ Custom model and API key <span class=\"badge good\">optional</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Any OpenAI-compatible providers are supported: <b>Groq</b>, <b>OpenRouter</b>, <b>OpenAI</b>, <b>Together.ai</b>, <b>Mistral</b> and others. The key is stored locally in your browser (localStorage) and is not sent anywhere except the selected provider.</div>\n\n      <div style=\"background:#0d1117;border-radius:12px;padding:20px;margin-top:12px;border:1px solid #30363d;\">\n\n        <div style=\"margin-bottom:12px;\">\n          <label style=\"display:block;font-size:12px;color:#8b949e;margin-bottom:5px;font-weight:600;\">🔌 Provider</label>\n          <select id=\"ai-provider\" onchange=\"aiProviderPreset()\" style=\"width:100%;padding:8px 12px;background:#161b22;border:1px solid #30363d;border-radius:8px;color:#e6edf3;font-size:13px;font-family:inherit;outline:none;box-sizing:border-box;cursor:pointer;\">\n            <option value=\"https://api.groq.com/openai/v1\">Groq</option>\n            <option value=\"https://openrouter.ai/api/v1\">OpenRouter</option>\n            <option value=\"https://api.openai.com/v1\">OpenAI</option>\n            <option value=\"https://api.together.xyz/v1\">Together.ai</option>\n            <option value=\"https://api.mistral.ai/v1\">Mistral</option>\n            <option value=\"custom\">Other (I will enter URL manually)</option>\n          </select>\n        </div>\n\n        <div style=\"margin-bottom:12px;\" id=\"ai-baseurl-wrap\">\n          <label style=\"display:block;font-size:12px;color:#8b949e;margin-bottom:5px;font-weight:600;\">🌐 Base URL</label>\n          <input id=\"ai-baseurl\" type=\"text\" placeholder=\"https://api.groq.com/openai/v1\" value=\"https://api.groq.com/openai/v1\" style=\"width:100%;padding:8px 12px;background:#161b22;border:1px solid #30363d;border-radius:8px;color:#e6edf3;font-size:13px;font-family:inherit;outline:none;box-sizing:border-box;\">\n        </div>\n\n        <div style=\"margin-bottom:12px;\">\n          <label style=\"display:block;font-size:12px;color:#8b949e;margin-bottom:5px;font-weight:600;\">🔑 API key</label>\n          <input id=\"ai-apikey\" type=\"password\" placeholder=\"sk-... / gsk_... / sk-or-v1-...\" style=\"width:100%;padding:8px 12px;background:#161b22;border:1px solid #30363d;border-radius:8px;color:#e6edf3;font-size:13px;font-family:inherit;outline:none;box-sizing:border-box;\">\n        </div>\n\n        <div style=\"margin-bottom:16px;\">\n          <label style=\"display:block;font-size:12px;color:#8b949e;margin-bottom:5px;font-weight:600;\">🤖 Model name</label>\n          <input id=\"ai-modelname\" type=\"text\" placeholder=\"for example: llama-3.3-70b-versatile, gpt-4o-mini, deepseek/deepseek-r1:free\" style=\"width:100%;padding:8px 12px;background:#161b22;border:1px solid #30363d;border-radius:8px;color:#e6edf3;font-size:13px;font-family:inherit;outline:none;box-sizing:border-box;\">\n          <div style=\"font-size:11px;color:#6e7681;margin-top:4px;\">Exact model name as required by the selected provider (check its documentation)</div>\n        </div>\n\n        <div style=\"display:flex;gap:8px;\">\n          <button onclick=\"aiSaveCustomConfig()\" style=\"flex:1;padding:11px;background:linear-gradient(135deg,#7c3aed,#a855f7);color:#fff;border:none;border-radius:8px;font-size:14px;font-weight:700;cursor:pointer;font-family:inherit;transition:opacity .2s;\" onmouseover=\"this.style.opacity='.85'\" onmouseout=\"this.style.opacity='1'\">\n            💾 Save\n          </button>\n          <button onclick=\"aiClearCustomConfig()\" style=\"padding:11px 16px;background:#30363d;color:#e6edf3;border:none;border-radius:8px;font-size:14px;font-weight:700;cursor:pointer;font-family:inherit;transition:background .2s;\" onmouseover=\"this.style.background='#3d444d'\" onmouseout=\"this.style.background='#30363d'\">\n            🗑 Clear\n          </button>\n        </div>\n\n        <div id=\"ai-config-status\" style=\"margin-top:12px;font-size:13px;display:none;padding:10px 14px;border-radius:8px;\"></div>\n\n        <div id=\"ai-saved-models-wrap\" style=\"margin-top:16px;display:none;\">\n          <div style=\"font-size:12px;color:#8b949e;margin-bottom:8px;font-weight:600;\">💾 Saved models</div>\n          <div id=\"ai-saved-models-list\" style=\"display:flex;flex-direction:column;gap:6px;\"></div>\n        </div>\n      </div>\n    </div>\n\n    "},{"id":"block-ai-examples","title":"Provider settings examples reference 🔗","html":"<div class=\"block\" id=\"block-ai-examples\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-ai-examples')\">Provider settings examples <span class=\"badge\">reference</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// Groq — free, very fast</span>\nBase URL: https://api.groq.com/openai/v1\nModel:   llama-3.3-70b-versatile\nKey:     console.groq.com/keys\n\n<span class=\"cm\">// OpenRouter — many models, free ones exist</span>\nBase URL: https://openrouter.ai/api/v1\nModel:   deepseek/deepseek-r1:free\nKey:     openrouter.ai/keys\n\n<span class=\"cm\">// OpenAI — paid</span>\nBase URL: https://api.openai.com/v1\nModel:   gpt-4o-mini\nKey:     platform.openai.com/api-keys\n\n<span class=\"cm\">// Mistral — has a free tier</span>\nBase URL: https://api.mistral.ai/v1\nModel:   mistral-small-latest\nKey:     console.mistral.ai/api-keys</div>\n      <div class=\"explain\">\n        <strong>Where to get a key:</strong> register with the provider → section API Keys → create a new key.<br>\n        <strong>Security:</strong> key is stored in localStorage only in your browser. not sent to anyone except directly to the selected provider.<br>\n        <strong>After saving</strong> choose “⚙ Custom model” in the dropdown in the chat window.\n      </div>\n    </div>\n\n    "},{"id":"block-ai-prompt-engineering","title":"Prompt Engineering for learning code practice 🔗","html":"<div class=\"block\" id=\"block-ai-prompt-engineering\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-ai-prompt-engineering')\">Prompt Engineering for learning code <span class=\"badge good\">practice</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">A good prompt is not \"make it nice\", but a clear task: role, context, constraints, response format, and check criteria.</div>\n      <div class=\"code\"><span class=\"cm\">// Bad prompt</span>\nMake me a website.\n\n<span class=\"cm\">// Good prompt</span>\nYou are a frontend mentor. I am learning HTML/CSS/JS.\nTask: help build responsive product card.\nConstraints: no frameworks, only HTML/CSS, explain briefly.\nFormat: first a plan on 3 steps, then a small code piece.\nCheck: tell what mistakes happen most often in this layout.\n\n<span class=\"cm\">// For checking your code</span>\nReview this code as a mentor: find bugs, extra complexity,\nresponsive issues and suggest improvements without a full rewrite.</div>\n      <div class=\"explain\">\n        <strong>Role</strong> sets the answer style: mentor, reviewer, interviewer, client.<br>\n        <strong>Context</strong> saves time: what you have already done, what files exist, what exactly does not work.<br>\n        <strong>Constraints</strong> protect from extra complexity: without React, without libraries, hints only, not the full answer.<br>\n        <strong>Check</strong> makes AI look for mistakes, instead of just agreeing.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-ai-prompt-1\" onchange=\"updateProgress(this)\"><span>I can give AI a role, context, and constraints</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-ai-prompt-2\" onchange=\"updateProgress(this)\"><span>I ask for code review without full rewrite</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-ai-prompt-3\" onchange=\"updateProgress(this)\"><span>I use AI as a mentor, not as a button \"do everything\"</span></label>\n      </div>\n    </div>\n  "}]},{"id":"sec-refactor","lessons":[{"id":"block-refactor-smells","title":"Code Smells — signs it is time to refactor basics 🔗","html":"<div class=\"block\" id=\"block-refactor-smells\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-refactor-smells')\">Code Smells — signs it is time to refactor <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Code Smell — not a bug, code works. But it is a signal that structure is bad and will create problems later.</div>\n      <div class=\"code\"><span class=\"cm\">// 1. Long Method — too long function</span>\n<span class=\"kw\">function</span> <span class=\"fn\">processOrder</span>(order) {\n  <span class=\"cm\">// 80 rows of code doing validation + calculation + saving + email...</span>\n} <span class=\"cm\">// ❌ Too many responsibilities</span>\n\n<span class=\"cm\">// 2. Duplicate Code — duplicated code</span>\n<span class=\"kw\">function</span> <span class=\"fn\">getUserName</span>(u) { <span class=\"kw\">return</span> u.first + <span class=\"str\">' '</span> + u.last; }\n<span class=\"kw\">function</span> <span class=\"fn\">getFullName</span>(u)  { <span class=\"kw\">return</span> u.first + <span class=\"str\">' '</span> + u.last; } <span class=\"cm\">// ❌ Duplicate</span>\n\n<span class=\"cm\">// 3. Magic Numbers — numbers without explanation</span>\n<span class=\"kw\">if</span> (user.age &gt; <span class=\"num\">17</span>) { <span class=\"cm\">/* ... */</span> } <span class=\"cm\">// ❌ What does it mean 17?</span>\n<span class=\"kw\">if</span> (user.age &gt;= ADULT_AGE) { <span class=\"cm\">/* ... */</span> } <span class=\"cm\">// ✅ Clear</span>\n\n<span class=\"cm\">// 4. Large Class — class does too much</span>\n<span class=\"kw\">class</span> <span class=\"fn\">User</span> { <span class=\"cm\">/* auth + profile + orders + notifications + ... */</span> }\n\n<span class=\"cm\">// 5. Long Parameter List</span>\n<span class=\"kw\">function</span> <span class=\"fn\">createUser</span>(name, email, age, city, country, phone, role) {} <span class=\"cm\">// ❌</span>\n<span class=\"kw\">function</span> <span class=\"fn\">createUser</span>(userData) {} <span class=\"cm\">// ✅ Pass an object</span></div>\n      <div class=\"explain\">\n        <strong>Long Method</strong> — if a function does not fit on screen, it probably does too much. Split it into parts.<br>\n        <strong>Magic Numbers</strong> — move into named constants. Code should explain itself.<br>\n        <strong>Long Parameter List</strong> — more than 3 parameters — reason to pass an object.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb328\" onchange=\"updateProgress(this)\"><span>Long Method — too long functions doing too much</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb329\" onchange=\"updateProgress(this)\"><span>Duplicate Code — duplicated code in different places</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb330\" onchange=\"updateProgress(this)\"><span>Magic Numbers — numbers without explanation, constants are you need</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-refactor-dry-kiss","title":"DRY, KISS, YAGNI — main principles basics 🔗","html":"<div class=\"block\" id=\"block-refactor-dry-kiss\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-refactor-dry-kiss')\">DRY, KISS, YAGNI — main principles <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// DRY — Don't Repeat Yourself</span>\n<span class=\"cm\">// ❌ Before</span>\n<span class=\"kw\">const</span> tax1 = price1 * <span class=\"num\">0.2</span>;\n<span class=\"kw\">const</span> tax2 = price2 * <span class=\"num\">0.2</span>;\n\n<span class=\"cm\">// ✅ After</span>\n<span class=\"kw\">const</span> calculateTax = price =&gt; price * TAX_RATE;\n\n<span class=\"cm\">// KISS — Keep It Simple, Stupid</span>\n<span class=\"cm\">// ❌ Too clever</span>\n<span class=\"kw\">const</span> isEven = n =&gt; !(n &amp; <span class=\"num\">1</span>);\n\n<span class=\"cm\">// ✅ Simple and clear</span>\n<span class=\"kw\">const</span> isEven = n =&gt; n % <span class=\"num\">2</span> === <span class=\"num\">0</span>;\n\n<span class=\"cm\">// YAGNI — You Aren't Gonna Need It</span>\n<span class=\"cm\">// ❌ \"What if it is needed in the future\"</span>\n<span class=\"kw\">function</span> <span class=\"fn\">processData</span>(data, options = {}) {\n  <span class=\"kw\">const</span> { format, validate, transform, cache, retry, timeout, logger } = options;\n  <span class=\"cm\">// 7 options, only format is used</span>\n}\n\n<span class=\"cm\">// ✅ Add complexity when it is REALLY needed</span>\n<span class=\"kw\">function</span> <span class=\"fn\">processData</span>(data, format) { <span class=\"cm\">/* ... */</span> }</div>\n      <div class=\"explain\">\n        <strong>DRY</strong> — if you copy code more than once, extract it into a function.<br>\n        <strong>KISS</strong> — write code for humans, not for computers. Readability matters more than \"cleverness\".<br>\n        <strong>YAGNI</strong> — do not add functionality \"for the future\". When needed — add it.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb331\" onchange=\"updateProgress(this)\"><span>DRY — do not repeat the same code</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb332\" onchange=\"updateProgress(this)\"><span>KISS — simple code is better than \"clever\" code</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb333\" onchange=\"updateProgress(this)\"><span>YAGNI — do not write code \"for the future\" in advance</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-refactor-extract","title":"Extract Function and Extract Variable important 🔗","html":"<div class=\"block\" id=\"block-refactor-extract\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-refactor-extract')\">Extract Function and Extract Variable <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// ❌ Before refactoring</span>\n<span class=\"kw\">function</span> <span class=\"fn\">printInvoice</span>(order) {\n  console.<span class=\"fn\">log</span>(<span class=\"str\">`Order #${order.id}`</span>);\n  <span class=\"kw\">let</span> total = <span class=\"num\">0</span>;\n  <span class=\"kw\">for</span> (<span class=\"kw\">const</span> item <span class=\"kw\">of</span> order.items) {\n    total += item.price * item.qty * (<span class=\"num\">1</span> - item.discount);\n  }\n  console.<span class=\"fn\">log</span>(<span class=\"str\">`Total: ${total}`</span>);\n}\n\n<span class=\"cm\">// ✅ After — Extract Function + Extract Variable</span>\n<span class=\"kw\">function</span> <span class=\"fn\">calculateItemTotal</span>(item) {\n  <span class=\"kw\">const</span> discountMultiplier = <span class=\"num\">1</span> - item.discount; <span class=\"cm\">// Extract Variable</span>\n  <span class=\"kw\">return</span> item.price * item.qty * discountMultiplier;\n}\n\n<span class=\"kw\">function</span> <span class=\"fn\">calculateOrderTotal</span>(order) { <span class=\"cm\">// Extract Function</span>\n  <span class=\"kw\">return</span> order.items.<span class=\"fn\">reduce</span>((sum, item) =&gt; sum + <span class=\"fn\">calculateItemTotal</span>(item), <span class=\"num\">0</span>);\n}\n\n<span class=\"kw\">function</span> <span class=\"fn\">printInvoice</span>(order) {\n  console.<span class=\"fn\">log</span>(<span class=\"str\">`Order #${order.id}`</span>);\n  console.<span class=\"fn\">log</span>(<span class=\"str\">`Total: ${calculateOrderTotal(order)}`</span>);\n} <span class=\"cm\">// Now each function does exactly one thing</span></div>\n      <div class=\"explain\">\n        <strong>Extract Function</strong> — extract a piece of logic into a separate function with a clear name.<br>\n        <strong>Extract Variable</strong> — give a name to a complex expression so it is clear what it means.<br>\n        <strong>Result</strong> — each function reads like a sentence and is easy to test separately.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb334\" onchange=\"updateProgress(this)\"><span>Extract Function — extract logic into a separate function</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb335\" onchange=\"updateProgress(this)\"><span>Extract Variable — naming complex expressions</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb336\" onchange=\"updateProgress(this)\"><span>Each function does one thing (Single Responsibility)</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-refactor-conditionals","title":"Refactoring conditions important 🔗","html":"<div class=\"block\" id=\"block-refactor-conditionals\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-refactor-conditionals')\">Refactoring conditions <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// ❌ Nested ifs are hard to read</span>\n<span class=\"kw\">function</span> <span class=\"fn\">getDiscount</span>(user) {\n  <span class=\"kw\">if</span> (user.isPremium) {\n    <span class=\"kw\">if</span> (user.years &gt; <span class=\"num\">2</span>) {\n      <span class=\"kw\">return</span> <span class=\"num\">0.3</span>;\n    } <span class=\"kw\">else</span> {\n      <span class=\"kw\">return</span> <span class=\"num\">0.2</span>;\n    }\n  } <span class=\"kw\">else</span> {\n    <span class=\"kw\">return</span> <span class=\"num\">0</span>;\n  }\n}\n\n<span class=\"cm\">// ✅ Early Return — exit immediately, without nesting</span>\n<span class=\"kw\">function</span> <span class=\"fn\">getDiscount</span>(user) {\n  <span class=\"kw\">if</span> (!user.isPremium) <span class=\"kw\">return</span> <span class=\"num\">0</span>;\n  <span class=\"kw\">if</span> (user.years &gt; <span class=\"num\">2</span>) <span class=\"kw\">return</span> <span class=\"num\">0.3</span>;\n  <span class=\"kw\">return</span> <span class=\"num\">0.2</span>;\n}\n\n<span class=\"cm\">// ✅ Replace Conditional with Polymorphism (when there are many conditions)</span>\n<span class=\"kw\">const</span> discountStrategies = {\n  premium2years: () =&gt; <span class=\"num\">0.3</span>,\n  premium: () =&gt; <span class=\"num\">0.2</span>,\n  regular: () =&gt; <span class=\"num\">0</span>\n};</div>\n      <div class=\"explain\">\n        <strong>Early Return</strong> — removes nested if-else. Code becomes flat and readable.<br>\n        <strong>Guard Clauses</strong> — checks at the beginning of a function that immediately exit if the condition is not met.<br>\n        <strong>Polymorphism instead of if/switch</strong> — when there are many conditions (5+), a table/object is cleaner.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb337\" onchange=\"updateProgress(this)\"><span>Early Return — remove nesting through early exit</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb338\" onchange=\"updateProgress(this)\"><span>Guard Clauses — checks at the beginning of a function</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb339\" onchange=\"updateProgress(this)\"><span>Replace big if/switch with an object dictionary</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-refactor-when","title":"When to refactor (and when not to) know 🔗","html":"<div class=\"block\" id=\"block-refactor-when\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-refactor-when')\">When to refactor (and when not to) <span class=\"badge\">know</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// ✅ Good time for refactoring:</span>\n- Before adding a new feature into dirty code\n- When you see a Code Smell twice (Rule of Three)\n- After tests are green (refactor with confidence)\n- Code review — colleague pointed out a problem\n\n<span class=\"cm\">// ❌ Bad time for refactoring:</span>\n- Right before a deadline\n- When there are no tests and you cannot check that nothing broke\n- \"Just because I dislike the style\" without a reason\n- If code works and does not need touching (legacy without changes)\n\n<span class=\"cm\">// Rule of Three</span>\n<span class=\"cm\">// 1st time: just write code</span>\n<span class=\"cm\">// 2nd time: copied something similar — this is OK, mark the duplicate</span>\n<span class=\"cm\">// 3rd time: repeated → now refactor into a shared function</span></div>\n      <div class=\"explain\">\n        <strong>Rule of Three</strong> — do not rush to abstract from the first repetition. On the third time — refactor for sure.<br>\n        <strong>Small steps</strong> — refactor in small safe changes, testing after each one.<br>\n        <strong>Tests are your protection</strong> — without tests, refactoring turns into Russian roulette.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb340\" onchange=\"updateProgress(this)\"><span>Rule of Three — refactor after the third repetition</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb341\" onchange=\"updateProgress(this)\"><span>I understand when NOT to refactor</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb342\" onchange=\"updateProgress(this)\"><span>I refactor in small steps with checks</span></label>\n      </div>\n    </div>\n  "}]},{"id":"sec-links","lessons":[{"id":"block-links-animation","title":"Animations and visual effects 🔗 links","html":"<div class=\"block\" id=\"block-links-animation\">\n      <div class=\"block-title\">Animations and visual effects <span class=\"badge good\">🔗 links</span></div>\n      <div style=\"display:flex;flex-direction:column;gap:10px;margin-top:8px;\">\n\n        <a href=\"https://animejs.com\" target=\"_blank\" style=\"display:flex;align-items:flex-start;gap:12px;padding:14px;background:var(--bg-card);border:1px solid var(--border);border-radius:10px;text-decoration:none;transition:border-color .2s;\" onmouseover=\"this.style.borderColor='#6366f1'\" onmouseout=\"this.style.borderColor='var(--border)'\">\n          <div style=\"font-size:1.8rem;flex-shrink:0;\">⚡</div>\n          <div>\n            <div style=\"font-weight:700;color:var(--text);font-size:14px;\">Anime.js — animejs.com</div>\n            <div style=\"color:var(--text-muted);font-size:12px;margin-top:3px;\">Best JS animation library. Lightweight, powerful, clear API. Animate CSS, SVG, DOM, and JS objects equally easily.</div>\n            <div style=\"margin-top:6px;display:flex;gap:6px;flex-wrap:wrap;\">\n              <span style=\"background:#4f46e5;color:#fff;padding:2px 8px;border-radius:4px;font-size:11px;\">JavaScript</span>\n              <span style=\"background:#0891b2;color:#fff;padding:2px 8px;border-radius:4px;font-size:11px;\">Animations</span>\n              <span style=\"background:#16a34a;color:#fff;padding:2px 8px;border-radius:4px;font-size:11px;\">Free</span>\n            </div>\n          </div>\n        </a>\n\n        <a href=\"https://gsap.com\" target=\"_blank\" style=\"display:flex;align-items:flex-start;gap:12px;padding:14px;background:var(--bg-card);border:1px solid var(--border);border-radius:10px;text-decoration:none;transition:border-color .2s;\" onmouseover=\"this.style.borderColor='#22c55e'\" onmouseout=\"this.style.borderColor='var(--border)'\">\n          <div style=\"font-size:1.8rem;flex-shrink:0;\">🟢</div>\n          <div>\n            <div style=\"font-weight:700;color:var(--text);font-size:14px;\">GSAP — gsap.com</div>\n            <div style=\"color:var(--text-muted);font-size:12px;margin-top:3px;\">Professional animation standard. Used on huge sites. Timeline, ScrollTrigger, SVG morphing.</div>\n            <div style=\"margin-top:6px;display:flex;gap:6px;flex-wrap:wrap;\">\n              <span style=\"background:#15803d;color:#fff;padding:2px 8px;border-radius:4px;font-size:11px;\">JavaScript</span>\n              <span style=\"background:#0891b2;color:#fff;padding:2px 8px;border-radius:4px;font-size:11px;\">Scroll</span>\n              <span style=\"background:#9333ea;color:#fff;padding:2px 8px;border-radius:4px;font-size:11px;\">SVG</span>\n            </div>\n          </div>\n        </a>\n\n        <a href=\"https://motion.dev\" target=\"_blank\" style=\"display:flex;align-items:flex-start;gap:12px;padding:14px;background:var(--bg-card);border:1px solid var(--border);border-radius:10px;text-decoration:none;transition:border-color .2s;\" onmouseover=\"this.style.borderColor='#f59e0b'\" onmouseout=\"this.style.borderColor='var(--border)'\">\n          <div style=\"font-size:1.8rem;flex-shrink:0;\">🎭</div>\n          <div>\n            <div style=\"font-weight:700;color:var(--text);font-size:14px;\">Motion — motion.dev</div>\n            <div style=\"color:var(--text-muted);font-size:12px;margin-top:3px;\">Framer Motion for React. Declarative animations directly in JSX. Standard for React projects.</div>\n            <div style=\"margin-top:6px;display:flex;gap:6px;flex-wrap:wrap;\">\n              <span style=\"background:#0891b2;color:#fff;padding:2px 8px;border-radius:4px;font-size:11px;\">React</span>\n              <span style=\"background:#4f46e5;color:#fff;padding:2px 8px;border-radius:4px;font-size:11px;\">Declarative</span>\n            </div>\n          </div>\n        </a>\n      </div>\n    </div>\n\n    "},{"id":"block-links-css-tools","title":"CSS tools 🔗 links","html":"<div class=\"block\" id=\"block-links-css-tools\">\n      <div class=\"block-title\">CSS tools <span class=\"badge good\">🔗 links</span></div>\n      <div style=\"display:flex;flex-direction:column;gap:10px;margin-top:8px;\">\n\n        <a href=\"https://uiverse.io\" target=\"_blank\" style=\"display:flex;align-items:flex-start;gap:12px;padding:14px;background:var(--bg-card);border:1px solid var(--border);border-radius:10px;text-decoration:none;transition:border-color .2s;\" onmouseover=\"this.style.borderColor='#8b5cf6'\" onmouseout=\"this.style.borderColor='var(--border)'\">\n          <div style=\"font-size:1.8rem;flex-shrink:0;\">🎨</div>\n          <div>\n            <div style=\"font-weight:700;color:var(--text);font-size:14px;\">UIverse — uiverse.io</div>\n            <div style=\"color:var(--text-muted);font-size:12px;margin-top:3px;\">Huge library of CSS components — buttons, cards, inputs, loaders. Everything is free and with code.</div>\n          </div>\n        </a>\n\n        <a href=\"https://cssgradient.io\" target=\"_blank\" style=\"display:flex;align-items:flex-start;gap:12px;padding:14px;background:var(--bg-card);border:1px solid var(--border);border-radius:10px;text-decoration:none;transition:border-color .2s;\" onmouseover=\"this.style.borderColor='#ec4899'\" onmouseout=\"this.style.borderColor='var(--border)'\">\n          <div style=\"font-size:1.8rem;flex-shrink:0;\">🌈</div>\n          <div>\n            <div style=\"font-weight:700;color:var(--text);font-size:14px;\">CSS Gradient — cssgradient.io</div>\n            <div style=\"color:var(--text-muted);font-size:12px;margin-top:3px;\">Visual gradient generator. Copy ready CSS in one click.</div>\n          </div>\n        </a>\n\n        <a href=\"https://cubic-bezier.com\" target=\"_blank\" style=\"display:flex;align-items:flex-start;gap:12px;padding:14px;background:var(--bg-card);border:1px solid var(--border);border-radius:10px;text-decoration:none;transition:border-color .2s;\" onmouseover=\"this.style.borderColor='#06b6d4'\" onmouseout=\"this.style.borderColor='var(--border)'\">\n          <div style=\"font-size:1.8rem;flex-shrink:0;\">📐</div>\n          <div>\n            <div style=\"font-weight:700;color:var(--text);font-size:14px;\">Cubic Bezier — cubic-bezier.com</div>\n            <div style=\"color:var(--text-muted);font-size:12px;margin-top:3px;\">Visual editor for animation curves. Indispensable for setting transition and animation timing.</div>\n          </div>\n        </a>\n      </div>\n    </div>\n\n    "},{"id":"block-links-dev-tools","title":"Developer tools 🔗 links","html":"<div class=\"block\" id=\"block-links-dev-tools\">\n      <div class=\"block-title\">Developer tools <span class=\"badge good\">🔗 links</span></div>\n      <div style=\"display:flex;flex-direction:column;gap:10px;margin-top:8px;\">\n\n        <a href=\"https://caniuse.com\" target=\"_blank\" style=\"display:flex;align-items:flex-start;gap:12px;padding:14px;background:var(--bg-card);border:1px solid var(--border);border-radius:10px;text-decoration:none;transition:border-color .2s;\" onmouseover=\"this.style.borderColor='#f97316'\" onmouseout=\"this.style.borderColor='var(--border)'\">\n          <div style=\"font-size:1.8rem;flex-shrink:0;\">🌐</div>\n          <div>\n            <div style=\"font-weight:700;color:var(--text);font-size:14px;\">Can I Use — caniuse.com</div>\n            <div style=\"color:var(--text-muted);font-size:12px;margin-top:3px;\">Check CSS and JS feature support in browsers. Open before using something new.</div>\n          </div>\n        </a>\n\n        <a href=\"https://bundlephobia.com\" target=\"_blank\" style=\"display:flex;align-items:flex-start;gap:12px;padding:14px;background:var(--bg-card);border:1px solid var(--border);border-radius:10px;text-decoration:none;transition:border-color .2s;\" onmouseover=\"this.style.borderColor='#ef4444'\" onmouseout=\"this.style.borderColor='var(--border)'\">\n          <div style=\"font-size:1.8rem;flex-shrink:0;\">📦</div>\n          <div>\n            <div style=\"font-weight:700;color:var(--text);font-size:14px;\">Bundlephobia — bundlephobia.com</div>\n            <div style=\"color:var(--text-muted);font-size:12px;margin-top:3px;\">Check npm package size before installing. Helps avoid bloating the bundle with unnecessary dependencies.</div>\n          </div>\n        </a>\n\n        <a href=\"https://ray.so\" target=\"_blank\" style=\"display:flex;align-items:flex-start;gap:12px;padding:14px;background:var(--bg-card);border:1px solid var(--border);border-radius:10px;text-decoration:none;transition:border-color .2s;\" onmouseover=\"this.style.borderColor='#8b5cf6'\" onmouseout=\"this.style.borderColor='var(--border)'\">\n          <div style=\"font-size:1.8rem;flex-shrink:0;\">📸</div>\n          <div>\n            <div style=\"font-weight:700;color:var(--text);font-size:14px;\">Ray.so — ray.so</div>\n            <div style=\"color:var(--text-muted);font-size:12px;margin-top:3px;\">Beautiful code screenshots for portfolios, README files and social media. Free, no registration.</div>\n          </div>\n        </a>\n      </div>\n    </div>\n\n  \n\n\n  "}]},{"id":"sec-algo","lessons":[{"id":"block-algo-complexity","title":"Big O — algorithm complexity basics 🔗","html":"<div class=\"block\" id=\"block-algo-complexity\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-algo-complexity')\">Big O — algorithm complexity <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Big O describes how runtime grows as data grows. This is the language used to talk about algorithm efficiency.</div>\n      <div class=\"code\"><span class=\"cm\">// O(1) — constant time (best)</span>\n<span class=\"kw\">const</span> getFirst = arr =&gt; arr[<span class=\"num\">0</span>]; <span class=\"cm\">// always 1 operation</span>\n\n<span class=\"cm\">// O(n) — linear time</span>\n<span class=\"kw\">const</span> findMax = arr =&gt; {\n  <span class=\"kw\">let</span> max = arr[<span class=\"num\">0</span>];\n  <span class=\"kw\">for</span> (<span class=\"kw\">const</span> x <span class=\"kw\">of</span> arr) <span class=\"kw\">if</span> (x &gt; max) max = x;\n  <span class=\"kw\">return</span> max;\n}; <span class=\"cm\">// n operations on n elements</span>\n\n<span class=\"cm\">// O(n²) — quadratic (bad for large data)</span>\n<span class=\"kw\">function</span> <span class=\"fn\">bubbleSort</span>(arr) {\n  <span class=\"kw\">for</span> (<span class=\"kw\">let</span> i = <span class=\"num\">0</span>; i &lt; arr.length; i++)\n    <span class=\"kw\">for</span> (<span class=\"kw\">let</span> j = <span class=\"num\">0</span>; j &lt; arr.length - i; j++)\n      <span class=\"kw\">if</span> (arr[j] &gt; arr[j+<span class=\"num\">1</span>]) [arr[j], arr[j+<span class=\"num\">1</span>]] = [arr[j+<span class=\"num\">1</span>], arr[j]];\n  <span class=\"kw\">return</span> arr;\n}\n\n<span class=\"cm\">// O(log n) — logarithmic (very fast)</span>\n<span class=\"cm\">// Binary search: split in half at each step</span>\n\n<span class=\"cm\">// Complexity cheat sheet</span>\n<span class=\"cm\">// Array.push/pop     → O(1)</span>\n<span class=\"cm\">// Array.includes     → O(n)</span>\n<span class=\"cm\">// Array.sort         → O(n log n)</span>\n<span class=\"cm\">// Object lookup      → O(1)</span></div>\n      <div class=\"explain\">\n        <strong>O(1)</strong> — ideal. Does not depend on data size.<br>\n        <strong>O(n)</strong> — normal. Grows linearly with data.<br>\n        <strong>O(n²)</strong> — careful. With 1000 elements = 1,000,000 operations.<br>\n        <strong>Main rule:</strong> if you see a loop inside a loop, it is most likely O(n²).\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb343\" onchange=\"updateProgress(this)\"><span>O(1), O(n), O(n²), O(log n) — understand the difference</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb344\" onchange=\"updateProgress(this)\"><span>I know the complexity of basic operations with arrays and objects</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-algo-array","title":"Array tasks — top interview topic basics 🔗","html":"<div class=\"block\" id=\"block-algo-array\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-algo-array')\">Array tasks — top interview topic <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// 1. Remove duplicates</span>\n<span class=\"kw\">const</span> unique = arr =&gt; [...<span class=\"kw\">new</span> Set(arr)];\n<span class=\"fn\">unique</span>([<span class=\"num\">1</span>,<span class=\"num\">2</span>,<span class=\"num\">2</span>,<span class=\"num\">3</span>]); <span class=\"cm\">// [1,2,3]</span>\n\n<span class=\"cm\">// 2. Sum of elements</span>\n<span class=\"kw\">const</span> sum = arr =&gt; arr.<span class=\"fn\">reduce</span>((a, b) =&gt; a + b, <span class=\"num\">0</span>);\n\n<span class=\"cm\">// 3. Reverse an array (without reverse)</span>\n<span class=\"kw\">const</span> rev = arr =&gt; arr.<span class=\"fn\">reduceRight</span>((acc, x) =&gt; [...acc, x], []);\n\n<span class=\"cm\">// 4. Find two numbers with sum N (Two Sum)</span>\n<span class=\"kw\">function</span> <span class=\"fn\">twoSum</span>(nums, target) {\n  <span class=\"kw\">const</span> map = <span class=\"kw\">new</span> Map();\n  <span class=\"kw\">for</span> (<span class=\"kw\">let</span> i = <span class=\"num\">0</span>; i &lt; nums.length; i++) {\n    <span class=\"kw\">const</span> diff = target - nums[i];\n    <span class=\"kw\">if</span> (map.<span class=\"fn\">has</span>(diff)) <span class=\"kw\">return</span> [map.<span class=\"fn\">get</span>(diff), i];\n    map.<span class=\"fn\">set</span>(nums[i], i);\n  }\n} <span class=\"cm\">// O(n) instead of O(n²) — use Map</span>\n\n<span class=\"cm\">// 5. Group by property</span>\n<span class=\"kw\">const</span> users = [{role:<span class=\"str\">'admin'</span>},{role:<span class=\"str\">'user'</span>},{role:<span class=\"str\">'admin'</span>}];\n<span class=\"kw\">const</span> grouped = users.<span class=\"fn\">reduce</span>((acc, u) =&gt; {\n  (acc[u.role] ??= []).<span class=\"fn\">push</span>(u);\n  <span class=\"kw\">return</span> acc;\n}, {});</div>\n      <div class=\"explain\">\n        <strong>Set</strong> — data structure without duplicates. Lookup O(1).<br>\n        <strong>Map</strong> — like an object, but the key can be anything. Use for search optimization.<br>\n        <strong>TwoSum with Map</strong> — classic example of how Map turns O(n²) into O(n).\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb345\" onchange=\"updateProgress(this)\"><span>Set — remove duplicates from an array</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb346\" onchange=\"updateProgress(this)\"><span>reduce — sum, grouping, accumulation</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb347\" onchange=\"updateProgress(this)\"><span>Map for optimization — O(n) instead of O(n²)</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-algo-string","title":"String tasks important 🔗","html":"<div class=\"block\" id=\"block-algo-string\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-algo-string')\">String tasks <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// 1. Palindrome</span>\n<span class=\"kw\">const</span> isPalin = s =&gt; s === [...s].<span class=\"fn\">reverse</span>().<span class=\"fn\">join</span>(<span class=\"str\">''</span>);\n\n<span class=\"cm\">// 2. Anagrams</span>\n<span class=\"kw\">const</span> isAnagram = (a, b) =&gt;\n  [...a].<span class=\"fn\">sort</span>().<span class=\"fn\">join</span>(<span class=\"str\">''</span>) === [...b].<span class=\"fn\">sort</span>().<span class=\"fn\">join</span>(<span class=\"str\">''</span>);\n\n<span class=\"cm\">// 3. Reverse a string</span>\n<span class=\"kw\">const</span> reverse = s =&gt; [...s].<span class=\"fn\">reverse</span>().<span class=\"fn\">join</span>(<span class=\"str\">''</span>);\n\n<span class=\"cm\">// 4. Count each character</span>\n<span class=\"kw\">const</span> <span class=\"fn\">charCount</span> = s =&gt;\n  [...s].<span class=\"fn\">reduce</span>((acc, c) =&gt; ({ ...acc, [c]: (acc[c] || <span class=\"num\">0</span>) + <span class=\"num\">1</span> }), {});\n\n<span class=\"cm\">// 5. First non-repeating character</span>\n<span class=\"kw\">const</span> <span class=\"fn\">firstUniq</span> = s =&gt; {\n  <span class=\"kw\">const</span> cnt = <span class=\"fn\">charCount</span>(s);\n  <span class=\"kw\">return</span> [...s].<span class=\"fn\">find</span>(c =&gt; cnt[c] === <span class=\"num\">1</span>) ?? <span class=\"str\">''</span>;\n};</div>\n      <div class=\"explain\">\n        <strong>[...s]</strong> — spreads a string into an array of characters. Needed for correct Unicode handling.<br>\n        <strong>Anagram through sort</strong> — simple O(n log n) solution. There is an O(n) solution through Map.<br>\n        <strong>charCount</strong> — frequency analysis pattern. Used in dozens of tasks.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb348\" onchange=\"updateProgress(this)\"><span>Palindrome, string reverse</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb349\" onchange=\"updateProgress(this)\"><span>Anagrams — sorting or Map</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb350\" onchange=\"updateProgress(this)\"><span>Frequency analysis of characters through reduce</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-algo-recursion","title":"Recursion important 🔗","html":"<div class=\"block\" id=\"block-algo-recursion\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-algo-recursion')\">Recursion <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// Recursion = function calls itself</span>\n<span class=\"cm\">// Required: base case (exit from recursion)</span>\n\n<span class=\"cm\">// Factorial</span>\n<span class=\"kw\">function</span> <span class=\"fn\">factorial</span>(n) {\n  <span class=\"kw\">if</span> (n &lt;= <span class=\"num\">1</span>) <span class=\"kw\">return</span> <span class=\"num\">1</span>;  <span class=\"cm\">// base case</span>\n  <span class=\"kw\">return</span> n * <span class=\"fn\">factorial</span>(n - <span class=\"num\">1</span>);\n}\n\n<span class=\"cm\">// Fibonacci numbers (with memoization)</span>\n<span class=\"kw\">const</span> memo = {};\n<span class=\"kw\">function</span> <span class=\"fn\">fib</span>(n) {\n  <span class=\"kw\">if</span> (n &lt;= <span class=\"num\">1</span>) <span class=\"kw\">return</span> n;\n  <span class=\"kw\">if</span> (memo[n]) <span class=\"kw\">return</span> memo[n];\n  <span class=\"kw\">return</span> memo[n] = <span class=\"fn\">fib</span>(n-<span class=\"num\">1</span>) + <span class=\"fn\">fib</span>(n-<span class=\"num\">2</span>);\n}\n\n<span class=\"cm\">// Traversing a nested object (real task)</span>\n<span class=\"kw\">function</span> <span class=\"fn\">deepSum</span>(obj) {\n  <span class=\"kw\">return</span> Object.<span class=\"fn\">values</span>(obj).<span class=\"fn\">reduce</span>((sum, val) =&gt;\n    sum + (<span class=\"kw\">typeof</span> val === <span class=\"str\">'object'</span> ? <span class=\"fn\">deepSum</span>(val) : val), <span class=\"num\">0</span>\n  );\n}</div>\n      <div class=\"explain\">\n        <strong>Base case</strong> — without it, infinite recursion and Stack Overflow.<br>\n        <strong>Memoization</strong> — cache results. fib(40) without memo = billions of calls, with memo = 40.<br>\n        <strong>Recursion for trees</strong> — DOM traversal, file systems, nested objects.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb351\" onchange=\"updateProgress(this)\"><span>Recursion — base case + recursive call</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb352\" onchange=\"updateProgress(this)\"><span>Memoization — cache for expensive recursion</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb353\" onchange=\"updateProgress(this)\"><span>Traversing nested structures through recursion</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-algo-data-structures","title":"Data structures: Stack, Queue, Tree, Graph important 🔗","html":"<div class=\"block\" id=\"block-algo-data-structures\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-algo-data-structures')\">Data structures: Stack, Queue, Tree, Graph <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">A data structure is a way to store data so the needed operations are convenient and fast.</div>\n      <div class=\"code\"><span class=\"cm\">// Stack — pile: last in, first out</span>\nconst stack = [];\nstack.push('modal-open');\nstack.push('tooltip-open');\nstack.pop(); <span class=\"cm\">// tooltip-open</span>\n\n<span class=\"cm\">// Queue — first in, first out</span>\nconst queue = [];\nqueue.push('task-1');\nqueue.push('task-2');\nqueue.shift(); <span class=\"cm\">// task-1</span>\n\n<span class=\"cm\">// Tree — DOM, menu, file system</span>\nconst menu = {\n  title: 'Frontend',\n  children: [\n    { title: 'HTML', children: [] },\n    { title: 'CSS', children: [] }\n  ]\n};\n\n<span class=\"cm\">// Graph — relationships between entities</span>\nconst graph = new Map([\n  ['home', ['about', 'catalog']],\n  ['catalog', ['product']],\n  ['product', ['cart']]\n]);</div>\n      <div class=\"explain\">\n        <strong>Stack</strong> needed for undo/redo, navigation history, closing nested windows.<br>\n        <strong>Queue</strong> needed for task queues, downloads, messages.<br>\n        <strong>Tree</strong> appears constantly: DOM, comments, categories, menu.<br>\n        <strong>Graph</strong> — relationships: routes, friends, package dependencies, links between pages.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-algo-ds-1\" onchange=\"updateProgress(this)\"><span>Stack and Queue — understand the difference LIFO/FIFO</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-algo-ds-2\" onchange=\"updateProgress(this)\"><span>Tree — understand using DOM and menu examples</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-algo-ds-3\" onchange=\"updateProgress(this)\"><span>Graph — understand as a set of nodes and edges</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-algo-advanced-concepts","title":"AST and Bloom Filter for the future 🔗","html":"<div class=\"block\" id=\"block-algo-advanced-concepts\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-algo-advanced-concepts')\">AST and Bloom Filter <span class=\"badge rec\">for the future</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">This is not a starting basic, but these words often appear in tools: linters, bundlers, search, antispam, cache.</div>\n      <div class=\"code\"><span class=\"cm\">// AST — code tree</span>\nconst x = 2 + 3;\n\n<span class=\"cm\">// Simplified: the parser sees it like this:</span>\nVariableDeclaration\n  name: \"x\"\n  value:\n    BinaryExpression\n      left: 2\n      operator: \"+\"\n      right: 3\n\n<span class=\"cm\">// Bloom Filter — fast \"maybe exists / definitely not\"</span>\nif (bloom.has(email)) {\n  <span class=\"cm\">// maybe already seen, check in database</span>\n} else {\n  <span class=\"cm\">// definitely not seen</span>\n}</div>\n      <div class=\"explain\">\n        <strong>AST</strong> used by Babel, ESLint, TypeScript, Prettier: they read code as a tree and can check or rewrite it.<br>\n        <strong>Bloom Filter</strong> saves memory and quickly answers: \"definitely not\" or \"maybe yes\". Downside — false positives happen.<br>\n        <strong>Point of the block:</strong> do not study deeply now, just understand what happens under the hood of tools.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-algo-advanced-1\" onchange=\"updateProgress(this)\"><span>I understand AST as a code tree for linters and bundlers</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-algo-advanced-2\" onchange=\"updateProgress(this)\"><span>I understand Bloom Filter at the \"definitely not / maybe yes\" level</span></label>\n      </div>\n    </div>\n  "}]},{"id":"sec-mistakes","lessons":[{"id":"mistakes-lesson-1","title":"HTML — what beginners do wrong read!","html":"<div class=\"block\">\n      <div class=\"block-title\">HTML — what beginners do wrong <span class=\"badge must\">read!</span></div>\n      <div class=\"code\" style=\"color:#f87171;\">❌ &lt;div onclick=\"...\"&gt;Button&lt;/div&gt;\n✅ &lt;button onclick=\"...\"&gt;Button&lt;/button&gt;</div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb367\" onchange=\"updateProgress(this)\"><span>Do not skip alt on &lt;img&gt;</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb368\" onchange=\"updateProgress(this)\"><span>Do not use &lt;br&gt; for spacing — CSS margin/padding are for this</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb369\" onchange=\"updateProgress(this)\"><span>One h1 per page!</span></label>\n      </div>\n    </div>\n    "},{"id":"mistakes-lesson-2","title":"CSS — what beginners do wrong read!","html":"<div class=\"block\">\n      <div class=\"block-title\">CSS — what beginners do wrong <span class=\"badge must\">read!</span></div>\n      <div class=\"code\" style=\"color:#f87171;\">❌ .box { width: 300px; padding: 20px; }   → real width 340px!\n✅ * { box-sizing: border-box; }\n   .box { width: 300px; padding: 20px; }  → width 300px</div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb370\" onchange=\"updateProgress(this)\"><span>* { box-sizing: border-box; } — first CSS line!</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb371\" onchange=\"updateProgress(this)\"><span>Do not use !important — learn specificity</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb372\" onchange=\"updateProgress(this)\"><span>position: absolute without position: relative on the parent = trouble</span></label>\n      </div>\n    </div>\n    "},{"id":"mistakes-lesson-3","title":"JavaScript — what beginners do wrong read!","html":"<div class=\"block\">\n      <div class=\"block-title\">JavaScript — what beginners do wrong <span class=\"badge must\">read!</span></div>\n      <div class=\"code\" style=\"color:#f87171;\">❌ if (x = 5)   → this is ASSIGNMENT, not comparison!\n✅ if (x === 5) → this is COMPARISON\n\n❌ \"5\" + 3 = \"53\"      → string + number = concatenation\n✅ Number(\"5\") + 3 = 8 → convert first</div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb373\" onchange=\"updateProgress(this)\"><span>=== (strict) instead of == (loose)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb374\" onchange=\"updateProgress(this)\"><span>Always const or let. Without them — global variable!</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb375\" onchange=\"updateProgress(this)\"><span>F12 → Console — ALL errors are printed there</span></label>\n      </div>\n    </div>\n    "},{"id":"block-mistakes-async","title":"async/await and Promise — typical traps read!","html":"<div class=\"block\" id=\"block-mistakes-async\">\n      <div class=\"block-title\">async/await and Promise — typical traps <span class=\"badge must\">read!</span></div>\n      <div class=\"code\" style=\"color:#f87171;\">❌ async function getData() {\n  const data = fetch('/api/users');  // forgot await!\n  console.log(data);                 // [object Promise], not data\n}\n\n❌ async function getData() {\n  const data = await fetch('/api/users');  // no try/catch\n  return data.json();                       // fails silently if the network is unavailable\n}\n\n✅ async function getData() {\n  try {\n    const res = await fetch('/api/users');\n    if (!res.ok) throw new Error('HTTP ' + res.status);\n    return await res.json();\n  } catch (err) {\n    console.error('Error:', err.message);\n  }\n}</div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb384\" onchange=\"updateProgress(this)\"><span>await is required before fetch(), otherwise you get a Promise, not data</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb385\" onchange=\"updateProgress(this)\"><span>Always wrap async code in try/catch — network can fail</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb386\" onchange=\"updateProgress(this)\"><span>Check res.ok — fetch does not throw an error on 404 or 500!</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-mistakes-scope","title":"z-index, position, overflow — three musketeers read!","html":"<div class=\"block\" id=\"block-mistakes-scope\">\n      <div class=\"block-title\">z-index, position, overflow — three musketeers <span class=\"badge must\">read!</span></div>\n      <div class=\"code\" style=\"color:#f87171;\">❌ .tooltip { position: static; z-index: 9999; }\n   /* z-index does NOT work without position: relative/absolute/fixed/sticky */\n\n✅ .tooltip { position: relative; z-index: 9999; }\n\n❌ .card { overflow: hidden; }\n   .card .dropdown { position: absolute; }\n   /* dropdown will be clipped by the parent! */\n\n✅ /* Either remove overflow: hidden from .card,\n      or move the dropdown to the end of body through JS */\n\n❌ .modal { position: fixed; top: 50%; left: 50%; }\n   /* not centered — corner, not center */\n✅ .modal { position: fixed; top: 50%; left: 50%;\n             transform: translate(-50%, -50%); }</div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb387\" onchange=\"updateProgress(this)\"><span>z-index works only on position: relative/absolute/fixed/sticky</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb388\" onchange=\"updateProgress(this)\"><span>overflow: hidden on the parent clips absolute children — careful with dropdowns</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb389\" onchange=\"updateProgress(this)\"><span>Centering a fixed element: top/left 50% + transform: translate(-50%,-50%)</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-mistakes-events","title":"EventListener — memory leaks and duplicates read!","html":"<div class=\"block\" id=\"block-mistakes-events\">\n      <div class=\"block-title\">EventListener — memory leaks and duplicates <span class=\"badge must\">read!</span></div>\n      <div class=\"code\" style=\"color:#f87171;\">❌ // Each click adds ONE MORE handler:\nfunction render() {\n  document.getElementById('btn').addEventListener('click', handler);\n}\nrender(); render(); render(); // now 3 identical handlers!\n\n✅ // Option 1 — remove before adding:\nbtn.removeEventListener('click', handler);\nbtn.addEventListener('click', handler);\n\n✅ // Option 2 — delegation (one handler on parent):\ndocument.getElementById('list').addEventListener('click', (e) =&gt; {\n  if (e.target.matches('.item')) handleItem(e.target);\n});\n\n❌ // Anonymous function — cannot be removed!\nbtn.addEventListener('click', () =&gt; doSomething());\nbtn.removeEventListener('click', () =&gt; doSomething()); // does NOT work!\n\n✅ function handler() { doSomething(); }\nbtn.addEventListener('click', handler);\nbtn.removeEventListener('click', handler); // ✓</div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb390\" onchange=\"updateProgress(this)\"><span>Do not add addEventListener repeatedly without removeEventListener — duplicates will appear</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb391\" onchange=\"updateProgress(this)\"><span>Event delegation — one handler on parent instead of 100 on children</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb392\" onchange=\"updateProgress(this)\"><span>Anonymous function cannot be removed through removeEventListener — give functions names</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-mistakes-specificity","title":"CSS specificity — why styles do not apply important","html":"<div class=\"block\" id=\"block-mistakes-specificity\">\n      <div class=\"block-title\">CSS specificity — why styles do not apply <span class=\"badge good\">important</span></div>\n      <div class=\"code\" style=\"color:#f87171;\">/* Specificity is read as (ID, class, tag) */\n/* More specific selector wins, not the one written lower! */\n\n❌ .nav a { color: blue; }   /* specificity: 0-1-1 */\n   a { color: red; }          /* specificity: 0-0-1 — LOSES */\n   /* Red will not apply, even though it is written later! */\n\n❌ /* \"Solution\" through !important — creates chaos */\n   a { color: red !important; }\n\n✅ /* Correct solution — align specificity */\n   .nav a { color: blue; }\n   .content a { color: red; } /* also 0-1-1, order wins */\n\n/* Specificity table:\n   Inline style=\"\"     → 1-0-0-0  (strongest)\n   #id                 → 0-1-0-0\n   .class, [attr], :hover → 0-0-1-0\n   div, p, span        → 0-0-0-1  (weakest) */</div>\n      <div class=\"specificity-tool\">\n        <div class=\"tool-row\">\n          <input class=\"tool-input\" id=\"specSelectorA\" value=\".nav ul li a:hover\" oninput=\"updateSpecificityTool()\" aria-label=\"First CSS selector\">\n          <input class=\"tool-input\" id=\"specSelectorB\" value=\"#header a\" oninput=\"updateSpecificityTool()\" aria-label=\"Second CSS selector\">\n        </div>\n        <div class=\"tool-result\" id=\"specResult\">Calculator shows specificity points.</div>\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb393\" onchange=\"updateProgress(this)\"><span>I understand how specificity is calculated: ID &gt; class &gt; tag</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb394\" onchange=\"updateProgress(this)\"><span>!important — last resort, not the first solution</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb395\" onchange=\"updateProgress(this)\"><span>Inline style overrides any CSS in the file</span></label>\n      </div>\n    </div>\n\n    "}]},{"id":"sec-resources","lessons":[{"id":"resources-lesson-1","title":"Free courses and textbooks must have","html":"<div class=\"block\">\n      <div class=\"block-title\">Free courses and textbooks <span class=\"badge must\">must have</span></div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb396\" onchange=\"updateProgress(this)\"><span>📖 <a href=\"https://developer.mozilla.org/ru/\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">MDN Web Docs</a> — official HTML/CSS/JS documentation</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb397\" onchange=\"updateProgress(this)\"><span>🎓 <a href=\"https://www.freecodecamp.org/\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">freeCodeCamp.org</a> — free lessons with practice and certificates</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb398\" onchange=\"updateProgress(this)\"><span>📘 <a href=\"https://learn.javascript.ru/\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">learn.javascript.ru</a> — a comprehensive JavaScript tutorial</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb399\" onchange=\"updateProgress(this)\"><span>🏫 <a href=\"https://htmlacademy.ru/\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">HTML Academy</a> — free interactive HTML/CSS exercises</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb400\" onchange=\"updateProgress(this)\"><span>🎮 <a href=\"https://css-tricks.com/snippets/css/a-guide-to-flexbox/\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">CSS-Tricks Flexbox Guide</a> — an excellent Flexbox reference</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb401\" onchange=\"updateProgress(this)\"><span>🕹️ <a href=\"https://flexboxfroggy.com/\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">Flexbox Froggy</a> — learn Flexbox through a game</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb402\" onchange=\"updateProgress(this)\"><span>🌐 <a href=\"https://codepen.io/\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">CodePen</a> / <a href=\"https://jsfiddle.net/\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">JSFiddle</a> — online playground</span></label>\n      </div>\n    </div>\n    "},{"id":"resources-lesson-2","title":"YouTube channels and podcasts content","html":"<div class=\"block\">\n      <div class=\"block-title\">YouTube channels and podcasts <span class=\"badge good\">content</span></div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb403\" onchange=\"updateProgress(this)\"><span>▶️ <a href=\"https://www.youtube.com/@VladilenMinin\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">Vladilen Minin</a> — React, TypeScript, and Node.js tutorials</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb404\" onchange=\"updateProgress(this)\"><span>▶️ <a href=\"https://www.youtube.com/@UlbiTV\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">Ulbi TV</a> — frontend, backend, and architecture</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb405\" onchange=\"updateProgress(this)\"><span>▶️ <a href=\"https://www.youtube.com/@TraversyMedia\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">Traversy Media</a> — practical tutorials in English</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb406\" onchange=\"updateProgress(this)\"><span>▶️ <a href=\"https://www.youtube.com/@KevinPowell\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">Kevin Powell</a> — great CSS tips and tricks</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb407\" onchange=\"updateProgress(this)\"><span>▶️ <a href=\"https://www.youtube.com/@Fireship\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">Fireship</a> — technology explained in 100 seconds</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb408\" onchange=\"updateProgress(this)\"><span>🎙️ <a href=\"https://syntax.fm/\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">Syntax.fm</a> — an English frontend podcast about current topics</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb409\" onchange=\"updateProgress(this)\"><span>🎙️ <a href=\"https://www.youtube.com/c/DevChatsTV\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">Web Standards</a> — a web development podcast</span></label>\n      </div>\n    </div>\n    "},{"id":"resources-lesson-3","title":"Tools important","html":"<div class=\"block\">\n      <div class=\"block-title\">Tools <span class=\"badge good\">important</span></div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb410\" onchange=\"updateProgress(this)\"><span><a href=\"https://code.visualstudio.com/\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">VS Code</a> + Live Server and Prettier extensions</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb411\" onchange=\"updateProgress(this)\"><span>Chrome DevTools (F12) — console, inspector, network tab</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb412\" onchange=\"updateProgress(this)\"><span><a href=\"https://github.com/\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">GitHub</a> — store code and show your portfolio to employers</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb413\" onchange=\"updateProgress(this)\"><span><a href=\"https://www.figma.com/\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">Figma</a> (free) — designs and layouts for frontend practice</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb414\" onchange=\"updateProgress(this)\"><span><a href=\"https://caniuse.com/\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">CanIUse.com</a> — check browser support for CSS and JavaScript features</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb415\" onchange=\"updateProgress(this)\"><span><a href=\"https://roadmap.sh/\" target=\"_blank\" rel=\"noopener\" style=\"color:inherit;font-weight:600;\">roadmap.sh</a> — frontend and backend developer roadmaps</span></label>\n      </div>\n    </div>\n    "}]},{"id":"sec-roadmap","lessons":[{"id":"roadmap-lesson-1","title":"🗺️ Map: from zero to first project plan","html":"<div class=\"block\">\n      <div class=\"block-title\">🗺️ Map: from zero to first project <span class=\"badge must\">plan</span></div>\n      <div class=\"tip\">Go step by step. Do not skip around! Mark each completed stage.</div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb416\" onchange=\"updateProgress(this)\"><span>📌 Stage 0: HTML — structure, tags, forms, semantics (1–2 weeks)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb417\" onchange=\"updateProgress(this)\"><span>📌 Stage 1: CSS — colors, text, box model (1–2 weeks)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb418\" onchange=\"updateProgress(this)\"><span>📌 Stage 2: Flexbox + Grid + responsiveness (2 weeks)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb419\" onchange=\"updateProgress(this)\"><span>📌 Stage 3: JS — variables, conditions, loops, arrays (3 weeks)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb420\" onchange=\"updateProgress(this)\"><span>📌 Stage 4: JS — functions, DOM, events (2 weeks)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb421\" onchange=\"updateProgress(this)\"><span>📌 Stage 5: fetch + async/await + localStorage (1–2 weeks)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb422\" onchange=\"updateProgress(this)\"><span>📌 Stage 6: Git + GitHub (1 week)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb423\" onchange=\"updateProgress(this)\"><span>📌 Stage 7: First project (2–3 weeks)</span></label>\n      </div>\n    </div>\n    "},{"id":"roadmap-lesson-2","title":"What to learn AFTER the basics next step","html":"<div class=\"block\">\n      <div class=\"block-title\"><iconify-icon icon=\"tabler:rocket\" width=\"18\" height=\"18\" style=\"vertical-align:middle\"></iconify-icon> What to learn AFTER the basics <span class=\"badge good\">next step</span></div>\n      <div class=\"code\">HTML → CSS → JS → Git\n     ↓\nReact → TypeScript\n     ↓\nNext.js → Node.js\n     ↓\nFreelance / Internship / Job</div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb424\" onchange=\"updateProgress(this)\"><span>React — most demanded framework</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb425\" onchange=\"updateProgress(this)\"><span>TypeScript — JS with types. Fewer errors</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb426\" onchange=\"updateProgress(this)\"><span>Do not learn frameworks until you know clean JS!</span></label>\n      </div>\n    </div>\n    "}]},{"id":"sec-git","lessons":[{"id":"block-git-init","title":"Install and first setup start 🔗","html":"<div class=\"block\" id=\"block-git-init\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-git-init')\">Install and first setup <span class=\"badge must\">start</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Install Git once and configure your name and email — they will appear in every commit.</div>\n      <div class=\"code\">\n# Check whether Git is installed\ngit --version        # git version 2.x.x\n\n# Configure name and email (once)\ngit config --global user.name  \"Your Name\"\ngit config --global user.email \"you@example.com\"\n\n# Check settings\ngit config --list\n\n# Create a new repository in the current folder\ngit init\n\n# Clone an existing repository from GitHub\ngit clone https://github.com/user/repo.git\ngit clone https://github.com/user/repo.git my-folder  # in folder my-folder</div>\n      <div class=\"explain\">\n        <strong>git init</strong> — creates a hidden .git folder. Now the folder is a repository.<br>\n        <strong>git clone</strong> — downloads an existing repository and automatically configures the remote.<br>\n        <strong>--global</strong> — a setting for the whole computer, not just one project.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb454\" onchange=\"updateProgress(this)\"><span>I installed Git and configured user.name and user.email</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb455\" onchange=\"updateProgress(this)\"><span>git init creates a repo, git clone [url] downloads one</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-git-status","title":"Status and adding files basics 🔗","html":"<div class=\"block\" id=\"block-git-status\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-git-status')\">Status and adding files <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">\n# See what changed\ngit status            # list changed / new files\ngit status -s         # short version\n\n# See the line-by-line difference\ngit diff              # what changed in the working folder\ngit diff --staged     # what is already staged\n\n# Add files to staging (index)\ngit add index.html    # one file\ngit add css/          # everything in folder\ngit add .             # ALL changes (use carefully!)\ngit add -p            # interactively choose chunks of changes\n\n# Remove a file from staging (does not delete changes!)\ngit restore --staged index.html</div>\n      <div class=\"explain\">\n        <strong>git status</strong> is your main tool. Check it before every commit.<br>\n        <strong>Staging area (index)</strong> is the “basket” where you collect changes before a commit. It lets you commit in parts.<br>\n        <strong>git diff</strong> — shows exactly what changed in files, line by line.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb456\" onchange=\"updateProgress(this)\"><span>git status — I check what changed before every commit</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb457\" onchange=\"updateProgress(this)\"><span>git add . — add everything; git add file — add one</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb458\" onchange=\"updateProgress(this)\"><span>git diff — I see the exact changed lines</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-git-commit","title":"Commits — save history basics 🔗","html":"<div class=\"block\" id=\"block-git-commit\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-git-commit')\">Commits — save history <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">\n# Create a commit\ngit commit -m \"feat: add registration form\"\n\n# Add all changed files (not new ones!) + commit in one step\ngit commit -am \"fix: fix validation error\"\n\n# View commit history\ngit log               # detailed\ngit log --onerow     # one line per commit\ngit log --oneline --graph --all  # tree of all branches\n\n# Change the last commit (careful: only if not pushed!)\ngit commit --amend -m \"New commit message\"\n\n# Go back by creating a new reverting commit\ngit revert abc1234\n\n# Undo commits (danger: rewrites history!)\ngit reset --soft HEAD~1   # undo 1 commit, changes stay staged\ngit reset --hard HEAD~1   # undo 1 commit, changes are DELETED</div>\n      <div class=\"explain\">\n        <strong>Commit naming convention (Conventional Commits):</strong><br>\n        <code>feat:</code> — new feature. <code>fix:</code> — bug fix. <code>docs:</code> — documentation. <code>refactor:</code> — refactoring. <code>style:</code> — formatting.<br><br>\n        <strong>git revert</strong> — safe undo. <strong>git reset --hard</strong> — rewrites history; do not use it on shared branches.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb459\" onchange=\"updateProgress(this)\"><span>git commit -m \"message\" — create a commit</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb460\" onchange=\"updateProgress(this)\"><span>git log --oneline — view commit history</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb461\" onchange=\"updateProgress(this)\"><span>feat:, fix:, docs: — I write clear commit messages</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-git-branches","title":"Branches — work in parallel basics 🔗","html":"<div class=\"block\" id=\"block-git-branches\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-git-branches')\">Branches — work in parallel <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">A branch is an independent copy of the code. Building a new feature? Create a branch — main stays untouched.</div>\n      <div class=\"code\">\n# View branches\ngit branch            # local\ngit branch -a         # all (including remote)\n\n# Create and switch\ngit checkout -b feature/login     # old method\ngit switch -c feature/login       # new (Git 2.23+)\n\n# Switch to an existing branch\ngit checkout main\ngit switch main\n\n# Delete a branch\ngit branch -d feature/login   # after merge\ngit branch -D feature/login   # forcefully\n\n# Merge a branch into the current one\ngit checkout main\ngit merge feature/login\n\n# Rebase for a cleaner history\ngit checkout feature/login\ngit rebase main        # replay commits on top of main</div>\n      <div class=\"explain\">\n        <strong>Typical flow:</strong> main (stable) → develop (development) → feature/* (features).<br>\n        <strong>merge</strong> — keeps the full history. <strong>rebase</strong> — makes the history linear.<br>\n        Teams usually use Pull Requests / Merge Requests on GitHub instead of merging directly.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb462\" onchange=\"updateProgress(this)\"><span>git switch -c name — create and switch to a branch</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb463\" onchange=\"updateProgress(this)\"><span>git merge branch — merge changes from a branch into the current one</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb464\" onchange=\"updateProgress(this)\"><span>I understand the difference between merge and rebase</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-git-remote","title":"Remote — job with GitHub basics 🔗","html":"<div class=\"block\" id=\"block-git-remote\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-git-remote')\">Remote — job with GitHub <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">\n# View connected remotes\ngit remote -v\n\n# Add remote (after git init)\ngit remote add origin https://github.com/user/repo.git\n\n# Push a branch to GitHub\ngit push origin main\ngit push origin feature/login\n\n# First push of a new branch\ngit push -u origin feature/login    # -u remembers the connection\n\n# Get changes from GitHub\ngit fetch             # download, but do not apply\ngit pull              # fetch + merge (apply)\ngit pull --rebase     # fetch + rebase (clean history)\n\n# Working with a PR (Pull Request)\n# 1. git switch -c feature/my-feature\n# 2. ... make changes and commit them ...\n# 3. git push -u origin feature/my-feature\n# 4. Create a Pull Request on GitHub\n# 5. After review, merge into main</div>\n      <div class=\"explain\">\n        <strong>origin</strong> — the standard remote name. You can add several remotes.<br>\n        <strong>git fetch vs pull</strong>: fetch — only downloads changes and does not modify your files. pull downloads and applies them.<br>\n        <strong>-u</strong> — sets upstream; after that you can simply write <code>git push</code> without origin and the branch name.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb465\" onchange=\"updateProgress(this)\"><span>git push origin branch — push to GitHub</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb466\" onchange=\"updateProgress(this)\"><span>git pull — get changes from the team</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb467\" onchange=\"updateProgress(this)\"><span>I know how to create a Pull Request on GitHub</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-git-conflicts","title":"Conflicts and how to solve them important 🔗","html":"<div class=\"block\" id=\"block-git-conflicts\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-git-conflicts')\">Conflicts and how to solve them <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Conflict = two people changed the same line. Git does not know whose version to take, so it asks you.</div>\n      <div class=\"code\">\n# A conflict looks like this in a file:\n&lt;&lt;&lt;&lt;&lt;&lt;&lt; HEAD\n    Your code (current branch)\n=======\n    Someone else’s code (incoming changes)\n&gt;&gt;&gt;&gt;&gt;&gt;&gt; feature/login\n\n# Steps to resolve:\n# 1. Open the file in the editor\n# 2. Choose the needed version or combine both\n# 3. Delete the &lt;&lt;&lt;, ===, &gt;&gt;&gt; markers\n# 4. git add file_with_conflict\n# 5. git commit\n\n# If you get lost, abort the merge completely:\ngit merge --abort\ngit rebase --abort\n\n# Useful tools\ngit log --merge       # commits that caused the conflict\ngit diff              # view all conflict places</div>\n      <div class=\"explain\">\n        <strong>Do not panic</strong> — conflicts are normal. They happen to everyone.<br>\n        VS Code highlights conflicts and shows buttons: “Accept Current”, “Accept Incoming”, “Accept Both”.<br>\n        After resolving all conflicts — <code>git add .</code> and <code>git commit</code>.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb468\" onchange=\"updateProgress(this)\"><span>I understand the &lt;&lt;&lt;HEAD / ======= / &gt;&gt;&gt;&gt;branch markers</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb469\" onchange=\"updateProgress(this)\"><span>I can resolve conflicts manually or through VS Code</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb470\" onchange=\"updateProgress(this)\"><span>git merge --abort — I know how to exit if everything breaks</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-git-gitignore","title":".gitignore — what NOT to add to the repo important 🔗","html":"<div class=\"block\" id=\"block-git-gitignore\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-git-gitignore')\">.gitignore — what NOT to add to the repo <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">\n# .gitignore file in the project root\n# Git will not track the listed files and folders\n\n# Dependencies (installed by command, not needed in the repo)\nnode_modules/\n\n# Builds (generated automatically)\ndist/\nbuild/\n.cache/\n\n# Secrets (NEVER add them to the repo!)\n.env\n.env.local\n*.key\nsecrets.json\n\n# System files\n.DS_Store          # macOS\nThumbs.db          # Windows\n\n# Logs\n*.log\nlogs/\n\n# IDE settings (depends on the team)\n.vscode/\n.idea/</div>\n      <div class=\"explain\">\n        <strong>Golden rule:</strong> secrets (passwords, API keys) must NEVER get into Git. Even if you delete them later, history keeps them. Use environment variables (.env).<br>\n        <strong>node_modules</strong> — always goes into .gitignore. Instead, the repo contains package.json, and the team runs npm install.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb471\" onchange=\"updateProgress(this)\"><span>node_modules/ and .env — always in .gitignore</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb472\" onchange=\"updateProgress(this)\"><span>I never commit passwords, API keys, or secrets</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-git-stash","title":"Stash and cherry-pick advanced 🔗","html":"<div class=\"block\" id=\"block-git-stash\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-git-stash')\">Stash and cherry-pick <span class=\"badge pro\">advanced</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\">\n# STASH — set uncommitted changes aside\ngit stash             # hides all changes\ngit stash push -m \"work on form\"  # with a name\n\ngit stash list        # list saved stashes\ngit stash pop         # restore the latest one and remove it from the list\ngit stash apply stash@{0}  # restore a specific stash\ngit stash drop stash@{0}   # delete from the list\n\n# CHERRY-PICK — take one commit from another branch\ngit cherry-pick abc1234   # copy a commit into the current branch\n\n# TAGS — mark a version\ngit tag v1.0.0\ngit tag -a v1.0.0 -m \"First release\"   # annotated tag\ngit push origin v1.0.0                 # submit tag on GitHub\ngit push origin --tags                 # all tags\n\n# Find when a bug appeared (binary search!)\ngit bisect start\ngit bisect bad          # current commit is bad\ngit bisect good v1.0.0  # this version was good\n# Git jumps to the middle; you test...\ngit bisect good / git bisect bad\ngit bisect reset        # finish the search</div>\n      <div class=\"explain\">\n        <strong>git stash</strong> — a temporary pocket for uncommitted changes. Useful when you urgently need to switch branches.<br>\n        <strong>cherry-pick</strong> — takes one specific commit and applies it to the current branch without everything else from that branch.<br>\n        <strong>bisect</strong> — binary bug search through history. Saves hours of searching.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb473\" onchange=\"updateProgress(this)\"><span>git stash / git stash pop — put away and bring back uncommitted changes</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb474\" onchange=\"updateProgress(this)\"><span>git cherry-pick [hash] — take one commit from another branch</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-git-viz","title":"Branch visualization — what it looks like diagram 🔗","html":"<div class=\"block\" id=\"block-git-viz\" style=\"margin-top:1.25rem;\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-git-viz')\">Branch visualization — what it looks like <span class=\"badge good\">diagram</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Each circle is a commit. The arrow goes from newer to older. Branches are parallel history lines.</div>\n      <div class=\"git-viz\">\n        <svg viewbox=\"0 0 640 220\" xmlns=\"http://www.w3.org/2000/svg\" style=\"width:100%;min-width:480px;\">\n          <!-- main branch row -->\n          <row x1=\"40\" y1=\"60\" x2=\"560\" y2=\"60\" stroke=\"#4ade80\" stroke-width=\"2\"></row>\n          <!-- feature branch row -->\n          <row x1=\"220\" y1=\"60\" x2=\"320\" y2=\"140\" stroke=\"#818cf8\" stroke-width=\"2\"></row>\n          <row x1=\"320\" y1=\"140\" x2=\"440\" y2=\"140\" stroke=\"#818cf8\" stroke-width=\"2\"></row>\n          <row x1=\"440\" y1=\"140\" x2=\"480\" y2=\"60\" stroke=\"#818cf8\" stroke-width=\"2\"></row>\n          <!-- hotfix branch -->\n          <row x1=\"340\" y1=\"60\" x2=\"380\" y2=\"30\" stroke=\"#f87171\" stroke-width=\"2\"></row>\n          <row x1=\"380\" y1=\"30\" x2=\"420\" y2=\"60\" stroke=\"#f87171\" stroke-width=\"2\" stroke-dasharray=\"4,3\"></row>\n          <!-- main commits -->\n          <circle cx=\"80\" cy=\"60\" r=\"12\" fill=\"#4ade80\" stroke=\"#0f172a\" stroke-width=\"3\"></circle>\n          <circle cx=\"160\" cy=\"60\" r=\"12\" fill=\"#4ade80\" stroke=\"#0f172a\" stroke-width=\"3\"></circle>\n          <circle cx=\"240\" cy=\"60\" r=\"12\" fill=\"#4ade80\" stroke=\"#0f172a\" stroke-width=\"3\"></circle>\n          <circle cx=\"340\" cy=\"60\" r=\"12\" fill=\"#4ade80\" stroke=\"#0f172a\" stroke-width=\"3\"></circle>\n          <circle cx=\"480\" cy=\"60\" r=\"14\" fill=\"#4ade80\" stroke=\"#22c55e\" stroke-width=\"3\"></circle>\n          <circle cx=\"560\" cy=\"60\" r=\"14\" fill=\"#fbbf24\" stroke=\"#f59e0b\" stroke-width=\"3\"></circle>\n          <!-- feature commits -->\n          <circle cx=\"320\" cy=\"140\" r=\"12\" fill=\"#818cf8\" stroke=\"#0f172a\" stroke-width=\"3\"></circle>\n          <circle cx=\"400\" cy=\"140\" r=\"12\" fill=\"#818cf8\" stroke=\"#0f172a\" stroke-width=\"3\"></circle>\n          <!-- hotfix commit -->\n          <circle cx=\"380\" cy=\"30\" r=\"10\" fill=\"#f87171\" stroke=\"#0f172a\" stroke-width=\"3\"></circle>\n          <!-- labels -->\n          <text x=\"80\" y=\"90\" text-anchor=\"middle\" fill=\"#94a3b8\" font-size=\"10\" font-family=\"monospace\">init</text>\n          <text x=\"160\" y=\"90\" text-anchor=\"middle\" fill=\"#94a3b8\" font-size=\"10\" font-family=\"monospace\">feat</text>\n          <text x=\"240\" y=\"90\" text-anchor=\"middle\" fill=\"#94a3b8\" font-size=\"10\" font-family=\"monospace\">fork</text>\n          <text x=\"340\" y=\"90\" text-anchor=\"middle\" fill=\"#94a3b8\" font-size=\"10\" font-family=\"monospace\">fix</text>\n          <text x=\"480\" y=\"90\" text-anchor=\"middle\" fill=\"#86efac\" font-size=\"10\" font-family=\"monospace\">merge</text>\n          <text x=\"560\" y=\"90\" text-anchor=\"middle\" fill=\"#fcd34d\" font-size=\"10\" font-family=\"monospace\">HEAD</text>\n          <text x=\"320\" y=\"165\" text-anchor=\"middle\" fill=\"#a5b4fc\" font-size=\"10\" font-family=\"monospace\">feat/A</text>\n          <text x=\"400\" y=\"165\" text-anchor=\"middle\" fill=\"#a5b4fc\" font-size=\"10\" font-family=\"monospace\">feat/B</text>\n          <text x=\"380\" y=\"20\" text-anchor=\"middle\" fill=\"#fca5a5\" font-size=\"10\" font-family=\"monospace\">hotfix</text>\n          <!-- branch badges -->\n          <rect x=\"10\" y=\"50\" width=\"42\" height=\"20\" rx=\"6\" fill=\"#166534\" opacity=\".8\"></rect>\n          <text x=\"31\" y=\"64\" text-anchor=\"middle\" fill=\"#4ade80\" font-size=\"10\" font-weight=\"bold\">main</text>\n          <rect x=\"266\" y=\"130\" width=\"56\" height=\"20\" rx=\"6\" fill=\"#312e81\" opacity=\".8\"></rect>\n          <text x=\"294\" y=\"144\" text-anchor=\"middle\" fill=\"#818cf8\" font-size=\"10\" font-weight=\"bold\">feature</text>\n          <rect x=\"345\" y=\"18\" width=\"46\" height=\"18\" rx=\"6\" fill=\"#450a0a\" opacity=\".8\"></rect>\n          <text x=\"368\" y=\"31\" text-anchor=\"middle\" fill=\"#f87171\" font-size=\"10\" font-weight=\"bold\">hotfix</text>\n        </svg>\n      </div>\n      <div class=\"explain\">\n        <strong>main</strong> (green) — stable branch with working code.<br>\n        <strong>feature</strong> (purple) — new functionality is developed separately without breaking main.<br>\n        <strong>hotfix</strong> (red) — urgent fix directly in main, then merged back.<br>\n        <strong>HEAD</strong> (yellow) — pointer to the current commit where you are now.\n      </div>\n    </div>\n\n    "},{"id":"block-git-scenarios","title":"Typical scenarios — step-by-step commands practice 🔗","html":"<div class=\"block\" id=\"block-git-scenarios\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-git-scenarios')\">Typical scenarios — step-by-step commands <span class=\"badge must\">practice</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Save or remember this — it is 90% of real Git work.</div>\n\n      <div class=\"git-scenario\">\n        <div class=\"git-scenario-title\"><iconify-icon icon=\"tabler:rocket\" width=\"18\" height=\"18\" style=\"vertical-align:middle\"></iconify-icon> Scenario 1: New project from scratch → GitHub</div>\n        <div class=\"code\" style=\"margin:0;\">cd my-project\ngit init\ngit add .\ngit commit -m \"feat: initial commit\"\ngit branch -M main\ngit remote add origin https://github.com/you/repo.git\ngit push -u origin main</div>\n      </div>\n\n      <div class=\"git-scenario\">\n        <div class=\"git-scenario-title\">✨ Scenario 2: Feature branch (standard flow)</div>\n        <div class=\"code\" style=\"margin:0;\">git switch main\ngit pull                          # sync with the team\ngit switch -c feature/auth        # create a branch\n# ... write code ...\ngit add .\ngit commit -m \"feat: add login form\"\ngit push -u origin feature/auth   # push the branch\n# → create a Pull Request on GitHub\n# → after review and approval, merge</div>\n      </div>\n\n      <div class=\"git-scenario\">\n        <div class=\"git-scenario-title\">🔥 Scenario 3: Urgent hotfix in production</div>\n        <div class=\"code\" style=\"margin:0;\">git stash                         # stash current work\ngit switch main\ngit pull\ngit switch -c hotfix/null-pointer\n# ... fix the bug ...\ngit commit -am \"fix: null pointer on empty cart\"\ngit switch main\ngit merge hotfix/null-pointer\ngit push\ngit branch -d hotfix/null-pointer\ngit switch -                      # switch back\ngit stash pop                     # restore stashed work</div>\n      </div>\n\n      <div class=\"git-scenario\">\n        <div class=\"git-scenario-title\">⏪ Scenario 4: Revert a bad commit</div>\n        <div class=\"code\" style=\"margin:0;\"># Safe: creates a new reverting commit:\ngit log --onerow                 # check history\ngit revert abc1234                # revert a specific commit\n\n# If the commit has not been pushed yet (careful):\ngit reset --soft HEAD~1           # remove the commit, keep changes\ngit reset --hard HEAD~1           # remove the commit AND changes</div>\n      </div>\n\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb475\" onchange=\"updateProgress(this)\"><span>I can create a project and connect it to GitHub</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb476\" onchange=\"updateProgress(this)\"><span>I work through feature branches + Pull Requests</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb477\" onchange=\"updateProgress(this)\"><span>I know how to make a hotfix without interrupting main work</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb478\" onchange=\"updateProgress(this)\"><span>I can revert a bad commit through git revert</span></label>\n      </div>\n    </div>\n\n\n    "},{"id":"block-git-push","title":"Push — sending changes to GitHub basics 🔗","html":"<div class=\"block\" id=\"block-git-push\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-git-push')\">Push — sending changes to GitHub <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Three commands you will write every day: <code>git add</code> → <code>git commit</code> → <code>git push</code>. This is what “upload to GitHub” means.</div>\n      <div class=\"code\"><span class=\"cm\"># Check what changed</span>\n<span class=\"kw\">git status</span>\n\n<span class=\"cm\"># Add files to the commit</span>\n<span class=\"kw\">git add .</span>             <span class=\"cm\"># all changes at once</span>\n<span class=\"kw\">git add index.html</span>    <span class=\"cm\"># or a specific file</span>\n\n<span class=\"cm\"># Create a commit with a description</span>\n<span class=\"kw\">git commit -m</span> <span class=\"str\">\"fix: adjust button styles\"</span>\n\n<span class=\"cm\"># Send to GitHub</span>\n<span class=\"kw\">git push</span>                    <span class=\"cm\"># if the branch is already linked</span>\n<span class=\"kw\">git push origin main</span>        <span class=\"cm\"># explicitly: remote=origin, branch=main</span>\n<span class=\"kw\">git push -u origin main</span>     <span class=\"cm\"># first time: -u remembers the connection</span></div>\n      <div class=\"explain\">\n        <strong>git add .</strong> — adds all changed files to the “queue” for a commit.<br>\n        <strong>git commit -m</strong> — records a snapshot. Without a commit, there is nothing to push.<br>\n        <strong>origin</strong> — is simply an alias for your repository address on GitHub.<br>\n        <strong>-u</strong> — remembers the branch connection with the remote. After that, just <code>git push</code>.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb479\" onchange=\"updateProgress(this)\"><span>git add . → git commit -m → git push — full cycle</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb480\" onchange=\"updateProgress(this)\"><span>git push -u origin main — first push with branch linking</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb481\" onchange=\"updateProgress(this)\"><span>git status — check before every commit</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-git-pull-conflict","title":"Conflict on git pull — what to do common 🔗","html":"<div class=\"block\" id=\"block-git-pull-conflict\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-git-pull-conflict')\">Conflict on git pull — what to do <span class=\"badge must\">common</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">90% of beginner conflicts happen not during branch merges, but in a simple situation: you changed a file locally, wrote <code>git pull</code> — and Git complains, refusing to update.</div>\n      <div class=\"code\"><span class=\"cm\">// Situation:</span>\n<span class=\"kw\">git pull</span>\n<span class=\"cm\">// error: Your local changes to the following files would be overwritten by merge:</span>\n<span class=\"cm\">//   index.html</span>\n<span class=\"cm\">// Please commit your changes or stash them before you merge.</span>\n\n<span class=\"cm\">// Solution: stash changes, pull updates, restore changes:</span>\n<span class=\"kw\">git stash</span>          <span class=\"cm\">// hides your uncommitted changes “in a pocket”</span>\n<span class=\"kw\">git pull</span>           <span class=\"cm\">// now pull passes without conflict</span>\n<span class=\"kw\">git stash pop</span>      <span class=\"cm\">// bring your changes back</span>\n\n<span class=\"cm\">// If Git shows a conflict after stash pop —</span>\n<span class=\"cm\">// it means your changes and the updates touched the same lines.</span>\n<span class=\"cm\">// Then open the file, find &lt;&lt;&lt;&lt;&lt;&lt;&lt; and resolve it like a normal merge conflict.</span></div>\n      <div class=\"explain\">\n        <strong>git stash</strong> — temporarily removes unsaved changes, returning the working copy to the latest commit. Changes are not lost; they are only hidden.<br>\n        <strong>git stash pop</strong> — brings hidden changes back and applies them. If there are no conflicts, it applies instantly.<br>\n        <strong>Alternative</strong> — if changes are ready, you can simply commit them (<code>git add . &amp;&amp; git commit</code>) before pull instead of stash.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb482\" onchange=\"updateProgress(this)\"><span>git stash → git pull → git stash pop — safe pull cycle</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb483\" onchange=\"updateProgress(this)\"><span>I understand why Git blocks pull with unsaved changes</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb484\" onchange=\"updateProgress(this)\"><span>I know the alternative: commit instead of stash</span></label>\n      </div>\n    </div>\n  "}]},{"id":"sec-node","lessons":[{"id":"block-node-next-overview-2026","title":"Node.js, Next.js, and a separate API MAP #","html":"<div class=\"block wdg-quality-block\" id=\"block-node-next-overview-2026\"><div class=\"block-title\" onclick=\"scrollToBlock('block-node-next-overview-2026')\">Node.js, Next.js, and a separate API <span class=\"badge good\">MAP</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">Node.js is a server-side JavaScript runtime. Next.js is a framework on top of Node.js and covers most junior full-stack app needs without a separate Express server.</div><div class=\"code\">// Next.js: pages, Route Handlers, and Server Actions in one project\nexport async function GET() {\n  return Response.json({ ok: true });\n}\n\n// Express/Fastify are useful for an independent API:\n// - a service for multiple clients\n// - WebSocket, queues, specialized architecture\n// - a backend with its own release cycle</div><div class=\"explain\">For a learning full-stack project, start with the Next App Router: Server Components read data, Route Handlers expose HTTP APIs, and Server Actions handle forms. Learn Express or Fastify at overview level and use one when the API must live independently. Next.js does not replace every possible backend, but a separate server adds needless complexity when used too early.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-node-next-overview-2026-1\" onchange=\"updateProgress(this)\"><span>I distinguish runtime from framework</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-node-next-overview-2026-2\" onchange=\"updateProgress(this)\"><span>I start typical full stack with Next.js</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-quality-block-node-next-overview-2026-3\" onchange=\"updateProgress(this)\"><span>I create a separate API for a reason</span></label></div></div>"},{"id":"block-next-app-router-2026","title":"Next.js App Router architecture 2026 CORE #","html":"<div class=\"block wdg-2026-block\" id=\"block-next-app-router-2026\"><div class=\"block-title\" onclick=\"scrollToBlock('block-next-app-router-2026')\">Next.js App Router architecture <span class=\"badge must\">2026 CORE</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">Pages are Server Components by default. Add use client only for state, effects, and browser events.</div><div class=\"code\">// app/projects/page.tsx - Server Component\nexport default async function ProjectsPage() {\n  const projects = await db.project.findMany();\n  return &lt;ProjectList projects={projects} /&gt;;\n}\n\n// app/projects/actions.ts\n\"use server\";\nexport async function createProject(formData: FormData) {\n  const data = schema.parse({ title: formData.get(\"title\") });\n  await db.project.create({ data });\n  revalidatePath(\"/projects\");\n}</div><div class=\"explain\">A Server Component reads the database without exposing secrets. A Server Action validates and mutates on the server, then refreshes data. Keep Route Handlers for webhooks or a public API. A separate Express backend is usually unnecessary.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-next-app-router-2026-1\" onchange=\"updateProgress(this)\"><span>I distinguish Server and Client Components</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-next-app-router-2026-2\" onchange=\"updateProgress(this)\"><span>I validate inside Server Actions</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-next-app-router-2026-3\" onchange=\"updateProgress(this)\"><span>I do not add Express without a reason</span></label></div><div class=\"wdg-quality-extension\"><div class=\"tip\"><strong>A Server Action directly in a form</strong>: the field still needs a <code>name</code> because the action reads it from <code>FormData</code>.</div><div class=\"code\">async function createUser(formData) {\n  \"use server\";\n  const name = String(formData.get(\"name\") ?? \"\").trim();\n  if (!name) return;\n  await db.user.create({ data: { name } });\n}\n\nexport default function NewUserForm() {\n  return (\n    &lt;form action={createUser}&gt;\n      &lt;input name=\"name\" required /&gt;\n      &lt;button type=\"submit\"&gt;Create&lt;/button&gt;\n    &lt;/form&gt;\n  );\n}</div><div class=\"explain\">A Server Action runs on the server, but input is still untrusted: normalize and validate it before writing to the database.</div></div></div>"},{"id":"block-node-nextjs-intro","title":"Next.js + Node.js — why they work better together important 🔗","html":"<div class=\"block\" id=\"block-node-nextjs-intro\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-node-nextjs-intro')\">Next.js + Node.js — why they work better together <span class=\"badge must\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Next.js is a framework on top of React that is itself a Node.js application. Understanding Node.js is required to truly understand Next.js instead of just copying code.</div>\n      <div class=\"code\"><span class=\"cm\">// Plain React (CRA/Vite) — client only</span>\nBrowser requests index.html\n  → loads an empty div#root\n  → JS downloads and renders everything on the client (CSR)\n  → SEO suffers, first load is slower\n\n<span class=\"cm\">// Next.js — Node.js server renders React</span>\nBrowser requests a page\n  → Next.js (running on Node.js!) renders React to HTML on the server\n  → Browser gets ready HTML with content (SSR)\n  → JS loads and “hydrates” the page\n  → SEO works out of the box, first load is faster\n\n<span class=\"cm\">// Next.js project structure (App Router)</span>\napp/\n  page.tsx        <span class=\"cm\">→ main page (\"/\")</span>\n  layout.tsx       <span class=\"cm\">→ shared layout for all pages</span>\n  api/\n    users/route.ts <span class=\"cm\">→ this is Node.js backend! Without Express</span>\n  blog/[slug]/\n    page.tsx        <span class=\"cm\">→ dynamic route /blog/my-post</span></div>\n      <div class=\"explain\">\n        <strong>Next.js = React + Node.js server in one framework.</strong> Next.js could not exist without Node.js underneath: server rendering, API routes, and middleware all run in a Node.js environment.<br>\n        <strong>Why learn it separately?</strong> If you understand plain Node.js (how the server, event loop and modules work), Next.js code stops feeling like magic: you understand what happens on each request.<br>\n        <strong>API Routes in Next.js</strong> — is a full Node.js backend without needing a separate Express server. One project contains both frontend and backend.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb511\" onchange=\"updateProgress(this)\"><span>I understand that Next.js runs on a Node.js server</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb512\" onchange=\"updateProgress(this)\"><span>SSR (Server-Side Rendering) — React render on the server</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb513\" onchange=\"updateProgress(this)\"><span>I understand the difference between CSR vs SSR and why SSR is needed</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-nextjs-routing","title":"App Router — file system as routing basics 🔗","html":"<div class=\"block\" id=\"block-nextjs-routing\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-nextjs-routing')\">App Router — file system as routing <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// Creating a project</span>\n<span class=\"kw\">npx create-next-app@latest</span> my-app\n<span class=\"kw\">cd</span> my-app &amp;&amp; <span class=\"kw\">npm run dev</span>\n\n<span class=\"cm\">// app/page.tsx — main page</span>\n<span class=\"kw\">export default function</span> <span class=\"fn\">Home</span>() {\n  <span class=\"kw\">return</span> &lt;<span class=\"tag\">h1</span>&gt;Home page&lt;/<span class=\"tag\">h1</span>&gt;;\n}\n\n<span class=\"cm\">// app/about/page.tsx → available at /about</span>\n<span class=\"kw\">export default function</span> <span class=\"fn\">About</span>() {\n  <span class=\"kw\">return</span> &lt;<span class=\"tag\">h1</span>&gt;About us&lt;/<span class=\"tag\">h1</span>&gt;;\n}\n\n<span class=\"cm\">// app/blog/[slug]/page.tsx → dynamic route</span>\n<span class=\"kw\">export default function</span> <span class=\"fn\">BlogPost</span>({ params }: { params: { slug: <span class=\"str\">string</span> } }) {\n  <span class=\"kw\">return</span> &lt;<span class=\"tag\">h1</span>&gt;Post: {params.slug}&lt;/<span class=\"tag\">h1</span>&gt;;\n}\n<span class=\"cm\">// /blog/hello-world → params.slug = \"hello-world\"</span>\n\n<span class=\"cm\">// app/layout.tsx — shared shell (header, footer)</span>\n<span class=\"kw\">export default function</span> <span class=\"fn\">RootLayout</span>({ children }) {\n  <span class=\"kw\">return</span> (\n    &lt;<span class=\"tag\">html</span>&gt;&lt;<span class=\"tag\">body</span>&gt;\n      &lt;<span class=\"fn\">Header</span> /&gt;\n      {children}\n      &lt;<span class=\"fn\">Footer</span> /&gt;\n    &lt;/<span class=\"tag\">body</span>&gt;&lt;/<span class=\"tag\">html</span>&gt;\n  );\n}</div>\n      <div class=\"explain\">\n        <strong>File = route.</strong> The <code>app/about/page.tsx</code> folder automatically becomes the page <code>/about</code>. No manual router needed.<br>\n        <strong>[slug]</strong> — square brackets create a dynamic URL parameter.<br>\n        <strong>layout.tsx</strong> — wraps all nested pages and does not rerender during navigation between them.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb514\" onchange=\"updateProgress(this)\"><span>app/page.tsx — Next.js file routing</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb515\" onchange=\"updateProgress(this)\"><span>[slug] — dynamic routes</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb516\" onchange=\"updateProgress(this)\"><span>layout.tsx — shared page shell</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-nextjs-data","title":"Server Components and loading data important 🔗","html":"<div class=\"block\" id=\"block-nextjs-data\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-nextjs-data')\">Server Components and loading data <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// Server Component (default in App Router!)</span>\n<span class=\"cm\">// Runs on the Node.js server and does NOT get into the browser JS bundle</span>\n<span class=\"kw\">export default async function</span> <span class=\"fn\">ProductList</span>() {\n  <span class=\"kw\">const</span> products = <span class=\"kw\">await</span> db.product.<span class=\"fn\">findMany</span>(); <span class=\"cm\">// direct database access!</span>\n  <span class=\"kw\">return</span> (\n    &lt;<span class=\"tag\">ul</span>&gt;\n      {products.<span class=\"fn\">map</span>(p =&gt; &lt;<span class=\"tag\">li</span> <span class=\"attr\">key</span>={p.id}&gt;{p.name}&lt;/<span class=\"tag\">li</span>&gt;)}\n    &lt;/<span class=\"tag\">ul</span>&gt;\n  );\n}\n\n<span class=\"cm\">// Client Component — needed for interactivity</span>\n<span class=\"str\">'use client'</span>; <span class=\"cm\">// required directive!</span>\n<span class=\"kw\">import</span> { useState } <span class=\"kw\">from</span> <span class=\"str\">'react'</span>;\n\n<span class=\"kw\">export default function</span> <span class=\"fn\">LikeButton</span>() {\n  <span class=\"kw\">const</span> [liked, setLiked] = <span class=\"fn\">useState</span>(<span class=\"kw\">false</span>);\n  <span class=\"kw\">return</span> &lt;<span class=\"tag\">button</span> <span class=\"attr\">onClick</span>={() =&gt; <span class=\"fn\">setLiked</span>(!liked)}&gt;{liked ? <span class=\"str\">'❤️'</span> : <span class=\"str\">'🤍'</span>}&lt;/<span class=\"tag\">button</span>&gt;;\n}</div>\n      <div class=\"explain\">\n        <strong>Server Component</strong> — can talk directly to the database, read files and use secret keys. The code never gets into the browser.<br>\n        <strong>'use client'</strong> — needed only when useState, useEffect, onClick or other interactivity is required.<br>\n        <strong>Main rule</strong> — by default everything is a Server Component. Add 'use client' only when it is really needed.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb520\" onchange=\"updateProgress(this)\"><span>Server Components run on the server and have direct database access</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb521\" onchange=\"updateProgress(this)\"><span>'use client' — when interactivity is needed (useState, onClick)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb522\" onchange=\"updateProgress(this)\"><span>I understand that Server Components do not increase JS bundle size</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-nextjs-api","title":"API Routes — Node.js backend inside Next.js important 🔗","html":"<div class=\"block\" id=\"block-nextjs-api\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-nextjs-api')\">API Routes — Node.js backend inside Next.js <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// app/api/users/route.ts — this is Node.js! Without Express</span>\n<span class=\"kw\">import</span> { NextResponse } <span class=\"kw\">from</span> <span class=\"str\">'next/server'</span>;\n\n<span class=\"kw\">export async function</span> <span class=\"fn\">GET</span>() {\n  <span class=\"kw\">const</span> users = <span class=\"kw\">await</span> db.user.<span class=\"fn\">findMany</span>();\n  <span class=\"kw\">return</span> NextResponse.<span class=\"fn\">json</span>(users);\n}\n\n<span class=\"kw\">export async function</span> <span class=\"fn\">POST</span>(request: Request) {\n  <span class=\"kw\">const</span> body = <span class=\"kw\">await</span> request.<span class=\"fn\">json</span>();\n  <span class=\"kw\">const</span> user = <span class=\"kw\">await</span> db.user.<span class=\"fn\">create</span>({ data: body });\n  <span class=\"kw\">return</span> NextResponse.<span class=\"fn\">json</span>(user, { status: <span class=\"num\">201</span> });\n}\n\n<span class=\"cm\">// Calling from the client — normal fetch to the same domain</span>\n<span class=\"kw\">const</span> res = <span class=\"kw\">await fetch</span>(<span class=\"str\">'/api/users'</span>);\n<span class=\"kw\">const</span> users = <span class=\"kw\">await</span> res.<span class=\"fn\">json</span>();\n\n<span class=\"cm\">// Server Actions — even simpler, without route.ts at all</span>\n<span class=\"str\">'use server'</span>;\n<span class=\"kw\">export async function</span> <span class=\"fn\">createUser</span>(formData: FormData) {\n  <span class=\"kw\">await</span> db.user.<span class=\"fn\">create</span>({ data: { name: formData.<span class=\"fn\">get</span>(<span class=\"str\">'name'</span>) } });\n}</div>\n      <div class=\"explain\">\n        <strong>route.ts</strong> — each export (GET, POST, PUT, DELETE) is a separate HTTP handler. This is full Node.js code.<br>\n        <strong>Server Actions</strong> — new Next.js way to call server code directly from forms without manual fetch.<br>\n        ⚠️ <strong>Security:</strong> Server Actions — these are hidden API endpoints. Check authorization and user permissions directly inside the action, not only in the UI.<br>\n        <strong>One project, one deploy</strong> — frontend and backend live together; no need to run Express separately.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb517\" onchange=\"updateProgress(this)\"><span>API Routes — GET/POST in route.ts</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb518\" onchange=\"updateProgress(this)\"><span>Server Actions — server functions without route.ts</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb519\" onchange=\"updateProgress(this)\"><span>I understand that a separate Express app is not needed for simple APIs</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-next-auth-2026","title":"Auth.js / Clerk and route protection 2026 CORE #","html":"<div class=\"block wdg-2026-block\" id=\"block-next-auth-2026\"><div class=\"block-title\" onclick=\"scrollToBlock('block-next-auth-2026')\">Auth.js / Clerk and route protection <span class=\"badge must\">2026 CORE</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">Auth.js gives more control; Clerk provides a hosted account platform. Access must still be checked on the server.</div><div class=\"code\">import { auth } from \"@/auth\";\nimport { redirect } from \"next/navigation\";\n\nexport default async function DashboardPage() {\n  const session = await auth();\n  if (!session?.user) redirect(\"/sign-in\");\n  return &lt;Dashboard user={session.user} /&gt;;\n}\n\n// middleware.ts\nexport { auth as middleware } from \"@/auth\";\nexport const config = { matcher: [\"/dashboard/:path*\"] };</div><div class=\"explain\">Hiding a button is not security. Check the session inside the protected server page and action. Clerk is faster for hosted account UI; Auth.js is more flexible. Provider secrets belong in environment variables.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-next-auth-2026-1\" onchange=\"updateProgress(this)\"><span>I verify sessions on the server</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-next-auth-2026-2\" onchange=\"updateProgress(this)\"><span>I protect route groups</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-next-auth-2026-3\" onchange=\"updateProgress(this)\"><span>I never commit secrets</span></label></div></div>"},{"id":"block-node-zod-validation","title":"Data validation with Zod commercial code basics 🔗","html":"<div class=\"block\" id=\"block-node-zod-validation\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-node-zod-validation')\">Data validation with Zod <span class=\"badge must\">commercial code basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">In commercial backend code, nobody validates req.body manually with if/else. A validation library is used; Zod is the most popular in TypeScript projects.</div>\n      <div class=\"code\"><span class=\"cm\">// ❌ Manual validation: lots of code, easy to forget a check</span>\napp.<span class=\"fn\">post</span>(<span class=\"str\">'/users'</span>, (req, res) =&gt; {\n  <span class=\"kw\">if</span> (!req.body.email || <span class=\"kw\">typeof</span> req.body.email !== <span class=\"str\">'string'</span>) {\n    <span class=\"kw\">return</span> res.<span class=\"fn\">status</span>(<span class=\"num\">400</span>).<span class=\"fn\">send</span>(<span class=\"str\">'Invalid email'</span>);\n  }\n  <span class=\"cm\">// ... 10 more checks for each field</span>\n});\n\n<span class=\"cm\">// ✅ Zod: describe the schema once, validation is automatic</span>\n<span class=\"kw\">import</span> { z } <span class=\"kw\">from</span> <span class=\"str\">'zod'</span>;\n\n<span class=\"kw\">const</span> userSchema = z.<span class=\"fn\">object</span>({\n  email: z.<span class=\"fn\">string</span>().<span class=\"fn\">email</span>(),\n  age: z.<span class=\"fn\">number</span>().<span class=\"fn\">min</span>(<span class=\"num\">18</span>).<span class=\"fn\">max</span>(<span class=\"num\">120</span>),\n  name: z.<span class=\"fn\">string</span>().<span class=\"fn\">min</span>(<span class=\"num\">2</span>)\n});\n\napp.<span class=\"fn\">post</span>(<span class=\"str\">'/users'</span>, (req, res) =&gt; {\n  <span class=\"kw\">const</span> result = userSchema.<span class=\"fn\">safeParse</span>(req.body);\n  <span class=\"kw\">if</span> (!result.success) {\n    <span class=\"kw\">return</span> res.<span class=\"fn\">status</span>(<span class=\"num\">400</span>).<span class=\"fn\">json</span>(result.error.issues);\n  }\n  <span class=\"cm\">// result.data is guaranteed valid and typed data</span>\n  <span class=\"kw\">const</span> user = <span class=\"kw\">await</span> db.user.<span class=\"fn\">create</span>({ data: result.data });\n});\n\n<span class=\"cm\">// Bonus: TypeScript type is inferred from the schema automatically</span>\n<span class=\"kw\">type</span> UserInput = z.infer&lt;<span class=\"kw\">typeof</span> userSchema&gt;;</div>\n      <div class=\"explain\">\n        <strong>safeParse</strong> — does not throw an error, returns <code>{success, data}</code> or <code>{success, error}</code> — convenient for handling.<br>\n        <strong>z.infer&lt;typeof schema&gt;</strong> — TypeScript type is inferred automatically from the Zod schema; no need to duplicate it manually.<br>\n        <strong>Where it is used:</strong> request body validation in Express/Next.js API Routes, form validation on the frontend, often with react-hook-form.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb535\" onchange=\"updateProgress(this)\"><span>z.object() — validation schema description</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb536\" onchange=\"updateProgress(this)\"><span>safeParse — safe validation without try/catch</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb537\" onchange=\"updateProgress(this)\"><span>z.infer — automatic TypeScript type from the schema</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-node-what","title":"What Node.js is and why it is needed basics 🔗","html":"<div class=\"block\" id=\"block-node-what\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-node-what')\">What Node.js is and why it is needed <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">The browser can run JS. But JS “outside” the browser — on a computer or server — runs through <strong>Node.js</strong>. This is the V8 engine (the same one as in Chrome), taken out of the browser and installed separately.</div>\n      <div class=\"explain\">\n        <strong>Why this is need:</strong><br>\n        • <strong>Server</strong> — a program that receives user requests and returns data (pages, API responses)<br>\n        • <strong>One language everywhere</strong> — frontend in JS, backend in JS. No need to learn a second language for the server<br>\n        • <strong>Fast start</strong> — since you already know JS, Node is easier than Python or PHP from scratch<br>\n        • <strong>Huge ecosystem</strong> — millions of ready-made packages (npm); almost everything has already been written before you<br><br>\n        <strong>Where it is used:</strong> chats, streaming, APIs, real-time servers, development tools.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb485\" onchange=\"updateProgress(this)\"><span>I understand: Node.js is JS outside the browser (on a server/computer)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb486\" onchange=\"updateProgress(this)\"><span>I know that one language (JS) can be used for both frontend and backend</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb487\" onchange=\"updateProgress(this)\"><span>I understand that a server is a program that responds to requests</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-node-install","title":"Install and first run basics 🔗","html":"<div class=\"block\" id=\"block-node-install\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-node-install')\">Install and first run <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Install Node from the official site <strong>nodejs.org</strong>. Choose the <strong>LTS</strong> (Long Term Support — stable). Together with Node you also get <strong>npm</strong> — package manager.</div>\n      <div class=\"code\">// Check that it is installed (in the terminal):\nnode -v      // shows the version, for example v20.11.0\nnpm -v       // npm version\n\n// Create a hello.js file:\nconsole.log(\"Hello with server!\");\n\n// Run it in the terminal:\nnode hello.js\n// → prints: Hello from server!</div>\n      <div class=\"explain\">\n        <strong>node hello.js</strong> — runs your JS file <em>directly</em>, without the browser. No HTML needed!<br>\n        <strong>console.log</strong> — works the same as in the browser, but prints to the <em>terminal</em>, not the browser console.<br>\n        <strong>LTS version</strong> — choose it, not “Current”. LTS is more stable and breaks less often.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb488\" onchange=\"updateProgress(this)\"><span>I installed Node.js (LTS) from nodejs.org</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb489\" onchange=\"updateProgress(this)\"><span>I checked node -v and npm -v in the terminal</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb490\" onchange=\"updateProgress(this)\"><span>I ran my first .js file through node file_name.js</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-node-npm","title":"npm — package manager basics 🔗","html":"<div class=\"block\" id=\"block-node-npm\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-node-npm')\">npm — package manager <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\"><strong>npm</strong> — is like a store of ready-made code. Need a library? Install it with one command instead of writing it yourself. Millions of packages.</div>\n      <div class=\"code\">// Create a project (creates package.json — the project passport):\nnpm init -y\n\n// Install a package (for example, express — a server framework):\nnpm install express\n\n// Install and save as a dev dependency:\nnpm install --save-dev nodemon\n\n// Run a script from package.json:\nnpm run start</div>\n      <div class=\"explain\">\n        <strong>package.json</strong> — file with the list of all packages your project uses. Like an ingredient list for a recipe.<br>\n        <strong>node_modules</strong> — folder where packages are downloaded. Huge. <em>Never upload it to GitHub</em> — add it to <code>.gitignore</code>.<br>\n        <strong>npm install</strong> (without a package name) installs ALL packages from package.json. Useful when you downloaded someone else’s project.<br>\n        <strong>nodemon</strong> — restarts the server automatically when you change code. Very convenient during development.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb491\" onchange=\"updateProgress(this)\"><span>I understand that npm is a manager for ready-made packages</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb492\" onchange=\"updateProgress(this)\"><span>I know that package.json is the project dependency list</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb493\" onchange=\"updateProgress(this)\"><span>I do NOT upload node_modules to GitHub (I add it to .gitignore)</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-node-next","title":"Where to go next later 🔗","html":"<div class=\"block\" id=\"block-node-next\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-node-next')\">Where to go next <span class=\"badge opt\">later</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"explain\">\n        When you master a basic Express server, the next topics are:<br>\n        • <strong>POST/PUT/DELETE</strong> — not only receiving data, but also creating, changing and deleting it<br>\n        • <strong>Middleware</strong> — intermediate handlers (auth checks, logs)<br>\n        • <strong>Connecting a database</strong> — so data is stored (see the SQL section)<br>\n        • <strong>Authorization</strong> — login/registration with tokens (JWT)<br>\n        • <strong>Environment variables</strong> (.env) — store passwords and keys separately from code<br><br>\n        💡 Best way to learn: <strong>move your TodoList to the server</strong>. Right now it stores tasks in localStorage (only in the browser). Make the tasks store on the server, and then they will be available from any device.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb500\" onchange=\"updateProgress(this)\"><span>I learned about POST/PUT/DELETE (methods for changing data)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb501\" onchange=\"updateProgress(this)\"><span>I understand why environment variables (.env) are needed</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb502\" onchange=\"updateProgress(this)\"><span>Goal: move TodoList to server-side storage</span></label>\n      </div>\n    </div>\n\n  \n    "},{"id":"block-node-env","title":"Environment variables and .env basics 🔗","html":"<div class=\"block\" id=\"block-node-env\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-node-env')\">Environment variables and .env <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\"># .env file</span>\nPORT=3000\nDB_URL=postgresql://localhost:5432/mydb\nJWT_SECRET=supersecretkey123\nNODE_ENV=development\n\n<span class=\"cm\">// Usage through dotenv</span>\n<span class=\"kw\">import</span> dotenv <span class=\"kw\">from</span> <span class=\"str\">'dotenv'</span>;\ndotenv.<span class=\"fn\">config</span>();\n\n<span class=\"kw\">const</span> port = process.env.PORT || <span class=\"num\">3000</span>;\n<span class=\"kw\">const</span> dbUrl = process.env.DB_URL;\n\n<span class=\"cm\">// Never commit .env!</span>\n<span class=\"cm\"># .gitignore</span>\n.env\n.env.local\nnode_modules/</div>\n      <div class=\"explain\">\n        <strong>process.env</strong> — global Node.js object with environment variables.<br>\n        <strong>dotenv</strong> — loads the .env file into process.env. Install: <code>npm i dotenv</code>.<br>\n        <strong>.env in .gitignore</strong> — required! Otherwise secrets will get into the public repository.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb506\" onchange=\"updateProgress(this)\"><span>process.env — environment variables in Node</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb507\" onchange=\"updateProgress(this)\"><span>dotenv — loading .env file</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb508\" onchange=\"updateProgress(this)\"><span>.env in .gitignore — secret protection</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-node-fs","title":"Working with the file system (fs) know 🔗","html":"<div class=\"block\" id=\"block-node-fs\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-node-fs')\">Working with the file system (fs) <span class=\"badge\">know</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"kw\">import</span> fs <span class=\"kw\">from</span> <span class=\"str\">'fs/promises'</span>; <span class=\"cm\">// async version</span>\n<span class=\"kw\">import</span> path <span class=\"kw\">from</span> <span class=\"str\">'path'</span>;\n\n<span class=\"cm\">// Reading a file</span>\n<span class=\"kw\">const</span> data = <span class=\"kw\">await</span> fs.<span class=\"fn\">readFile</span>(<span class=\"str\">'data.json'</span>, <span class=\"str\">'utf-8'</span>);\n<span class=\"kw\">const</span> json = JSON.<span class=\"fn\">parse</span>(data);\n\n<span class=\"cm\">// Writing a file</span>\n<span class=\"kw\">await</span> fs.<span class=\"fn\">writeFile</span>(<span class=\"str\">'output.json'</span>, JSON.<span class=\"fn\">stringify</span>(json, <span class=\"kw\">null</span>, <span class=\"num\">2</span>));\n\n<span class=\"cm\">// Creating a folder</span>\n<span class=\"kw\">await</span> fs.<span class=\"fn\">mkdir</span>(<span class=\"str\">'uploads'</span>, { recursive: <span class=\"kw\">true</span> });\n\n<span class=\"cm\">// File path — use path.join!</span>\n<span class=\"kw\">const</span> filePath = path.<span class=\"fn\">join</span>(__dirname, <span class=\"str\">'data'</span>, <span class=\"str\">'file.json'</span>);\n<span class=\"cm\">// Do NOT do: './data/' + filename (path traversal vulnerability)</span></div>\n      <div class=\"explain\">\n        <strong>fs/promises</strong> — use instead of the callback version. Works with async/await.<br>\n        <strong>path.join</strong> — always build paths through path.join, not through string concatenation.<br>\n        <strong>recursive: true</strong> — creates all nested folders and will not fail if they already exist.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb509\" onchange=\"updateProgress(this)\"><span>fs/promises — readFile, writeFile, mkdir</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb510\" onchange=\"updateProgress(this)\"><span>path.join — safe path building</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-nextjs-ssg-isr","title":"SSG and ISR — static generation Next.js strength 🔗","html":"<div class=\"block\" id=\"block-nextjs-ssg-isr\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-nextjs-ssg-isr')\">SSG and ISR — static generation <span class=\"badge good\">Next.js strength</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Besides CSR and SSR, Next.js has two more rendering modes. They make Next.js fast and popular for content websites: blogs, stores and documentation.</div>\n      <div class=\"code\"><span class=\"cm\">// SSG (Static Site Generation) — page is generated ONCE at build time</span>\n<span class=\"kw\">export default async function</span> <span class=\"fn\">BlogPost</span>({ params }) {\n  <span class=\"kw\">const</span> post = <span class=\"kw\">await</span> <span class=\"fn\">getPost</span>(params.slug);\n  <span class=\"kw\">return</span> &lt;<span class=\"tag\">article</span>&gt;{post.title}&lt;/<span class=\"tag\">article</span>&gt;;\n}\n\n<span class=\"cm\">// Specify which pages to generate in advance during npm run build</span>\n<span class=\"kw\">export async function</span> <span class=\"fn\">generateStaticParams</span>() {\n  <span class=\"kw\">const</span> posts = <span class=\"kw\">await</span> <span class=\"fn\">getAllPosts</span>();\n  <span class=\"kw\">return</span> posts.<span class=\"fn\">map</span>(p =&gt; ({ slug: p.slug }));\n}\n<span class=\"cm\">// Result: ready HTML for each post, served instantly like a normal file</span>\n\n<span class=\"cm\">// ISR (Incremental Static Regeneration) — static page that updates itself</span>\n<span class=\"kw\">export const</span> revalidate = <span class=\"num\">60</span>; <span class=\"cm\">// rebuild the page no more than once every 60 seconds</span>\n\n<span class=\"kw\">export default async function</span> <span class=\"fn\">ProductPage</span>({ params }) {\n  <span class=\"kw\">const</span> product = <span class=\"kw\">await</span> <span class=\"fn\">getProduct</span>(params.id); <span class=\"cm\">// data can change (price, availability)</span>\n  <span class=\"kw\">return</span> &lt;<span class=\"tag\">div</span>&gt;{product.price}&lt;/<span class=\"tag\">div</span>&gt;;\n}\n<span class=\"cm\">// First visitor after 60 seconds gets the old version,</span>\n<span class=\"cm\">// but Next.js rebuilds the page in the background; next visitors see the new version</span></div>\n      <div class=\"explain\">\n        <strong>SSG</strong> — best option for content that rarely changes: blog, docs, landing page. The page is ready in advance and served instantly as a static file.<br>\n        <strong>ISR</strong> — compromise between SSG and SSR: the page is static and fast, but automatically updates at a set interval without rebuilding the whole site.<br>\n        <strong>PPR (Partial Prerendering)</strong> — modern Next.js approach: static shell is served instantly, and dynamic zones stream in through Suspense.<br>\n        <strong>Edge Runtime</strong> — running some server code closer to the user when low latency matters and there is no dependency on Node-only APIs.<br>\n        <strong>When to choose what:</strong> SSG — content almost does not change; ISR — changes sometimes (prices, stock); SSR — changes on every request (account, dashboard).\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb523\" onchange=\"updateProgress(this)\"><span>SSG — generateStaticParams, pages are ready at build time</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb524\" onchange=\"updateProgress(this)\"><span>ISR — revalidate, static pages auto-update in the background</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb525\" onchange=\"updateProgress(this)\"><span>I understand when to choose SSG, ISR or SSR</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb525a\" onchange=\"updateProgress(this)\"><span>PPR and Edge Runtime — I understand modern Next.js rendering modes</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-node-auth-types","title":"Session vs JWT — two authorization approaches critical 🔗","html":"<div class=\"block\" id=\"block-node-auth-types\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-node-auth-types')\">Session vs JWT — two authorization approaches <span class=\"badge must\">critical</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">This is a backend fundamental. The difference between session-based and token-based authorization is asked at almost every interview.</div>\n      <div class=\"code\"><span class=\"cm\">// ===== Session-based (classic approach) =====</span>\n<span class=\"cm\">// 1. User logs in → server creates a session in DB/memory</span>\n<span class=\"cm\">// 2. Server sends a cookie with session ID</span>\n<span class=\"cm\">// 3. Every request → server looks up the session by ID in its storage</span>\n\napp.<span class=\"fn\">post</span>(<span class=\"str\">'/login'</span>, (req, res) =&gt; {\n  req.session.userID = user.id; <span class=\"cm\">// saved on the server (Redis/DB)</span>\n  res.<span class=\"fn\">send</span>(<span class=\"str\">'OK'</span>);\n});\n<span class=\"cm\">// Server MUST store session state — this is stateful</span>\n\n<span class=\"cm\">// ===== JWT (Token-based, modern approach) =====</span>\n<span class=\"cm\">// 1. User logs in → server signs a token and sends it</span>\n<span class=\"cm\">// 2. Server does NOT store the token — all info is inside the token</span>\n<span class=\"cm\">// 3. Every request → server only checks the token signature</span>\n\n<span class=\"kw\">const</span> token = jwt.<span class=\"fn\">sign</span>({ userID: user.id }, SECRET, { expiresIn: <span class=\"str\">'15m'</span> });\nres.<span class=\"fn\">json</span>({ token });\n<span class=\"cm\">// Server stores NOTHING — this is stateless and scales easily</span></div>\n      <div class=\"explain\">\n        <strong>Session</strong> — server stores state. Easy to revoke access by deleting the session, but harder to scale across many servers.<br>\n        <strong>JWT</strong> — server stores nothing (stateless). Easy to scale, but harder to revoke a token before it expires.<br>\n        <strong>In practice:</strong> JWT is standard for API and SPA/mobile apps. Session is sometimes used in classic server apps (Django, Rails).\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb526\" onchange=\"updateProgress(this)\"><span>Session-based — server stores state</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb527\" onchange=\"updateProgress(this)\"><span>JWT — all information is inside the token, server is stateless</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb528\" onchange=\"updateProgress(this)\"><span>I understand the pros and cons of each approach</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-node-access-refresh","title":"Access and Refresh tokens critical 🔗","html":"<div class=\"block\" id=\"block-node-access-refresh\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-node-access-refresh')\">Access and Refresh tokens <span class=\"badge must\">critical</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Why not issue one token forever? Because if it is stolen (XSS, interception), the attacker gets permanent access. Solution: short-lived Access + long-lived Refresh.</div>\n      <div class=\"code\"><span class=\"cm\">// Access Token lives SHORTLY (minutes), used in every request</span>\n<span class=\"kw\">const</span> accessToken = jwt.<span class=\"fn\">sign</span>({ userID }, ACCESS_SECRET, { expiresIn: <span class=\"str\">'15m'</span> });\n\n<span class=\"cm\">// Refresh Token lives LONG (days/weeks), stored safely (httpOnly cookie)</span>\n<span class=\"kw\">const</span> refreshToken = jwt.<span class=\"fn\">sign</span>({ userID }, REFRESH_SECRET, { expiresIn: <span class=\"str\">'7d'</span> });\n\n<span class=\"cm\">// When Access Token expires, client uses Refresh to get a new one</span>\napp.<span class=\"fn\">post</span>(<span class=\"str\">'/refresh'</span>, (req, res) =&gt; {\n  <span class=\"kw\">const</span> { refreshToken } = req.cookies;\n  <span class=\"kw\">try</span> {\n    <span class=\"kw\">const</span> payload = jwt.<span class=\"fn\">verify</span>(refreshToken, REFRESH_SECRET);\n    <span class=\"kw\">const</span> newAccessToken = jwt.<span class=\"fn\">sign</span>({ userID: payload.userID }, ACCESS_SECRET, { expiresIn: <span class=\"str\">'15m'</span> });\n    res.<span class=\"fn\">json</span>({ accessToken: newAccessToken }); <span class=\"cm\">// rotation: issue a new one</span>\n  } <span class=\"kw\">catch</span> {\n    res.<span class=\"fn\">status</span>(<span class=\"num\">401</span>).<span class=\"fn\">send</span>(<span class=\"str\">'Refresh token is invalid — login again'</span>);\n  }\n});</div>\n      <div class=\"explain\">\n        <strong>Why two tokens:</strong> Access lives briefly, so even if stolen the attack window is small (15 minutes). Refresh lives longer, but is stored only in an httpOnly cookie unavailable to JS/XSS.<br>\n        <strong>Token rotation</strong> — each time Refresh is used to get a new Access token, sometimes a new Refresh token is issued and the old one is invalidated.<br>\n        <strong>If Refresh is stolen</strong> — the server can revoke it (store a blacklist), unlike pure stateless JWT.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb529\" onchange=\"updateProgress(this)\"><span>Access Token — short-lived, used in every request</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb530\" onchange=\"updateProgress(this)\"><span>Refresh Token — long-lived, used to get a new Access token</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb531\" onchange=\"updateProgress(this)\"><span>I understand why token rotation is needed</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-node-cookies-security","title":"Secure cookies: httpOnly, Secure, SameSite critical for frontend 🔗","html":"<div class=\"block\" id=\"block-node-cookies-security\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-node-cookies-security')\">Secure cookies: httpOnly, Secure, SameSite <span class=\"badge must\">critical for frontend</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Storing tokens in localStorage in real projects is unsafe: any script embedded on the page (XSS attack) can read them. httpOnly cookie solves this problem.</div>\n      <div class=\"code\"><span class=\"cm\">// ❌ localStorage is available to ANY JS on the page</span>\nlocalStorage.<span class=\"fn\">setItem</span>(<span class=\"str\">'token'</span>, accessToken);\n<span class=\"cm\">// If a malicious script (XSS) gets onto the site, it steals the token</span>\n\n<span class=\"cm\">// ✅ httpOnly cookie — JavaScript CANNOT read it</span>\nres.<span class=\"fn\">cookie</span>(<span class=\"str\">'refreshToken'</span>, refreshToken, {\n  httpOnly: <span class=\"kw\">true</span>,   <span class=\"cm\">// unavailable through document.cookie / JS</span>\n  secure: <span class=\"kw\">true</span>,     <span class=\"cm\">// sent only through HTTPS</span>\n  sameSite: <span class=\"str\">'strict'</span>, <span class=\"cm\">// CSRF protection — not sent from other sites</span>\n  maxAge: <span class=\"num\">7</span> * <span class=\"num\">24</span> * <span class=\"num\">60</span> * <span class=\"num\">60</span> * <span class=\"num\">1000</span> <span class=\"cm\">// 7 days in milliseconds</span>\n});</div>\n      <div class=\"explain\">\n        <strong>httpOnly</strong> — cookie is unavailable through <code>document.cookie</code>, protects from XSS (malicious scripts on the page).<br>\n        <strong>Secure</strong> — cookie is sent only via HTTPS, not regular HTTP.<br>\n        <strong>SameSite: strict/lax</strong> — browser does not send cookies if the request came from another domain; CSRF protection.<br>\n        <strong>Practice:</strong> Refresh Token goes into httpOnly cookie. Access Token can be kept in app memory (JS variable), not localStorage.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb532\" onchange=\"updateProgress(this)\"><span>httpOnly — cookie is unavailable to JavaScript, protection from XSS</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb533\" onchange=\"updateProgress(this)\"><span>Secure and SameSite — transport protection and CSRF protection</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb534\" onchange=\"updateProgress(this)\"><span>I understand why localStorage is unsafe for tokens</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-node-cors-security","title":"CORS and Security Headers often breaks 🔗","html":"<div class=\"block\" id=\"block-node-cors-security\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-node-cors-security')\">CORS and Security Headers <span class=\"badge must\">often breaks</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">When frontend is on one domain and API on another, the browser enables a CORS check. This is not a JS error, but browser protection.</div>\n      <div class=\"code\"><span class=\"cm\">// Express + cors</span>\n<span class=\"kw\">import</span> cors <span class=\"kw\">from</span> <span class=\"str\">'cors'</span>;\n<span class=\"kw\">import</span> helmet <span class=\"kw\">from</span> <span class=\"str\">'helmet'</span>;\n\napp.<span class=\"fn\">use</span>(<span class=\"fn\">cors</span>({\n  origin: <span class=\"str\">'https://my-frontend.ru'</span>,\n  credentials: <span class=\"kw\">true</span>,\n  methods: [<span class=\"str\">'GET'</span>, <span class=\"str\">'POST'</span>, <span class=\"str\">'PUT'</span>, <span class=\"str\">'DELETE'</span>]\n}));\n\napp.<span class=\"fn\">use</span>(<span class=\"fn\">helmet</span>({\n  contentSecurityPolicy: {\n    directives: {\n      defaultSrc: [<span class=\"str\">\"'self'\"</span>],\n      scriptSrc: [<span class=\"str\">\"'self'\"</span>]\n    }\n  }\n}));</div>\n      <div class=\"explain\">\n        <strong>Access-Control-Allow-Origin</strong> tells the browser which frontend may read the API response.<br>\n        <strong>credentials: true</strong> is needed when requests use cookies. Then you cannot set <code>origin: '*'</code>.<br>\n        <strong>CSP, HSTS, X-Content-Type-Options</strong> — security headers. In Express they are often set through <code>helmet</code>.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-node-cors-1\" onchange=\"updateProgress(this)\"><span>CORS — I understand why the browser blocks another origin</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-node-cors-2\" onchange=\"updateProgress(this)\"><span>credentials + cookie require an exact origin, not *</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-node-cors-3\" onchange=\"updateProgress(this)\"><span>Helmet — basic security headers for Express</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-node-zod-advanced","title":"Zod: refine and transform practice 🔗","html":"<div class=\"block\" id=\"block-node-zod-advanced\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-node-zod-advanced')\">Zod: refine and transform <span class=\"badge good\">practice</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">A basic schema checks types. In real code you often need extra rules: password matching, string cleanup, converting strings to numbers.</div>\n      <div class=\"code\"><span class=\"kw\">const</span> registerSchema = z.<span class=\"fn\">object</span>({\n  email: z.<span class=\"fn\">string</span>().<span class=\"fn\">trim</span>().<span class=\"fn\">toLowerCase</span>().<span class=\"fn\">email</span>(),\n  password: z.<span class=\"fn\">string</span>().<span class=\"fn\">min</span>(<span class=\"num\">8</span>),\n  confirm: z.<span class=\"fn\">string</span>(),\n  age: z.<span class=\"fn\">string</span>().<span class=\"fn\">transform</span>(Number)\n}).<span class=\"fn\">refine</span>(\n  data =&gt; data.password === data.confirm,\n  { path: [<span class=\"str\">'confirm'</span>], message: <span class=\"str\">'Passwords do not match'</span> }\n);\n\n<span class=\"kw\">const</span> result = registerSchema.<span class=\"fn\">safeParse</span>(req.body);</div>\n      <div class=\"explain\">\n        <strong>transform</strong> changes a value after validation: for example, string <code>\"18\"</code> turns into number <code>18</code>.<br>\n        <strong>refine</strong> adds a rule that depends on several fields at once.<br>\n        <strong>path</strong> shows which field to attach the error to so the frontend highlights the correct input.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-node-zod-advanced-1\" onchange=\"updateProgress(this)\"><span>transform — data transformation after validation</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-node-zod-advanced-2\" onchange=\"updateProgress(this)\"><span>refine — custom check, for example password match</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-node-api-styles","title":"REST, GraphQL, gRPC, tRPC and SSE API architecture 🔗","html":"<div class=\"block\" id=\"block-node-api-styles\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-node-api-styles')\">REST, GraphQL, gRPC, tRPC and SSE <span class=\"badge good\">API architecture</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">REST is the base. But teams also use other approaches: GraphQL for flexible queries, gRPC for microservices, tRPC for TypeScript fullstack, SSE for streaming.</div>\n      <div class=\"explain\">\n        <strong>REST</strong> — resources and HTTP-methods: GET, POST, PUT/PATCH, DELETE. Best start for a beginner.<br>\n        <strong>GraphQL</strong> — client chooses fields through Query/Mutation, while the server describes resolver functions.<br>\n        <strong>gRPC + Protobuf</strong> — binary protocol for service-to-service communication. Faster than JSON, but harder to start.<br>\n        <strong>tRPC</strong> — end-to-end typing between frontend and backend in TypeScript projects without a manual OpenAPI schema.<br>\n        <strong>SSE</strong> — Server-Sent Events. Native stream from server to client: feeds, progress, AI text generation. WebSocket is more common for chats.\n      </div>\n      <div class=\"code\"><span class=\"cm\">// SSE: server sends an event stream</span>\napp.<span class=\"fn\">get</span>(<span class=\"str\">'/events'</span>, (req, res) =&gt; {\n  res.<span class=\"fn\">setHeader</span>(<span class=\"str\">'Content-Type'</span>, <span class=\"str\">'text/event-stream'</span>);\n  res.<span class=\"fn\">write</span>(<span class=\"str\">'data: hello\\\\n\\\\n'</span>);\n});\n\n<span class=\"cm\">// Client</span>\n<span class=\"kw\">const</span> events = <span class=\"kw\">new</span> <span class=\"fn\">EventSource</span>(<span class=\"str\">'/events'</span>);\nevents.<span class=\"fn\">onmessage</span> = (e) =&gt; console.<span class=\"fn\">log</span>(e.data);</div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-node-api-styles-1\" onchange=\"updateProgress(this)\"><span>REST — API base through HTTP methods</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-node-api-styles-2\" onchange=\"updateProgress(this)\"><span>GraphQL, gRPC and tRPC — I understand where they are used</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-node-api-styles-3\" onchange=\"updateProgress(this)\"><span>SSE — one-way event stream from the server</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-node-websockets","title":"WebSockets — real time (Socket.io) important 🔗","html":"<div class=\"block\" id=\"block-node-websockets\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-node-websockets')\">WebSockets — real time (Socket.io) <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">REST API works by the “request → response” principle. But chats, real-time notifications and live updates (for example, collaborative editing) need a persistent connection — that is what WebSockets are for.</div>\n      <div class=\"code\"><span class=\"cm\">// Server (Node.js + Socket.io)</span>\n<span class=\"kw\">import</span> { Server } <span class=\"kw\">from</span> <span class=\"str\">'socket.io'</span>;\n\n<span class=\"kw\">const</span> io = <span class=\"kw\">new</span> <span class=\"fn\">Server</span>(httpServer);\n\nio.<span class=\"fn\">on</span>(<span class=\"str\">'connection'</span>, (socket) =&gt; {\n  console.<span class=\"fn\">log</span>(<span class=\"str\">'Client connected'</span>);\n\n  socket.<span class=\"fn\">on</span>(<span class=\"str\">'message'</span>, (text) =&gt; {\n    io.<span class=\"fn\">emit</span>(<span class=\"str\">'message'</span>, text); <span class=\"cm\">// send to ALL connected clients</span>\n  });\n\n  socket.<span class=\"fn\">on</span>(<span class=\"str\">'disconnect'</span>, () =&gt; console.<span class=\"fn\">log</span>(<span class=\"str\">'Client disconnected'</span>));\n});\n\n<span class=\"cm\">// Client (React)</span>\n<span class=\"kw\">import</span> { io } <span class=\"kw\">from</span> <span class=\"str\">'socket.io-client'</span>;\n\n<span class=\"kw\">const</span> socket = <span class=\"fn\">io</span>(<span class=\"str\">'http://localhost:3000'</span>);\n\nsocket.<span class=\"fn\">on</span>(<span class=\"str\">'message'</span>, (text) =&gt; {\n  <span class=\"fn\">setMessages</span>(prev =&gt; [...prev, text]); <span class=\"cm\">// new message appears instantly</span>\n});\n\nsocket.<span class=\"fn\">emit</span>(<span class=\"str\">'message'</span>, <span class=\"str\">'Hello everyone!'</span>); <span class=\"cm\">// send message to server</span></div>\n      <div class=\"explain\">\n        <strong>Main difference from HTTP:</strong> the connection stays open, so the server can send data to the client without the client requesting first.<br>\n        <strong>socket.emit</strong> — send an event. <strong>socket.on</strong> — subscribe to an event.<br>\n        <strong>Where it is used:</strong> chats, live notifications, collaborative document editing, online games, real-time stock quotes.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb538\" onchange=\"updateProgress(this)\"><span>I understand the difference between WebSocket and a normal REST request</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb539\" onchange=\"updateProgress(this)\"><span>socket.emit / socket.on — basic Socket.io API</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb540\" onchange=\"updateProgress(this)\"><span>I know common use cases: chats, notifications, real-time boards</span></label>\n      </div>\n    </div>\n"}]},{"id":"sec-sql","lessons":[{"id":"block-sql-practice","title":"Where to practice tip 🔗","html":"<div class=\"block\" id=\"block-sql-practice\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-sql-practice')\">Where to practice <span class=\"badge opt\">tip</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"explain\">\n        <strong>Without installation (in the browser):</strong><br>\n        • <strong>sqlbolt.com</strong> — interactive SQL tutorial from scratch, best for start<br>\n        • <strong>sql-ex.ru</strong> — tasks in Russian<br>\n        • <strong>db-fiddle.com</strong> — sandbox, try queries online<br><br>\n        <strong>For projects:</strong><br>\n        • <strong>SQLite</strong> — the simplest DB, the whole database in one file. Perfect for starting with Node.js<br>\n        • <strong>PostgreSQL</strong> — serious DB for real projects. Free and powerful<br><br>\n        💡 With Node.js, databases are connected through packages: <code>better-sqlite3</code> (for SQLite) or <code>pg</code> (for PostgreSQL).\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb553\" onchange=\"updateProgress(this)\"><span>I completed the interactive course on sqlbolt.com</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb554\" onchange=\"updateProgress(this)\"><span>I tried SQLite (database in one file)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb555\" onchange=\"updateProgress(this)\"><span>Goal: connect a DB to my Node.js server</span></label>\n      </div>\n    </div>\n\n  \n    "},{"id":"block-sql-aggregate","title":"Aggregate functions and GROUP BY basics 🔗","html":"<div class=\"block\" id=\"block-sql-aggregate\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-sql-aggregate')\">Aggregate functions and GROUP BY <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">-- Aggregate functions</span>\n<span class=\"kw\">SELECT</span>\n  <span class=\"fn\">COUNT</span>(*) <span class=\"kw\">AS</span> total_orders,\n  <span class=\"fn\">SUM</span>(amount) <span class=\"kw\">AS</span> revenue,\n  <span class=\"fn\">AVG</span>(amount) <span class=\"kw\">AS</span> avg_order,\n  <span class=\"fn\">MAX</span>(amount) <span class=\"kw\">AS</span> max_order,\n  <span class=\"fn\">MIN</span>(amount) <span class=\"kw\">AS</span> min_order\n<span class=\"kw\">FROM</span> orders;\n\n<span class=\"cm\">-- GROUP BY — grouping</span>\n<span class=\"kw\">SELECT</span> user_id, <span class=\"fn\">COUNT</span>(*) <span class=\"kw\">AS</span> orders_count, <span class=\"fn\">SUM</span>(amount)\n<span class=\"kw\">FROM</span> orders\n<span class=\"kw\">GROUP BY</span> user_id\n<span class=\"kw\">ORDER BY</span> orders_count <span class=\"kw\">DESC</span>;\n\n<span class=\"cm\">-- HAVING — filter after grouping (not WHERE!)</span>\n<span class=\"kw\">SELECT</span> user_id, <span class=\"fn\">SUM</span>(amount) <span class=\"kw\">AS</span> total\n<span class=\"kw\">FROM</span> orders\n<span class=\"kw\">GROUP BY</span> user_id\n<span class=\"kw\">HAVING</span> <span class=\"fn\">SUM</span>(amount) &gt; <span class=\"num\">1000</span>; <span class=\"cm\">-- only large customers</span></div>\n      <div class=\"explain\">\n        <strong>COUNT(*)</strong> — counts all rows. COUNT(column) counts only non-NULL values.<br>\n        <strong>GROUP BY</strong> — is required when you use aggregate functions with other columns.<br>\n        <strong>HAVING vs WHERE</strong> — WHERE filters rows BEFORE grouping, HAVING AFTER.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb559\" onchange=\"updateProgress(this)\"><span>COUNT, SUM, AVG, MAX, MIN — aggregate functions</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb560\" onchange=\"updateProgress(this)\"><span>GROUP BY — result grouping</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb561\" onchange=\"updateProgress(this)\"><span>HAVING — filtering after grouping</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-sql-indexes","title":"Indexes and optimization important 🔗","html":"<div class=\"block\" id=\"block-sql-indexes\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-sql-indexes')\">Indexes and optimization <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">-- Index speeds up search (B-tree structure)</span>\n<span class=\"kw\">CREATE INDEX</span> idx_users_email <span class=\"kw\">ON</span> users(email);\n<span class=\"kw\">CREATE INDEX</span> idx_orders_user_id <span class=\"kw\">ON</span> orders(user_id);\n\n<span class=\"cm\">-- Unique index</span>\n<span class=\"kw\">CREATE UNIQUE INDEX</span> idx_unique_email <span class=\"kw\">ON</span> users(email);\n\n<span class=\"cm\">-- EXPLAIN ANALYZE — view query plan</span>\n<span class=\"kw\">EXPLAIN ANALYZE</span>\n<span class=\"kw\">SELECT</span> * <span class=\"kw\">FROM</span> users <span class=\"kw\">WHERE</span> email = <span class=\"str\">'test@test.com'</span>;\n<span class=\"cm\">-- Without an index: Seq Scan (scans all rows)</span>\n<span class=\"cm\">-- With an index: Index Scan (instant)</span>\n\n<span class=\"cm\">-- When to create an index:</span>\n<span class=\"cm\">-- ✓ Columns in WHERE, JOIN ON, ORDER BY</span>\n<span class=\"cm\">-- ✗ Columns that update often</span>\n<span class=\"cm\">-- ✗ Small tables (&lt; 1000 rows)</span></div>\n      <div class=\"explain\">\n        <strong>Index</strong> is like a table of contents in a book. Without it, the DB reads all rows (Seq Scan).<br>\n        <strong>PRIMARY KEY</strong> automatically creates an index.<br>\n        <strong>EXPLAIN ANALYZE</strong> — main optimization tool. Shows how a query is executed.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb562\" onchange=\"updateProgress(this)\"><span>CREATE INDEX — speeds up search by column</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb563\" onchange=\"updateProgress(this)\"><span>EXPLAIN ANALYZE — execution plan analysis</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb564\" onchange=\"updateProgress(this)\"><span>I know when an index helps and when it does not</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-sql-transactions-isolation","title":"Transactions and isolation levels important 🔗","html":"<div class=\"block\" id=\"block-sql-transactions-isolation\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-sql-transactions-isolation')\">Transactions and isolation levels <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">A transaction is a group of queries that must complete as a whole. If one step fails, everything rolls back.</div>\n      <div class=\"code\"><span class=\"cm\">-- Money transfer: either both queries run, or none</span>\n<span class=\"kw\">BEGIN</span>;\n\n<span class=\"kw\">UPDATE</span> accounts\n<span class=\"kw\">SET</span> balance = balance - <span class=\"num\">1000</span>\n<span class=\"kw\">WHERE</span> id = <span class=\"num\">1</span>;\n\n<span class=\"kw\">UPDATE</span> accounts\n<span class=\"kw\">SET</span> balance = balance + <span class=\"num\">1000</span>\n<span class=\"kw\">WHERE</span> id = <span class=\"num\">2</span>;\n\n<span class=\"kw\">COMMIT</span>;   <span class=\"cm\">-- save changes</span>\n<span class=\"cm\">-- ROLLBACK; -- cancel everything inside the transaction</span>\n\n<span class=\"cm\">-- Isolation level: how much transactions see each other</span>\n<span class=\"kw\">BEGIN</span>;\n<span class=\"kw\">SET TRANSACTION ISOLATION LEVEL</span> SERIALIZABLE;\n<span class=\"cm\">-- important queries...</span>\n<span class=\"kw\">COMMIT</span>;</div>\n      <div class=\"explain\">\n        <strong>ACID</strong> — database protects data: atomicity, consistency, isolation, durability.<br>\n        <strong>Read Committed</strong> — default in PostgreSQL: you see only committed data.<br>\n        <strong>Repeatable Read / Serializable</strong> — stricter, but more expensive for performance. Needed for money, bookings and product stock.<br>\n        <strong>PgBouncer</strong> — connection pooler before PostgreSQL. Helps avoid killing the DB with thousands of connections.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-sql-tx-1\" onchange=\"updateProgress(this)\"><span>BEGIN / COMMIT / ROLLBACK — I understand the basic transaction cycle</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-sql-tx-2\" onchange=\"updateProgress(this)\"><span>I understand why isolation levels are needed</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-sql-tx-3\" onchange=\"updateProgress(this)\"><span>I have heard of PgBouncer as a connection pooler</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-sql-nosql-redis","title":"Redis and NoSQL — when SQL is not enough overview 🔗","html":"<div class=\"block\" id=\"block-sql-nosql-redis\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-sql-nosql-redis')\">Redis and NoSQL — when SQL is not enough <span class=\"badge rec\">overview</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">SQL remains the foundation for most projects. Redis and MongoDB are added when there is a specific task: cache, sessions, queues or flexible documents.</div>\n      <div class=\"code\"><span class=\"cm\"># Redis — fast data in memory</span>\nSET user:42 \"Alex\"\nGET user:42\nEXPIRE user:42 3600       <span class=\"cm\"># delete after an hour</span>\n\n<span class=\"cm\"># List as a simple task queue</span>\nLPUSH jobs \"send-email\"\nRPOP jobs\n\n<span class=\"cm\"># Common scenarios</span>\ncache:homepage\nsession:user:42\nrate-limit:ip:127.0.0.1\nqueue:emails</div>\n      <div class=\"explain\">\n        <strong>Redis</strong> — super-fast in-memory key-value storage. Often used for cache, sessions, rate limits and queues.<br>\n        <strong>MongoDB</strong> — document-oriented database. Useful when data structure changes often.<br>\n        <strong>Main rule:</strong> start with PostgreSQL/SQL. Add NoSQL not “because it is trendy”, but when there is a real reason.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-sql-redis-1\" onchange=\"updateProgress(this)\"><span>I understand Redis as a fast key-value cache</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-sql-redis-2\" onchange=\"updateProgress(this)\"><span>I know scenarios: sessions, rate limit, queues, cache</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-sql-redis-3\" onchange=\"updateProgress(this)\"><span>I understand: NoSQL does not replace SQL by default</span></label>\n      </div>\n    </div>\n"},{"id":"block-sql-select","title":"SELECT — get data basics 🔗","html":"<div class=\"block\" id=\"block-sql-select\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-sql-select')\">SELECT — get data <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\"><strong>SELECT</strong> — the most common command. “Select/show me data”.</div>\n      <div class=\"code\">-- Get all columns of all users\nSELECT * FROM users;\n\n-- Only name and email\nSELECT name, email FROM users;\n\n-- With a condition: only adults\nSELECT * FROM users WHERE age &gt;= 18;\n\n-- Sort by name\nSELECT * FROM users ORDER BY name;\n\n-- Only first 10\nSELECT * FROM users LIMIT 10;</div>\n      <div class=\"explain\">\n        <strong>SELECT</strong> — what to show (* = everything, or list columns).<br>\n        <strong>FROM</strong> — from which table.<br>\n        <strong>WHERE</strong> — condition (filter). Like <code>filter()</code> in JS!<br>\n        <strong>ORDER BY</strong> — sorting.<br>\n        <strong>LIMIT</strong> — limit the count.<br>\n        💡 Notice: <code>WHERE age &gt;= 18</code> — this is the same logic as <code>tasks.filter(t =&gt; t.age &gt;= 18)</code> in your JS.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb544\" onchange=\"updateProgress(this)\"><span>I can write SELECT * FROM table</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb545\" onchange=\"updateProgress(this)\"><span>I understand WHERE (filter, like filter in JS)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb546\" onchange=\"updateProgress(this)\"><span>I know ORDER BY (sorting) and LIMIT (limit)</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-sql-crud","title":"INSERT, UPDATE, DELETE basics 🔗","html":"<div class=\"block\" id=\"block-sql-crud\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-sql-crud')\">INSERT, UPDATE, DELETE <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">This is CRUD: Create, Read, Update, Delete. Basic data operations. SELECT is Read; the other three are here.</div>\n      <div class=\"code\">-- CREATE: add a new user\nINSERT INTO users (name, email, age)\nVALUES ('sweety', 'sweety@mail.ru', 16);\n\n-- UPDATE: change data\nUPDATE users\nSET age = 17\nWHERE name = 'sweety';\n\n-- DELETE: delete\nDELETE FROM users\nWHERE id = 5;</div>\n      <div class=\"explain\">\n        <strong>INSERT INTO ... VALUES</strong> — adds a new row (record).<br>\n        <strong>UPDATE ... SET ... WHERE</strong> — changes data. <em>ALWAYS use WHERE!</em> Without WHERE you update ALL rows!<br>\n        <strong>DELETE FROM ... WHERE</strong> — deletes data. <em>Also always use WHERE!</em> Without WHERE you delete the whole table!<br><br>\n        ⚠️ <strong>Main beginner mistake:</strong> forgetting WHERE in UPDATE or DELETE. This deletes/changes EVERYTHING. In real work this is a disaster. Always check WHERE with SELECT first.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb547\" onchange=\"updateProgress(this)\"><span>I know CRUD: Create, Read, Update, Delete</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb548\" onchange=\"updateProgress(this)\"><span>I can use INSERT, UPDATE, DELETE</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb549\" onchange=\"updateProgress(this)\"><span>I ALWAYS write WHERE in UPDATE/DELETE, otherwise everything changes!</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-sql-keys","title":"Keys and table relationships important 🔗","html":"<div class=\"block\" id=\"block-sql-keys\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-sql-keys')\">Keys and table relationships <span class=\"badge rec\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Tables can be <strong>connected</strong> to each other. For example, the “posts” table is connected to “users”: each post knows its author.</div>\n      <div class=\"code\">-- Each table has a PRIMARY KEY (unique id)\nCREATE TABLE users (\n  id SERIAL PRIMARY KEY,    -- unique number, auto-increments\n  name TEXT,\n  email TEXT,\n  age INTEGER\n);\n\nCREATE TABLE posts (\n  id SERIAL PRIMARY KEY,\n  title TEXT,\n  user_id INTEGER REFERENCES users(id)  -- relationship!\n);</div>\n      <div class=\"explain\">\n        <strong>PRIMARY KEY</strong> — unique row identifier. Usually <code>id</code>. There cannot be two identical ones.<br>\n        <strong>SERIAL</strong> — auto-increment. First record = 1, second = 2, etc. You do not set it manually.<br>\n        <strong>FOREIGN KEY (REFERENCES)</strong> — “foreign key”, link to another table. <code>user_id</code> in posts points to <code>id</code> in users.<br>\n        💡 This avoids duplicating data. The user name is stored <em>once</em> in users, while posts simply refer to it by id.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb550\" onchange=\"updateProgress(this)\"><span>I understand PRIMARY KEY (unique row id)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb551\" onchange=\"updateProgress(this)\"><span>I understand table relationships through FOREIGN KEY</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb552\" onchange=\"updateProgress(this)\"><span>I understand why not to duplicate data (relationships instead of copies)</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-sql-joins","title":"JOIN — merge tables basics 🔗","html":"<div class=\"block\" id=\"block-sql-joins\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-sql-joins')\">JOIN — merge tables <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">-- Tables</span>\nusers:  id, name, email\norders: id, user_id, product, amount\n\n<span class=\"cm\">-- INNER JOIN — only matching rows</span>\n<span class=\"kw\">SELECT</span> users.name, orders.product, orders.amount\n<span class=\"kw\">FROM</span> users\n<span class=\"kw\">INNER JOIN</span> orders <span class=\"kw\">ON</span> users.id = orders.user_id;\n\n<span class=\"cm\">-- LEFT JOIN — all users, even without orders</span>\n<span class=\"kw\">SELECT</span> users.name, orders.product\n<span class=\"kw\">FROM</span> users\n<span class=\"kw\">LEFT JOIN</span> orders <span class=\"kw\">ON</span> users.id = orders.user_id;\n<span class=\"cm\">-- orders.product will be NULL if there are no orders</span>\n\n<span class=\"cm\">-- Multiple JOINs</span>\n<span class=\"kw\">SELECT</span> u.name, o.product, c.city\n<span class=\"kw\">FROM</span> users u\n<span class=\"kw\">JOIN</span> orders o <span class=\"kw\">ON</span> u.id = o.user_id\n<span class=\"kw\">JOIN</span> cities c <span class=\"kw\">ON</span> u.city_id = c.id;</div>\n      <div class=\"explain\">\n        <strong>INNER JOIN</strong> — intersection. Rows without a pair are dropped from both sides.<br>\n        <strong>LEFT JOIN</strong> — all rows from the left table + matching rows from the right one (NULL if none).<br>\n        <strong>Aliases (u, o)</strong> shorten queries with many JOINs.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb556\" onchange=\"updateProgress(this)\"><span>INNER JOIN — only matching rows</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb557\" onchange=\"updateProgress(this)\"><span>LEFT JOIN — all from left + NULL from right</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb558\" onchange=\"updateProgress(this)\"><span>Multiple JOINs in one query</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-sql-what","title":"What a database is basics 🔗","html":"<div class=\"block\" id=\"block-sql-what\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-sql-what')\">What a database is <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">A database is a place where data is stored so it can be <strong>quickly found, added, changed and deleted</strong>. Imagine a huge Excel table, but smarter and faster.</div>\n      <div class=\"explain\">\n        <strong>Relational DBs (SQL)</strong> store data in <em>tables</em> with rows and columns. PostgreSQL, MySQL, SQLite.<br>\n        <strong>Table</strong> — for example “users”. Columns: id, name, email. Each row is one user.<br>\n        <strong>SQL</strong> (Structured Query Language) is the language you use to ask the database: “give me all users older than 18”.<br><br>\n        <strong>There are also NoSQL databases</strong> (MongoDB), where data is stored as objects (like JSON), not tables. Start with <strong>SQL</strong>: it is more universal and in demand.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb541\" onchange=\"updateProgress(this)\"><span>I understand that a DB stores data for fast search</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb542\" onchange=\"updateProgress(this)\"><span>I know: table = rows (records) + columns (fields)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb543\" onchange=\"updateProgress(this)\"><span>I understand the difference between SQL (tables) and NoSQL (objects)</span></label>\n      </div>\n    </div>\n\n    "}]},{"id":"sec-devops","lessons":[{"id":"block-devops-server","title":"How a server works overview 🔗","html":"<div class=\"block\" id=\"block-devops-server\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-devops-server')\">How a server works <span class=\"badge rec\">overview</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\"><strong>Server</strong> is just a computer that is always on and responds to requests from the internet. When you open a site, your browser sends a request to the server and the server responds.</div>\n      <div class=\"explain\">\n        <strong>What happens when you open a site:</strong><br>\n        1. Browser sends a <strong>request</strong> to the server (by address/domain)<br>\n        2. <strong>DNS</strong> translates a domain (site.com) into the server IP address (for example 95.12.44.1)<br>\n        3. Server gets the request and processes it (may query the database)<br>\n        4. Server sends a <strong>response</strong> (HTML, JSON, image)<br>\n        5. Browser shows the result<br><br>\n        <strong>The more people</strong> — the more simultaneous requests. One server can choke. Next: how to deal with it.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb565\" onchange=\"updateProgress(this)\"><span>I understand: a server is an always-on computer responding to requests</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb566\" onchange=\"updateProgress(this)\"><span>I know that DNS translates a domain into an IP address</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb567\" onchange=\"updateProgress(this)\"><span>I understand the cycle: request → processing → response</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-devops-cache","title":"Caching — main speed booster overview 🔗","html":"<div class=\"block\" id=\"block-devops-cache\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-devops-cache')\">Caching — main speed booster <span class=\"badge rec\">overview</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\"><strong>Cache</strong> means “remember the result so you do not calculate it again”. The most important trick for speed and load.</div>\n      <div class=\"explain\">\n        <strong>Example:</strong> the home page shows “top 10 posts”. To collect them, you need to query the database, count and sort. This is <em>slow</em>. If 10,000 people open the home page, the database computes the same thing 10,000 times. <strong>Wasteful.</strong><br><br>\n        <strong>With cache:</strong> calculate once → <em>remember</em> the result for 5 minutes → the next 10,000 people get the ready result <em>instantly</em>. The database is unloaded.<br><br>\n        <strong>Tools:</strong><br>\n        • <strong>Redis</strong> — in-memory storage, very fast. Main cache tool<br>\n        • <strong>CDN</strong> (Cloudflare) — caches images/files on servers around the world, closer to the user<br>\n        • <strong>Browser cache</strong> — browser remembers images so it does not download them again\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb568\" onchange=\"updateProgress(this)\"><span>I understand cache: calculate once, remember, return ready result</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb569\" onchange=\"updateProgress(this)\"><span>I have heard of Redis (fast in-memory cache)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb570\" onchange=\"updateProgress(this)\"><span>I understand that CDN serves files closer to the user</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-devops-balance","title":"Load balancing overview 🔗","html":"<div class=\"block\" id=\"block-devops-balance\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-devops-balance')\">Load balancing <span class=\"badge rec\">overview</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">When there are too many people for one server, several servers are used and requests are spread between them. This is load balancing.</div>\n      <div class=\"explain\">\n        <strong>Problem:</strong> one server handles, for example, 1000 people at once. 5000 arrive — it falls.<br><br>\n        <strong>Solution — horizontal scaling:</strong><br>\n        1. Use <strong>5 identical servers</strong> instead of one<br>\n        2. Put a <strong>load balancer</strong> in front of them, for example Nginx<br>\n        3. The load balancer <em>distributes</em> requests: first person to server 1, second to server 2, etc.<br>\n        4. The load is split: each server handles its share<br><br>\n        <strong>Vertical scaling</strong> — means “make one server stronger” (more memory, CPU). Easier, but has a ceiling.<br>\n        <strong>Horizontal</strong> — means “add more servers”. Harder, but scales almost endlessly (this is how Google/Yandex work).\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb571\" onchange=\"updateProgress(this)\"><span>I understand that a load balancer spreads requests across servers</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb572\" onchange=\"updateProgress(this)\"><span>I know the difference: vertical (stronger) vs horizontal (more servers)</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb573\" onchange=\"updateProgress(this)\"><span>I have heard of Nginx as a load balancer/web server</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-devops-docker","title":"Docker — containers overview 🔗","html":"<div class=\"block\" id=\"block-devops-docker\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-devops-docker')\">Docker — containers <span class=\"badge rec\">overview</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\"><strong>Docker</strong> solves the “works on my machine, not on the server” problem. It packages the app with its whole environment into a container that works the same everywhere.</div>\n      <div class=\"explain\">\n        <strong>Problem without Docker:</strong> you wrote an app. Your computer has Node 20, teammate has Node 18, server has Node 16. Library versions differ. Works somewhere, breaks somewhere. Pain.<br><br>\n        <strong>With Docker:</strong> you describe in a <code>Dockerfile</code> the exact environment: Node version and packages. Docker creates a <strong>container</strong>, an isolated package containing everything the app needs. The container works <em>the same way</em> on your computer, a teammate's computer, and a server.<br><br>\n        <strong>Analogy:</strong> a container is like a shipping container on a ship. It does not matter what is inside: it has a standard size and fits any ship, crane or truck. Docker containers run the same on any server.\n      </div>\n      <div class=\"code\"># Simple Dockerfile for a Node app\nFROM node:20            # take a ready environment with Node 20\nWORKDIR /app            # working folder inside the container\nCOPY package.json .     # copy dependency list\nRUN npm install         # install packages\nCOPY . .                # copy all code\nCMD [\"node\", \"server.js\"]  # start command</div>\n      <div class=\"explain\">\n        <strong>FROM</strong> — what we build from (base image with Node).<br>\n        <strong>COPY</strong> — copy files into the container.<br>\n        <strong>RUN</strong> — run a command during build (package install).<br>\n        <strong>CMD</strong> — what to run when the container starts.<br>\n        💡 This is an <em>overview</em>: do not try to master Docker right now. Just understand the idea: package the app so it works the same everywhere.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb574\" onchange=\"updateProgress(this)\"><span>I understand the “works on my machine, not on the server” problem</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb575\" onchange=\"updateProgress(this)\"><span>I understand Docker: package an app with its environment</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb576\" onchange=\"updateProgress(this)\"><span>I know that Dockerfile describes how to build a container</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-devops-path","title":"Full picture: path to “many users” map 🔗","html":"<div class=\"block\" id=\"block-devops-path\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-devops-path')\">Full picture: path to “many users” <span class=\"badge opt\">map</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"explain\">\n        Here is the path from beginner to “the site handles load”, in order:<br><br>\n        <strong>1. Frontend</strong> (you are here) — HTML, CSS, JS<br>\n        <strong>2. Node.js</strong> — servers in familiar JS<br>\n        <strong>3. Databases</strong> — SQL, data storage<br>\n        <strong>4. Architecture</strong> — how to build an app correctly without bottlenecks<br>\n        <strong>5. Caching</strong> — Redis, CDN — speed<br>\n        <strong>6. Scaling</strong> — balancing, multiple servers<br>\n        <strong>7. Docker + clouds</strong> — packaging and deployment (AWS, Yandex Cloud)<br>\n        <strong>8. Monitoring</strong> — watch load, logs and crashes<br><br>\n        💡 This path takes <strong>years</strong>, not months. But each step logically follows the previous one. Right now your task is <strong>step 1</strong>. Do not jump ahead. Everything has its time.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb577\" onchange=\"updateProgress(this)\"><span>I see the full path to high-load systems</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb578\" onchange=\"updateProgress(this)\"><span>I understand that this is a years-long path, step by step</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb579\" onchange=\"updateProgress(this)\"><span>I focus on the current step and do not jump ahead</span></label>\n      </div>\n    </div>\n\n  \n    "},{"id":"block-devops-github-actions","title":"CI/CD: GitHub Actions — deployment automation connects Git + servers 🔗","html":"<div class=\"block\" id=\"block-devops-github-actions\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-devops-github-actions')\">CI/CD: GitHub Actions — deployment automation <span class=\"badge good\">connects Git + servers</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">CI/CD automates what you would otherwise do manually: code checks and deployment. One file — and on every push to main, the linter checks code and the project deploys automatically.</div>\n      <div class=\"code\"><span class=\"cm\"># .github/workflows/deploy.yml</span>\nname: Deploy\n\n<span class=\"kw\">on</span>:\n  push:\n    branches: [main]   <span class=\"cm\"># runs on push to main</span>\n\njobs:\n  build-and-deploy:\n    runs-on: ubuntu-latest\n\n    steps:\n      - <span class=\"kw\">uses</span>: actions/checkout@v4        <span class=\"cm\"># downloads repository code</span>\n\n      - <span class=\"kw\">uses</span>: actions/setup-node@v4\n        <span class=\"kw\">with</span>:\n          node-version: <span class=\"str\">'20'</span>\n\n      - <span class=\"kw\">run</span>: npm install                  <span class=\"cm\"># installs dependencies</span>\n      - <span class=\"kw\">run</span>: npm run lint                  <span class=\"cm\"># checks code with linter</span>\n      - <span class=\"kw\">run</span>: npm run build                 <span class=\"cm\"># builds the project</span>\n\n      - <span class=\"kw\">name</span>: Deploy to server\n        <span class=\"kw\">run</span>: |\n          echo \"Deploying to production...\"\n          <span class=\"cm\"># deployment command here: rsync, scp, or action for Vercel/Netlify</span></div>\n      <div class=\"explain\">\n        <strong>on: push: branches: [main]</strong> — runs workflow automatically on every push to the selected branch.<br>\n        <strong>jobs / steps</strong> — sequence of actions. If even one step fails (for example, lint finds errors), deploy will not happen.<br>\n        <strong>actions/checkout, actions/setup-node</strong> — ready-made pieces from GitHub that do typical things: download code, install Node.js.<br>\n        <strong>Career connection:</strong> configured CI/CD in your portfolio project is a strong signal to an employer that you understand not only code, but also the development process.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb580\" onchange=\"updateProgress(this)\"><span>.github/workflows/*.yml — where GitHub Actions live</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb581\" onchange=\"updateProgress(this)\"><span>on: push — automatic run on push to a branch</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb582\" onchange=\"updateProgress(this)\"><span>I configured automatic lint + build in at least one of my projects</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-devops-compose-nginx","title":"Docker Compose and Nginx reverse proxy overview 🔗","html":"<div class=\"block\" id=\"block-devops-compose-nginx\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-devops-compose-nginx')\">Docker Compose and Nginx reverse proxy <span class=\"badge rec\">overview</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Dockerfile builds one container. Docker Compose runs several at once: site, server, database, Redis. Nginx receives requests outside and forwards them inside.</div>\n      <div class=\"code\"><span class=\"cm\"># docker-compose.yml</span>\nservices:\n  app:\n    build: .\n    ports:\n      - \"3000:3000\"\n    env_file: .env\n    depends_on:\n      - db\n      - redis\n\n  db:\n    image: postgres:16\n    environment:\n      POSTGRES_PASSWORD: example\n\n  redis:\n    image: redis:7\n\n<span class=\"cm\"># nginx.conf — reverse proxy</span>\nserver {\n  listen 80;\n  server_name example.com;\n\n  location / {\n    proxy_pass http://app:3000;\n    proxy_set_header Host $host;\n    proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\n  }\n}</div>\n      <div class=\"explain\">\n        <strong>depends_on</strong> — shows container startup order.<br>\n        <strong>env_file</strong> — connects environment variables without hardcoding them in code.<br>\n        <strong>Reverse proxy</strong> — Nginx stands before the app: receives HTTP/HTTPS, serves static files, proxies requests to the Node server.<br>\n        <strong>For now the goal is simple:</strong> understand the scheme, not memorize DevOps.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-devops-compose-1\" onchange=\"updateProgress(this)\"><span>I understand: Compose runs several services with one command</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-devops-compose-2\" onchange=\"updateProgress(this)\"><span>I understand Nginx role as a reverse proxy before the app</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-devops-compose-3\" onchange=\"updateProgress(this)\"><span>I know why env_file is needed and why secrets are not written in code</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-devops-message-brokers","title":"Message queues: RabbitMQ and Kafka overview 🔗","html":"<div class=\"block\" id=\"block-devops-message-brokers\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-devops-message-brokers')\">Message queues: RabbitMQ and Kafka <span class=\"badge rec\">overview</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">A queue is needed when a task is heavy or can be done later: email, PDF generation, image processing, notifications.</div>\n      <div class=\"code\"><span class=\"cm\">// Without a queue: user waits for everything immediately</span>\nPOST /order\n  save order\n  send email\n  recalculate analytics\n  respond to user\n\n<span class=\"cm\">// With a queue: fast response, heavy work is done by a worker</span>\nPOST /order\n  save order\n  addJob(\"send-email\", orderID)\n  addJob(\"update-analytics\", orderID)\n  respond to user\n\n<span class=\"cm\">// Worker works separately</span>\nwhile (true) {\n  const job = queue.take();\n  process(job);\n}</div>\n      <div class=\"explain\">\n        <strong>RabbitMQ</strong> — classic task queues: take a message, process it, confirm it.<br>\n        <strong>Kafka</strong> — event stream for large systems: events are stored and different services can read them.<br>\n        <strong>For a beginner:</strong> it is enough to understand the producer → queue → worker idea. You will really need it later in backend projects.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-devops-queue-1\" onchange=\"updateProgress(this)\"><span>I understand why heavy tasks are moved to a queue</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-devops-queue-2\" onchange=\"updateProgress(this)\"><span>I know the producer → queue → worker chain</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-devops-queue-3\" onchange=\"updateProgress(this)\"><span>I distinguish RabbitMQ for tasks and Kafka for event streams at a basic level</span></label>\n      </div>\n    </div>\n"}]},{"id":"sec-pg","lessons":[{"id":"block-pg-cloud-2026","title":"Cloud PostgreSQL: Neon or Supabase 2026 CORE #","html":"<div class=\"block wdg-2026-block\" id=\"block-pg-cloud-2026\"><div class=\"block-title\" onclick=\"scrollToBlock('block-pg-cloud-2026')\">Cloud PostgreSQL: Neon or Supabase <span class=\"badge must\">2026 CORE</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">A managed cloud database removes lengthy local administration. Start with DATABASE_URL and basic CRUD.</div><div class=\"code\"># .env.local - never commit this file\nDATABASE_URL=\"postgresql://user:password@host/database?sslmode=require\"\n\nSELECT id, title FROM projects ORDER BY id DESC;\nINSERT INTO projects (title, author_id) VALUES ('Roadmap', 1);\nUPDATE projects SET title = 'WebDevGym' WHERE id = 1;\nDELETE FROM projects WHERE id = 1;</div><div class=\"explain\"><strong>Neon</strong> focuses on serverless PostgreSQL and database branches. <strong>Supabase</strong> adds auth, storage, realtime, and a dashboard. Keep <code>DATABASE_URL</code> in env and run migrations through the ORM.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-pg-cloud-2026-1\" onchange=\"updateProgress(this)\"><span>I connect through DATABASE_URL</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-pg-cloud-2026-2\" onchange=\"updateProgress(this)\"><span>I never commit the database URL</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-pg-cloud-2026-3\" onchange=\"updateProgress(this)\"><span>I perform SELECT/INSERT/UPDATE/DELETE</span></label></div></div>"},{"id":"block-pg-orm-2026","title":"Relations with Prisma or Drizzle 2026 CORE #","html":"<div class=\"block wdg-2026-block\" id=\"block-pg-orm-2026\"><div class=\"block-title\" onclick=\"scrollToBlock('block-pg-orm-2026')\">Relations with Prisma or Drizzle <span class=\"badge must\">2026 CORE</span><span class=\"anchor-icon\">#</span></div><div class=\"tip\">An ORM covers schema, migrations, and typed queries. SQL remains essential for understanding and debugging.</div><div class=\"code\">model User {\n  id       Int       @id @default(autoincrement())\n  email    String    @unique\n  projects Project[]\n}\n\nmodel Project {\n  id       Int    @id @default(autoincrement())\n  title    String\n  author   User   @relation(fields: [authorId], references: [id])\n  authorId Int\n}\n\nconst projects = await prisma.project.findMany({\n  where: { authorId: userId },\n  include: { author: true }\n});</div><div class=\"explain\"><strong>Prisma</strong> uses its own schema and generated client. <strong>Drizzle</strong> stays closer to SQL with TypeScript schemas. Pick one ORM. A foreign key creates one-to-many; a junction table creates many-to-many.</div><div class=\"items\"><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-pg-orm-2026-1\" onchange=\"updateProgress(this)\"><span>I model one-to-many and many-to-many</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-pg-orm-2026-2\" onchange=\"updateProgress(this)\"><span>I distinguish Prisma from Drizzle</span></label><label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"wdg-2026-block-pg-orm-2026-3\" onchange=\"updateProgress(this)\"><span>I run migrations</span></label></div></div>"},{"id":"block-pg-prisma","title":"Prisma ORM — working with PostgreSQL from Node.js important 🔗","html":"<div class=\"block\" id=\"block-pg-prisma\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-pg-prisma')\">Prisma ORM — working with PostgreSQL from Node.js <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\"># Installation</span>\n<span class=\"kw\">npm install</span> prisma @prisma/client\n<span class=\"kw\">npx prisma init</span>\n\n<span class=\"cm\">// schema.prisma</span>\ngenerator client {\n  provider = <span class=\"str\">\"prisma-client-js\"</span>\n}\ndatasource db {\n  provider = <span class=\"str\">\"postgresql\"</span>\n  url      = env(<span class=\"str\">\"DATABASE_URL\"</span>)\n}\nmodel User {\n  id        Int      @id @default(autoincrement())\n  name      String\n  email     String   @unique\n  posts     Post[]\n  createdAt DateTime @default(now())\n}\nmodel Post {\n  id      Int    @id @default(autoincrement())\n  title   String\n  user    User   @relation(field: [userID], references: [id])\n  userID  Int\n}\n\n<span class=\"cm\">// Usage in code</span>\n<span class=\"kw\">import</span> { PrismaClient } <span class=\"kw\">from</span> <span class=\"str\">'@prisma/client'</span>;\n<span class=\"kw\">const</span> prisma = <span class=\"kw\">new</span> <span class=\"fn\">PrismaClient</span>();\n\n<span class=\"cm\">// Create a user</span>\n<span class=\"kw\">const</span> user = <span class=\"kw\">await</span> prisma.user.<span class=\"fn\">create</span>({\n  data: { name: <span class=\"str\">'John'</span>, email: <span class=\"str\">'ivan@mail.ru'</span> }\n});\n\n<span class=\"cm\">// Find with relations</span>\n<span class=\"kw\">const</span> users = <span class=\"kw\">await</span> prisma.user.<span class=\"fn\">findMany</span>({\n  where: { email: { <span class=\"fn\">contains</span>: <span class=\"str\">'@mail.ru'</span> } },\n  include: { posts: <span class=\"kw\">true</span> },\n  orderBy: { createdAt: <span class=\"str\">'desc'</span> },\n  take: <span class=\"num\">10</span>\n});</div>\n      <div class=\"explain\">\n        <strong>Prisma</strong> is an ORM that generates a typed client from your schema. It is popular in TypeScript projects.<br>\n        <strong>npx prisma migrate dev</strong> — creates a migration and applies it to the database.<br>\n        <strong>include</strong> — loads related data, similar to JOIN. <strong>take</strong> = LIMIT, <strong>skip</strong> = OFFSET.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb601\" onchange=\"updateProgress(this)\"><span>schema.prisma — model and relation definitions</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb602\" onchange=\"updateProgress(this)\"><span>prisma.model.create/findMany/update/delete</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb603\" onchange=\"updateProgress(this)\"><span>include — loading related data</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb604\" onchange=\"updateProgress(this)\"><span>npx prisma migrate dev — applying migrations</span></label>\n      </div>\n    </div>\n"},{"id":"block-pg-schema","title":"DB schema and migrations important 🔗","html":"<div class=\"block\" id=\"block-pg-schema\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-pg-schema')\">DB schema and migrations <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">-- Create tables</span>\n<span class=\"kw\">CREATE TABLE</span> users (\n  id        <span class=\"str\">SERIAL PRIMARY KEY</span>,      <span class=\"cm\">-- auto-increment</span>\n  name      <span class=\"str\">VARCHAR(100) NOT NULL</span>,\n  email     <span class=\"str\">VARCHAR(255) UNIQUE NOT NULL</span>,\n  role      <span class=\"str\">VARCHAR(20) DEFAULT</span> <span class=\"str\">'user'</span>,\n  created_at <span class=\"str\">TIMESTAMP DEFAULT NOW()</span>\n);\n\n<span class=\"kw\">CREATE TABLE</span> posts (\n  id      <span class=\"str\">SERIAL PRIMARY KEY</span>,\n  user_id <span class=\"str\">INT REFERENCES</span> users(id) <span class=\"kw\">ON DELETE CASCADE</span>,\n  title   <span class=\"str\">TEXT NOT NULL</span>,\n  body    <span class=\"str\">TEXT</span>,\n  tags    <span class=\"str\">TEXT[]</span>                    <span class=\"cm\">-- array in PostgreSQL!</span>\n);\n\n<span class=\"cm\">-- Migrations through node-pg-migrate or Prisma</span>\n<span class=\"cm\">-- Never change DB manually in production!</span>\n<span class=\"cm\">-- Always through migration files</span></div>\n      <div class=\"explain\">\n        <strong>SERIAL</strong> — auto-increment numeric ID. In PostgreSQL 10+, GENERATED ALWAYS AS IDENTITY is preferred.<br>\n        <strong>ON DELETE CASCADE</strong> — when a user is deleted, all their posts are deleted too.<br>\n        <strong>TEXT[]</strong> — native PostgreSQL array type. Very convenient for tags.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb589\" onchange=\"updateProgress(this)\"><span>SERIAL, VARCHAR, TEXT, TIMESTAMP — main types</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb590\" onchange=\"updateProgress(this)\"><span>REFERENCES + ON DELETE CASCADE — foreign keys</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb591\" onchange=\"updateProgress(this)\"><span>Migrations — schema changes through files</span></label>\n      </div>\n    </div>\n  \n    "},{"id":"block-pg-crud","title":"CRUD operations in PostgreSQL basics 🔗","html":"<div class=\"block\" id=\"block-pg-crud\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-pg-crud')\">CRUD operations in PostgreSQL <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">-- CREATE</span>\n<span class=\"kw\">INSERT INTO</span> users (name, email) \n<span class=\"kw\">VALUES</span> (<span class=\"str\">'John'</span>, <span class=\"str\">'ivan@mail.ru'</span>)\n<span class=\"kw\">RETURNING</span> *; <span class=\"cm\">-- returns the created row</span>\n\n<span class=\"cm\">-- READ with filters</span>\n<span class=\"kw\">SELECT</span> id, name, email <span class=\"kw\">FROM</span> users\n<span class=\"kw\">WHERE</span> role = <span class=\"str\">'admin'</span> <span class=\"kw\">AND</span> created_at &gt; <span class=\"str\">'2024-01-01'</span>\n<span class=\"kw\">ORDER BY</span> created_at <span class=\"kw\">DESC</span>\n<span class=\"kw\">LIMIT</span> <span class=\"num\">10</span> <span class=\"kw\">OFFSET</span> <span class=\"num\">20</span>; <span class=\"cm\">-- pagination</span>\n\n<span class=\"cm\">-- UPDATE</span>\n<span class=\"kw\">UPDATE</span> users \n<span class=\"kw\">SET</span> name = <span class=\"str\">'Peter'</span>, updated_at = <span class=\"kw\">NOW</span>()\n<span class=\"kw\">WHERE</span> id = <span class=\"num\">1</span>\n<span class=\"kw\">RETURNING</span> *;\n\n<span class=\"cm\">-- DELETE</span>\n<span class=\"kw\">DELETE FROM</span> users <span class=\"kw\">WHERE</span> id = <span class=\"num\">1</span> <span class=\"kw\">RETURNING</span> id;</div>\n      <div class=\"explain\">\n        <strong>RETURNING</strong> — removes the need to do SELECT after INSERT/UPDATE/DELETE.<br>\n        <strong>OFFSET</strong> — skip N rows. Use for pagination: page 2 = OFFSET 10 with LIMIT 10.<br>\n        <strong>NOW()</strong> — current time on the DB server. Convenient for updated_at field.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb592\" onchange=\"updateProgress(this)\"><span>INSERT INTO ... VALUES ... RETURNING *</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb593\" onchange=\"updateProgress(this)\"><span>SELECT with WHERE, ORDER BY, LIMIT, OFFSET</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb594\" onchange=\"updateProgress(this)\"><span>UPDATE ... SET ... WHERE RETURNING *</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-pg-queries","title":"Parameterized queries and security basics 🔗","html":"<div class=\"block\" id=\"block-pg-queries\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-pg-queries')\">Parameterized queries and security <span class=\"badge must\">basics</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">// ❌ NEVER do this — SQL injection!</span>\n<span class=\"kw\">const</span> query = <span class=\"str\">`SELECT * FROM users WHERE email = '${email}'`</span>;\n\n<span class=\"cm\">// ✅ Correct: parameterized query</span>\n<span class=\"kw\">const</span> { rows } = <span class=\"kw\">await</span> pool.<span class=\"fn\">query</span>(\n  <span class=\"str\">'SELECT * FROM users WHERE email = $1'</span>,\n  [email]  <span class=\"cm\">// $1 — first parameter</span>\n);\n\n<span class=\"cm\">// Multiple parameters</span>\n<span class=\"kw\">await</span> pool.<span class=\"fn\">query</span>(\n  <span class=\"str\">'INSERT INTO users (name, email) VALUES ($1, $2) RETURNING *'</span>,\n  [name, email]\n);\n\n<span class=\"cm\">// Transaction</span>\n<span class=\"kw\">const</span> client = <span class=\"kw\">await</span> pool.<span class=\"fn\">connect</span>();\n<span class=\"kw\">try</span> {\n  <span class=\"kw\">await</span> client.<span class=\"fn\">query</span>(<span class=\"str\">'BEGIN'</span>);\n  <span class=\"kw\">await</span> client.<span class=\"fn\">query</span>(<span class=\"str\">'UPDATE accounts SET balance = balance - $1 WHERE id = $2'</span>, [amount, fromID]);\n  <span class=\"kw\">await</span> client.<span class=\"fn\">query</span>(<span class=\"str\">'UPDATE accounts SET balance = balance + $1 WHERE id = $2'</span>, [amount, toID]);\n  <span class=\"kw\">await</span> client.<span class=\"fn\">query</span>(<span class=\"str\">'COMMIT'</span>);\n} <span class=\"kw\">catch</span> (e) {\n  <span class=\"kw\">await</span> client.<span class=\"fn\">query</span>(<span class=\"str\">'ROLLBACK'</span>);\n} <span class=\"kw\">finally</span> { client.<span class=\"fn\">release</span>(); }\n</div>\n      <div class=\"explain\">\n        <strong>SQL Injection</strong> — if you insert data directly into a string, an attacker can execute arbitrary SQL.<br>\n        <strong>$1, $2...</strong> — PostgreSQL parameter syntax. MySQL uses ?.<br>\n        <strong>RETURNING *</strong> — returns the inserted/updated row without an extra SELECT.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb586\" onchange=\"updateProgress(this)\"><span>Parameterized queries $1, $2 — protection from SQL Injection</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb587\" onchange=\"updateProgress(this)\"><span>RETURNING * — get result after INSERT/UPDATE</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb588\" onchange=\"updateProgress(this)\"><span>Transactions — BEGIN / COMMIT / ROLLBACK</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-pg-json","title":"JSON and JSONB in PostgreSQL important 🔗","html":"<div class=\"block\" id=\"block-pg-json\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-pg-json')\">JSON and JSONB in PostgreSQL <span class=\"badge good\">important</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">-- JSONB — binary JSON (indexable, faster)</span>\n<span class=\"kw\">CREATE TABLE</span> products (\n  id    <span class=\"str\">SERIAL PRIMARY KEY</span>,\n  name  <span class=\"str\">TEXT NOT NULL</span>,\n  meta  <span class=\"str\">JSONB</span>   <span class=\"cm\">-- any data</span>\n);\n\n<span class=\"kw\">INSERT INTO</span> products (name, meta)\n<span class=\"kw\">VALUES</span> (<span class=\"str\">'Laptop'</span>, <span class=\"str\">'{\"brand\":\"Apple\",\"ram\":16,\"tags\":[\"tech\",\"sale\"]}'</span>);\n\n<span class=\"cm\">-- Access JSONB fields</span>\n<span class=\"kw\">SELECT</span> \n  name,\n  meta-&gt;<span class=\"str\">'brand'</span>    <span class=\"kw\">AS</span> brand,   <span class=\"cm\">-- returns JSON</span>\n  meta-&gt;&gt;<span class=\"str\">'brand'</span>   <span class=\"kw\">AS</span> brand_text <span class=\"cm\">-- returns text</span>\n<span class=\"kw\">FROM</span> products\n<span class=\"kw\">WHERE</span> meta-&gt;&gt;<span class=\"str\">'brand'</span> = <span class=\"str\">'Apple'</span>\n  <span class=\"kw\">AND</span> (meta-&gt;&gt;<span class=\"str\">'ram'</span>)::<span class=\"str\">int</span> &gt; <span class=\"num\">8</span>;\n\n<span class=\"cm\">-- Index by JSONB field</span>\n<span class=\"kw\">CREATE INDEX</span> idx_products_brand \n  <span class=\"kw\">ON</span> products ((meta-&gt;&gt;<span class=\"str\">'brand'</span>));</div>\n      <div class=\"explain\">\n        <strong>JSONB vs JSON</strong> — JSONB is stored in binary format, faster for search. Use JSONB.<br>\n        <strong>-&gt;</strong> returns JSON type, <strong>-&gt;&gt;</strong> returns text. For comparison, you need -&gt;&gt;.<br>\n        <strong>::int</strong> — type conversion (cast). JSONB often returns text; cast it for numeric comparisons.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb595\" onchange=\"updateProgress(this)\"><span>JSONB — flexible data storage</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb596\" onchange=\"updateProgress(this)\"><span>-&gt; and -&gt;&gt; — access JSON fields</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb597\" onchange=\"updateProgress(this)\"><span>Index by JSONB field for fast search</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-pg-functions","title":"Functions, triggers and views know 🔗","html":"<div class=\"block\" id=\"block-pg-functions\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-pg-functions')\">Functions, triggers and views <span class=\"badge\">know</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"code\"><span class=\"cm\">-- VIEW — virtual table</span>\n<span class=\"kw\">CREATE VIEW</span> active_users <span class=\"kw\">AS</span>\n<span class=\"kw\">SELECT</span> id, name, email <span class=\"kw\">FROM</span> users\n<span class=\"kw\">WHERE</span> is_active = <span class=\"kw\">true</span>;\n\n<span class=\"cm\">-- Usage as a regular table</span>\n<span class=\"kw\">SELECT</span> * <span class=\"kw\">FROM</span> active_users <span class=\"kw\">WHERE</span> name <span class=\"kw\">LIKE</span> <span class=\"str\">'A%'</span>;\n\n<span class=\"cm\">-- FUNCTION — stored function</span>\n<span class=\"kw\">CREATE OR REPLACE FUNCTION</span> <span class=\"fn\">get_user_orders</span>(user_id <span class=\"str\">INT</span>)\n<span class=\"kw\">RETURNS TABLE</span>(order_id <span class=\"str\">INT</span>, product <span class=\"str\">TEXT</span>, amount <span class=\"str\">NUMERIC</span>) <span class=\"kw\">AS</span> $$\n  <span class=\"kw\">SELECT</span> id, product, amount <span class=\"kw\">FROM</span> orders\n  <span class=\"kw\">WHERE</span> orders.user_id = get_user_orders.user_id;\n$$ <span class=\"kw\">LANGUAGE</span> sql;\n\n<span class=\"kw\">SELECT</span> * <span class=\"kw\">FROM</span> <span class=\"fn\">get_user_orders</span>(<span class=\"num\">1</span>);\n\n<span class=\"cm\">-- TRIGGER — automatically on change</span>\n<span class=\"kw\">CREATE OR REPLACE FUNCTION</span> <span class=\"fn\">update_timestamp</span>()\n<span class=\"kw\">RETURNS TRIGGER AS</span> $$\n<span class=\"kw\">BEGIN</span>\n  NEW.updated_at = <span class=\"kw\">NOW</span>();\n  <span class=\"kw\">RETURN</span> NEW;\n<span class=\"kw\">END</span>; $$ <span class=\"kw\">LANGUAGE</span> plpgsql;\n\n<span class=\"kw\">CREATE TRIGGER</span> set_timestamp\n  <span class=\"kw\">BEFORE UPDATE ON</span> users\n  <span class=\"kw\">FOR EACH ROW EXECUTE FUNCTION</span> <span class=\"fn\">update_timestamp</span>();</div>\n      <div class=\"explain\">\n        <strong>VIEW</strong> — saved SELECT query. Simplifies complex queries and hides details.<br>\n        <strong>Trigger</strong> automatically updates updated_at without changing app code.<br>\n        <strong>$$ ... $$</strong> — function body delimiter in PostgreSQL.\n      </div>\n      <div class=\"items\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb598\" onchange=\"updateProgress(this)\"><span>CREATE VIEW — virtual table from SELECT</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb599\" onchange=\"updateProgress(this)\"><span>Stored functions — CREATE FUNCTION</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb600\" onchange=\"updateProgress(this)\"><span>Trigger — automatic field updates</span></label>\n      </div>\n    </div>\n\n    "}]},{"id":"sec-github","lessons":[{"id":"block-git-github-create","title":"🆕 Create a new repository practice 🔗","html":"<div class=\"block\" id=\"block-git-github-create\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-git-github-create')\">🆕 Create a new repository <span class=\"badge good\">practice</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Create a repository directly here without opening GitHub. Use the same token as for file uploads; it needs the <code>repo</code> scope.</div>\n\n      <div style=\"background:#0d1117;border-radius:12px;padding:20px;margin-top:12px;border:1px solid #30363d;\">\n\n        <div style=\"margin-bottom:12px;\">\n          <label style=\"display:block;font-size:12px;color:#8b949e;margin-bottom:5px;font-weight:600;\">🔑 Personal Access Token <a href=\"https://github.com/settings/tokens/new?scopes=repo&amp;description=Roadmap+Uploader\" target=\"_blank\" style=\"color:#58a6ff;text-decoration:none;margin-left:8px;font-weight:400;\">→ Create token</a></label>\n          <input id=\"ghc-token\" type=\"password\" placeholder=\"ghp_xxxxxxxxxxxxxxxxxxxx\" oninput=\"ghSaveField('ghc-token', this.value)\" style=\"width:100%;padding:8px 12px;background:#161b22;border:1px solid #30363d;border-radius:8px;color:#e6edf3;font-size:13px;font-family:inherit;outline:none;box-sizing:border-box;\">\n          <div style=\"font-size:11px;color:#6e7681;margin-top:4px;\">🔒 The same token can be used below for file uploads</div>\n        </div>\n\n        <div style=\"display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:12px;\">\n          <div>\n            <label style=\"display:block;font-size:12px;color:#8b949e;margin-bottom:5px;font-weight:600;\">📁 Repository name</label>\n            <input id=\"ghc-name\" type=\"text\" placeholder=\"my-awesome-project\" oninput=\"ghSaveField('ghc-name', this.value)\" style=\"width:100%;padding:8px 12px;background:#161b22;border:1px solid #30363d;border-radius:8px;color:#e6edf3;font-size:13px;font-family:inherit;outline:none;box-sizing:border-box;\">\n          </div>\n          <div>\n            <label style=\"display:block;font-size:12px;color:#8b949e;margin-bottom:5px;font-weight:600;\">👁 Visibility</label>\n            <select id=\"ghc-visibility\" oninput=\"ghSaveField('ghc-visibility', this.value)\" style=\"width:100%;padding:8px 12px;background:#161b22;border:1px solid #30363d;border-radius:8px;color:#e6edf3;font-size:13px;font-family:inherit;outline:none;box-sizing:border-box;cursor:pointer;\">\n              <option value=\"false\">🌍 Public</option>\n              <option value=\"true\">🔒 Private</option>\n            </select>\n          </div>\n        </div>\n\n        <div style=\"margin-bottom:12px;\">\n          <label style=\"display:block;font-size:12px;color:#8b949e;margin-bottom:5px;font-weight:600;\">📝 Description (optional)</label>\n          <input id=\"ghc-desc\" type=\"text\" placeholder=\"Short project description\" oninput=\"ghSaveField('ghc-desc', this.value)\" style=\"width:100%;padding:8px 12px;background:#161b22;border:1px solid #30363d;border-radius:8px;color:#e6edf3;font-size:13px;font-family:inherit;outline:none;box-sizing:border-box;\">\n        </div>\n\n        <label style=\"display:flex;align-items:center;gap:8px;margin-bottom:16px;font-size:13px;color:#c9d1d9;cursor:pointer;\">\n          <input type=\"checkbox\" id=\"ghc-readme\" checked style=\"width:16px;height:16px;cursor:pointer;accent-color:#238636;\">\n          Create with README.md (recommended)\n        </label>\n\n        <button onclick=\"githubCreateRepo()\" style=\"width:100%;padding:11px;background:linear-gradient(135deg,#238636,#2ea043);color:#fff;border:none;border-radius:8px;font-size:14px;font-weight:700;cursor:pointer;font-family:inherit;transition:opacity .2s;\" onmouseover=\"this.style.opacity='.85'\" onmouseout=\"this.style.opacity='1'\">\n          🆕 Create repository\n        </button>\n\n        <div id=\"ghc-status\" style=\"margin-top:12px;font-size:13px;display:none;padding:10px 14px;border-radius:8px;\"></div>\n      </div>\n\n      <div class=\"items\" style=\"margin-top:14px;\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb605\" onchange=\"updateProgress(this)\"><span>Created a new repository through the API</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb606\" onchange=\"updateProgress(this)\"><span>I understand the difference between public and private repositories</span></label>\n      </div>\n    </div>\n\n    "},{"id":"block-git-github-upload","title":"🚀 Upload a file to a GitHub repository practice 🔗","html":"<div class=\"block\" id=\"block-git-github-upload\">\n      <div class=\"block-title\" onclick=\"scrollToBlock('block-git-github-upload')\">🚀 Upload a file to a GitHub repository <span class=\"badge good\">practice</span><span class=\"anchor-icon\">🔗</span></div>\n      <div class=\"tip\">Upload a file directly to your GitHub repository through the API. The token is not saved anywhere.</div>\n\n      <div style=\"background:#0d1117;border-radius:12px;padding:20px;margin-top:12px;border:1px solid #30363d;\">\n        <div style=\"display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:12px;\">\n          <div>\n            <label style=\"display:block;font-size:12px;color:#8b949e;margin-bottom:5px;font-weight:600;\">👤 GitHub Username</label>\n            <input id=\"gh-username\" type=\"text\" placeholder=\"your-username\" style=\"width:100%;padding:8px 12px;background:#161b22;border:1px solid #30363d;border-radius:8px;color:#e6edf3;font-size:13px;font-family:inherit;outline:none;box-sizing:border-box;\" oninput=\"ghSaveField('gh-username', this.value)\">\n          </div>\n          <div>\n            <label style=\"display:block;font-size:12px;color:#8b949e;margin-bottom:5px;font-weight:600;\">📁 Repository Name</label>\n            <input id=\"gh-repo\" type=\"text\" placeholder=\"your-repo-name\" style=\"width:100%;padding:8px 12px;background:#161b22;border:1px solid #30363d;border-radius:8px;color:#e6edf3;font-size:13px;font-family:inherit;outline:none;box-sizing:border-box;\" oninput=\"ghSaveField('gh-repo', this.value)\">\n          </div>\n        </div>\n        <div style=\"margin-bottom:12px;\">\n          <label style=\"display:block;font-size:12px;color:#8b949e;margin-bottom:5px;font-weight:600;\">🔑 Personal Access Token <a href=\"https://github.com/settings/tokens/new?scopes=repo&amp;description=Roadmap+Uploader\" target=\"_blank\" style=\"color:#58a6ff;text-decoration:none;margin-left:8px;font-weight:400;\">→ Create token</a></label>\n          <input id=\"gh-token\" type=\"password\" placeholder=\"ghp_xxxxxxxxxxxxxxxxxxxx\" style=\"width:100%;padding:8px 12px;background:#161b22;border:1px solid #30363d;border-radius:8px;color:#e6edf3;font-size:13px;font-family:inherit;outline:none;box-sizing:border-box;\" oninput=\"ghSaveField('gh-token', this.value)\">\n          <div style=\"font-size:11px;color:#6e7681;margin-top:4px;\">🔒 The token is not saved and remains only in this tab's memory</div>\n        </div>\n        <div style=\"display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:12px;\">\n          <div>\n            <label style=\"display:block;font-size:12px;color:#8b949e;margin-bottom:5px;font-weight:600;\">📄 File path in the repository</label>\n            <input id=\"gh-filepath\" type=\"text\" placeholder=\"index.html\" style=\"width:100%;padding:8px 12px;background:#161b22;border:1px solid #30363d;border-radius:8px;color:#e6edf3;font-size:13px;font-family:inherit;outline:none;box-sizing:border-box;\" oninput=\"ghSaveField('gh-filepath', this.value)\">\n          </div>\n          <div>\n            <label style=\"display:block;font-size:12px;color:#8b949e;margin-bottom:5px;font-weight:600;\">🌿 Branch</label>\n            <input id=\"gh-branch\" type=\"text\" placeholder=\"main\" value=\"main\" style=\"width:100%;padding:8px 12px;background:#161b22;border:1px solid #30363d;border-radius:8px;color:#e6edf3;font-size:13px;font-family:inherit;outline:none;box-sizing:border-box;\" oninput=\"ghSaveField('gh-branch', this.value)\">\n          </div>\n        </div>\n        <div style=\"margin-bottom:12px;\">\n          <label style=\"display:block;font-size:12px;color:#8b949e;margin-bottom:5px;font-weight:600;\">💬 Commit message</label>\n          <input id=\"gh-message\" type=\"text\" placeholder=\"update: roadmap content\" style=\"width:100%;padding:8px 12px;background:#161b22;border:1px solid #30363d;border-radius:8px;color:#e6edf3;font-size:13px;font-family:inherit;outline:none;box-sizing:border-box;\">\n        </div>\n        <div style=\"margin-bottom:16px;\">\n          <label style=\"display:block;font-size:12px;color:#8b949e;margin-bottom:5px;font-weight:600;\">📎 File to upload</label>\n          <input id=\"gh-file-input\" type=\"file\" style=\"width:100%;padding:8px 12px;background:#161b22;border:1px solid #30363d;border-radius:8px;color:#e6edf3;font-size:13px;font-family:inherit;cursor:pointer;box-sizing:border-box;\">\n        </div>\n        <button onclick=\"githubUpload()\" style=\"width:100%;padding:11px;background:linear-gradient(135deg,#238636,#2ea043);color:#fff;border:none;border-radius:8px;font-size:14px;font-weight:700;cursor:pointer;font-family:inherit;transition:opacity .2s;\" onmouseover=\"this.style.opacity='.85'\" onmouseout=\"this.style.opacity='1'\">\n          ↑ Push on GitHub\n        </button>\n        <div id=\"gh-status\" style=\"margin-top:12px;font-size:13px;display:none;padding:10px 14px;border-radius:8px;\"></div>\n      </div>\n\n      <div class=\"items\" style=\"margin-top:14px;\">\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb607\" onchange=\"updateProgress(this)\"><span>Created a Personal Access Token on GitHub</span></label>\n        <label class=\"item\"><input type=\"checkbox\" class=\"prog-cb\" data-pid=\"pcb608\" onchange=\"updateProgress(this)\"><span>Successfully uploaded a file through the GitHub API</span></label>\n      </div>\n    </div>\n\n  "}]}]};
